const int _kActionGridColumns = 3;
const double _kActionTileWidth = 96.0;
const double _kActionTileHeight = 96.0;
const double _kActionGridSpacing = 12.0;
const double _kActionGridHPadding = 12.0;
const double _kActionGridVPadding = 12.0;
const Key _kCalendarActionsMenuPanelKey = ValueKey(
  'calendar-actions-menu-panel',
);
const Key _kCalendarActionsGridKey = ValueKey('calendar-actions-grid');

bool _isLandscapeMenu(BuildContext context) =>
    MediaQuery.orientationOf(context) == Orientation.landscape;

double _landscapeMenuPanelWidth(BuildContext context) {
  const double defaultGridWidth =
      _kActionGridHPadding * 2 +
      _kActionGridColumns * _kActionTileWidth +
      (_kActionGridColumns - 1) * _kActionGridSpacing;
  final screenWidth = MediaQuery.sizeOf(context).width;
  return math.min(defaultGridWidth, screenWidth * 0.82);
}

double _landscapeMenuMaxGridHeight(
  BuildContext context, {
  required double bottomInset,
}) {
  final media = MediaQuery.of(context);
  const handleChrome = 10.0 + 3.0 + 8.0;
  final targetPanelHeight = media.size.height * 0.80;
  return math.max(96.0, targetPanelHeight - handleChrome - bottomInset);
}

class _CalendarAction {
  final IconData? icon;
  final String? glyph;
  final double glyphSize;
  final Gradient gradient;
  final String label;
  final bool showNotificationDot;
  final bool dispatchBeforeClose;
  final FutureOr<void> Function() onSelected;

  const _CalendarAction({
    this.icon,
    this.glyph,
    this.glyphSize = 22,
    required this.gradient,
    required this.label,
    this.showNotificationDot = false,
    this.dispatchBeforeClose = false,
    required this.onSelected,
  }) : assert(icon != null || glyph != null);
}

class _NotificationDotOverlay extends StatelessWidget {
  final Widget child;
  final bool show;
  final double top;
  final double right;

  const _NotificationDotOverlay({
    required this.child,
    required this.show,
    this.top = -2,
    this.right = -2,
  });

  @override
  Widget build(BuildContext context) {
    return Stack(
      clipBehavior: Clip.none,
      children: [
        child,
        if (show)
          Positioned(
            top: top,
            right: right,
            child: Container(
              width: 10,
              height: 10,
              decoration: BoxDecoration(
                color: Colors.redAccent,
                shape: BoxShape.circle,
                border: Border.all(color: Colors.black, width: 1.5),
              ),
            ),
          ),
      ],
    );
  }
}

class _CalendarActionsGrid extends StatelessWidget {
  final List<_CalendarAction> actions;
  final void Function(_CalendarAction action) onSelected;
  final double? maxHeight;

  const _CalendarActionsGrid({
    required this.actions,
    required this.onSelected,
    this.maxHeight,
  });

  @override
  Widget build(BuildContext context) {
    final rows =
        (actions.length + _kActionGridColumns - 1) ~/ _kActionGridColumns;
    const double defaultWidth =
        _kActionGridHPadding * 2 +
        _kActionGridColumns * _kActionTileWidth +
        (_kActionGridColumns - 1) * _kActionGridSpacing;
    final double height =
        _kActionGridVPadding * 2 +
        rows * _kActionTileHeight +
        (rows - 1) * _kActionGridSpacing;

    return LayoutBuilder(
      builder: (context, constraints) {
        final constrainedWidth = constraints.maxWidth.isFinite
            ? constraints.maxWidth
            : defaultWidth;
        final width = math.min(defaultWidth, constrainedWidth);
        final tileWidth = math.max(
          1.0,
          (width -
                  _kActionGridHPadding * 2 -
                  (_kActionGridColumns - 1) * _kActionGridSpacing) /
              _kActionGridColumns,
        );

        final grid = GridView.builder(
          key: _kCalendarActionsGridKey,
          physics: maxHeight == null
              ? const NeverScrollableScrollPhysics()
              : const ClampingScrollPhysics(),
          padding: EdgeInsets.zero,
          gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
            crossAxisCount: _kActionGridColumns,
            mainAxisSpacing: _kActionGridSpacing,
            crossAxisSpacing: _kActionGridSpacing,
            childAspectRatio: tileWidth / _kActionTileHeight,
          ),
          itemCount: actions.length,
          itemBuilder: (ctx, index) {
            final action = actions[index];
            final actionIcon = action.glyph != null
                ? GlossyGlyph(
                    glyph: action.glyph!,
                    gradient: action.gradient,
                    size: action.glyphSize,
                  )
                : _GlossyIcon(action.icon!, gradient: action.gradient);
            return InkWell(
              onTap: () => onSelected(action),
              borderRadius: BorderRadius.circular(12),
              child: Container(
                height: _kActionTileHeight,
                decoration: BoxDecoration(
                  color: const Color(0xFF111111),
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: Colors.white12),
                ),
                child: Column(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    SizedBox(
                      height: 30,
                      child: Center(
                        child: _NotificationDotOverlay(
                          show: action.showNotificationDot,
                          top: -4,
                          right: -6,
                          child: actionIcon,
                        ),
                      ),
                    ),
                    const SizedBox(height: 8),
                    Text(
                      action.label,
                      textAlign: TextAlign.center,
                      style: const TextStyle(
                        color: Colors.white,
                        fontSize: 12,
                        height: 1.2,
                      ),
                      maxLines: 2,
                      overflow: TextOverflow.ellipsis,
                    ),
                  ],
                ),
              ),
            );
          },
        );

        final gridBody = Padding(
          padding: const EdgeInsets.symmetric(
            horizontal: _kActionGridHPadding,
            vertical: _kActionGridVPadding,
          ),
          child: grid,
        );

        return SizedBox(
          width: width,
          height: maxHeight == null ? height : math.min(height, maxHeight!),
          child: gridBody,
        );
      },
    );
  }
}

Future<_CalendarAction?> _showCalendarActionsBottomSheet({
  required BuildContext context,
  required List<_CalendarAction> Function(bool hasUnreadInbox) actionsBuilder,
}) {
  return showModalBottomSheet<_CalendarAction>(
    context: context,
    useRootNavigator: true,
    isDismissible: true,
    enableDrag: true,
    isScrollControlled: true,
    useSafeArea: false,
    routeSettings: const RouteSettings(name: calendarActionsMenuRouteName),
    backgroundColor: Colors.transparent,
    barrierColor: Colors.black45,
    clipBehavior: Clip.none,
    builder: (sheetContext) {
      return _CalendarActionsMenuPanel(
        actionsBuilder: actionsBuilder,
        onSelected: (action) async {
          Navigator.of(sheetContext, rootNavigator: true).pop(action);
        },
      );
    },
  );
}

class _CalendarActionsMenuPanel extends StatelessWidget {
  const _CalendarActionsMenuPanel({
    required this.actionsBuilder,
    required this.onSelected,
  });

  final List<_CalendarAction> Function(bool hasUnreadInbox) actionsBuilder;
  final Future<void> Function(_CalendarAction action) onSelected;

  @override
  Widget build(BuildContext context) {
    final media = MediaQuery.of(context);
    final isLandscape = _isLandscapeMenu(context);
    final panelWidth = isLandscape
        ? _landscapeMenuPanelWidth(context)
        : double.infinity;
    final bottomInset = media.padding.bottom + 16;
    final maxGridHeight = isLandscape
        ? _landscapeMenuMaxGridHeight(context, bottomInset: bottomInset)
        : null;
    final shareRepo = ShareRepo(Supabase.instance.client);

    return Align(
      widthFactor: 1,
      heightFactor: 1,
      alignment: Alignment.bottomCenter,
      child: Material(
        color: Colors.transparent,
        child: Container(
          key: _kCalendarActionsMenuPanelKey,
          width: panelWidth,
          decoration: BoxDecoration(
            color: const Color(0xF6000000),
            borderRadius: isLandscape
                ? const BorderRadius.vertical(top: Radius.circular(16))
                : BorderRadius.zero,
            boxShadow: const [
              BoxShadow(
                color: Color(0xB3000000),
                blurRadius: 18,
                offset: Offset(0, -8),
              ),
            ],
          ),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              const SizedBox(height: 10),
              Container(
                width: 38,
                height: 3,
                decoration: BoxDecoration(
                  color: Colors.white24,
                  borderRadius: BorderRadius.circular(999),
                ),
              ),
              const SizedBox(height: 8),
              StreamBuilder<InboxUnreadState>(
                initialData: shareRepo.currentUnreadState,
                stream: shareRepo.watchUnreadState(),
                builder: (context, snapshot) {
                  final hasUnreadInbox =
                      (snapshot.data ?? const InboxUnreadState()).hasUnread;
                  return _CalendarActionsGrid(
                    actions: actionsBuilder(hasUnreadInbox),
                    maxHeight: maxGridHeight,
                    onSelected: (action) {
                      unawaited(onSelected(action));
                    },
                  );
                },
              ),
              SizedBox(height: bottomInset),
            ],
          ),
        ),
      ),
    );
  }
}

