    if (state == null || !state.mounted) return null;
    return state;
  }

  static bool get hasMountedHost => _mountedState != null;

  static FlowDetailActionPolicy resolveCanonicalCustomFlowActionPolicy({
    required FlowDetailSource source,
    required bool isLocalFlow,
    bool isOwner = false,
    bool isImported = false,
    bool isSaved = false,
    bool isReadOnly = false,
    bool busy = false,
    FutureOr<void> Function()? onPressed,
    String? startDateLabel,
    FutureOr<void> Function()? onStartDatePressed,
  }) {
    if (isReadOnly) {
      return FlowDetailActionPolicy(
        source: source,
        kind: FlowDetailActionKind.viewOnly,
        label: 'View Only',
        icon: Icons.visibility_outlined,
        enabled: false,
        onPressed: null,
      );
    }

    if (source == FlowDetailSource.inboxShare ||
        source == FlowDetailSource.directShare) {
      if (isImported || isLocalFlow) {
        return FlowDetailActionPolicy(
          source: source,
          kind: FlowDetailActionKind.openImported,
          label: 'Manage Flow',
          icon: Icons.tune,
          busy: busy,
          onPressed: onPressed,
        );
      }
      return FlowDetailActionPolicy(
        source: source,
        kind: FlowDetailActionKind.importFlow,
        label: 'Import Flow',
        busyLabel: 'Importing...',
        icon: Icons.file_download_outlined,
        busy: busy,
        onPressed: onPressed,
        startDateLabel: startDateLabel,
        onStartDatePressed: onStartDatePressed,
      );
    }

    if (source == FlowDetailSource.profilePost ||
        source == FlowDetailSource.profileActivity) {
      if (isSaved || isImported || isLocalFlow) {
        return FlowDetailActionPolicy(
          source: source,
          kind: FlowDetailActionKind.openSaved,
          label: 'Manage Flow',
          icon: Icons.tune,
          busy: busy,
          onPressed: onPressed,
        );
      }
      return FlowDetailActionPolicy(
        source: source,
        kind: FlowDetailActionKind.addToMyFlows,
        label: 'Add to My Flows',
        busyLabel: 'Adding...',
        icon: Icons.bookmark_add_outlined,
        busy: busy,
        onPressed: onPressed,
      );
    }

    return FlowDetailActionPolicy(
      source: source,
      kind: FlowDetailActionKind.manage,
      label: isOwner || isLocalFlow ? 'Manage Flow' : 'View Only',
      icon: isOwner || isLocalFlow ? Icons.tune : Icons.visibility_outlined,
      enabled: isOwner || isLocalFlow,
      busy: busy,
      onPressed: isOwner || isLocalFlow ? onPressed : null,
    );
  }

  static Widget buildCanonicalCustomFlowDetail({
    required String name,
    required int color,
    String? notes,
    List<dynamic> rulesJson = const <dynamic>[],
    List<dynamic> eventsJson = const <dynamic>[],
    int? flowId,
    DateTime? startDate,
    DateTime? endDate,
    bool active = true,
    bool isSaved = false,
    bool previewAsTemplate = false,
    FlowDetailActionPolicy? actionPolicy,
    bool showFlowOptions = false,
  }) {
    final syntheticId = flowId ?? _syntheticFlowIdForSnapshot(name, eventsJson);
    final flow = _Flow(
      id: syntheticId,
      name: name.trim().isEmpty ? 'Flow' : name.trim(),
      color: _flowDetailColor(color),
      active: active,
      isSaved: isSaved || previewAsTemplate,
      savedAt: isSaved || previewAsTemplate ? DateTime.now().toUtc() : null,
      rules: _parseCanonicalFlowDetailRules(rulesJson),
      start: startDate?.toLocal(),
      end: endDate?.toLocal(),
      notes: notes,
    );

    final events = _canonicalFlowDetailEventsFromSnapshot(
      eventsJson,
      flowId: syntheticId,
      flowName: flow.name,
      baseStart: flow.start,
    );
    final metrics = events.isEmpty
        ? const <int, _FlowPreviewMetrics>{}
        : <int, _FlowPreviewMetrics>{
            syntheticId: _metricsForCanonicalFlowDetail(
              events,
              template: previewAsTemplate || isSaved || !active,
            ),
          };
    final initialEventsByFlow = events.isEmpty
        ? null
        : <int, List<FlowEventRow>>{syntheticId: events};
    final mode = previewAsTemplate || isSaved || !active
        ? _FlowPreviewMode.saved
        : _FlowPreviewMode.active;

    return _FlowPreviewPage(
      flow: flow,
      mode: mode,
      metricsByFlow: metrics,
      initialEventsByFlow: initialEventsByFlow,
      getDecanLabel: (km, di) =>
          (DecanMetadata.decanNames[km] ?? const ['I', 'II', 'III'])[di],
      fmt: _formatDetachedGregorian,
      onEdit: (_) {},
      onAppendToJournal: null,
      onEndMaatFlow: null,
      actionPolicy: actionPolicy,
      showFlowOptions: showFlowOptions,
    );
  }

  static Widget? buildCanonicalMaatFlowDetail({
    required String name,
    String? notes,
    List<dynamic> eventsJson = const <dynamic>[],
  }) {
    final templateKey = _canonicalMaatTemplateKeyForSnapshot(
      name: name,
      notes: notes,
      eventsJson: eventsJson,
    );
    if (templateKey == null) return null;

    for (final template in _kMaatFlowTemplates) {
      if (template.key != templateKey) continue;
      return _MaatFlowTemplateDetailPage(
        template: template,
        addInstance: _addMaatFlowInstanceHeadless,
      );
    }
    return null;
  }

  static String? _canonicalMaatTemplateKeyForSnapshot({
    required String name,
    String? notes,
    List<dynamic> eventsJson = const <dynamic>[],
  }) {
    final directKind = resolveMaatFlowKind(flowName: name, flowNotes: notes);
    if (directKind != null) return directKind.flowKey;

    for (final raw in eventsJson) {
      if (raw is! Map) continue;
      final event = Map<String, dynamic>.from(raw);
      final behaviorPayload = event['behavior_payload'];
      final behaviorPayloadMap = behaviorPayload is Map
          ? Map<String, dynamic>.from(behaviorPayload)
          : null;
      final eventKind = resolveMaatFlowKind(
        actionId: event['action_id']?.toString(),
        behaviorPayload: behaviorPayloadMap,
      );
      if (eventKind != null) return eventKind.flowKey;
    }
    return null;
  }

  static Color _flowDetailColor(int raw) {
    if ((raw & 0xFF000000) != 0) return Color(raw);
    return Color(rgbToArgb(raw));
  }

  static int _syntheticFlowIdForSnapshot(
    String name,
    List<dynamic> eventsJson,
  ) {
    var hash = 17;
    for (final unit in name.codeUnits) {
      hash = ((hash * 31) + unit) & 0x3FFFFFFF;
    }
    hash = ((hash * 31) + eventsJson.length) & 0x3FFFFFFF;
    return -(hash + 1);
  }

  static List<FlowRule> _parseCanonicalFlowDetailRules(
    List<dynamic> rulesJson,
  ) {
    if (rulesJson.isEmpty) return const <FlowRule>[];
    final parsed = <FlowRule>[];
    for (final raw in rulesJson) {
      if (raw is! Map) continue;
      try {
        parsed.add(ruleFromJson(Map<String, dynamic>.from(raw)));
      } catch (_) {
        // Ignore malformed snapshot rules; the event snapshot still renders.
      }
    }
    return parsed;
  }

  static _FlowPreviewMetrics _metricsForCanonicalFlowDetail(
    List<FlowEventRow> events, {
    required bool template,
  }) {
    final total = events.length;
    if (template) {
      return _FlowPreviewMetrics(
        totalEventCount: total,
        remainingEventCount: total,
        completedEventCount: 0,
      );
    }
    final today = DateUtils.dateOnly(DateTime.now());
    final remaining = events.where((event) {
      final date = DateUtils.dateOnly(event.startsAtUtc.toLocal());
      return !date.isBefore(today);
    }).length;
    return _FlowPreviewMetrics(
      totalEventCount: total,
      remainingEventCount: remaining,
      completedEventCount: total - remaining,
    );
  }

  static List<FlowEventRow> _canonicalFlowDetailEventsFromSnapshot(
    List<dynamic> eventsJson, {
    required int flowId,
    required String flowName,
    DateTime? baseStart,
  }) {
    if (eventsJson.isEmpty) return const <FlowEventRow>[];
    final base = DateUtils.dateOnly(baseStart ?? DateTime.now());
    final rows = <FlowEventRow>[];
    for (var index = 0; index < eventsJson.length; index++) {
      final raw = eventsJson[index];
      if (raw is! Map) continue;
      final event = Map<String, dynamic>.from(raw);
      final allDay = (event['all_day'] as bool?) ?? false;
      final offset = (event['offset_days'] as num?)?.toInt() ?? index;
      final date =
          _dateOnlyFromSnapshot(event['date']) ??
          _dateOnlyFromSnapshot(event['start_date']) ??
          base.add(Duration(days: offset));
      final startParts = _timePartsFromSnapshot(event['start_time']);
      final endParts = _optionalTimePartsFromSnapshot(event['end_time']);
      final start = DateTime(
        date.year,
        date.month,
        date.day,
        allDay ? 9 : startParts.$1,
        allDay ? 0 : startParts.$2,
      );
      final DateTime? end = allDay
          ? null
          : endParts == null
          ? start.add(const Duration(hours: 1))
          : DateTime(date.year, date.month, date.day, endParts.$1, endParts.$2);

      rows.add((
        id: event['id'] as String?,
        clientEventId:
            event['client_event_id'] as String? ??
            'snapshot_flow_${flowId}_$index',
        calendarId: event['calendar_id'] as String?,
        calendarName: event['calendar_name'] as String?,
        calendarColor: (event['calendar_color'] as num?)?.toInt(),
        calendarIsPersonal: (event['calendar_is_personal'] as bool?) ?? true,
        title: (event['title'] as String?)?.trim().isNotEmpty == true
            ? (event['title'] as String).trim()
            : flowName,
        detail: event['detail'] as String?,
        location: event['location'] as String?,
        allDay: allDay,
        startsAtUtc: start.toUtc(),
        endsAtUtc: end?.toUtc(),
        flowLocalId: flowId,
        category: event['category'] as String?,
        actionId: (event['action_id'] as String?)?.trim(),
        behaviorPayload: event['behavior_payload'] is Map
            ? Map<String, dynamic>.from(event['behavior_payload'] as Map)
            : null,
      ));
    }
    rows.sort((a, b) => a.startsAtUtc.compareTo(b.startsAtUtc));
    return rows;
  }

  static DateTime? _dateOnlyFromSnapshot(dynamic value) {
    if (value == null) return null;
    if (value is DateTime) return DateUtils.dateOnly(value);
    final parsed = DateTime.tryParse(value.toString());
    return parsed == null ? null : DateUtils.dateOnly(parsed.toLocal());
  }

  static (int, int) _timePartsFromSnapshot(dynamic value) {
    return _optionalTimePartsFromSnapshot(value) ?? (9, 0);
  }

  static (int, int)? _optionalTimePartsFromSnapshot(dynamic value) {
    final raw = value?.toString().trim();
    if (raw == null || raw.isEmpty) return null;
    final match = RegExp(
      r'^(\d{1,2}):(\d{2})(?:\s*(am|pm))?$',
      caseSensitive: false,
    ).firstMatch(raw);
    if (match == null) return null;
    var hour = int.tryParse(match.group(1) ?? '') ?? 9;
    final minute = int.tryParse(match.group(2) ?? '') ?? 0;
    final meridian = match.group(3)?.toLowerCase();
    if (meridian == 'pm' && hour < 12) hour += 12;
    if (meridian == 'am' && hour == 12) hour = 0;
    return (hour.clamp(0, 23).toInt(), minute.clamp(0, 59).toInt());
  }

  static Future<void> dismissMountedReflectionPromptIfAny() async {
    final state = _mountedState;
    if (state == null) return;
    await state._dismissReflectionPrompt();
  }

  static bool _isRootRouteLocation(String location) {
    final uri = Uri.tryParse(location.trim());
    return uri == null || uri.path.isEmpty || uri.path == '/';
  }

  static String _currentRouteLocationForContext(BuildContext context) {
    try {
      final location = GoRouterState.of(context).uri.toString().trim();
      if (location.isNotEmpty) return location;
    } catch (_) {
      // Contexts from popup/menu routes may not carry a GoRouterState.
    }

    try {
      final location = GoRouter.of(
        context,
      ).routerDelegate.currentConfiguration.uri.toString().trim();
      if (location.isNotEmpty) return location;
    } catch (_) {
      // Fall through to the calendar root.
    }

    return '/';
  }

  static bool _shouldUseMountedCalendarHost(BuildContext context) {
    final state = _mountedState;
    if (state == null || !state.mounted) return false;
    return _isRootRouteLocation(_currentRouteLocationForContext(context));
  }

  static CalendarPageState? _mountedCalendarHostForContext(
    BuildContext context,
  ) {
    final state = _mountedState;
    if (state == null || !state.mounted) return null;
    if (!_isRootRouteLocation(_currentRouteLocationForContext(context))) {
      return null;
    }
    return state;
  }

  static bool _isTransientFlowStudioEditorState(Map<String, dynamic> state) {
    return state['mode'] == _kFlowStudioModeEditor;
  }

  static bool _isTransientFlowStudioEditorOverlay(Map<String, dynamic> entry) {
    return entry['kind'] == _kCalendarOverlayKindFlowStudio &&
        _isTransientFlowStudioEditorState(entry);
  }

  static Future<void> _removeCalendarOverlayKinds(
    Set<String> kinds, {
    OverlayStackMutationReason reason = OverlayStackMutationReason.programmatic,
  }) async {
    if (kinds.isEmpty) return;
    final stack = await AppRestorationService.instance.readOverlayStack();
    final next = stack
        .where((entry) => !kinds.contains(entry['kind']))
        .toList(growable: false);
    await AppRestorationService.instance.saveOverlayStack(next, reason: reason);
    unawaited(RestorationCoordinator.instance.flush());
  }

  static Future<void> _clearFlowStudioTransientState({
    bool clearDraft = true,
    OverlayStackMutationReason reason = OverlayStackMutationReason.programmatic,
  }) async {
    await _removeCalendarOverlayKinds({
      _kCalendarOverlayKindFlowStudio,
    }, reason: reason);
    if (clearDraft) {
      await AppRestorationService.instance.saveEditorState(
        _kFlowStudioDraftEditorKey,
        null,
      );
    }
    _lastDetachedCalendarOverlayRestoreKey = null;
  }

  @visibleForTesting
  static Future<void> clearFlowStudioTransientStateForTesting() {
    return _clearFlowStudioTransientState();
  }

  static bool get _hasCalendarOwnedTransientOverlayOpenOrOpening {
    final mountedState = _mountedState;
    return CalendarEventDetailSheetCoordinator.isOpenOrOpening ||
        _calendarOwnedTransientRouteDepth > 0 ||
        _detachedSharedCalendarsSheetOpenOrOpening ||
        _detachedFlowStudioSheetOpenOrOpening ||
        _detachedQuickAddSheetOpenOrOpening ||
        (mountedState?._sharedCalendarsSheetOpenOrOpening ?? false) ||
        (mountedState?._flowStudioSheetOpenOrOpening ?? false) ||
        (mountedState?._daySheetOpenOrOpening ?? false) ||
        (mountedState?._quickAddSheetOpenOrOpening ?? false);
  }

  static Future<T> runWithCalendarOwnedTransientRoute<T>(
    Future<T> Function() action,
  ) async {
    _calendarOwnedTransientRouteDepth += 1;
    _mountedState?._markCalendarOwnedTransientRouteChanged();
    try {
      return await action();
    } finally {
      await WidgetsBinding.instance.endOfFrame;
      final mountedState = _mountedState;
      final routeIsCurrent = mountedState == null
          ? true
          : mountedState._calendarRouteIsCurrent;
      if (!routeIsCurrent) {
        await Future<void>.delayed(Duration.zero);
        await WidgetsBinding.instance.endOfFrame;
      }
      if (_calendarOwnedTransientRouteDepth > 0) {
        _calendarOwnedTransientRouteDepth -= 1;
      }
      _mountedState?._markCalendarOwnedTransientRouteChanged();
    }
  }

  static Future<void> dismissAppOwnedTransientOverlaysForRouteChange(
    BuildContext context,
  ) async {
    if (!_hasCalendarOwnedTransientOverlayOpenOrOpening) return;

    final kindsToClear = <String>{};
    final mountedState = _mountedState;
    if (CalendarEventDetailSheetCoordinator.isOpenOrOpening) {
      kindsToClear.add(_kCalendarOverlayKindEventDetail);
    }
    if (_detachedSharedCalendarsSheetOpenOrOpening ||
        (mountedState?._sharedCalendarsSheetOpenOrOpening ?? false)) {
      kindsToClear.add(_kCalendarOverlayKindSharedCalendars);
    }
    final flowStudioOpen =
        _detachedFlowStudioSheetOpenOrOpening ||
        (mountedState?._flowStudioSheetOpenOrOpening ?? false);
    if (flowStudioOpen) {
      kindsToClear.add(_kCalendarOverlayKindFlowStudio);
    }
    await _removeCalendarOverlayKinds(
      kindsToClear,
      reason: OverlayStackMutationReason.userDismissed,
    );
    if (flowStudioOpen) {
      await AppRestorationService.instance.saveEditorState(
        _kFlowStudioDraftEditorKey,
        null,
      );
    }

    if (!context.mounted) return;
    try {
      final navigator = Navigator.of(context, rootNavigator: true);
      if (navigator.canPop()) {
        navigator.pop();
      }
    } catch (_) {
      // Route-change cleanup can be scheduled during shell teardown.
    }
  }

  static List<String> _stringListFromRestorationValue(Object? raw) {
    if (raw is! Iterable) return const <String>[];
    return raw
        .map((value) => value.toString().trim())
        .where((value) => value.isNotEmpty)
        .toList(growable: false);
  }

  static Map<String, dynamic>? _restorableCalendarOverlayFromStack(
    List<Map<String, dynamic>> stack,
  ) {
    for (final entry in stack.reversed) {
      final kind = (entry['kind'] as String?)?.trim();
      if (_isTransientFlowStudioEditorOverlay(entry)) {
        continue;
      }
      if (kind == _kCalendarOverlayKindSharedCalendars ||
          kind == _kCalendarOverlayKindFlowStudio) {
        return Map<String, dynamic>.from(entry);
      }
      if (kind == _kCalendarOverlayKindEventDetail) {
        final parentRoute = (entry['parentRoute'] as String?)?.trim();
        final parentSurface = (entry['parentSurface'] as String?)?.trim();
        final isRootParentRoute =
            parentRoute == null ||
            parentRoute.isEmpty ||
            _isRootRouteLocation(parentRoute);
        final isRootParentSurface =
            parentSurface == null ||
            parentSurface.isEmpty ||
            parentSurface == _kCalendarParentSurfaceRoot;
        if (isRootParentRoute && isRootParentSurface) {
          return Map<String, dynamic>.from(entry);
        }
      }
    }
    return null;
  }

  static String? restorableOverlayParentRouteFromStack(
    List<Map<String, dynamic>> stack,
  ) {
    final overlay = _restorableCalendarOverlayFromStack(stack);
    final parentRoute = (overlay?['parentRoute'] as String?)?.trim();
    if (parentRoute == null ||
        parentRoute.isEmpty ||
        _isRootRouteLocation(parentRoute)) {
      return null;
    }
    return parentRoute;
  }

  static String _parentSurfaceForRoute(String parentRoute) {
    final uri = Uri.tryParse(parentRoute.trim());
    final path = uri?.path ?? parentRoute.trim();
    if (path.isEmpty || path == '/') return _kCalendarParentSurfaceRoot;
    if (path.startsWith('/profile/')) return _kProfileParentSurface;
    if (path == '/rhythm/today') return _kPlannerTodayParentSurface;
    if (path.startsWith('/rhythm/')) return _kPlannerParentSurface;
    return _kRouteParentSurface;
  }

  static String _calendarOverlayRestoreSurfaceKey(
    Map<String, dynamic> overlay,
  ) {
    final kind = (overlay['kind'] as String?)?.trim() ?? '';
    final parentRoute = (overlay['parentRoute'] as String?)?.trim() ?? '/';
    final parentSurface = (overlay['parentSurface'] as String?)?.trim() ?? '';
    return '${RestorationCoordinator.calendarOverlayStackSurface}|'
        '$kind|$parentRoute|$parentSurface|${overlay['updatedAtMs']}|'
        '${overlay['mode']}|${overlay['templateKey']}|'
        '${overlay['initialFlowId']}|${overlay['editFlowId']}|'
        '${overlay['identityType']}|${overlay['identityValue']}';
  }

  static Future<void> waitForInitialCalendarRestorationToSettle({
    Duration timeout = const Duration(milliseconds: 3600),
  }) async {
    final snapshot = await RestorationCoordinator.instance.readBestSnapshot(
      includeRemote: Supabase.instance.client.auth.currentSession != null,
    );
    final savedDayView = snapshot.snapshot?.dayView;
    final overlay = _restorableCalendarOverlayFromStack(
      snapshot.snapshot?.overlayStack ?? const <Map<String, dynamic>>[],
    );
    final shouldWaitForDayView =
        savedDayView != null &&
        savedDayView.isOpen &&
        RestorationCoordinator.instance.canRestoreSurface(
          RestorationCoordinator.calendarDayViewSurface,
          requireRootTarget: true,
        );
    final overlayKey = overlay == null
        ? null
        : _calendarOverlayRestoreSurfaceKey(overlay);
    final parentRoute = (overlay?['parentRoute'] as String?)?.trim();
    final shouldWaitForRootOverlay =
        overlay != null &&
        (parentRoute == null ||
            parentRoute.isEmpty ||
            _isRootRouteLocation(parentRoute)) &&
        overlayKey != null &&
        RestorationCoordinator.instance.canRestoreSurface(
          overlayKey,
          requireRootTarget: true,
        );
    final shouldWaitForDetachedOverlay =
        overlay != null &&
        parentRoute != null &&
        parentRoute.isNotEmpty &&
        !_isRootRouteLocation(parentRoute) &&
        overlayKey != null &&
        RestorationCoordinator.instance.canRestoreSurface(overlayKey);

    if (!shouldWaitForDayView &&
        !shouldWaitForRootOverlay &&
        !shouldWaitForDetachedOverlay) {
      return;
    }

    final overlayRestoreKey = overlayKey ?? '';
    final deadline = DateTime.now().add(timeout);
    while (DateTime.now().isBefore(deadline)) {
      final state = _mountedState;
      final dayViewSettled =
          !shouldWaitForDayView ||
          state == null ||
          state._persistentDayViewRestoreAttempted;
      final rootOverlaySettled =
          !shouldWaitForRootOverlay ||
          state == null ||
          state._calendarOverlayRestorePresentationStarted ||
          !RestorationCoordinator.instance.canRestoreSurface(
            overlayRestoreKey,
            requireRootTarget: true,
          );
      final detachedOverlaySettled =
          !shouldWaitForDetachedOverlay ||
          _detachedSharedCalendarsSheetOpenOrOpening ||
          _detachedFlowStudioSheetOpenOrOpening ||
          !RestorationCoordinator.instance.canRestoreSurface(overlayRestoreKey);

      if (dayViewSettled && rootOverlaySettled && detachedOverlaySettled) {
        return;
      }
      await Future<void>.delayed(const Duration(milliseconds: 80));
    }
  }

  static Future<void> _saveDetachedCalendarOverlayState({
    required String parentRoute,
    required String kind,
    required Map<String, dynamic> state,
  }) async {
    final normalizedParentRoute = parentRoute.trim().isEmpty
        ? '/'
        : parentRoute.trim();
    final parentPath = Uri.tryParse(normalizedParentRoute)?.path;
    if ((kind == _kCalendarOverlayKindFlowStudio && parentPath == '/flows') ||
        (kind == _kCalendarOverlayKindSharedCalendars &&
            parentPath == '/calendars')) {
      return;
    }
    if (kind == _kCalendarOverlayKindFlowStudio &&
        _isTransientFlowStudioEditorState(state)) {
      return;
    }
    try {
      await RestorationCoordinator.instance.recordOverlayStackPageState(
        <Map<String, dynamic>>[
          <String, dynamic>{
            'kind': kind.trim(),
            'parentRoute': normalizedParentRoute,
            'parentSurface': _parentSurfaceForRoute(normalizedParentRoute),
            'updatedAtMs': DateTime.now().millisecondsSinceEpoch,
            ...state,
          },
        ],
        reason: 'detached_calendar_overlay',
      );
      unawaited(RestorationCoordinator.instance.flush());
    } catch (error) {
      NavigationTrace.instance.record(
        'detached calendar overlay state save skipped',
        state: <String, Object?>{
          'kind': kind.trim(),
          'parentRoute': normalizedParentRoute,
          'error': error.runtimeType,
        },
      );
    }
  }

  static Future<void> _clearDetachedCalendarOverlayState(String kind) async {
    final stack = await RestorationCoordinator.instance.readOverlayStack();
    final next = stack
        .where((entry) => entry['kind'] != kind)
        .toList(growable: false);
    await RestorationCoordinator.instance.saveOverlayStack(
      next,
      reason: OverlayStackMutationReason.userDismissed,
    );
  }

