  static String? _trimmedOrNull(String? value) {
    final trimmed = value?.trim();
    if (trimmed == null || trimmed.isEmpty) return null;
    return trimmed;
  }

  static int? _positiveFiledFlowId(FiledEvent filedEvent) {
    final filedFlowId = filedEvent.flowId;
    if (filedFlowId != null && filedFlowId > 0) return filedFlowId;
    final eventFlowId = filedEvent.event.flowLocalId;
    if (filedEvent.kind == FiledItemKind.flow &&
        eventFlowId != null &&
        eventFlowId > 0) {
      return eventFlowId;
    }
    return null;
  }

  static _SharedCalendarEventDetailSnapshot
  _sharedCalendarEventDetailSnapshotForFiledEvent({
    required SharedCalendarSummary calendar,
    required FiledEvent filedEvent,
  }) {
    final event = filedEvent.event;
    final decodedDetail = _decodeDetailMetadata(event.detail);
    final eventCalendarId = _trimmedOrNull(event.calendarId);
    final filedCalendarId = _trimmedOrNull(filedEvent.calendar.id);
    final calendarId = eventCalendarId ?? filedCalendarId ?? calendar.id;
    final eventCalendarName = _trimmedOrNull(event.calendarName);
    final filedCalendarName = _trimmedOrNull(filedEvent.calendar.name);
    final calendarName =
        eventCalendarName ?? filedCalendarName ?? calendar.name.trim();
    final colorValue =
        event.calendarColor ?? filedEvent.calendar.color ?? calendar.colorValue;
    final location = _trimmedOrNull(event.location);
    final cleanedDetail = _cleanDetail(decodedDetail.detail);
    final detail = cleanedDetail.isEmpty ? null : cleanedDetail;
    final title = event.title.trim().isEmpty
        ? 'Untitled event'
        : event.title.trim();

    return _SharedCalendarEventDetailSnapshot(
      eventId: _trimmedOrNull(event.id),
      clientEventId: _trimmedOrNull(event.clientEventId),
      title: title,
      detail: detail,
      location: location,
      allDay: event.allDay,
      startsAtLocal: event.startsAt.toLocal(),
      endsAtLocal: event.endsAt?.toLocal(),
      calendarId: _trimmedOrNull(calendarId),
      calendarName: calendarName.isEmpty ? null : calendarName,
      calendarColor: decodedDetail.color ?? Color(colorValue),
      calendar: calendar,
      flowId: _positiveFiledFlowId(filedEvent),
      category: _trimmedOrNull(event.category),
      isReminder:
          filedEvent.kind == FiledItemKind.reminder ||
          (filedEvent.flowOwner?.isReminder ?? false),
      reminderId: null,
      alertOffsetMinutes: decodedDetail.alertMinutes,
      actionId: _trimmedOrNull(event.actionId),
      behaviorPayload: event.behaviorPayload == null
          ? null
          : Map<String, dynamic>.from(event.behaviorPayload!),
    );
  }

  static Future<List<_Flow>> _loadSharedCalendarFlowsForFiledEvents(
    Iterable<FiledEvent> filedEvents,
  ) async {
    final flowIds = <int>{
      for (final filedEvent in filedEvents)
        if (_positiveFiledFlowId(filedEvent) case final flowId?) flowId,
    }.toList()..sort();
    if (flowIds.isEmpty) return const <_Flow>[];

    final repo = FlowsRepo(Supabase.instance.client);
    final flows = <_Flow>[];
    for (final flowId in flowIds) {
      try {
        final row = await repo.getFlowById(flowId);
        if (row != null) {
          flows.add(_flowFromFiledRowDetached(row));
        }
      } catch (error, stackTrace) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[SharedCalendarEventTap] shared flow hydrate failed '
            'flowId=$flowId: $error',
          );
          _calendarDebugPrint('$stackTrace');
        }
      }
    }
    return List<_Flow>.unmodifiable(flows);
  }

  static int? _firstVisibleMinuteFromSharedCalendarSnapshot(
    _SharedCalendarEventDetailSnapshot snapshot,
  ) {
    if (snapshot.allDay) return null;
    return snapshot.startsAtLocal.hour * 60 + snapshot.startsAtLocal.minute;
  }

  static EventDetailRestorationState?
  _eventDetailRestorationStateForFiledCalendarEvent({
    required int kYear,
    required int kMonth,
    required int kDay,
    required FiledEvent filedEvent,
  }) {
    final event = filedEvent.event;
    final clientEventId = event.clientEventId?.trim();
    if (clientEventId != null && clientEventId.isNotEmpty) {
      return EventDetailRestorationState(
        kYear: kYear,
        kMonth: kMonth,
        kDay: kDay,
        identityType: eventDetailIdentityClientEventId,
        identityValue: clientEventId,
      );
    }

    final eventId = event.id.trim();
    if (eventId.isNotEmpty) {
      return EventDetailRestorationState(
        kYear: kYear,
        kMonth: kMonth,
        kDay: kDay,
        identityType: eventDetailIdentityEventId,
        identityValue: eventId,
      );
    }

    return null;
  }

  static Future<void> openFiledCalendarEventFromAnyContext(
    BuildContext context, {
    required SharedCalendarSummary calendar,
    required FiledEvent filedEvent,
    List<FiledEvent> calendarEvents = const [],
  }) async {
    final localStart = filedEvent.event.startsAt.toLocal();
    final kDate = KemeticMath.fromGregorian(localStart);
    final detail = _eventDetailRestorationStateForFiledCalendarEvent(
      kYear: kDate.kYear,
      kMonth: kDate.kMonth,
      kDay: kDate.kDay,
      filedEvent: filedEvent,
    );
    if (detail == null) return;
    final snapshot = _sharedCalendarEventDetailSnapshotForFiledEvent(
      calendar: calendar,
      filedEvent: filedEvent,
    );

    if (kDebugMode) {
      _calendarDebugPrint(
        '[SharedCalendarEventTap] route request ${snapshot.debugIdentity} '
        'k=${kDate.kYear}-${kDate.kMonth}-${kDate.kDay}',
      );
    }
    final sameDayEvents = _sameDayFiledEvents(
      calendarEvents,
      kYear: kDate.kYear,
      kMonth: kDate.kMonth,
      kDay: kDate.kDay,
    );
    final sharedCalendarFlows = await _loadSharedCalendarFlowsForFiledEvents(
      <FiledEvent>{filedEvent, ...sameDayEvents},
    );
    if (!context.mounted) return;

    final mountedHost = _shouldUseMountedCalendarHost(context)
        ? _mountedCalendarHostForContext(context)
        : null;
    if (mountedHost != null) {
      mountedHost._rememberSharedCalendarSnapshot(calendar);
      mountedHost._seedSharedCalendarFlows(sharedCalendarFlows);
      mountedHost._seedSameDaySharedCalendarFiledEvents(
        calendar: calendar,
        filedEvents: sameDayEvents,
        kYear: kDate.kYear,
        kMonth: kDate.kMonth,
        kDay: kDate.kDay,
      );
      mountedHost._seedOneShotSharedCalendarEventSnapshot(
        kYear: kDate.kYear,
        kMonth: kDate.kMonth,
        kDay: kDate.kDay,
        snapshot: snapshot,
        detail: detail,
      );
      mountedHost._publishWarmStateSnapshot();
      if (!mountedHost.mounted) return;
      mountedHost._openDayView(
        mountedHost.context,
        kDate.kYear,
        kDate.kMonth,
        kDate.kDay,
        initialEventDetailRestorationState: detail,
        debugOpenSource: 'shared_calendar_event_tap',
      );
      unawaited(mountedHost._loadCalendarState());
      unawaited(
        mountedHost._loadFromDisk(
          source: 'shared_calendar_event_tap_background',
        ),
      );
      return;
    }

    final warmStartSnapshot = await _loadWarmStartSearchSnapshot();
    final warmCalendarSnapshot = await _loadWarmCalendarStateSnapshot();
    if (!context.mounted) return;
    _pendingSharedCalendarRealDayViewIntent = _SharedCalendarRealDayViewIntent(
      kYear: kDate.kYear,
      kMonth: kDate.kMonth,
      kDay: kDate.kDay,
      detail: detail,
      snapshot: snapshot,
      calendar: calendar,
      warmStartNotes: warmStartSnapshot.notes,
      warmStartFlows: warmStartSnapshot.flows,
      warmCalendarSummariesById: <String, SharedCalendarSummary>{
        ...warmCalendarSnapshot.calendarSummariesById,
        calendar.id: calendar,
      },
      warmHiddenCalendarIds: warmCalendarSnapshot.hiddenCalendarIds,
      warmPersonalCalendarId: warmCalendarSnapshot.personalCalendarId,
      sameCalendarEvents: sameDayEvents,
      sharedCalendarFlows: sharedCalendarFlows,
    );
    try {
      GoRouter.of(context).go('/');
    } catch (error, stackTrace) {
      NavigationTrace.instance.recordError(
        'shared calendar event day view route go error',
        error,
        stackTrace,
        state: <String, Object?>{
          'targetRoute': '/',
          'event': snapshot.debugIdentity,
        },
      );
    }
    unawaited(
      _clearDetachedCalendarOverlayState(_kCalendarOverlayKindSharedCalendars),
    );
  }

  static Future<void> openMyFlowsFromAnyContext(BuildContext context) async {
    final mountedHost = _shouldUseMountedCalendarHost(context)
        ? _mountedCalendarHostForContext(context)
        : null;
    if (mountedHost != null) {
      await mountedHost.openMyFlowsFromOutside();
      return;
    }
    await openFlowStudioFromAnyContext(
      context,
      restorationState: const <String, dynamic>{
        'mode': _kFlowStudioModeMyFlows,
      },
    );
  }

  static Future<void> openSharedCalendarsFromAnyContext(
    BuildContext context, {
    Map<String, dynamic>? restorationState,
  }) async {
    final debugOpen = debugOpenSharedCalendarsFromAnyContext;
    if (debugOpen != null) {
      await debugOpen(context);
      return;
    }
    final mountedHost = _shouldUseMountedCalendarHost(context)
        ? _mountedCalendarHostForContext(context)
        : null;
    if (mountedHost != null) {
      await mountedHost._openSharedCalendarsSheet(
        restorationState: restorationState,
      );
      return;
    }
    await _openDetachedSharedCalendarsSheet(
      context,
      restorationState: restorationState,
    );
  }

  static Future<void> openFlowStudioFromAnyContext(
    BuildContext context, {
    Map<String, dynamic>? restorationState,
  }) async {
    final debugOpen = debugOpenFlowStudioFromAnyContext;
    if (debugOpen != null) {
      await debugOpen(context);
      return;
    }
    final mountedHost = _shouldUseMountedCalendarHost(context)
        ? _mountedCalendarHostForContext(context)
        : null;
    if (mountedHost != null) {
      final state = mountedHost;
      final mode = (restorationState?['mode'] as String?)?.trim();
      if (mode == _kFlowStudioModeMyFlows) {
        state._openMyFlowsList(
          initialFlowId: (restorationState?['initialFlowId'] as num?)?.toInt(),
        );
      } else if (restorationState == null || restorationState.isEmpty) {
        state._getFlowStudioCallback()(null);
      } else {
        await state._restoreFlowStudioOverlay(restorationState);
      }
      return;
    }
    await _openDetachedFlowStudioSheet(
      context,
      restorationState:
          restorationState ??
          const <String, dynamic>{'mode': _kFlowStudioModeHub},
    );
  }

  static String flowEditorRouteLocation({
    required int flowId,
    String? calendarId,
    String? fallbackLocation,
  }) {
    final query = <String, String>{};
    final trimmedCalendarId = calendarId?.trim();
    if (trimmedCalendarId != null && trimmedCalendarId.isNotEmpty) {
      query['calendarId'] = trimmedCalendarId;
    }
    final fallback = _validFlowEditorFallbackLocation(fallbackLocation);
    if (fallback != null) {
      query['fallback'] = fallback;
    }
    return Uri(
      path: '/flows/$flowId/edit',
      queryParameters: query.isEmpty ? null : query,
    ).toString();
  }

  static Future<void> openFlowEditorFromAnyContext(
    BuildContext context, {
    required int flowId,
    String? calendarId,
    String? fallbackLocation,
    String source = 'unknown',
  }) async {
    if (flowId <= 0) return;
    final route = flowEditorRouteLocation(
      flowId: flowId,
      calendarId: calendarId,
      fallbackLocation: fallbackLocation,
    );
    if (kDebugMode) {
      debugPrint('[EditFlow] tapped flowId=$flowId calendarId=$calendarId');
      debugPrint('[EditFlow] route=$route');
    }
    if (kIsWeb) {
      if (!context.mounted) return;
      if (kDebugMode) {
        debugPrint('[EditFlow] open studio source=$source');
      }
      await _clearFlowStudioTransientState();
      await _removeCalendarOverlayKinds({_kCalendarOverlayKindEventDetail});
      if (!context.mounted) return;
      unawaited(openDetailRoute<void>(context, route));
      return;
    }

    final mountedHost = _shouldUseMountedCalendarHost(context)
        ? _mountedCalendarHostForContext(context)
        : null;
    if (mountedHost != null) {
      if (kDebugMode) {
        debugPrint('[EditFlow] open studio source=$source');
      }
      mountedHost._openFlowEditorDirectly(flowId);
      return;
    }

    if (kDebugMode) {
      debugPrint('[EditFlow] open studio source=$source');
    }
    await _openDetachedFlowStudioSheet(
      context,
      restorationState: <String, dynamic>{
        'mode': _kFlowStudioModeEditor,
        'editFlowId': flowId,
      },
    );
  }

