  }) {
    return _FlowEditorRoutePage(
      flowId: flowId,
      calendarId: calendarId,
      fallbackLocation: fallbackLocation,
    );
  }

  static Widget buildFlowStudioRoutePage({Uri? routeUri}) {
    return _FlowStudioRoutePage(routeUri: routeUri);
  }

  static Map<String, dynamic> _flowStudioRouteStateFromUri(Uri? routeUri) {
    final mode = routeUri?.queryParameters['mode']?.trim();
    if (mode == _kFlowStudioModeMyFlows || mode == _kFlowStudioModeMaatFlows) {
      return <String, dynamic>{'mode': mode};
    }
    if (mode == _kFlowStudioModeMaatTemplate) {
      final templateKey = routeUri?.queryParameters['templateKey']?.trim();
      if (templateKey != null && templateKey.isNotEmpty) {
        return <String, dynamic>{
          'mode': _kFlowStudioModeMaatTemplate,
          'templateKey': templateKey,
        };
      }
    }
    return const <String, dynamic>{'mode': _kFlowStudioModeHub};
  }

  static String? _flowStudioDurableRouteForState(Map<String, dynamic> state) {
    final mode = (state['mode'] as String?)?.trim();
    if (mode == null || mode.isEmpty || mode == _kFlowStudioModeHub) {
      return '/flows';
    }
    if (mode == _kFlowStudioModeMyFlows || mode == _kFlowStudioModeMaatFlows) {
      return Uri(
        path: '/flows',
        queryParameters: <String, String>{'mode': mode},
      ).toString();
    }
    if (mode == _kFlowStudioModeMaatTemplate) {
      final templateKey = (state['templateKey'] as String?)?.trim();
      if (templateKey != null && templateKey.isNotEmpty) {
        return Uri(
          path: '/flows',
          queryParameters: <String, String>{
            'mode': mode,
            'templateKey': templateKey,
          },
        ).toString();
      }
    }
    return null;
  }

  static Widget buildSharedCalendarsRoutePage() {
    return const _SharedCalendarsRoutePage();
  }

  static String? _validFlowEditorFallbackLocation(String? fallbackLocation) {
    final fallback = fallbackLocation?.trim();
    if (fallback == null || fallback.isEmpty) return null;
    final uri = Uri.tryParse(fallback);
    if (uri == null ||
        uri.hasScheme ||
        uri.host.isNotEmpty ||
        !uri.path.startsWith('/')) {
      return null;
    }
    return uri.toString();
  }

  static String _routeLocationForNavigationTrace(BuildContext context) {
    try {
      return GoRouter.of(
        context,
      ).routerDelegate.currentConfiguration.uri.toString();
    } catch (error) {
      return '<unavailable:${error.runtimeType}>';
    }
  }

  static Map<String, Object?> _profileNavigationTraceState(
    BuildContext context, {
    String? phase,
    String? targetRoute,
  }) {
    return <String, Object?>{
      if (phase != null) 'phase': phase,
      if (targetRoute != null) 'targetRoute': targetRoute,
      'timestampMs': DateTime.now().millisecondsSinceEpoch,
      'currentRoute': _routeLocationForNavigationTrace(context),
      'rootRoute': rootRouterUriForNavigationTrace,
      'contextMounted': context.mounted,
      'rootNavigatorContextMounted':
          rootNavigatorContextMountedForNavigationTrace,
      'rootNavigatorOverlayMounted':
          rootNavigatorOverlayContextMountedForNavigationTrace,
      'calendarStateMounted': globalKey.currentState?.mounted ?? false,
    };
  }

  static void _clearProfileFeedContinuityWithoutBlocking(String userId) {
    NavigationTrace.instance.record(
      'profile feed continuity clear requested',
      state: <String, Object?>{
        'timestampMs': DateTime.now().millisecondsSinceEpoch,
      },
    );
    // Feed continuity cleanup is diagnostic/restoration hygiene; it must not
    // delay the user-visible profile navigation.
    unawaited(() async {
      try {
        await RestorationCoordinator.instance.clearProfileFeedContinuity(
          userId,
        );
        NavigationTrace.instance.record(
          'profile feed continuity clear completed',
          state: <String, Object?>{
            'timestampMs': DateTime.now().millisecondsSinceEpoch,
          },
        );
      } catch (error) {
        NavigationTrace.instance.record(
          'profile feed continuity clear skipped',
          state: <String, Object?>{
            'timestampMs': DateTime.now().millisecondsSinceEpoch,
            'error': error.runtimeType,
          },
        );
      }
    }());
  }

  static Future<void> openProfileFromAnyContext(BuildContext context) async {
    NavigationTrace.instance.record('openProfileFromAnyContext entered');
    final state = _mountedState;
    if (state != null) {
      await state.openProfileFromOutside(context);
      return;
    }

    final userId = Supabase.instance.client.auth.currentUser?.id;
    NavigationTrace.instance.record(
      'current user id resolved',
      state: <String, Object?>{'hasUserId': userId != null},
    );
    if (userId == null) {
      NavigationTrace.instance.record(
        'profile route stopped',
        state: const <String, Object?>{'reason': 'missingUserId'},
      );
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Please log in to view your profile')),
        );
      }
      return;
    }
    if (!context.mounted) return;
    _clearProfileFeedContinuityWithoutBlocking(userId);
    if (!context.mounted) return;
    NavigationTrace.instance.record('/profile/me route command issued');
    NavigationTrace.instance.record(
      'profile route push requested',
      state: _profileNavigationTraceState(
        context,
        phase: 'beforePush',
        targetRoute: '/profile/me',
      ),
    );
    try {
      unawaited(openDetailRoute<void>(context, '/profile/me'));
      NavigationTrace.instance.record(
        'profile route push completed/current uri',
        state: _profileNavigationTraceState(
          context,
          phase: 'afterPush',
          targetRoute: '/profile/me',
        ),
      );
    } catch (error, stackTrace) {
      NavigationTrace.instance.recordError(
        'profile route push error',
        error,
        stackTrace,
        state: _profileNavigationTraceState(
          context,
          phase: 'goCatch',
          targetRoute: '/profile/me',
        ),
      );
      rethrow;
    }
  }

