        glyphSize: 20,
        gradient: goldGloss,
        label: 'Flow Studio',
        onSelected: () async {
          NavigationTrace.instance.record('Flow Studio tile tapped');
          await (onOpenFlowStudio ??
                  () => openFlowStudioFromAnyContext(context))
              .call();
        },
      ),
      _CalendarAction(
        glyph: MeduNeterGlyphs.library,
        glyphSize: 20,
        gradient: goldGloss,
