  static Future<void> _openDetachedSharedCalendarsSheet(
    BuildContext context, {
    Map<String, dynamic>? restorationState,
  }) async {
    if (!context.mounted) return;
    final parentRoute = _currentRouteLocationForContext(context);
    final initialExpandedCalendarIds = _stringListFromRestorationValue(
      restorationState?['expandedCalendarIds'],
    );
    await _saveDetachedCalendarOverlayState(
      parentRoute: parentRoute,
      kind: _kCalendarOverlayKindSharedCalendars,
      state: <String, dynamic>{
        'expandedCalendarIds': initialExpandedCalendarIds,
      },
    );
    if (!context.mounted) return;
    if (_detachedSharedCalendarsSheetOpenOrOpening) return;
    _detachedSharedCalendarsSheetOpenOrOpening = true;

    try {
      NavigationTrace.instance.record(
        'sheet open success',
        state: const <String, Object?>{
          'sheet': 'calendars',
          'host': 'detached',
        },
      );
      await SharedCalendarsSheet.show(
        context,
        repo: SharedCalendarsRepo(Supabase.instance.client),
        initialExpandedCalendarIds: initialExpandedCalendarIds,
        onEventTapRequested:
            (calendar, filedEvent, {calendarEvents = const []}) =>
                openFiledCalendarEventFromAnyContext(
                  context,
                  calendar: calendar,
                  filedEvent: filedEvent,
                  calendarEvents: calendarEvents,
                ),
        onContinuityChanged: (state) {
          unawaited(
            _saveDetachedCalendarOverlayState(
              parentRoute: parentRoute,
              kind: _kCalendarOverlayKindSharedCalendars,
              state: state,
            ),
          );
        },
      );
    } catch (error) {
      NavigationTrace.instance.record(
        'sheet open error',
        state: <String, Object?>{
          'sheet': 'calendars',
          'host': 'detached',
          'error': error.runtimeType,
        },
      );
      rethrow;
    } finally {
      try {
        if (context.mounted) {
          await _clearDetachedCalendarOverlayState(
            _kCalendarOverlayKindSharedCalendars,
          );
        }
      } finally {
        _detachedSharedCalendarsSheetOpenOrOpening = false;
      }
    }
  }

  static bool _isTabletForContext(BuildContext context) =>
      MediaQuery.sizeOf(context).shortestSide >= 600;

  static String _formatDetachedGregorian(DateTime? d) => d == null
      ? '--'
      : '${d.year}-${d.month.toString().padLeft(2, '0')}-${d.day.toString().padLeft(2, '0')}';

  static List<FlowRule> _parseDetachedFlowRowRules(List<dynamic> rules) {
    if (rules.isEmpty) return const [];
    final parsed = <FlowRule>[];
    for (final raw in rules) {
      if (raw is! Map) continue;
      try {
        parsed.add(CalendarPage.ruleFromJson(Map<String, dynamic>.from(raw)));
      } catch (_) {
        // Skip malformed rows from older records without dropping the flow.
      }
    }
    return parsed;
  }

  static _Flow _flowFromFiledRowDetached(FlowRow row) {
    return _Flow(
      id: row.id,
      calendarId: row.calendarId,
      name: row.name,
      color: Color(rgbToArgb(row.color)),
      active: row.active,
      isSaved: row.isSaved,
      savedAt: row.savedAt,
      rules: _parseDetachedFlowRowRules(row.rules),
      start: row.startDate?.toLocal(),
      end: row.endDate?.toLocal(),
      notes: row.notes,
      shareId: row.shareId,
      isHidden: row.isHidden,
      isReminder: row.isReminder,
      reminderUuid: row.reminderUuid,
    );
  }

  static _MyFlowsFilingSnapshot _myFlowsFilingSnapshotFromRowsDetached(
    List<FlowRow> rows,
  ) {
    final flows = <_Flow>[];
    final activeIds = <int>{};
    final savedIds = <int>{};
    final totalCounts = <int, int>{};
    final remainingCounts = <int, int>{};

    for (final row in rows) {
      flows.add(_flowFromFiledRowDetached(row));
      if (row.visibleInActiveList) activeIds.add(row.id);
      if (row.visibleInSavedList) savedIds.add(row.id);
      totalCounts[row.id] = row.totalEventCount;
      remainingCounts[row.id] = row.remainingLiveEventCount;
    }

    return _MyFlowsFilingSnapshot(
      flows: List<_Flow>.unmodifiable(flows),
      activeFlowIds: Set<int>.unmodifiable(activeIds),
      savedFlowIds: Set<int>.unmodifiable(savedIds),
      totalEventCounts: Map<int, int>.unmodifiable(totalCounts),
      remainingEventCounts: Map<int, int>.unmodifiable(remainingCounts),
    );
  }

  static _MyFlowsFilingSnapshot? _cachedDetachedMyFlowsFilingSnapshot(
    FlowsRepo repo,
  ) {
    final cachedRows = repo.cachedMyFiledFlowsSync();
    if (cachedRows == null) return null;
    return _myFlowsFilingSnapshotFromRowsDetached(cachedRows);
  }

  static Future<_MyFlowsFilingSnapshot> _loadDetachedMyFlowsFilingSnapshot(
    FlowsRepo repo,
  ) async {
    final cachedRows = await repo.restoreCachedFiledFlows();
    if (cachedRows != null) {
      unawaited(
        repo.refreshMyFiledFlows().then((rows) {
          _reconcileRememberedMaatJoinsFromLiveSnapshot(
            _myFlowsFilingSnapshotFromRowsDetached(rows),
          );
        }),
      );
      return _myFlowsFilingSnapshotFromRowsDetached(cachedRows);
    }
    final rows = await repo.refreshMyFiledFlows();
    final snapshot = _myFlowsFilingSnapshotFromRowsDetached(rows);
    _reconcileRememberedMaatJoinsFromLiveSnapshot(snapshot);
    return snapshot;
  }

  static bool _snapshotHasActiveMaatInstanceFor(
    _MyFlowsFilingSnapshot? snapshot,
    String tplKey,
  ) {
    if (_hasRememberedJoinedMaatTemplate(tplKey)) return true;
    if (snapshot == null) return false;
    return snapshot.flows.any((flow) {
      return _flowMatchesActiveMaatTemplate(flow, tplKey);
    });
  }

  static _MaatFlowCompletionStatus? _snapshotMaatCompletionStatusFor(
    _MyFlowsFilingSnapshot? snapshot,
    String tplKey,
  ) {
    if (snapshot == null) return null;
    for (final flow in snapshot.flows) {
      if (!_flowMatchesActiveMaatTemplate(flow, tplKey)) continue;
      return _maatCompletionStatusFromCounts(
        totalEventCount: snapshot.totalEventCounts[flow.id] ?? 0,
        remainingEventCount: snapshot.remainingEventCounts[flow.id] ?? 0,
      );
    }
    return null;
  }

  static _MaatFlowCompletionStatus? _maatCompletionStatusFromCounts({
    required int totalEventCount,
    required int remainingEventCount,
  }) {
    if (totalEventCount <= 0) return null;
    final remaining = remainingEventCount.clamp(0, totalEventCount).toInt();
    final completed = totalEventCount - remaining;
    return (
      progress: completed / totalEventCount,
      label: '$completed of $totalEventCount',
    );
  }

  static void _rememberJoinedMaatFlowTemplate({
    required String templateKey,
    required int flowId,
  }) {
    final key = templateKey.trim();
    if (key.isEmpty || flowId <= 0) return;
    final scope = _currentRememberedJoinedMaatUserScope();
    if (scope == null) {
      _clearRememberedJoinedMaatFlowTemplates();
      return;
    }
    if (_rememberedJoinedMaatUserScope != null &&
        _rememberedJoinedMaatUserScope != scope) {
      _clearRememberedJoinedMaatFlowTemplates();
    }
    _rememberedJoinedMaatUserScope = scope;
    _rememberedJoinedMaatFlowIdsByTemplateKey[key] = flowId;
    _rememberedJoinedMaatTemplateKeysByFlowId[flowId] = key;
  }

  static bool _hasRememberedJoinedMaatTemplate(String templateKey) {
    if (!_rememberedJoinedMaatScopeIsCurrent()) return false;
    final key = templateKey.trim();
    return key.isNotEmpty &&
        _rememberedJoinedMaatFlowIdsByTemplateKey.containsKey(key);
  }

  static void _forgetRememberedJoinedMaatFlow(int flowId) {
    if (!_rememberedJoinedMaatScopeIsCurrent()) return;
    final key = _rememberedJoinedMaatTemplateKeysByFlowId.remove(flowId);
    if (key != null) {
      _rememberedJoinedMaatFlowIdsByTemplateKey.remove(key);
    }
  }

  static String? _currentRememberedJoinedMaatUserScope() {
    try {
      final userId = Supabase.instance.client.auth.currentUser?.id.trim();
      if (userId == null || userId.isEmpty) return null;
      return userId;
    } catch (_) {
      String? uninitializedSupabaseTestScope;
      assert(() {
        uninitializedSupabaseTestScope = '__uninitialized_supabase_test__';
        return true;
      }());
      return uninitializedSupabaseTestScope;
    }
  }

  static void _clearRememberedJoinedMaatFlowTemplates() {
    _rememberedJoinedMaatFlowIdsByTemplateKey.clear();
    _rememberedJoinedMaatTemplateKeysByFlowId.clear();
    _rememberedJoinedMaatUserScope = null;
  }

  static bool _rememberedJoinedMaatScopeIsCurrent() {
    final scope = _currentRememberedJoinedMaatUserScope();
    if (scope == null) {
      _clearRememberedJoinedMaatFlowTemplates();
      return false;
    }
    final rememberedScope = _rememberedJoinedMaatUserScope;
    if (rememberedScope == null) {
      if (_rememberedJoinedMaatFlowIdsByTemplateKey.isEmpty &&
          _rememberedJoinedMaatTemplateKeysByFlowId.isEmpty) {
        _rememberedJoinedMaatUserScope = scope;
        return true;
      }
      _clearRememberedJoinedMaatFlowTemplates();
      return false;
    }
    if (rememberedScope != scope) {
      _clearRememberedJoinedMaatFlowTemplates();
      return false;
    }
    return true;
  }

  static void _reconcileRememberedMaatJoinsFromLiveSnapshot(
    _MyFlowsFilingSnapshot snapshot,
  ) {
    if (!_rememberedJoinedMaatScopeIsCurrent()) return;
    if (_rememberedJoinedMaatFlowIdsByTemplateKey.isEmpty) return;
    final keysToForget = <String>[];
    for (final entry in _rememberedJoinedMaatFlowIdsByTemplateKey.entries) {
      final hasCanonicalFlow = snapshot.flows.any((flow) {
        return flow.id == entry.value &&
            _flowMatchesActiveMaatTemplate(flow, entry.key);
      });
      if (hasCanonicalFlow) keysToForget.add(entry.key);
    }
    for (final key in keysToForget) {
      final flowId = _rememberedJoinedMaatFlowIdsByTemplateKey.remove(key);
      if (flowId != null) {
        _rememberedJoinedMaatTemplateKeysByFlowId.remove(flowId);
      }
    }
  }

  static void _reconcileRememberedMaatJoinsFromLiveFlows(
    Iterable<_Flow> flows,
  ) {
    if (!_rememberedJoinedMaatScopeIsCurrent()) return;
    if (_rememberedJoinedMaatFlowIdsByTemplateKey.isEmpty) return;
    final keysToForget = <String>[];
    for (final entry in _rememberedJoinedMaatFlowIdsByTemplateKey.entries) {
      final hasCanonicalFlow = flows.any((flow) {
        return flow.id == entry.value &&
            _flowMatchesActiveMaatTemplate(flow, entry.key);
      });
      if (hasCanonicalFlow) keysToForget.add(entry.key);
    }
    for (final key in keysToForget) {
      final flowId = _rememberedJoinedMaatFlowIdsByTemplateKey.remove(key);
      if (flowId != null) {
        _rememberedJoinedMaatTemplateKeysByFlowId.remove(flowId);
      }
    }
  }

  static bool _flowMatchesActiveMaatTemplate(_Flow flow, String tplKey) {
    final kind = resolveMaatFlowKind(
      flowName: flow.name,
      flowNotes: flow.notes,
    );
    if (kind?.flowKey != tplKey) return false;
    if (!flow.active || flow.isHidden || flow.isReminder) return false;
    return isFlowScheduleOpenLocally(active: flow.active, endDate: flow.end);
  }

  static Future<String?> _loadHeadlessPersonalCalendarId() async {
    final repo = SharedCalendarsRepo(Supabase.instance.client);
    try {
      final cached = await repo.restoreCachedSnapshot();
      final cachedId = cached?.personalCalendarId?.trim();
      if (cachedId != null && cachedId.isNotEmpty) return cachedId;
    } catch (_) {
      // Fall through to a live snapshot.
    }
    try {
      final snapshot = await repo.loadSnapshot();
      final id = snapshot.personalCalendarId?.trim();
      return id == null || id.isEmpty ? null : id;
    } catch (_) {
      return null;
    }
  }

  static Future<
    ({List<SharedCalendarSummary> calendars, String? personalCalendarId})
  >
  _loadHeadlessEditableCalendarsForFlow(String? currentCalendarId) async {
    final repo = SharedCalendarsRepo(Supabase.instance.client);
    SharedCalendarsSnapshot? snapshot;
    try {
      snapshot = await repo.loadSnapshot();
    } catch (_) {
      snapshot = await repo.restoreCachedSnapshot();
    }
    final current = currentCalendarId?.trim();
    final calendars = (snapshot?.calendars ?? const <SharedCalendarSummary>[])
        .where(
          (calendar) =>
              calendar.canEdit ||
              (current != null && current.isNotEmpty && calendar.id == current),
        )
        .toList(growable: false);
    calendars.sort((a, b) {
      if (a.isPersonal != b.isPersonal) {
        return a.isPersonal ? -1 : 1;
      }
      return a.name.toLowerCase().compareTo(b.name.toLowerCase());
    });
    return (
      calendars: calendars,
      personalCalendarId: snapshot?.personalCalendarId,
    );
  }

  static Future<void> _fileHeadlessEventDelivery({
    required EventFilingService eventFiling,
    required String debugLabel,
    required String clientEventId,
    required DateTime startsAtLocal,
    required int? alertOffsetMinutes,
    required String title,
    String? body,
    int? kYear,
    int? kMonth,
    int? kDay,
    String? eventId,
    int? flowId,
  }) async {
    try {
      await eventFiling.fileDelivery(
        clientEventId: clientEventId,
        startsAtLocal: startsAtLocal,
        alertOffsetMinutes: alertOffsetMinutes,
        title: title,
        body: body,
        payload: _calendarNotificationPayloadJson(
          itemType: flowId != null && flowId > 0
              ? calendarPushItemTypeFlowEvent
              : calendarPushItemTypeNote,
          kYear: kYear,
          kMonth: kMonth,
          kDay: kDay,
          eventId: eventId,
          clientEventId: clientEventId,
          flowId: flowId,
        ),
      );
    } catch (e, st) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[$debugLabel] delivery filing failed for $clientEventId: $e',
        );
        _calendarDebugPrint('$st');
      }
    }
  }

  static String _calendarNotificationPayloadJson({
    required String itemType,
    int? kYear,
    int? kMonth,
    int? kDay,
    String? eventId,
    String? clientEventId,
    String? reminderId,
    int? flowId,
  }) {
    DateTime? gregorianDay;
    if (kYear != null && kMonth != null && kDay != null) {
      gregorianDay = KemeticMath.toGregorian(kYear, kMonth, kDay);
    }

    final payload = <String, dynamic>{
      'kind': 'calendar_event',
      'item_type': itemType,
      if (kYear != null) 'k_year': kYear,
      if (kMonth != null) 'k_month': kMonth,
      if (kDay != null) 'k_day': kDay,
      if (gregorianDay != null) 'local_date': _formatIsoDate(gregorianDay),
      if (eventId != null && eventId.trim().isNotEmpty)
        'event_id': eventId.trim(),
      if (clientEventId != null && clientEventId.trim().isNotEmpty)
        'client_event_id': clientEventId.trim(),
      if (reminderId != null && reminderId.trim().isNotEmpty)
        'reminder_id': reminderId.trim(),
      if (flowId != null && flowId > 0) 'flow_id': flowId,
    };
    return jsonEncode(payload);
  }

  static String _formatIsoDate(DateTime date) {
    return [
      date.year.toString().padLeft(4, '0'),
      date.month.toString().padLeft(2, '0'),
      date.day.toString().padLeft(2, '0'),
    ].join('-');
  }

  static void _publishHeadlessCalendarInvalidation({
    required CalendarInvalidationReason reason,
    required int flowId,
    required List<String> clientEventIds,
  }) {
    CalendarInvalidationBus.instance.publish(
      CalendarInvalidated(
        reason: reason,
        flowId: flowId,
        clientEventIds: List.unmodifiable(clientEventIds),
      ),
    );
  }

  static Future<int> _addMaatFlowInstanceHeadless({
    required _MaatFlowTemplate template,
    DateTime? startDate,
    bool? useKemetic,
    TrackSkyTimeZone? trackSkyTimeZone,
    int? alertMinutesBefore,
    bool? dawnDiscreetMode,
    DawnHouseRiteLens? dawnLens,
    bool? eveningDiscreetMode,
    EveningThresholdRiteLens? eveningLens,
    int? eveningFallbackMinutesAfterMidnight,
    TheWeighingLens? theWeighingLens,
    OfferingTableLens? offeringTableLens,
    bool? offeringNoCupMode,
    TheTendingLens? theTendingLens,
    KeptWordLens? keptWordLens,
    CourseLens? courseLens,
    MoonReturnLens? moonReturnLens,
    WagLens? wagLens,
    DecanWatchLens? decanWatchLens,
    OpenHandLens? openHandLens,
    DjedLens? djedLens,
    List<ReadingHouseSitting>? readingHouseSittings,
    String? eveningThresholdInitialCarry,
  }) async {
    final personalCalendarId = await _loadHeadlessPersonalCalendarId();
    if (template.kind == _MaatFlowTemplateKind.trackSky) {
      final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
      final flowData = await loadTrackSkyFlowData(timezone);
      final events = upcomingTrackSkyEvents(flowData);
      if (events.isEmpty) return -1;

      final dates = <DateTime>{
        for (final event in events)
          DateUtils.dateOnly(trackSkyEventStartLocal(event, timezone)),
      };
      final orderedDates = dates.toList()..sort();
      final alertMinutes = alertMinutesBefore ?? _alertNoneMinutes;
      final flow = _Flow(
        id: -1,
        calendarId: personalCalendarId,
        name: template.title,
        color: template.color,
        active: true,
        rules: <FlowRule>[_RuleDates(dates: dates)],
        start: orderedDates.first,
        end: orderedDates.last,
        notes: [
          'mode=gregorian',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'sky_tz=${timezone.key}',
        ].join(';'),
      );
      final planned = <_PlannedNote>[];
      for (final event in events) {
        final startLocal = trackSkyEventStartLocal(event, timezone);
        final endLocal = trackSkyEventEndLocal(event, timezone);
        final dayOnly = DateUtils.dateOnly(startLocal);
        final k = KemeticMath.fromGregorian(dayOnly);
        planned.add(
          _PlannedNote(
            ky: k.kYear,
            km: k.kMonth,
            kd: k.kDay,
            note: _Note(
              title: event.title,
              detail: _encodeDetailWithMeta(
                event.detailText,
                alertMinutes: alertMinutes,
              ),
              allDay: event.schedule.allDay,
              start: event.schedule.allDay
                  ? null
                  : TimeOfDay(hour: startLocal.hour, minute: startLocal.minute),
              end: event.schedule.allDay
                  ? null
                  : TimeOfDay(hour: endLocal.hour, minute: endLocal.minute),
              category: event.category,
              alertOffsetMinutes: alertMinutes,
            ),
          ),
        );
      }
      return await _persistFlowStudioResultHeadless(
            _FlowStudioResult(savedFlow: flow, plannedNotes: planned),
          ) ??
          -1;
    }

    if (template.kind == _MaatFlowTemplateKind.moonReturn) {
      final result = await FlowJoinService().joinMoonReturnHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: moonReturnLens ?? MoonReturnLens.neutral,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.theWag) {
      final result = await FlowJoinService().joinWagHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: wagLens ?? WagLens.neutral,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.daysOutsideTheYear) {
      final result = await FlowJoinService().joinDaysOutsideYearHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.theOpenHand) {
      final result = await FlowJoinService().joinOpenHandHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: openHandLens ?? OpenHandLens.neutral,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.theDjed) {
      final result = await FlowJoinService().joinDjedHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: djedLens ?? DjedLens.neutral,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.readingHouse) {
      final result = await FlowJoinService().joinReadingHouseHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        plan: readingHousePlanFromDraftValues(
          kMaatFlowResponseDraftStore.valuesForFlow(template.key),
        ),
        readingHouseSittings: readingHouseSittings,
        alertOffsetMinutes: kEventFilingNoAlertMinutes,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.maatDecan) {
      final definition = maatDecanFlowDefinitionForKey(template.key);
      if (definition == null) return -1;
      final result = await FlowJoinService().joinMaatDecanFlowHeadless(
        definition: definition,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.decanWatch) {
      final result = await FlowJoinService().joinDecanWatchHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: decanWatchLens ?? DecanWatchLens.neutral,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.dawnHouseRite) {
      final result = await FlowJoinService().joinDawnHouseRiteHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        discreet: dawnDiscreetMode == true,
        lens: dawnLens ?? DawnHouseRiteLens.neutral,
        alertOffsetMinutes: kEventFilingNoAlertMinutes,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.eveningThreshold) {
      final result = await FlowJoinService().joinEveningThresholdHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        alertOffsetMinutes: 0,
        initialCarryText: eveningThresholdInitialCarry,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.eveningThresholdRite) {
      final fallbackMinutes =
          eveningFallbackMinutesAfterMidnight ??
          kEveningThresholdDefaultFallbackMinutes;
      final result = await FlowJoinService().joinEveningThresholdRiteHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        discreet: eveningDiscreetMode == true,
        lens: eveningLens ?? EveningThresholdRiteLens.neutral,
        fallbackMinutesAfterMidnight: fallbackMinutes,
        alertOffsetMinutes: kEventFilingNoAlertMinutes,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.theWeighing) {
      final result = await FlowJoinService().joinTheWeighingHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: theWeighingLens ?? TheWeighingLens.neutral,
        alertOffsetMinutes: kEventFilingNoAlertMinutes,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.offeringTable) {
      final result = await FlowJoinService().joinOfferingTableHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: offeringTableLens ?? OfferingTableLens.neutral,
        noCupMode: offeringNoCupMode == true,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.theTending) {
      final result = await FlowJoinService().joinTheTendingHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: theTendingLens ?? TheTendingLens.neutral,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.keptWord) {
      final result = await FlowJoinService().joinKeptWordHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: keptWordLens ?? KeptWordLens.neutral,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (template.kind == _MaatFlowTemplateKind.theCourse) {
      final result = await FlowJoinService().joinTheCourseHeadless(
        templateKey: template.key,
        templateTitle: template.title,
        templateOverview: template.overview,
        templateColor: template.color,
        personalCalendarId: personalCalendarId,
        timezone: trackSkyTimeZone ?? detectTrackSkyTimeZone(),
        startDate: startDate,
        lens: courseLens ?? CourseLens.neutral,
        alertOffsetMinutes: 0,
      );
      return result.flowIdOrNegativeOne;
    }

    if (startDate == null) return -1;
    final dates = <DateTime>{};
    final useKemeticStart = useKemetic == true;
    final firstG = useKemeticStart
        ? (() {
            final k = KemeticMath.fromGregorian(startDate);
            return KemeticMath.toGregorian(k.kYear, k.kMonth, k.kDay);
          })()
        : DateUtils.dateOnly(startDate);
    for (var i = 0; i < 10; i++) {
      dates.add(DateUtils.dateOnly(firstG.add(Duration(days: i))));
    }

    final flow = _Flow(
      id: -1,
      calendarId: personalCalendarId,
      name: template.title,
      color: template.color,
      active: true,
      rules: <FlowRule>[
        _RuleDates(
          dates: dates,
          allDay: false,
          start: const TimeOfDay(hour: 9, minute: 0),
          end: const TimeOfDay(hour: 10, minute: 0),
        ),
      ],
      start: firstG,
      end: firstG.add(const Duration(days: 9)),
      notes: [
        useKemeticStart ? 'mode=kemetic' : 'mode=gregorian',
        'split=1',
        if (template.overview.trim().isNotEmpty)
          'ov=${Uri.encodeComponent(template.overview.trim())}',
        'maat=${template.key}',
      ].join(';'),
    );

    final planned = <_PlannedNote>[];
    var dayIndex = 0;
    final ordered = dates.toList()..sort();
    for (final g in ordered) {
      final k = KemeticMath.fromGregorian(g);
      final day = template.days[dayIndex];
      for (final slot in day.notes) {
        planned.add(
          _PlannedNote(
            ky: k.kYear,
            km: k.kMonth,
            kd: k.kDay,
            note: _Note(
              title: slot.title,
              detail: slot.detail,
              allDay: false,
              start: slot.start,
              end: slot.end,
            ),
          ),
        );
      }
      dayIndex++;
    }

    return await _persistFlowStudioResultHeadless(
          _FlowStudioResult(savedFlow: flow, plannedNotes: planned),
        ) ??
        -1;
  }

  static Future<void> _endFlowHeadless(int flowId) async {
    await UserEventsRepo(Supabase.instance.client).endFlow(
      flowId: flowId,
      endedAtLocal: DateTime.now(),
      deleteAllMaterialized: true,
    );
    _forgetRememberedJoinedMaatFlow(flowId);
  }

  static bool _isFlowStudioRouteParent(String parentRoute) {
    final uri = Uri.tryParse(parentRoute.trim());
    return uri != null &&
        !uri.hasScheme &&
        uri.host.isEmpty &&
        uri.path == '/flows';
  }

  static Future<void> _recordDetachedFlowStudioRouteState({
    required BuildContext context,
    required String parentRoute,
    required Map<String, dynamic> state,
  }) async {
    if (!_isFlowStudioRouteParent(parentRoute)) return;
    final route = _flowStudioDurableRouteForState(state);
    if (route == null) return;

    try {
      if (context.mounted) {
        final router = GoRouter.of(context);
        final current = router.routerDelegate.currentConfiguration.uri
            .toString();
        if (!_sameRouteLocation(current, route)) {
          router.go(route);
        }
      }
    } catch (_) {
      // Some detached restore paths do not have a GoRouter ancestor; the
      // durable write below is still enough for the next launch.
    }

    await AppNavigationRestorationController.instance.recordVisibleSurface(
      route: route,
      source: NavigationSource.programmatic,
    );
  }

  static Future<T?> _pushDetachedFlowStudioRoute<T>(
    NavigatorState navigator,
    Route<T> route, {
    required String parentRoute,
    required Map<String, dynamic> visibleState,
    required Map<String, dynamic> returnState,
  }) async {
    await _recordDetachedFlowStudioRouteState(
      context: navigator.context,
      parentRoute: parentRoute,
      state: visibleState,
    );
    await _saveDetachedCalendarOverlayState(
      parentRoute: parentRoute,
      kind: _kCalendarOverlayKindFlowStudio,
      state: visibleState,
    );
    try {
      return await navigator.push<T>(route);
    } finally {
      if (navigator.mounted &&
          !RestorationCoordinator
              .instance
              .shouldPreserveOverlayForLifecycleClose) {
        await _recordDetachedFlowStudioRouteState(
          context: navigator.context,
          parentRoute: parentRoute,
          state: returnState,
        );
        await _saveDetachedCalendarOverlayState(
          parentRoute: parentRoute,
          kind: _kCalendarOverlayKindFlowStudio,
          state: returnState,
        );
      }
    }
  }

  static Future<_FlowStudioResult?> _pushDetachedFlowStudioEditor(
    NavigatorState navigator, {
    required String parentRoute,
    required FlowsRepo flowsRepo,
    int? editFlowId,
    ImportFlowData? importData,
    required Map<String, dynamic> returnState,
  }) {
    Future<void> handleResult(_FlowStudioResult result) async {
      final savedId = await _persistFlowStudioResultHeadless(result);
      if (savedId != null) {
        await flowsRepo.clearMyFiledFlowsCache();
        unawaited(flowsRepo.refreshMyFiledFlows());
      }
      if (navigator.mounted) {
        navigator.pop();
      }
    }

    final cachedFlows =
        _cachedDetachedMyFlowsFilingSnapshot(flowsRepo)?.flows ??
        const <_Flow>[];
    _Flow? readingHouseFlow;
    if (editFlowId != null && importData == null) {
      for (final flow in cachedFlows) {
        if (flow.id == editFlowId &&
            (resolveMaatFlowKind(flowNotes: flow.notes) ==
                    MaatFlowKind.readingHouse ||
                isReadingHouseFlowReference(
                  flowName: flow.name,
                  flowNotes: flow.notes,
                ))) {
          readingHouseFlow = flow;
          break;
        }
      }
    }
    if (readingHouseFlow != null) {
      final mountedHost = CalendarPage._mountedState;
      final sharedCalendarsRepo =
          mountedHost?._sharedCalendarsRepo ??
          SharedCalendarsRepo(Supabase.instance.client);
      final onCalendarChanged =
          mountedHost?._moveReadingHouseFlowToCalendar ??
          (flow, calendar) => _moveReadingHouseFlowToCalendarHeadless(
            flow,
            calendar,
            flowsRepo,
          );
      return _pushDetachedFlowStudioRoute<_FlowStudioResult>(
        navigator,
        MaterialPageRoute<_FlowStudioResult>(
          builder: (_) => _ReadingHouseAuthoringPage(
            flow: readingHouseFlow!,
            calendar: mountedHost?._calendarSummary(
              readingHouseFlow.calendarId,
            ),
            personalCalendarId: mountedHost?._personalCalendarId,
            sharedCalendarsRepo: sharedCalendarsRepo,
            onCalendarChanged: onCalendarChanged,
            onSave: handleResult,
          ),
        ),
        parentRoute: parentRoute,
        visibleState: <String, dynamic>{
          'mode': _kFlowStudioModeEditor,
          'editFlowId': editFlowId,
          'templateKey': kReadingHouseFlowKey,
        },
        returnState: returnState,
      );
    }

    return _pushDetachedFlowStudioRoute<_FlowStudioResult>(
      navigator,
      MaterialPageRoute<_FlowStudioResult>(
        builder: (_) => _FlowStudioPage(
          existingFlows: cachedFlows,
          editFlowId: editFlowId,
          importData: importData,
          onRouteResult: handleResult,
          onContinuityChanged: (state) {
            unawaited(
              _saveDetachedCalendarOverlayState(
                parentRoute: parentRoute,
                kind: _kCalendarOverlayKindFlowStudio,
                state: state,
              ),
            );
          },
        ),
      ),
      parentRoute: parentRoute,
      visibleState: <String, dynamic>{
        'mode': _kFlowStudioModeEditor,
        if (editFlowId != null) 'editFlowId': editFlowId,
      },
      returnState: returnState,
    );
  }

  static Future<_Flow> _moveFlowToCalendarHeadless(
    _Flow flow,
    SharedCalendarSummary calendar,
    FlowsRepo flowsRepo, {
    String source = 'flow_detail_calendar_move_headless',
  }) async {
    final calendarId = calendar.id.trim();
    if (calendarId.isEmpty) {
      throw ArgumentError.value(
        calendar.id,
        'calendar.id',
        'Must not be empty.',
      );
    }
    await flowsRepo.updateCalendar(id: flow.id, calendarId: calendarId);
    await UserEventsRepo(
      Supabase.instance.client,
    ).updateCalendarForFlowEvents(flowId: flow.id, calendarId: calendarId);
    await _ensureSharedExperienceForFlow(
      flowId: flow.id,
      calendarId: calendarId,
      source: source,
    );
    final startDate = flow.start == null
        ? null
        : DateUtils.dateOnly(flow.start!);
    final k = startDate == null ? null : KemeticMath.fromGregorian(startDate);
    await SharedCalendarsRepo(
      Supabase.instance.client,
    ).notifySharedCalendarItemAdded(
      calendarId: calendarId,
      itemType: 'flow',
      itemId: flow.id.toString(),
      itemTitle: flow.name,
      flowId: flow.id,
      startDate: startDate,
      kYear: k?.kYear,
      kMonth: k?.kMonth,
      kDay: k?.kDay,
    );
    await flowsRepo.clearMyFiledFlowsCache();
    unawaited(flowsRepo.refreshMyFiledFlows());
    flow.calendarId = calendarId;
    return flow;
  }

  static Future<_Flow> _moveReadingHouseFlowToCalendarHeadless(
    _Flow flow,
    SharedCalendarSummary calendar,
    FlowsRepo flowsRepo,
  ) {
    return _moveFlowToCalendarHeadless(
      flow,
      calendar,
      flowsRepo,
      source: 'reading_house_shared_calendar_move_headless',
    );
  }

  static Future<int?> _pushDetachedMaatFlowTemplateDetail(
    NavigatorState navigator,
    _MaatFlowTemplate template, {
    required String parentRoute,
    required Map<String, dynamic> returnState,
  }) {
    return _pushDetachedFlowStudioRoute<int?>(
