          template: template,
          addInstance: _addMaatFlowInstanceHeadless,
        ),
      ),
      parentRoute: parentRoute,
      visibleState: <String, dynamic>{
        'mode': _kFlowStudioModeMaatTemplate,
        'templateKey': template.key,
      },
      returnState: returnState,
    );
  }

  static Widget _buildDetachedMyFlowsPage({
    required NavigatorState navigator,
    required String parentRoute,
    required FlowsRepo flowsRepo,
    int? initialFlowId,
  }) {
    final mountedHost = CalendarPage._mountedState;
    if (initialFlowId != null) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!navigator.mounted) return;
        unawaited(
          _pushDetachedFlowStudioEditor(
            navigator,
            parentRoute: parentRoute,
            flowsRepo: flowsRepo,
            editFlowId: initialFlowId,
            returnState: const <String, dynamic>{
              'mode': _kFlowStudioModeMyFlows,
            },
          ),
        );
      });
    }

    return _FlowsViewerPage(
      loadFilingSnapshot: () => _loadDetachedMyFlowsFilingSnapshot(flowsRepo),
      initialFilingSnapshot: _cachedDetachedMyFlowsFilingSnapshot(flowsRepo),
      fmtGregorian: _formatDetachedGregorian,
      onCreateNew: () async {
        final edited = await _pushDetachedFlowStudioEditor(
          navigator,
          parentRoute: parentRoute,
          flowsRepo: flowsRepo,
          returnState: const <String, dynamic>{'mode': _kFlowStudioModeMyFlows},
        );
        await _saveDetachedCalendarOverlayState(
          parentRoute: parentRoute,
          kind: _kCalendarOverlayKindFlowStudio,
          state: const <String, dynamic>{'mode': _kFlowStudioModeMyFlows},
        );
        if (edited != null) {
          await _persistFlowStudioResultHeadless(edited);
        }
      },
      onEditFlow: (id) async {
        final edited = await _pushDetachedFlowStudioEditor(
          navigator,
          parentRoute: parentRoute,
          flowsRepo: flowsRepo,
          editFlowId: id,
          returnState: const <String, dynamic>{'mode': _kFlowStudioModeMyFlows},
        );
        await _saveDetachedCalendarOverlayState(
          parentRoute: parentRoute,
          kind: _kCalendarOverlayKindFlowStudio,
          state: const <String, dynamic>{'mode': _kFlowStudioModeMyFlows},
        );
        if (edited != null) {
          await _persistFlowStudioResultHeadless(edited);
        }
      },
      onEndFlow: _endFlowHeadless,
      onImportFlow: (_) async {
        await flowsRepo.refreshMyFiledFlows();
      },
      onCalendarChanged:
          mountedHost?._moveFlowToCalendar ??
          (flow, calendar) =>
              _moveFlowToCalendarHeadless(flow, calendar, flowsRepo),
    );
  }

  static Widget _buildDetachedMaatFlowsListPage({
    required NavigatorState navigator,
    required String parentRoute,
    required FlowsRepo flowsRepo,
    VoidCallback? onClose,
  }) {
    final cachedSnapshot = _cachedDetachedMyFlowsFilingSnapshot(flowsRepo);
    return _MaatFlowsListPageWithSnapshot(
      title: _kMaatFlowsDisplayTitle,
      templates: _kMaatFlowTemplates,
      initialSnapshot: cachedSnapshot,
      loadSnapshot: () async {
        final rows = await flowsRepo.refreshMyFiledFlows();
        final snapshot = _myFlowsFilingSnapshotFromRowsDetached(rows);
        _reconcileRememberedMaatJoinsFromLiveSnapshot(snapshot);
        return snapshot;
      },
      onPickTemplate: (template) async {
        final importedFlowId = await _pushDetachedMaatFlowTemplateDetail(
          navigator,
          template,
          parentRoute: parentRoute,
          returnState: const <String, dynamic>{
            'mode': _kFlowStudioModeMaatFlows,
          },
        );
        if (importedFlowId != null && importedFlowId > 0 && navigator.mounted) {
          _rememberJoinedMaatFlowTemplate(
            templateKey: template.key,
            flowId: importedFlowId,
          );
          await flowsRepo.clearMyFiledFlowsCache();
          if (!navigator.mounted) return importedFlowId;
          unawaited(
            flowsRepo.refreshMyFiledFlows().then((rows) {
              _reconcileRememberedMaatJoinsFromLiveSnapshot(
                _myFlowsFilingSnapshotFromRowsDetached(rows),
              );
            }),
          );
          if (navigator.canPop()) {
            navigator.pop(importedFlowId);
          } else {
            Navigator.of(navigator.context, rootNavigator: true).pop();
          }
        }
        return importedFlowId;
      },
      onCreateNew: () async {
        final edited = await _pushDetachedFlowStudioEditor(
          navigator,
          parentRoute: parentRoute,
          flowsRepo: flowsRepo,
          returnState: const <String, dynamic>{
            'mode': _kFlowStudioModeMaatFlows,
          },
        );
        if (edited != null) {
          await _persistFlowStudioResultHeadless(edited);
        }
      },
      onClose: () {
        if (!navigator.mounted) return;
        if (navigator.canPop()) {
          navigator.pop();
        } else {
          if (onClose != null) {
            onClose();
            return;
          }
          final rootNavigator = Navigator.of(
            navigator.context,
            rootNavigator: true,
          );
          if (rootNavigator.canPop()) {
            rootNavigator.pop();
          }
        }
      },
    );
  }

  static Widget _buildDetachedFlowStudioRoot({
    required BuildContext innerCtx,
    required String parentRoute,
    required FlowsRepo flowsRepo,
    required Map<String, dynamic> restorationState,
    VoidCallback? onClose,
  }) {
    final navigator = Navigator.of(innerCtx);
    final mode = (restorationState['mode'] as String?)?.trim();

    if (mode == _kFlowStudioModeEditor) {
      final editFlowId = (restorationState['editFlowId'] as num?)?.toInt();
      return _FlowStudioPage(
        existingFlows:
            _cachedDetachedMyFlowsFilingSnapshot(flowsRepo)?.flows ??
            const <_Flow>[],
        editFlowId: editFlowId,
        onRouteClose: onClose,
        onRouteResult: (result) async {
          final savedId = await _persistFlowStudioResultHeadless(result);
          if (savedId != null) {
            await flowsRepo.clearMyFiledFlowsCache();
            unawaited(flowsRepo.refreshMyFiledFlows());
          }
          if (onClose != null) {
            onClose();
            return;
          }
          if (!navigator.mounted) return;
          final rootNavigator = Navigator.of(
            navigator.context,
            rootNavigator: true,
          );
          if (rootNavigator.canPop()) {
            rootNavigator.pop();
          }
        },
        onContinuityChanged: (state) {
          unawaited(
            _saveDetachedCalendarOverlayState(
              parentRoute: parentRoute,
              kind: _kCalendarOverlayKindFlowStudio,
              state: state,
            ),
          );
        },
      );
    }

    if (mode == _kFlowStudioModeMyFlows) {
      return _buildDetachedMyFlowsPage(
        navigator: navigator,
        parentRoute: parentRoute,
        flowsRepo: flowsRepo,
        initialFlowId: (restorationState['initialFlowId'] as num?)?.toInt(),
      );
    }

    if (mode == _kFlowStudioModeMaatFlows ||
        mode == _kFlowStudioModeMaatTemplate) {
      final templateKey = (restorationState['templateKey'] as String?)?.trim();
      if (mode == _kFlowStudioModeMaatTemplate &&
          templateKey != null &&
          templateKey.isNotEmpty) {
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (!navigator.mounted) return;
          for (final template in _kMaatFlowTemplates) {
            if (template.key != templateKey) continue;
            unawaited(
              _pushDetachedMaatFlowTemplateDetail(
                navigator,
                template,
                parentRoute: parentRoute,
                returnState: const <String, dynamic>{
                  'mode': _kFlowStudioModeMaatFlows,
                },
              ),
            );
            break;
          }
        });
      }
      return _buildDetachedMaatFlowsListPage(
        navigator: navigator,
        parentRoute: parentRoute,
        flowsRepo: flowsRepo,
        onClose: onClose,
      );
    }

    return _FlowHubPage(
      onClose: onClose,
      openMyFlows: () {
        unawaited(
          _pushDetachedFlowStudioRoute<void>(
            navigator,
            MaterialPageRoute<void>(
              builder: (ctx) => _buildDetachedMyFlowsPage(
                navigator: Navigator.of(ctx),
                parentRoute: parentRoute,
                flowsRepo: flowsRepo,
              ),
            ),
            parentRoute: parentRoute,
            visibleState: const <String, dynamic>{
              'mode': _kFlowStudioModeMyFlows,
            },
            returnState: const <String, dynamic>{'mode': _kFlowStudioModeHub},
          ),
        );
      },
      openMaatFlows: () {
        unawaited(
          _pushDetachedFlowStudioRoute<int?>(
            navigator,
            MaterialPageRoute<int?>(
              builder: (ctx) => _buildDetachedMaatFlowsListPage(
                navigator: Navigator.of(ctx),
                parentRoute: parentRoute,
                flowsRepo: flowsRepo,
                onClose: onClose,
              ),
            ),
            parentRoute: parentRoute,
            visibleState: const <String, dynamic>{
              'mode': _kFlowStudioModeMaatFlows,
            },
            returnState: const <String, dynamic>{'mode': _kFlowStudioModeHub},
          ).then((importedFlowId) async {
            if (importedFlowId != null && importedFlowId > 0) {
              await flowsRepo.refreshMyFiledFlows();
            }
          }),
        );
      },
      onCreateNew: () {
        unawaited(
          _pushDetachedFlowStudioEditor(
            navigator,
            parentRoute: parentRoute,
            flowsRepo: flowsRepo,
            returnState: const <String, dynamic>{'mode': _kFlowStudioModeHub},
          ).then((edited) async {
            if (edited != null) {
              await _persistFlowStudioResultHeadless(edited);
            }
          }),
        );
      },
    );
  }

  static List<Route<dynamic>> _detachedFlowStudioInitialRoutes({
    required String parentRoute,
    required FlowsRepo flowsRepo,
    required Map<String, dynamic> restorationState,
    VoidCallback? onClose,
    VoidCallback? onReturnToHub,
  }) {
    final mode = (restorationState['mode'] as String?)?.trim();
    final templateKey = (restorationState['templateKey'] as String?)?.trim();
    Route<dynamic> hubRoute() => MaterialPageRoute<dynamic>(
      builder: (innerCtx) => _buildDetachedFlowStudioRoot(
        innerCtx: innerCtx,
        parentRoute: parentRoute,
        flowsRepo: flowsRepo,
        restorationState: const <String, dynamic>{'mode': _kFlowStudioModeHub},
        onClose: onClose,
      ),
    );

    void recordReturnToHub() {
      if (RestorationCoordinator
          .instance
          .shouldPreserveOverlayForLifecycleClose) {
        return;
      }
      onReturnToHub?.call();
      unawaited(
        _saveDetachedCalendarOverlayState(
          parentRoute: parentRoute,
          kind: _kCalendarOverlayKindFlowStudio,
          state: const <String, dynamic>{'mode': _kFlowStudioModeHub},
        ),
      );
    }

    if (mode == _kFlowStudioModeMaatFlows) {
      final listRoute = MaterialPageRoute<int?>(
        builder: (innerCtx) => _buildDetachedMaatFlowsListPage(
          navigator: Navigator.of(innerCtx),
          parentRoute: parentRoute,
          flowsRepo: flowsRepo,
          onClose: onClose,
        ),
      );
      unawaited(listRoute.popped.then((_) => recordReturnToHub()));
      return <Route<dynamic>>[hubRoute(), listRoute];
    }

    if (mode == _kFlowStudioModeMyFlows) {
      final listRoute = MaterialPageRoute<dynamic>(
        builder: (innerCtx) => _buildDetachedMyFlowsPage(
          navigator: Navigator.of(innerCtx),
          parentRoute: parentRoute,
          flowsRepo: flowsRepo,
          initialFlowId: (restorationState['initialFlowId'] as num?)?.toInt(),
        ),
      );
      unawaited(listRoute.popped.then((_) => recordReturnToHub()));
      return <Route<dynamic>>[hubRoute(), listRoute];
    }

    if (mode != _kFlowStudioModeMaatTemplate ||
        templateKey == null ||
        templateKey.isEmpty) {
      return <Route<dynamic>>[
        MaterialPageRoute<dynamic>(
          builder: (innerCtx) => _buildDetachedFlowStudioRoot(
            innerCtx: innerCtx,
            parentRoute: parentRoute,
            flowsRepo: flowsRepo,
            restorationState: restorationState,
            onClose: onClose,
          ),
        ),
      ];
    }

    _MaatFlowTemplate? template;
    for (final candidate in _kMaatFlowTemplates) {
      if (candidate.key == templateKey) {
        template = candidate;
        break;
      }
    }

    final listRoute = MaterialPageRoute<dynamic>(
      builder: (innerCtx) => _buildDetachedMaatFlowsListPage(
        navigator: Navigator.of(innerCtx),
        parentRoute: parentRoute,
        flowsRepo: flowsRepo,
        onClose: onClose,
      ),
    );
    unawaited(listRoute.popped.then((_) => recordReturnToHub()));
    if (template == null) return <Route<dynamic>>[hubRoute(), listRoute];

    final detailRoute = MaterialPageRoute<int?>(
      builder: (_) => _MaatFlowTemplateDetailPage(
        template: template!,
        addInstance: _addMaatFlowInstanceHeadless,
      ),
    );
    unawaited(
      detailRoute.popped.then((importedFlowId) async {
        if (RestorationCoordinator
            .instance
            .shouldPreserveOverlayForLifecycleClose) {
          return;
        }
        await _saveDetachedCalendarOverlayState(
          parentRoute: parentRoute,
          kind: _kCalendarOverlayKindFlowStudio,
          state: const <String, dynamic>{'mode': _kFlowStudioModeMaatFlows},
        );
        if (importedFlowId != null && importedFlowId > 0) {
          _rememberJoinedMaatFlowTemplate(
            templateKey: template!.key,
            flowId: importedFlowId,
          );
          await flowsRepo.clearMyFiledFlowsCache();
          unawaited(
            flowsRepo.refreshMyFiledFlows().then((rows) {
              _reconcileRememberedMaatJoinsFromLiveSnapshot(
                _myFlowsFilingSnapshotFromRowsDetached(rows),
              );
            }),
          );
        }
      }),
    );

    return <Route<dynamic>>[hubRoute(), listRoute, detailRoute];
  }

  static Future<void> _openDetachedFlowStudioSheet(
    BuildContext context, {
    required Map<String, dynamic> restorationState,
  }) async {
    if (!context.mounted) return;
    final parentRoute = _currentRouteLocationForContext(context);
    final mode = (restorationState['mode'] as String?)?.trim();
    final continuityState = <String, dynamic>{
      'mode': mode == null || mode.isEmpty ? _kFlowStudioModeHub : mode,
      if (restorationState['initialFlowId'] != null)
        'initialFlowId': restorationState['initialFlowId'],
      if (restorationState['editFlowId'] != null)
        'editFlowId': restorationState['editFlowId'],
      if (restorationState['templateKey'] != null)
        'templateKey': restorationState['templateKey'],
    };
    if (_detachedFlowStudioSheetOpenOrOpening) return;
    _detachedFlowStudioSheetOpenOrOpening = true;

    final flowsRepo = FlowsRepo(Supabase.instance.client);
    try {
      await _saveDetachedCalendarOverlayState(
        parentRoute: parentRoute,
        kind: _kCalendarOverlayKindFlowStudio,
        state: continuityState,
      );
      if (!context.mounted) return;

      NavigationTrace.instance.record(
        'sheet open success',
        state: const <String, Object?>{
          'sheet': 'flowStudio',
          'host': 'detached',
        },
      );
      final isTablet = _isTabletForContext(context);
      final result = await showModalBottomSheet<_FlowStudioResult?>(
        context: context,
        isScrollControlled: true,
        backgroundColor: Colors.transparent,
        barrierColor: Colors.black54,
        useSafeArea: true,
        useRootNavigator: true,
        isDismissible: !isTablet,
        enableDrag: !isTablet,
        builder: (outerCtx) {
          Widget buildNavigator() {
            return Navigator(
              onGenerateInitialRoutes: (nav, initial) {
                return _detachedFlowStudioInitialRoutes(
                  parentRoute: parentRoute,
                  flowsRepo: flowsRepo,
                  restorationState: continuityState,
                  onClose: () {
                    final rootNavigator = Navigator.of(
                      outerCtx,
                      rootNavigator: true,
                    );
                    if (rootNavigator.canPop()) {
                      rootNavigator.pop();
                    }
                  },
                );
              },
            );
          }

          if (isTablet) {
            return SafeArea(
              child: FractionallySizedBox(
                heightFactor: 0.9,
                child: ClipRRect(
                  borderRadius: const BorderRadius.vertical(
                    top: Radius.circular(16),
                  ),
                  child: Material(
                    color: Colors.black,
                    child: Column(
                      children: [
                        Align(
                          alignment: Alignment.topRight,
                          child: IconButton(
                            icon: const Icon(Icons.close, color: Colors.white),
                            onPressed: () => Navigator.of(outerCtx).pop(),
                          ),
                        ),
                        Expanded(child: buildNavigator()),
                      ],
                    ),
                  ),
                ),
              ),
            );
          }

          return DraggableScrollableSheet(
            initialChildSize: 0.8,
            minChildSize: 0.4,
            maxChildSize: 1.0,
            snap: true,
            snapSizes: const <double>[0.8, 1.0],
            expand: false,
            builder: (innerCtx, scrollController) {
              return ClipRRect(
                borderRadius: const BorderRadius.vertical(
                  top: Radius.circular(16),
                ),
                child: Material(
                  color: Colors.black,
                  child: Column(
                    children: [
                      const SizedBox(height: 10),
                      Container(
                        width: 36,
                        height: 4,
                        decoration: BoxDecoration(
                          color: Colors.white24,
                          borderRadius: BorderRadius.circular(2),
                        ),
                      ),
                      const SizedBox(height: 8),
                      Expanded(child: buildNavigator()),
                    ],
                  ),
                ),
              );
            },
          );
        },
      );

      if (result != null) {
        await _persistFlowStudioResultHeadless(result);
      }
    } catch (error) {
      NavigationTrace.instance.record(
        'sheet open error',
        state: <String, Object?>{
          'sheet': 'flowStudio',
          'host': 'detached',
          'error': error.runtimeType,
        },
      );
      rethrow;
    } finally {
      try {
        if (context.mounted) {
          await _clearFlowStudioTransientState(
            reason: OverlayStackMutationReason.userDismissed,
          );
        }
      } finally {
        _detachedFlowStudioSheetOpenOrOpening = false;
      }
    }
  }

  static bool _sameRouteLocation(String a, String b) {
    final aUri = Uri.tryParse(a.trim());
    final bUri = Uri.tryParse(b.trim());
    if (aUri == null || bUri == null) return a.trim() == b.trim();
    return aUri.path == bUri.path && aUri.query == bUri.query;
  }

  static Future<bool> restoreDetachedCalendarOverlayFromAnyContext(
    BuildContext context, {
    String? currentLocation,
  }) async {
    if (_detachedCalendarOverlayRestoreInFlight) return false;
    final snapshot = await RestorationCoordinator.instance.readBestSnapshot(
      includeRemote: Supabase.instance.client.auth.currentSession != null,
    );
    final overlay = _restorableCalendarOverlayFromStack(
      snapshot.snapshot?.overlayStack ?? const <Map<String, dynamic>>[],
    );
    if (overlay == null) return false;
    if (!context.mounted) return false;

    final parentRoute = (overlay['parentRoute'] as String?)?.trim();
    if (parentRoute == null ||
        parentRoute.isEmpty ||
        _isRootRouteLocation(parentRoute)) {
      return false;
    }

    final activeLocation = currentLocation?.trim().isNotEmpty == true
        ? currentLocation!.trim()
        : _currentRouteLocationForContext(context);
    if (!_sameRouteLocation(activeLocation, parentRoute)) return false;

    final restoreKey = _calendarOverlayRestoreSurfaceKey(overlay);
    if (_lastDetachedCalendarOverlayRestoreKey == restoreKey) return false;
    if (!RestorationCoordinator.instance.claimRestoreSurface(restoreKey)) {
      return false;
    }

    _lastDetachedCalendarOverlayRestoreKey = restoreKey;
    _detachedCalendarOverlayRestoreInFlight = true;
    try {
      if (overlay['kind'] == _kCalendarOverlayKindSharedCalendars) {
        await _openDetachedSharedCalendarsSheet(
          context,
          restorationState: overlay,
        );
        return true;
      }

      if (overlay['kind'] == _kCalendarOverlayKindFlowStudio) {
        await _openDetachedFlowStudioSheet(context, restorationState: overlay);
        return true;
      }
    } finally {
      _detachedCalendarOverlayRestoreInFlight = false;
    }
    return false;
  }

