    NavigationTrace.instance.record('Today restoration state saved');
  }

  static void openMainCalendarAtToday(
    BuildContext context, {
    bool animate = false,
  }) {
    NavigationTrace.instance.record('openMainCalendarAtToday entered');
    RestorationCoordinator.instance.suppressRestoreForUserNavigation(
      reason: 'calendar_today_command',
      surfaces: const <String>[
        RestorationCoordinator.calendarDayViewSurface,
        RestorationCoordinator.calendarOverlayStackSurface,
        RestorationCoordinator.plannerSurface,
      ],
    );
    CalendarPage._pendingDetachedLaunchAction = null;
    CalendarPage._pendingDetachedSearchResult = null;
    CalendarPage._pendingDetachedSearchDay = null;
    CalendarPage._pendingSharedCalendarRealDayViewIntent = null;
    CalendarPage._pendingTodayNavigationCommand = true;
    final mountedState = _mountedState;
    mountedState?._suppressPendingRestoresForUserNavigation();
    unawaited(
      AppNavigationRestorationController.instance.recordPrimaryTabSelection(
        AppSection.calendar,
      ),
    );
    unawaited(_recordCalendarTodayCommandState(mountedState));

    final router = GoRouter.of(context);
    final rootNavigator = Navigator.of(context, rootNavigator: true);
    if (rootNavigator.canPop()) {
      rootNavigator.popUntil((route) => route.isFirst);
    }
    NavigationTrace.instance.record("go('/') issued");
    router.go('/');
    if (mountedState != null) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!mountedState.mounted) return;
        CalendarPage._pendingTodayNavigationCommand = false;
        mountedState._applyTodayNavigationCommand(
          animate: animate,
          reason: 'today_command:mounted_calendar',
        );
      });
    }
    _scheduleTodayJumpAfterNavigation(animate: animate);
  }

  // Static method for parsing rules from JSON (used by inbox import)
  static FlowRule ruleFromJson(Map<String, dynamic> j) {
    final allDay = (j['allDay'] ?? true) as bool;
    TimeOfDay? start;
    TimeOfDay? end;

    if (j['startHour'] != null && j['startMinute'] != null) {
      start = TimeOfDay(
        hour: (j['startHour'] as num).toInt(),
        minute: (j['startMinute'] as num).toInt(),
      );
    }
    if (j['endHour'] != null && j['endMinute'] != null) {
      end = TimeOfDay(
        hour: (j['endHour'] as num).toInt(),
        minute: (j['endMinute'] as num).toInt(),
      );
    }

    switch (j['type']) {
      case 'week':
        return _RuleWeek(
          weekdays: {...(j['weekdays'] as List).map((e) => (e as num).toInt())},
          allDay: allDay,
          start: start,
          end: end,
        );
      case 'decan':
        return _RuleDecan(
          months: {...(j['months'] as List).map((e) => (e as num).toInt())},
          decans: {...(j['decans'] as List).map((e) => (e as num).toInt())},
          daysInDecan: {
            ...(j['daysInDecan'] as List).map((e) => (e as num).toInt()),
          },
          allDay: allDay,
          start: start,
          end: end,
        );
      case 'dates':
        return _RuleDates(
          dates: {
            for (final n in (j['dates'] as List))
              DateUtils.dateOnly(
                DateTime.fromMillisecondsSinceEpoch((n as num).toInt()),
              ),
          },
          allDay: allDay,
          start: start,
          end: end,
        );
    }
    throw ArgumentError('Unknown rule type ${j['type']}');
  }

  static ({
    String? detail,
    String? location,
    String? category,
    int? alertMinutes,
  })
  _decodeHeadlessFlowNotes(String? rawNotes) {
    if (rawNotes == null || rawNotes.isEmpty) {
      return (detail: null, location: null, category: null, alertMinutes: null);
    }

    try {
      final meta = jsonDecode(rawNotes) as Map<String, dynamic>;
      if (meta['kind'] == 'repeating_note') {
        return (
          detail: (meta['detail'] as String?)?.trim(),
          location: (meta['location'] as String?)?.trim(),
          category: (meta['category'] as String?)?.trim(),
          alertMinutes: (meta['alertMinutes'] as num?)?.toInt(),
        );
      }
    } catch (_) {
      // Fall through to legacy Flow Studio note decoding.
    }

    try {
      final decoded = notesDecode(rawNotes);
      final overview = decoded.overview.trim();
      return (
        detail: overview.isEmpty ? null : overview,
        location: null,
        category: null,
        alertMinutes: null,
      );
    } catch (_) {
      return (detail: null, location: null, category: null, alertMinutes: null);
    }
  }

  // Headless persistence helper: save/delete flows + planned notes without calendar state.
  static Future<int?> _persistFlowStudioResultHeadless(
    _FlowStudioResult r,
  ) async {
    final userEventsRepo = UserEventsRepo(Supabase.instance.client);

    // Deletes
    final deleteId = r.deleteFlowId;
    if (deleteId != null) {
      await userEventsRepo.deleteByFlowId(deleteId);
      await userEventsRepo.deleteFlow(deleteId);
      _publishHeadlessCalendarInvalidation(
        reason: CalendarInvalidationReason.flowDeleted,
        flowId: deleteId,
        clientEventIds: const <String>[],
      );
      return deleteId;
    }

    // Saves
    if (r.savedFlow == null) return null;
    final f = r.savedFlow!;
    final isNewFlowSave = f.id <= 0;
    final rulesJson = jsonEncode(
      f.rules.map(CalendarPageState.ruleToJson).toList(),
    );

    final savedId = await userEventsRepo.upsertFlow(
      id: f.id > 0 ? f.id : null,
      name: f.name,
      color: f.color.toARGB32(),
      active: f.active,
      calendarId: f.calendarId,
      startDate: f.start,
      endDate: f.end,
      notes: f.notes,
      rules: rulesJson,
      isHidden: f.isHidden,
      isSaved: f.isSaved,
      originType: r.originType,
      originFlowId: r.originFlowId,
      originShareId: r.originShareId ?? f.shareId,
      originGenerationId: r.originGenerationId,
      rootFlowId: r.rootFlowId,
      aiMetadata: r.aiMetadata,
    );

    // Persist planned notes (with individual titles)
    final clientEventIds = <String>[];
    String? firstClientEventId;
    bool generationCommitted = false;

    Future<void> commitGenerationIfNeeded() async {
      if (generationCommitted || r.originGenerationId == null) return;
      generationCommitted = true;
      try {
        await userEventsRepo.flowCommit(
          generationId: r.originGenerationId!,
          flowId: savedId,
        );
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudioHeadless] flow_commit failed for generation ${r.originGenerationId}: $e',
          );
        }
      }
    }

    Future<void> rollbackNewFlowSave(
      Object error,
      StackTrace stackTrace,
    ) async {
      if (!isNewFlowSave) return;
      if (kDebugMode) {
        _calendarDebugPrint(
          '[persistFlowStudioHeadless] Rolling back new flow $savedId after planned-note save failed: $error',
        );
        _calendarDebugPrint('$stackTrace');
      }
      try {
        await userEventsRepo.deleteByFlowId(
          savedId,
          semantic: 'flow_save_rollback',
          suppressesClient: false,
          sourceFeature: 'CalendarPage._persistFlowStudioResultHeadless',
          deleteScope: 'failed_new_flow_save',
        );
      } catch (rollbackError) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudioHeadless] rollback deleteByFlowId failed: $rollbackError',
          );
        }
      }
      try {
        await userEventsRepo.deleteFlow(savedId);
      } catch (rollbackError) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudioHeadless] rollback deleteFlow failed: $rollbackError',
          );
        }
      }
    }

    if (r.plannedNotes.isNotEmpty) {
      final eventFiling = EventFilingService();
      try {
        for (final p in r.plannedNotes) {
          final n = p.note;
          final gDay = KemeticMath.toGregorian(p.ky, p.km, p.kd);
          final startsAt = DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            n.start?.hour ?? 9,
            n.start?.minute ?? 0,
          );
          DateTime? endsAt;
          if (!n.allDay && n.end != null) {
            endsAt = DateTime(
              gDay.year,
              gDay.month,
              gDay.day,
              n.end!.hour,
              n.end!.minute,
            );
          } else if (!n.allDay) {
            endsAt = startsAt.add(const Duration(hours: 1));
          }

          final cid = EventCidUtil.buildClientEventId(
            ky: p.ky,
            km: p.km,
            kd: p.kd,
            title: n.title,
            startHour: n.start?.hour ?? 9,
            startMinute: n.start?.minute ?? 0,
            allDay: n.allDay,
            flowId: savedId,
          );
          clientEventIds.add(cid);

          final savedEvent = await userEventsRepo.upsertByClientId(
            clientEventId: cid,
            title: n.title,
            startsAtUtc: startsAt.toUtc(),
            detail: (n.detail ?? '').trim().isEmpty ? null : n.detail,
            location: (n.location ?? '').trim().isEmpty ? null : n.location,
            allDay: n.allDay,
            endsAtUtc: endsAt?.toUtc(),
            calendarId: f.calendarId,
            flowLocalId: savedId,
            category: n.category,
            actionId: n.actionId,
            behaviorPayload: n.behaviorPayload,
            caller: 'flow_save_notes',
          );
          firstClientEventId ??= savedEvent.clientEventId ?? cid;

          final bodyLines = <String>[
            if ((n.location ?? '').trim().isNotEmpty) n.location!.trim(),
            if ((n.detail ?? '').trim().isNotEmpty) n.detail!.trim(),
          ];
          await _fileHeadlessEventDelivery(
            eventFiling: eventFiling,
            debugLabel: 'flowStudioHeadless',
            clientEventId: cid,
            startsAtLocal: startsAt,
            alertOffsetMinutes: n.alertOffsetMinutes,
            title: n.title,
            body: bodyLines.isEmpty ? null : bodyLines.join('\n'),
            kYear: p.ky,
            kMonth: p.km,
            kDay: p.kd,
            eventId: savedEvent.id,
            flowId: savedId,
          );
        }
      } catch (error, stackTrace) {
        await rollbackNewFlowSave(error, stackTrace);
        rethrow;
      }
    }

    Future<int> materializeRuleEventsIfNeeded() async {
      if (!f.active || f.rules.isEmpty || r.plannedNotes.isNotEmpty) return 0;

      final scheduleStart = DateUtils.dateOnly(f.start ?? DateTime.now());
      final scheduleEnd = DateUtils.dateOnly(
        f.end ?? scheduleStart.add(const Duration(days: 90)),
      );
      final noteTitle = f.name.trim().isEmpty ? 'Flow Event' : f.name.trim();
      final noteMeta = _decodeHeadlessFlowNotes(f.notes);
      final eventFiling = EventFilingService();
      final candidateDates = <DateTime>[];

      for (
        var date = scheduleStart;
        !date.isAfter(scheduleEnd);
        date = date.add(const Duration(days: 1))
      ) {
        final kDate = KemeticMath.fromGregorian(date);
        for (final rule in f.rules) {
          if (rule.matches(
            ky: kDate.kYear,
            km: kDate.kMonth,
            kd: kDate.kDay,
            g: date,
          )) {
            candidateDates.add(date);
            break;
          }
        }
      }

      if (candidateDates.isEmpty) return 0;

      await userEventsRepo.deleteByFlowId(
        savedId,
        fromDate: scheduleStart.toUtc(),
        semantic: 'flow_reschedule',
        suppressesClient: false,
        sourceFeature: 'CalendarPage._persistFlowStudioResultHeadless',
        deleteScope: 'flow_reschedule',
      );

      var savedCount = 0;
      for (final date in candidateDates) {
        final kDate = KemeticMath.fromGregorian(date);
        for (final rule in f.rules) {
          if (!rule.matches(
            ky: kDate.kYear,
            km: kDate.kMonth,
            kd: kDate.kDay,
            g: date,
          )) {
            continue;
          }

          final startHour = rule.allDay ? 9 : (rule.start?.hour ?? 9);
          final startMinute = rule.allDay ? 0 : (rule.start?.minute ?? 0);
          final startsAt = DateTime(
            date.year,
            date.month,
            date.day,
            startHour,
            startMinute,
          );

          DateTime? endsAt;
          if (!rule.allDay) {
            endsAt = rule.end == null
                ? startsAt.add(const Duration(hours: 1))
                : DateTime(
                    date.year,
                    date.month,
                    date.day,
                    rule.end!.hour,
                    rule.end!.minute,
                  );
          }

          final cid = EventCidUtil.buildClientEventId(
            ky: kDate.kYear,
            km: kDate.kMonth,
            kd: kDate.kDay,
            title: noteTitle,
            startHour: startHour,
            startMinute: startMinute,
            allDay: rule.allDay,
            flowId: savedId,
          );
          clientEventIds.add(cid);

          final savedEvent = await userEventsRepo.upsertByClientId(
            clientEventId: cid,
            title: noteTitle,
            startsAtUtc: startsAt.toUtc(),
            detail: noteMeta.detail,
            location: noteMeta.location,
            allDay: rule.allDay,
            endsAtUtc: endsAt?.toUtc(),
            calendarId: f.calendarId,
            flowLocalId: savedId,
            category: noteMeta.category,
            caller: 'flow_save_rules_headless',
          );
          firstClientEventId ??= savedEvent.clientEventId ?? cid;
          savedCount++;

          final bodyLines = <String>[
            if ((noteMeta.location ?? '').trim().isNotEmpty)
              noteMeta.location!.trim(),
            if ((noteMeta.detail ?? '').trim().isNotEmpty)
              noteMeta.detail!.trim(),
          ];
          await _fileHeadlessEventDelivery(
            eventFiling: eventFiling,
            debugLabel: 'flowStudioHeadlessRules',
            clientEventId: cid,
            startsAtLocal: startsAt,
            alertOffsetMinutes: noteMeta.alertMinutes ?? _alertNoneMinutes,
            title: noteTitle,
            body: bodyLines.isEmpty ? null : bodyLines.join('\n'),
            kYear: kDate.kYear,
            kMonth: kDate.kMonth,
            kDay: kDate.kDay,
            eventId: savedEvent.id,
            flowId: savedId,
          );
        }
      }

      return savedCount;
    }

    try {
      await materializeRuleEventsIfNeeded();
    } catch (error, stackTrace) {
      await rollbackNewFlowSave(error, stackTrace);
      rethrow;
    }

    await commitGenerationIfNeeded();
    await _ensureSharedExperienceForFlow(
      flowId: savedId,
      calendarId: f.calendarId,
      source: 'CalendarPage._persistFlowStudioResultHeadless',
    );

    if (isNewFlowSave) {
      await SharedCalendarsRepo(
        Supabase.instance.client,
      ).notifySharedCalendarItemAdded(
        calendarId: f.calendarId,
        itemType: 'flow',
        itemId: savedId.toString(),
        itemTitle: f.name,
        clientEventId: firstClientEventId,
        flowId: savedId,
        startDate: f.start,
        endDate: f.end,
      );
    }

    _publishHeadlessCalendarInvalidation(
      reason: CalendarInvalidationReason.flowStudioPersisted,
      flowId: savedId,
      clientEventIds: clientEventIds,
    );
    return savedId;
  }

  static Future<int?> importFlowFromShare(
    BuildContext context,
    ImportFlowData data,
  ) async {
    int? persistedFlowId;
    final result = await showModalBottomSheet<_FlowStudioResult?>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      barrierColor: Colors.black54,
      builder: (outerCtx) {
        return DraggableScrollableSheet(
          initialChildSize: 0.8,
          minChildSize: 0.4,
          maxChildSize: 1.0,
          snap: true,
          snapSizes: const [0.8, 1.0],
          expand: false,
          builder: (_, _) {
            return ClipRRect(
              borderRadius: const BorderRadius.vertical(
                top: Radius.circular(16),
              ),
              child: Material(
                color: Colors.black,
                child: Navigator(
                  onGenerateInitialRoutes: (nav, _) => [
                    MaterialPageRoute(
                      builder: (ctx) => _FlowStudioPage(
                        existingFlows: const [],
                        importData: data,
                        onRouteResult: (result) async {
                          final state = CalendarPage.globalKey.currentState;
                          if (state != null) {
                            persistedFlowId = await state
                                ._persistFlowStudioResult(result);
                          } else {
                            persistedFlowId =
                                await CalendarPage._persistFlowStudioResultHeadless(
                                  result,
                                );
                          }
                          if (!ctx.mounted) return;
                          final rootNavigator = Navigator.of(
                            ctx,
                            rootNavigator: true,
                          );
                          if (rootNavigator.canPop()) {
                            rootNavigator.pop();
                          }
                        },
                      ),
                    ),
                  ],
                ),
              ),
            );
          },
        );
      },
    );

    if (persistedFlowId != null) {
      return persistedFlowId;
    }
    if (result != null && result.savedFlow != null) {
      final state = CalendarPage.globalKey.currentState;
      if (state != null) {
        return await state._persistFlowStudioResult(result);
      } else {
        return await CalendarPage._persistFlowStudioResultHeadless(result);
      }
    }
    return null;
  }

  static Future<int?> importGeneratedFlowFromAnyContext(
    BuildContext context, {
    required AIFlowGenerationResponse response,
    required DateTime baseStart,
  }) async {
    final data = _importDataFromAiGenerationResponse(response, baseStart);
    if (data == null) return null;
    return importFlowFromShare(context, data);
  }

  static ImportFlowData? _importDataFromAiGenerationResponse(
    AIFlowGenerationResponse response,
    DateTime baseStart,
  ) {
    try {
      final events = buildAiFlowImportEvents(response);
      if (events.isEmpty) return null;

      final now = DateTime.now();
      final share = InboxShareItem(
        shareId: 'ai-local-${now.millisecondsSinceEpoch}',
        kind: InboxShareKind.flow,
        recipientId: '',
        senderId: '',
        payloadId: 'ai-local',
        title: response.flowName ?? 'AI Flow',
        createdAt: now,
        payloadJson: {'events': events},
      );

      final cleaned = (response.flowColor ?? '#4dd0e1').replaceFirst('#', '');
      final rgb = int.tryParse(cleaned, radix: 16) ?? 0x4dd0e1;

      return ImportFlowData(
        share: share,
        name: response.flowName ?? 'AI Flow',
        color: 0xFF000000 | rgb,
        notes: response.notes,
        rules: const [],
        suggestedStartDate: baseStart,
        suggestedEndDate: response.requestedEndDate,
        overview: response.overviewSummary ?? response.overviewTitle ?? '',
        generationId: response.generationId,
        originType: 'ai',
        originFlowId: response.flowId,
        rootFlowId: response.flowId,
        aiMetadata: response.aiMetadata,
      );
    } catch (_) {
      return null;
    }
  }

  @override
  State<CalendarPage> createState() => CalendarPageState();
}

class _FlowStudioRoutePage extends StatefulWidget {
  const _FlowStudioRoutePage({this.routeUri});

  final Uri? routeUri;

  @override
  State<_FlowStudioRoutePage> createState() => _FlowStudioRoutePageState();
}

class _FlowStudioRoutePageState extends State<_FlowStudioRoutePage> {
  final GlobalKey<NavigatorState> _flowStudioNavigatorKey =
      GlobalKey<NavigatorState>();
  late final FlowsRepo _flowsRepo = FlowsRepo(Supabase.instance.client);
  bool _routeCloseRequested = false;

  void _closeRoute() {
    if (!mounted || _routeCloseRequested) return;
    _routeCloseRequested = true;
    RestorationCoordinator.instance.suppressRestoreForUserNavigation(
      reason: 'flow_studio_route_close',
    );
    unawaited(CalendarPage._clearFlowStudioTransientState());
    closeOrReturn(context, '/');
  }

  void _returnToFlowStudioHubRoute() {
    if (!mounted) return;
    final uri = GoRouter.of(context).routerDelegate.currentConfiguration.uri;
    if (uri.path == '/flows' && uri.queryParameters.isNotEmpty) {
      context.go('/flows');
    }
  }

  bool _handleSystemBack() {
    final nestedNavigator = _flowStudioNavigatorKey.currentState;
    if (nestedNavigator != null && nestedNavigator.canPop()) {
      nestedNavigator.pop();
      return true;
    }
    return false;
  }

  @override
  Widget build(BuildContext context) {
    final restorationState = CalendarPage._flowStudioRouteStateFromUri(
      widget.routeUri,
    );
    return UtilitySheetRouteScaffold(
      semanticLabel: 'Flow Studio',
      onClose: _closeRoute,
      onBackPressed: _handleSystemBack,
      showRouteChrome: false,
      heightFactor: 1,
      topRadius: 0,
      child: Navigator(
        key: _flowStudioNavigatorKey,
        onGenerateInitialRoutes: (navigator, initial) =>
            CalendarPage._detachedFlowStudioInitialRoutes(
              parentRoute: '/flows',
              flowsRepo: _flowsRepo,
              restorationState: restorationState,
              onClose: _closeRoute,
              onReturnToHub: _returnToFlowStudioHubRoute,
            ),
      ),
    );
  }
}

class _SharedCalendarsRoutePage extends StatelessWidget {
