  bool _noteBelongsToStandaloneLane(_Note note) {
    return note.isReminder || (note.flowId ?? -1) <= 0;
  }

  bool _hasPaintedStandaloneLane(Map<String, List<_Note>> notesByDay) {
    return notesByDay.values.any(
      (notes) => notes.any(_noteBelongsToStandaloneLane),
    );
  }

  bool _hasPaintedEventSnapshot(Map<String, List<_Note>> notesByDay) {
    return notesByDay.values.any((notes) => notes.isNotEmpty);
  }

  bool _sameStandaloneLaneNote(_Note a, _Note b) {
    final aClientEventId = a.clientEventId?.trim();
    final bClientEventId = b.clientEventId?.trim();
    if (aClientEventId != null &&
        aClientEventId.isNotEmpty &&
        aClientEventId == bClientEventId) {
      return true;
    }

    final aId = a.id?.trim();
    final bId = b.id?.trim();
    if (aId != null && aId.isNotEmpty && aId == bId) {
      return true;
    }

    if (a.isReminder && b.isReminder) {
      final aReminderId = a.reminderId?.trim();
      final bReminderId = b.reminderId?.trim();
      if (aReminderId != null &&
          aReminderId.isNotEmpty &&
          aReminderId == bReminderId &&
          a.allDay == b.allDay &&
          a.start?.hour == b.start?.hour &&
          a.start?.minute == b.start?.minute) {
        return true;
      }
    }

    return _standaloneDedupeKey(a) == _standaloneDedupeKey(b);
  }

  bool _sameStableStandaloneLaneNote(_Note a, _Note b) {
    final aClientEventId = a.clientEventId?.trim();
    final bClientEventId = b.clientEventId?.trim();
    if (aClientEventId != null &&
        aClientEventId.isNotEmpty &&
        bClientEventId != null &&
        bClientEventId.isNotEmpty) {
      return aClientEventId == bClientEventId;
    }

    final aId = a.id?.trim();
    final bId = b.id?.trim();
    if (aId != null && aId.isNotEmpty && bId != null && bId.isNotEmpty) {
      return aId == bId;
    }

    if (a.isReminder && b.isReminder) {
      final aReminderId = a.reminderId?.trim();
      final bReminderId = b.reminderId?.trim();
      return aReminderId != null &&
          aReminderId.isNotEmpty &&
          bReminderId != null &&
          bReminderId.isNotEmpty &&
          aReminderId == bReminderId &&
          a.allDay == b.allDay &&
          a.start?.hour == b.start?.hour &&
          a.start?.minute == b.start?.minute;
    }

    return false;
  }

  int _mergePaintedStandaloneLaneInto(Map<String, List<_Note>> notesByDay) {
    var preserved = 0;
    for (final entry in _notes.entries) {
      final bucket = notesByDay.putIfAbsent(entry.key, () => <_Note>[]);
      for (final note in entry.value) {
        if (!_noteBelongsToStandaloneLane(note)) continue;
        if (notesByDay.values.any(
          (incomingBucket) => incomingBucket.any(
            (incoming) =>
                _noteBelongsToStandaloneLane(incoming) &&
                _sameStableStandaloneLaneNote(incoming, note),
          ),
        )) {
          continue;
        }
        if (bucket.any(
          (incoming) =>
              _noteBelongsToStandaloneLane(incoming) &&
              _sameStandaloneLaneNote(incoming, note),
        )) {
          continue;
        }
        bucket.add(note);
        preserved++;
      }
    }
    return preserved;
  }

  void _rememberPendingOnboardingTargetEvent({
    required String dayKey,
    required int flowId,
    required String clientEventId,
  }) {
    final trimmedClientEventId = clientEventId.trim();
    if (flowId <= 0 || trimmedClientEventId.isEmpty) return;

    final bucket = _notes[dayKey];
    _Note? stagedNote;
    if (bucket != null) {
      for (final note in bucket) {
        if (note.clientEventId?.trim() == trimmedClientEventId) {
          stagedNote = note;
          break;
        }
      }
    }
    if (stagedNote == null) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[onboardingTarget] no staged note found to remember '
          'flow=$flowId cid=${safeLogIdentifier(trimmedClientEventId)} '
          'day=$dayKey',
        );
      }
      return;
    }

    _pendingOnboardingTargetDayKey = dayKey;
    _pendingOnboardingTargetClientEventId = trimmedClientEventId;
    _pendingOnboardingTargetFlowId = flowId;
    _pendingOnboardingTargetNote = _CalendarWarmStateStore._copyNote(stagedNote)
        .copyWith(
          behaviorPayload: <String, dynamic>{
            if (stagedNote.behaviorPayload != null)
              ...stagedNote.behaviorPayload!,
            'onboarding_pending_target': true,
          },
        );
    if (kDebugMode) {
      _calendarDebugPrint(
        '[onboardingTarget] remembered pending first-flow target '
        'flow=$flowId cid=${safeLogIdentifier(trimmedClientEventId)} '
        'day=$dayKey',
      );
    }
  }

  void _clearPendingOnboardingTargetEvent(String reason) {
    if (_pendingOnboardingTargetNote == null &&
        _pendingOnboardingTargetClientEventId == null) {
      return;
    }
    if (kDebugMode) {
      _calendarDebugPrint(
        '[onboardingTarget] cleared pending first-flow target reason=$reason '
        'flow=$_pendingOnboardingTargetFlowId '
        'cid=${safeLogIdentifier(_pendingOnboardingTargetClientEventId)}',
      );
    }
    _pendingOnboardingTargetDayKey = null;
    _pendingOnboardingTargetClientEventId = null;
    _pendingOnboardingTargetFlowId = null;
    _pendingOnboardingTargetNote = null;
  }

  bool _noteMatchesPendingOnboardingTarget(_Note note) {
    final pendingClientEventId = _pendingOnboardingTargetClientEventId?.trim();
    final noteClientEventId = note.clientEventId?.trim();
    if (pendingClientEventId != null &&
        pendingClientEventId.isNotEmpty &&
        noteClientEventId != null &&
        noteClientEventId.isNotEmpty &&
        pendingClientEventId == noteClientEventId) {
      return true;
    }

    final pendingNote = _pendingOnboardingTargetNote;
    final pendingFlowId = _pendingOnboardingTargetFlowId;
    if (pendingNote == null || pendingFlowId == null || pendingFlowId <= 0) {
      return false;
    }
    return note.flowId == pendingFlowId &&
        note.title == pendingNote.title &&
        note.allDay == pendingNote.allDay &&
        note.start?.hour == pendingNote.start?.hour &&
        note.start?.minute == pendingNote.start?.minute &&
        note.end?.hour == pendingNote.end?.hour &&
        note.end?.minute == pendingNote.end?.minute;
  }

  bool _noteIsPendingOnboardingTargetCopy(_Note note) {
    return note.behaviorPayload?['onboarding_pending_target'] == true &&
        _noteMatchesPendingOnboardingTarget(note);
  }

  int _mergePendingOnboardingTargetInto(
    Map<String, List<_Note>> notesByDay, {
    required String source,
    required String phase,
  }) {
    final pendingDayKey = _pendingOnboardingTargetDayKey;
    final pendingNote = _pendingOnboardingTargetNote;
    if (pendingDayKey == null || pendingDayKey.isEmpty || pendingNote == null) {
      return 0;
    }

    final reconciliation = reconcilePendingOnboardingTarget<_Note>(
      refreshedItems: notesByDay.values.expand((bucket) => bucket),
      matchesTarget: _noteMatchesPendingOnboardingTarget,
      isPendingCopy: _noteIsPendingOnboardingTargetCopy,
    );

    for (final entry in notesByDay.entries) {
      entry.value.removeWhere(_noteIsPendingOnboardingTargetCopy);
    }
    notesByDay.removeWhere((_, bucket) => bucket.isEmpty);

    if (reconciliation.authoritativeTargetFound) {
      _clearPendingOnboardingTargetEvent(
        'authoritative_refresh:$source:$phase',
      );
      return 0;
    }
    if (!reconciliation.shouldPreservePending) return 0;

    final bucket = notesByDay.putIfAbsent(pendingDayKey, () => <_Note>[]);
    if (bucket.any(_noteMatchesPendingOnboardingTarget)) {
      return 0;
    }
    bucket.add(_CalendarWarmStateStore._copyNote(pendingNote));
    if (kDebugMode) {
      _calendarDebugPrint(
        '[onboardingTarget] preserved pending first-flow target during '
        'refresh source=$source phase=$phase '
        'flow=$_pendingOnboardingTargetFlowId '
        'cid=${safeLogIdentifier(_pendingOnboardingTargetClientEventId)}',
      );
    }
    return 1;
  }

  TimeOfDay? _timeOfDayFromMinutes(dynamic raw) {
    final totalMinutes = (raw as num?)?.toInt();
    if (totalMinutes == null || totalMinutes < 0) return null;
    return TimeOfDay(
      hour: (totalMinutes ~/ 60) % 24,
      minute: totalMinutes % 60,
    );
  }

  int? _timeOfDayToMinutes(TimeOfDay? time) {
    if (time == null) return null;
    return time.hour * 60 + time.minute;
  }

  DateTime? _parseWarmStartDateTime(Object? raw) {
    final value = raw?.toString().trim();
    if (value == null || value.isEmpty) return null;
    return DateTime.tryParse(value);
  }

  DateTime? _warmStartDateFromKey(String key) {
    final parts = key.split('-');
    if (parts.length != 3) return null;
    final ky = int.tryParse(parts[0]);
    final km = int.tryParse(parts[1]);
    final kd = int.tryParse(parts[2]);
    if (ky == null || km == null || kd == null) return null;
    try {
      return DateUtils.dateOnly(KemeticMath.toGregorian(ky, km, kd));
    } catch (_) {
      return null;
    }
  }

  Map<int, int> _decodeWarmStartIntMap(Object? raw) {
    if (raw is! Map) return const <int, int>{};
    final result = <int, int>{};
    raw.forEach((key, value) {
      final id = int.tryParse(key.toString());
      final count = (value as num?)?.toInt();
      if (id == null || count == null) return;
      result[id] = count;
    });
    return result;
  }

  Map<String, dynamic> _encodeWarmStartIntMap(Map<int, int> values) {
    return <String, dynamic>{
      for (final entry in values.entries) entry.key.toString(): entry.value,
    };
  }

  Map<String, dynamic> _serializeWarmStartFlow(_Flow flow) {
    return <String, dynamic>{
      'id': flow.id,
      'calendarId': flow.calendarId,
      'name': flow.name,
      'color': flow.color.toARGB32(),
      'active': flow.active,
      'isSaved': flow.isSaved,
      'savedAt': flow.savedAt?.toIso8601String(),
      'start': flow.start?.toIso8601String(),
      'end': flow.end?.toIso8601String(),
      'rules': flow.rules.map(ruleToJson).toList(growable: false),
      'notes': flow.notes,
      'shareId': flow.shareId,
      'isHidden': flow.isHidden,
      'isReminder': flow.isReminder,
      'reminderUuid': flow.reminderUuid,
    };
  }

  _Flow? _deserializeWarmStartFlow(Object? raw) {
    if (raw is! Map) return null;
    try {
      final json = Map<String, dynamic>.from(raw);
      final id = (json['id'] as num?)?.toInt();
      final name = json['name'] as String?;
      final colorValue = (json['color'] as num?)?.toInt();
      if (id == null || name == null || colorValue == null) return null;
      final rulesRaw = (json['rules'] as List?) ?? const [];
      final rules = <FlowRule>[];
      for (final item in rulesRaw.whereType<Map>()) {
        try {
          rules.add(CalendarPage.ruleFromJson(Map<String, dynamic>.from(item)));
        } catch (_) {
          // Skip malformed cached rules instead of dropping the entire flow.
        }
      }
      return _Flow(
        id: id,
        calendarId: json['calendarId'] as String?,
        name: name,
        color: Color(colorValue),
        active: (json['active'] as bool?) ?? true,
        isSaved: (json['isSaved'] as bool?) ?? false,
        savedAt: _parseWarmStartDateTime(json['savedAt'])?.toUtc(),
        rules: rules,
        start: _parseWarmStartDateTime(json['start'])?.toLocal(),
        end: _parseWarmStartDateTime(json['end'])?.toLocal(),
        notes: json['notes'] as String?,
        shareId: json['shareId'] as String?,
        isHidden: (json['isHidden'] as bool?) ?? false,
        isReminder: (json['isReminder'] as bool?) ?? false,
        reminderUuid: json['reminderUuid'] as String?,
      );
    } catch (_) {
      return null;
    }
  }

  Map<String, dynamic> _serializeWarmStartNote(_Note note) {
    return <String, dynamic>{
      'id': note.id,
      'clientEventId': note.clientEventId,
      'calendarId': note.calendarId,
      'calendarName': note.calendarName,
      'title': note.title,
      'detail': note.detail,
      'location': note.location,
      'allDay': note.allDay,
      'startMinutes': _timeOfDayToMinutes(note.start),
      'endMinutes': _timeOfDayToMinutes(note.end),
      'flowId': note.flowId,
      'manualColor': note.manualColor?.toARGB32(),
      'resolvedColor': _noteColor(note).toARGB32(),
      'category': note.category,
      'isReminder': note.isReminder,
      'reminderId': note.reminderId,
      'alertOffsetMinutes': note.alertOffsetMinutes,
      'actionId': note.actionId,
      'behaviorPayload': note.behaviorPayload,
    };
  }

  _Note? _deserializeWarmStartNote(Object? raw) {
    if (raw is! Map) return null;
    try {
      final json = Map<String, dynamic>.from(raw);
      final title = json['title'] as String?;
      final allDay = json['allDay'] as bool?;
      if (title == null || allDay == null) return null;
      final flowId = (json['flowId'] as num?)?.toInt();
      final explicitColorValue = (json['manualColor'] as num?)?.toInt();
      final resolvedColorValue = (json['resolvedColor'] as num?)?.toInt();
      final warmStartColorValue =
          explicitColorValue ??
          ((flowId != null && flowId != -1) ? resolvedColorValue : null);
      return _Note(
        id: json['id'] as String?,
        clientEventId: json['clientEventId'] as String?,
        calendarId: json['calendarId'] as String?,
        calendarName: json['calendarName'] as String?,
        title: title,
        detail: json['detail'] as String?,
        location: json['location'] as String?,
        allDay: allDay,
        start: _timeOfDayFromMinutes(json['startMinutes']),
        end: _timeOfDayFromMinutes(json['endMinutes']),
        flowId: flowId,
        manualColor: warmStartColorValue == null
            ? null
            : Color(warmStartColorValue),
        category: json['category'] as String?,
        isReminder: (json['isReminder'] as bool?) ?? false,
        reminderId: json['reminderId'] as String?,
        alertOffsetMinutes: (json['alertOffsetMinutes'] as num?)?.toInt(),
        actionId: json['actionId'] as String?,
        behaviorPayload: json['behaviorPayload'] is Map
            ? Map<String, dynamic>.from(json['behaviorPayload'] as Map)
            : null,
      );
    } catch (_) {
      return null;
    }
  }

  Map<String, dynamic> _buildWarmStartSnapshot({
    required String userId,
    required String projectRef,
    required bool trimmed,
  }) {
    final centerDay =
        (_lastViewKy != null && _lastViewKm != null && _lastViewKd != null)
        ? DateUtils.dateOnly(
            KemeticMath.toGregorian(_lastViewKy!, _lastViewKm!, _lastViewKd!),
          )
        : DateUtils.dateOnly(DateTime.now());
    final trimmedStart = centerDay.subtract(_warmStartTrimPast);
    final trimmedEnd = centerDay.add(_warmStartTrimFuture);

    final notesJson = <String, dynamic>{};
    _notes.forEach((key, notes) {
      final day = _warmStartDateFromKey(key);
      if (trimmed &&
          day != null &&
          (day.isBefore(trimmedStart) || day.isAfter(trimmedEnd))) {
        return;
      }
      notesJson[key] = notes
          .map(_serializeWarmStartNote)
          .toList(growable: false);
    });

    return <String, dynamic>{
      'schemaVersion': _kWarmStartCacheSchemaVersion,
      'projectRef': projectRef,
      'userId': userId,
      'savedAt': DateTime.now().toUtc().toIso8601String(),
      'loadCompleted': true,
      'nextFlowId': _nextFlowId,
      'flows': _flows.map(_serializeWarmStartFlow).toList(growable: false),
      'notes': notesJson,
      'flowTotalEventCounts': _encodeWarmStartIntMap(_flowTotalEventCounts),
      'flowRemainingEventCounts': _encodeWarmStartIntMap(
        _flowRemainingEventCounts,
      ),
    };
  }

  void _scheduleWarmStartCacheSave() {
    final userId = _activeWarmStartUserId();
    if (userId == null) return;
    _warmStartCacheDebounceTimer?.cancel();
    _warmStartCacheDebounceTimer = Timer(_warmStartCacheDebounce, () {
      _warmStartCacheDebounceTimer = null;
      unawaited(_persistWarmStartCacheNow(userId: userId));
    });
  }

  Future<void> _flushPendingWarmStartCacheSave({
    String reason = 'manual',
  }) async {
    final timer = _warmStartCacheDebounceTimer;
    if (timer == null) return;
    _warmStartCacheDebounceTimer = null;
    if (timer.isActive) {
      timer.cancel();
    }
    await _persistWarmStartCacheNow(debugReason: reason);
  }

  Future<void> _persistWarmStartCacheNow({
    String? userId,
    String debugReason = 'debounced',
  }) async {
    final resolvedUserId = userId ?? _activeWarmStartUserId();
    if (resolvedUserId == null) return;
    final projectRef = _activeWarmStartProjectRef();
    if (projectRef == null) return;
    final prefs = await SharedPreferences.getInstance();
    final key = _warmStartCacheKey(resolvedUserId);
    if (key == null) return;

    if (!_hasUsableCalendarSnapshotForPaint()) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[warmStart] skip non-authoritative cache save '
          'reason=$debugReason',
        );
      }
      return;
    }

    var encoded = jsonEncode(
      _buildWarmStartSnapshot(
        userId: resolvedUserId,
        projectRef: projectRef,
        trimmed: false,
      ),
    );
    if (encoded.length > _warmStartCacheMaxChars) {
      encoded = jsonEncode(
        _buildWarmStartSnapshot(
          userId: resolvedUserId,
          projectRef: projectRef,
          trimmed: true,
        ),
      );
      if (encoded.length > _warmStartCacheMaxChars) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[warmStart] skip cache save reason=$debugReason size=${encoded.length}',
          );
        }
        return;
      }
    }

    await prefs.setString(key, encoded);
    if (kDebugMode) {
      _calendarDebugPrint(
        '[warmStart] saved cache reason=$debugReason size=${encoded.length}',
      );
    }
  }

  Future<void> _restoreWarmStartCacheIfAvailable({
    String reason = 'startup',
  }) async {
    final userId = _activeWarmStartUserId();
    if (userId == null) return;
    final projectRef = _activeWarmStartProjectRef();
    if (projectRef == null) return;
    if (_warmStartCacheRestoredForUserId == userId &&
        _warmStartCacheRestoredForProjectRef == projectRef) {
      return;
    }

    try {
      await _loadEndedReminderIds();
      final prefs = await SharedPreferences.getInstance();
      final key = _warmStartCacheKey(userId);
      if (key == null) return;
      final raw = prefs.getString(key);
      if (raw == null || raw.trim().isEmpty) {
        _warmStartCacheRestoredForUserId = userId;
        _warmStartCacheRestoredForProjectRef = projectRef;
        return;
      }

      final decoded = jsonDecode(raw);
      if (decoded is! Map) {
        _warmStartCacheRestoredForUserId = userId;
        _warmStartCacheRestoredForProjectRef = projectRef;
        return;
      }
      final json = Map<String, dynamic>.from(decoded);
      if ((json['schemaVersion'] as num?)?.toInt() !=
          _kWarmStartCacheSchemaVersion) {
        _warmStartCacheRestoredForUserId = userId;
        _warmStartCacheRestoredForProjectRef = projectRef;
        return;
      }
      if (json['loadCompleted'] != true) {
        _warmStartCacheRestoredForUserId = userId;
        _warmStartCacheRestoredForProjectRef = projectRef;
        return;
      }
      final snapshotUserId = (json['userId'] as String?)?.trim();
      if (snapshotUserId == null ||
          snapshotUserId.isEmpty ||
          snapshotUserId != userId) {
        _warmStartCacheRestoredForUserId = userId;
        _warmStartCacheRestoredForProjectRef = projectRef;
        return;
      }
      final snapshotProjectRef = (json['projectRef'] as String?)?.trim();
      if (snapshotProjectRef == null || snapshotProjectRef != projectRef) {
        _warmStartCacheRestoredForUserId = userId;
        _warmStartCacheRestoredForProjectRef = projectRef;
        return;
      }

      final flows = ((json['flows'] as List?) ?? const [])
          .map(_deserializeWarmStartFlow)
          .whereType<_Flow>()
          .toList(growable: false);
      final restoredTrackSkyFlowIds = flows
          .where((flow) => _isTrackSkyFlowName(flow.name))
          .map((flow) => flow.id)
          .where((flowId) => flowId > 0)
          .toSet();
      final notesByDay = <String, List<_Note>>{};
      final notesRaw = json['notes'];
      if (notesRaw is Map) {
        notesRaw.forEach((key, value) {
          if (value is! List) return;
          final notes = _dedupeVisibleDayNotes(
            value
                .map(_deserializeWarmStartNote)
                .whereType<_Note>()
                .toList(growable: false),
            trackSkyFlowIds: restoredTrackSkyFlowIds,
          );
          if (notes.isNotEmpty) {
            notesByDay[key.toString()] = notes;
          }
        });
      }

      final nextFlowId =
          (json['nextFlowId'] as num?)?.toInt() ??
          ((flows.isEmpty
                  ? 0
                  : flows
                        .map((flow) => flow.id)
                        .reduce((a, b) => a > b ? a : b)) +
              1);
      final totalCounts = _decodeWarmStartIntMap(json['flowTotalEventCounts']);
      final remainingCounts = _decodeWarmStartIntMap(
        json['flowRemainingEventCounts'],
      );

      if (!mounted) return;
      setState(() {
        _flows
          ..clear()
          ..addAll(flows);
        _notes
          ..clear()
          ..addAll(notesByDay);
        _flowTotalEventCounts
          ..clear()
          ..addAll(totalCounts);
        _flowRemainingEventCounts
          ..clear()
          ..addAll(remainingCounts);
        _nextFlowId = nextFlowId > 0 ? nextFlowId : _nextFlowId;
      });
      _rebuildReminderRulesFromFlowsIfMissing();
      _warmStartCacheRestoredForUserId = userId;
      _warmStartCacheRestoredForProjectRef = projectRef;
      _warmStartSnapshotVisible = true;
      _lastSuccessfulHydrationAt ??= DateTime.now();
      if (kDebugMode) {
        final totalNotes = notesByDay.values.fold<int>(
          0,
          (sum, list) => sum + list.length,
        );
        _calendarDebugPrint(
          '[warmStart] restored cache reason=$reason flows=${flows.length} notes=$totalNotes',
        );
      }
      _notifyDayViewDataChanged(persistWarmStartCache: false);
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[warmStart] restore failed reason=$reason error=$e',
        );
      }
    }
  }

  void _restoreWarmStartCacheForFirstPaint({required String reason}) {
    final flight = _warmStartRestoreFlight ??=
        _restoreWarmStartCacheIfAvailable(reason: reason).whenComplete(() {
          _warmStartRestoreFlight = null;
        });
    unawaited(flight);
  }

  Future<void> _loadCalendarState() async {
    final snapshot = await _sharedCalendarsRepo.loadSnapshot();
    if (!mounted) return;
    setState(() {
      _calendarSummariesById = <String, SharedCalendarSummary>{
        for (final calendar in snapshot.calendars) calendar.id: calendar,
      };
      _hiddenCalendarIds = Set<String>.from(snapshot.hiddenCalendarIds);
      _personalCalendarId = snapshot.personalCalendarId;
      _calendarStateLoaded = true;
    });
    _publishWarmStateSnapshot();
  }

  void _rememberSharedCalendarSnapshot(
    SharedCalendarSummary calendar, {
    bool publishWarmState = true,
  }) {
    final calendarId = _normalizeCalendarId(calendar.id);
    if (calendarId == null) return;
    _calendarSummariesById[calendarId] = calendar;
    if (publishWarmState) {
      _publishWarmStateSnapshot();
    }
  }

  void _seedSharedCalendarFlows(
    Iterable<_Flow> flows, {
    bool publishWarmState = false,
  }) {
    var changed = false;
    for (final flow in flows) {
      if (flow.id <= 0) continue;
      final existingIndex = _flows.indexWhere((existing) {
        return existing.id == flow.id;
      });
      final nextFlow = _CalendarWarmStateStore._copyFlow(flow);
      if (existingIndex >= 0) {
        _flows[existingIndex] = nextFlow;
      } else {
        _flows.add(nextFlow);
      }
      if (flow.id >= _nextFlowId) {
        _nextFlowId = flow.id + 1;
      }
      changed = true;
    }
    if (changed) {
      _rebuildReminderRulesFromFlowsIfMissing();
      _bumpDataVersion();
      if (publishWarmState) {
        _publishWarmStateSnapshot();
      }
    }
  }

  _Note _noteFromSharedCalendarEventSnapshot(
    _SharedCalendarEventDetailSnapshot snapshot,
  ) {
    return _Note(
      id: snapshot.eventId,
      clientEventId: snapshot.clientEventId,
      calendarId: snapshot.calendarId,
      calendarName: snapshot.calendarName,
      title: snapshot.title,
      detail: snapshot.detail,
      location: snapshot.location,
      allDay: snapshot.allDay,
      start: snapshot.allDay
          ? null
          : TimeOfDay.fromDateTime(snapshot.startsAtLocal),
      end: snapshot.allDay || snapshot.endsAtLocal == null
          ? null
          : TimeOfDay.fromDateTime(snapshot.endsAtLocal!),
      flowId: snapshot.flowId ?? -1,
      manualColor: snapshot.calendarColor,
      category: snapshot.category,
      isReminder: snapshot.isReminder,
      reminderId: snapshot.reminderId,
      alertOffsetMinutes: snapshot.alertOffsetMinutes,
      actionId: snapshot.actionId,
      behaviorPayload: snapshot.behaviorPayload,
    );
  }

  _Note _noteFromSharedCalendarFiledEvent({
    required SharedCalendarSummary calendar,
    required FiledEvent filedEvent,
  }) {
    return _noteFromSharedCalendarEventSnapshot(
      CalendarPage._sharedCalendarEventDetailSnapshotForFiledEvent(
        calendar: calendar,
        filedEvent: filedEvent,
      ),
    );
  }

  bool _noteMatchesFiledEventIdentity(_Note note, FiledEvent filedEvent) {
    final clientEventId = filedEvent.event.clientEventId?.trim();
    if (clientEventId != null &&
        clientEventId.isNotEmpty &&
        note.clientEventId?.trim() == clientEventId) {
      return true;
    }
    final eventId = filedEvent.event.id.trim();
    return eventId.isNotEmpty && note.id?.trim() == eventId;
  }

  void _seedSameDaySharedCalendarFiledEvents({
    required SharedCalendarSummary calendar,
    required List<FiledEvent> filedEvents,
    required int kYear,
    required int kMonth,
    required int kDay,
  }) {
    if (filedEvents.isEmpty) return;
    final key = _kKey(kYear, kMonth, kDay);
    final bucket = _notes.putIfAbsent(key, () => <_Note>[]);
    for (final filedEvent in filedEvents) {
      final note = _noteFromSharedCalendarFiledEvent(
        calendar: calendar,
        filedEvent: filedEvent,
      );
      final incomingBaseKey = _visibleDayNoteBaseKey(note);
      final incomingStandaloneKey = _standaloneDedupeKey(note);
      bucket.removeWhere((existing) {
        if (_noteMatchesFiledEventIdentity(existing, filedEvent)) {
          return true;
        }
        if (_visibleDayNoteBaseKey(existing) == incomingBaseKey) {
          return true;
        }
        if ((existing.flowId ?? -1) <= 0 &&
            (note.flowId ?? -1) <= 0 &&
            _standaloneDedupeKey(existing) == incomingStandaloneKey) {
          return true;
        }
        return false;
      });
      bucket.add(note);
    }
    final trackSkyFlowIds = _flows
        .where((flow) => _isTrackSkyFlowName(flow.name))
        .map((flow) => flow.id)
        .where((flowId) => flowId > 0)
        .toSet();
    final deduped = _dedupeVisibleDayNotes(
      bucket,
      trackSkyFlowIds: trackSkyFlowIds,
    );
    _notes[key] = List<_Note>.from(deduped);

    if (kDebugMode) {
      _calendarDebugPrint(
        '[SharedCalendarEventTap] seeded same-day filed events '
        'calendarId=${calendar.id} day=$key filed=${filedEvents.length} '
        'notes=${_notes[key]?.length ?? 0}',
      );
    }
  }

  bool _noteMatchesEventDetailRestorationState(
    _Note note,
    EventDetailRestorationState state,
  ) {
    switch (state.identityType) {
      case eventDetailIdentityClientEventId:
        return note.clientEventId?.trim() == state.identityValue;
      case eventDetailIdentityEventId:
        return note.id?.trim() == state.identityValue;
      case eventDetailIdentityReminderId:
        return note.reminderId?.trim() == state.identityValue;
    }
    return false;
  }

  void _seedOneShotSharedCalendarEventSnapshot({
    required int kYear,
    required int kMonth,
    required int kDay,
    required _SharedCalendarEventDetailSnapshot snapshot,
    required EventDetailRestorationState detail,
  }) {
    final note = _noteFromSharedCalendarEventSnapshot(snapshot);
    final key = _kKey(kYear, kMonth, kDay);
    final bucket = _notes.putIfAbsent(key, () => <_Note>[]);
    if (bucket.any(
      (existing) => _noteMatchesEventDetailRestorationState(existing, detail),
    )) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[SharedCalendarEventTap] using cached real detail note '
          '${snapshot.debugIdentity} day=$key notes=${bucket.length}',
        );
      }
      return;
    }
    final incomingBaseKey = _visibleDayNoteBaseKey(note);
    final incomingStandaloneKey = _standaloneDedupeKey(note);
    bucket.removeWhere((existing) {
      if (_noteMatchesEventDetailRestorationState(existing, detail)) {
        return true;
      }
      if (_visibleDayNoteBaseKey(existing) == incomingBaseKey) {
        return true;
      }
      if ((existing.flowId ?? -1) <= 0 &&
          (note.flowId ?? -1) <= 0 &&
          _standaloneDedupeKey(existing) == incomingStandaloneKey) {
        return true;
      }
      return false;
    });
    bucket.add(note);

    if (kDebugMode) {
      _calendarDebugPrint(
        '[SharedCalendarEventTap] seeded one-shot detail snapshot '
        '${snapshot.debugIdentity} day=$key notes=${bucket.length}',
      );
    }
  }

  bool _consumePendingSharedCalendarRealDayViewIntentIfAny() {
    final intent = CalendarPage._pendingSharedCalendarRealDayViewIntent;
    if (intent == null) return false;
    CalendarPage._pendingSharedCalendarRealDayViewIntent = null;
    _sharedCalendarRealDayViewOpening = true;
    _pendingPersistentDayViewState = null;
    _persistentDayViewRestoreAttempted = true;
    _calendarOverlayRestoreAttempted = true;
    _calendarOverlayRestoreInFlight = false;
    _calendarOverlayRestorePresentationStarted = false;

    _rememberSharedCalendarSnapshot(intent.calendar, publishWarmState: false);
    _flows
      ..clear()
      ..addAll(intent.warmStartFlows);
    _seedSharedCalendarFlows(intent.sharedCalendarFlows);
    _notes
      ..clear()
      ..addEntries(
        intent.warmStartNotes.entries.map(
          (entry) => MapEntry(entry.key, List<_Note>.from(entry.value)),
        ),
      );
    _calendarSummariesById
      ..clear()
      ..addAll(intent.warmCalendarSummariesById);
    _hiddenCalendarIds = Set<String>.from(intent.warmHiddenCalendarIds);
    _personalCalendarId = intent.warmPersonalCalendarId;
    _calendarStateLoaded = intent.warmCalendarSummariesById.isNotEmpty;
    if (_flows.isNotEmpty) {
      final maxFlowId = _flows
          .map((flow) => flow.id)
          .reduce((a, b) => a > b ? a : b);
      _nextFlowId = math.max(_nextFlowId, maxFlowId + 1);
    }
    _seedSameDaySharedCalendarFiledEvents(
      calendar: intent.calendar,
      filedEvents: intent.sameCalendarEvents,
      kYear: intent.kYear,
      kMonth: intent.kMonth,
      kDay: intent.kDay,
    );
    _seedOneShotSharedCalendarEventSnapshot(
      kYear: intent.kYear,
      kMonth: intent.kMonth,
      kDay: intent.kDay,
      snapshot: intent.snapshot,
      detail: intent.detail,
    );
    _rebuildReminderRulesFromFlowsIfMissing();
    _warmStartCacheRestoredForUserId = _activeWarmStartUserId();
    _warmStartSnapshotVisible =
        intent.warmStartFlows.isNotEmpty || intent.warmStartNotes.isNotEmpty;
    _lastSuccessfulHydrationAt ??= DateTime.now();
    _dataVersion++;
    _notifyDayViewDataChanged();

    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      _openDayView(
        context,
        intent.kYear,
        intent.kMonth,
        intent.kDay,
        initialFirstVisibleMinute:
            CalendarPage._firstVisibleMinuteFromSharedCalendarSnapshot(
              intent.snapshot,
            ),
        initialEventDetailRestorationState: intent.detail,
        debugOpenSource: 'shared_calendar_event_tap',
      );
      _sharedCalendarRealDayViewOpening = false;
      unawaited(_loadCalendarState());
      unawaited(
        _requestInitialStartupRun(
          reason: 'shared_calendar_event_tap_background',
        ),
      );
    });

    if (kDebugMode) {
      final key = _kKey(intent.kYear, intent.kMonth, intent.kDay);
      _calendarDebugPrint(
        '[SharedCalendarEventTap] CalendarPage init consumed real day '
        'intent ${intent.snapshot.debugIdentity} '
        'warmFlows=${intent.warmStartFlows.length} '
        'warmDayNotes=${intent.warmStartNotes[key]?.length ?? 0}',
      );
    }
    return true;
  }

  Future<void> _requestInitialStartupRun({required String reason}) async {
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) {
      _pendingInitialHydration = true;
      return;
    }
    final userId = user.id;
    if (_initialStartupUserId == userId) {
      if (_startupFlight != null && !(_startupFlight!.isCompleted)) {
        await _startupFlight!.future;
      }
      return;
    }
    _initialStartupUserId = userId;
    await _requestStartupRun(reason: reason);
  }

  void _scheduleInitialStartupRunAfterFirstFrame({
    required String reason,
    Future<void> Function()? onComplete,
  }) {
    unawaited(() async {
      await _waitForFirstRasterizedFrameForDeferredStartup();
      void runStartup() {
        if (!mounted) return;
        unawaited(
          _requestInitialStartupRun(reason: reason).then((_) async {
            if (!mounted) return;
            await onComplete?.call();
          }),
        );
      }

      if (_isWidgetTestBindingForDeferredStartup()) {
        runStartup();
      } else {
        Timer.run(runStartup);
      }
    }());
  }

  void _scheduleAfterFirstDrawableFrame(Future<void> Function() action) {
    unawaited(() async {
      await _waitForFirstRasterizedFrameForDeferredStartup();
      void runAction() {
        if (!mounted) return;
        unawaited(
          action().catchError((Object error, StackTrace stackTrace) {
            if (!kDebugMode) return;
            _calendarDebugPrint('[startup] post-frame task failed: $error');
            _calendarDebugPrint('$stackTrace');
          }),
        );
      }

      if (_isWidgetTestBindingForDeferredStartup()) {
        runAction();
      } else {
        Timer.run(runAction);
      }
    }());
  }

  bool _isWidgetTestBindingForDeferredStartup() {
    return WidgetsBinding.instance.runtimeType.toString().contains('Test');
  }

  Future<void> _waitForFirstRasterizedFrameForDeferredStartup() async {
    final binding = WidgetsBinding.instance;
    final isTestBinding = _isWidgetTestBindingForDeferredStartup();
    if (!binding.firstFrameRasterized) {
      final timeout = isTestBinding
          ? const Duration(milliseconds: 1)
          : const Duration(seconds: 4);
      try {
        await binding.waitUntilFirstFrameRasterized.timeout(timeout);
      } catch (_) {
        // Widget tests do not always complete the rasterized-frame future.
      }
    }

    if (isTestBinding) return;

    try {
      await binding.endOfFrame.timeout(const Duration(milliseconds: 500));
    } catch (_) {
      // Best effort: deferred startup work should never crash the route.
    }
    try {
      await SchedulerBinding.instance
          .scheduleTask<void>(
            () {},
            Priority.idle,
            debugLabel: 'calendar deferred startup idle gate',
          )
          .timeout(const Duration(milliseconds: 250));
    } catch (_) {
      // Best effort: deferred startup work should never crash the route.
    }
  }

  void _restoreMyFlowsFilingSnapshotCacheAfterFirstFrame({
    required String reason,
  }) {
    _scheduleAfterFirstDrawableFrame(() {
      return _restoreMyFlowsFilingSnapshotCache(reason: reason);
    });
  }

  List<String> _stringListFromRestoration(Object? raw) {
    if (raw is! Iterable) return const <String>[];
    return raw
        .map((value) => value.toString().trim())
        .where((value) => value.isNotEmpty)
        .toList(growable: false);
  }

  Map<String, dynamic> _calendarOverlayParentMetadata() {
    final dayViewState = _activeDayViewRestorationState;
    if (dayViewState != null && dayViewState.isOpen) {
      return <String, dynamic>{
        'parentSurface': _kCalendarParentSurfaceDayView,
        'dayView': dayViewState.toJson(),
      };
    }
    return const <String, dynamic>{
      'parentSurface': _kCalendarParentSurfaceRoot,
    };
  }

  Future<void> _saveCalendarOverlayState(
    String kind,
    Map<String, dynamic> state,
  ) async {
    final normalizedKind = kind.trim();
    if (normalizedKind.isEmpty) return;
    if (normalizedKind == _kCalendarOverlayKindFlowStudio &&
        CalendarPage._isTransientFlowStudioEditorState(state)) {
      return;
    }
    try {
      await AppRestorationService.instance.saveOverlayStack(
        <Map<String, dynamic>>[
          <String, dynamic>{
            'kind': normalizedKind,
            'parentRoute': '/',
            ..._calendarOverlayParentMetadata(),
            'updatedAtMs': DateTime.now().millisecondsSinceEpoch,
            ...state,
          },
        ],
      );
      unawaited(RestorationCoordinator.instance.flush());
    } catch (error) {
      NavigationTrace.instance.record(
        'calendar overlay state save skipped',
        state: <String, Object?>{
          'kind': normalizedKind,
          'error': error.runtimeType,
        },
      );
    }
  }

  Future<void> _clearCalendarOverlayState(String kind) async {
    if (!mounted) {
      return;
    }
    final stack = await AppRestorationService.instance.readOverlayStack();
    final next = stack
        .where((entry) => entry['kind'] != kind)
        .toList(growable: false);
    await AppRestorationService.instance.saveOverlayStack(
      next,
      reason: OverlayStackMutationReason.userDismissed,
    );
  }

  bool _sameEventDetailRestorationState(
    EventDetailRestorationState? a,
    EventDetailRestorationState b,
  ) {
    return a != null &&
        a.kYear == b.kYear &&
        a.kMonth == b.kMonth &&
        a.kDay == b.kDay &&
        a.identityType == b.identityType &&
        a.identityValue == b.identityValue;
  }

  Future<void> _enqueueCalendarEventDetailOverlayWrite(
    Future<void> Function() write,
  ) {
    final next = _calendarEventDetailOverlayWriteQueue
        .catchError((Object error, StackTrace stackTrace) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[eventDetailOverlay] prior write failed: $error',
            );
            _calendarDebugPrint('$stackTrace');
          }
        })
        .then((_) => write());
    _calendarEventDetailOverlayWriteQueue = next.catchError((
      Object error,
      StackTrace stackTrace,
    ) {
      if (kDebugMode) {
        _calendarDebugPrint('[eventDetailOverlay] write failed: $error');
        _calendarDebugPrint('$stackTrace');
      }
    });
    return next;
  }

  Future<void> _saveCalendarEventDetailOverlayState(
    EventDetailRestorationState state,
  ) {
    final revision = ++_calendarEventDetailOverlayRevision;
    _activeCalendarEventDetailRestoration = state;
    final payload = state
        .copyWith(
          parentSurface: _kCalendarParentSurfaceRoot,
          clearUpdatedAtMs: true,
        )
        .toJson();
    return _enqueueCalendarEventDetailOverlayWrite(() async {
      if (revision != _calendarEventDetailOverlayRevision ||
          !_sameEventDetailRestorationState(
            _activeCalendarEventDetailRestoration,
            state,
          )) {
        return;
      }
      await _saveCalendarOverlayState(
        _kCalendarOverlayKindEventDetail,
        payload,
      );
    });
  }

  Future<void> _saveCalendarEventDetailOverlayForTarget(
    DayViewSheetEventTarget target,
  ) async {
    final state = eventDetailRestorationStateForTarget(
      target,
      parentSurface: _kCalendarParentSurfaceRoot,
    );
    if (state == null) {
      await _clearCalendarEventDetailOverlayState();
      return;
    }
    await _saveCalendarEventDetailOverlayState(state);
  }

  Future<void> _clearCalendarEventDetailOverlayState() {
    if (_preserveEventDetailOverlayForOrientationHandoff) {
      return Future<void>.value();
    }
    final revision = ++_calendarEventDetailOverlayRevision;
    _activeCalendarEventDetailRestoration = null;
    return _enqueueCalendarEventDetailOverlayWrite(() async {
      if (revision != _calendarEventDetailOverlayRevision ||
          _activeCalendarEventDetailRestoration != null) {
        return;
      }
      await _clearCalendarOverlayState(_kCalendarOverlayKindEventDetail);
    });
  }

  DayViewSheetEventTarget? _calendarEventDetailTargetFromState(
    EventDetailRestorationState state,
  ) {
    return eventDetailTargetFromRestorationState(
      state: state,
      events: _calendarSheetEventsForDay(state.kYear, state.kMonth, state.kDay),
    );
  }

  Future<void> _openCalendarEventDetailSheet(
    DayViewSheetEventTarget initialTarget,
  ) async {
    if (!mounted) return;
    if (!CalendarEventDetailSheetCoordinator.tryMarkOpenOrOpening()) {
      return;
    }

    try {
      await _saveCalendarEventDetailOverlayForTarget(initialTarget);
      if (!mounted) return;

      await showModalBottomSheet(
        context: context,
        backgroundColor: Colors.transparent,
        isScrollControlled: true,
        builder: (_) => CalendarEventDetailSheet(
          hostContext: context,
          initialTarget: initialTarget,
          flowResolver: _calendarChromeFlowDataForId,
          activeLedgerFlowIds: _buildActiveLedgerFlowIds(),
          resolveCurrentEventTarget: _resolveCalendarCurrentEventTarget,
          resolveAdjacentEventTarget: _resolveCalendarAdjacentEventTarget,
          onTargetChanged: (target) {
            unawaited(_saveCalendarEventDetailOverlayForTarget(target));
          },
          onManageFlows: _getMyFlowsCallback(),
          onEditNote: _editNoteByEvent,
          onDeleteNote: _deleteNoteByEvent,
          onShareNote: (event) async => _shareNoteSimple(event),
          onEditReminder: _editReminderById,
          onEndReminder: _endReminderRule,
          onShareReminder: (event) async => _shareNoteSimple(event),
          onEndFlow: (id) => unawaited(_endFlow(id).then<void>((_) {})),
          onAppendToJournal: _appendToJournalAndRefresh,
          onWriteJournalResponse: _writeMaatJournalResponseBlockAndRefresh,
          onSaveFlow: _saveFlowById,
          dataVersion: _dayViewDataVersion,
          onRecordCompletion:
              ({
                required String clientEventId,
                required int flowId,
                required DateTime completedOnDate,
                Map<String, dynamic>? metadata,
              }) => _recordEventCompletion(
                clientEventId: clientEventId,
                flowId: flowId,
                completedOnDate: completedOnDate,
                metadata: metadata,
              ),
          onUnrecordCompletion: _unrecordEventCompletion,
          onRemoveCompletionBadge: _removeCompletionBadgeAndRefresh,
        ),
      );
    } finally {
      CalendarEventDetailSheetCoordinator.markClosed();
      await _clearCalendarEventDetailOverlayState();
    }
  }

  Future<bool> _restoreCalendarEventDetailOverlay(
    Map<String, dynamic> overlay,
  ) async {
    if (!_restored || !_initialViewportSettled) return false;
    final startupFlight = _startupFlight;
    if (startupFlight != null && !startupFlight.isCompleted) {
      return false;
    }

    final state = EventDetailRestorationState.fromJson(overlay);
    if (state == null) {
      await _clearCalendarEventDetailOverlayState();
      return true;
    }

    final target = _calendarEventDetailTargetFromState(state);
    if (target == null) {
      await _clearCalendarEventDetailOverlayState();
      return true;
    }

    await _openCalendarEventDetailSheet(target);
    return true;
  }

  void _schedulePersistentOverlayRestore({required String reason}) {
    if (_sharedCalendarRealDayViewOpening) {
      return;
    }
    if (_calendarOverlayRestoreAttempted || _calendarOverlayRestoreInFlight) {
      return;
    }
    if (RestorationCoordinator.instance.isRestoreSurfaceSuppressed(
      RestorationCoordinator.calendarOverlayStackSurface,
    )) {
      return;
    }
    _calendarOverlayRestoreAttempted = true;
    _calendarOverlayRestorePresentationStarted = false;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      unawaited(_restorePersistentCalendarOverlayWithRetries(reason: reason));
    });
  }

  String _currentRouteTraceLabel() {
    final location = CalendarPage._currentRouteLocationForContext(context);
    final uri = Uri.tryParse(location);
    if (uri == null) return location.trim().isEmpty ? '/' : location.trim();
    final path = uri.path.isEmpty ? '/' : uri.path;
    final queryKeys =
        uri.queryParameters.keys
            .where((key) => key.trim().isNotEmpty)
            .toList(growable: false)
          ..sort();
    if (queryKeys.isEmpty) return path;
    return '$path?${queryKeys.map((key) => '$key=<redacted>').join('&')}';
  }

  bool _schedulePendingDetachedLaunchActionIfAny() {
    final pendingSearchResult = CalendarPage._pendingDetachedSearchResult;
    if (pendingSearchResult != null) {
      CalendarPage._pendingDetachedSearchResult = null;
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!mounted) return;
        _openDayView(
          context,
          pendingSearchResult.ky,
          pendingSearchResult.km,
          pendingSearchResult.kd,
          initialEventDetailRestorationState: pendingSearchResult.eventDetail,
        );
      });
      return true;
    }

    final pendingSearchDay = CalendarPage._pendingDetachedSearchDay;
    if (pendingSearchDay != null) {
      CalendarPage._pendingDetachedSearchDay = null;
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!mounted) return;
        _openDaySheet(
          pendingSearchDay.ky,
          pendingSearchDay.km,
          pendingSearchDay.kd,
        );
      });
      return true;
    }

    final action = CalendarPage._pendingDetachedLaunchAction;
    if (action == null) return false;
    CalendarPage._pendingDetachedLaunchAction = null;

    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      switch (action) {
        case _CalendarDetachedLaunchAction.quickAdd:
          unawaited(_openQuickAddSheet());
          break;
        case _CalendarDetachedLaunchAction.sharedCalendars:
          unawaited(_openSharedCalendarsSheet());
          break;
        case _CalendarDetachedLaunchAction.flowStudio:
          _getFlowStudioCallback()(null);
          break;
        case _CalendarDetachedLaunchAction.myFlows:
          _openMyFlowsList();
          break;
        case _CalendarDetachedLaunchAction.search:
          _openSearch();
          break;
      }
    });
    return true;
  }

  Future<void> _restorePersistentCalendarOverlayWithRetries({
    required String reason,
  }) async {
    var restored = false;
    try {
      for (var attempt = 0; attempt < 30; attempt++) {
        if (!mounted) return;
        restored = await _restorePersistentCalendarOverlay(
          reason: '$reason:$attempt',
        );
        if (restored) return;
        await Future<void>.delayed(const Duration(milliseconds: 150));
      }
    } finally {
      if (!restored) {
        _calendarOverlayRestoreAttempted = false;
      }
    }
  }

  Future<bool> _restorePersistentCalendarOverlay({
    required String reason,
  }) async {
    if (_calendarOverlayRestoreInFlight) return false;
    _calendarOverlayRestoreInFlight = true;
    try {
      final snapshot = await RestorationCoordinator.instance.readBestSnapshot(
        includeRemote: Supabase.instance.client.auth.currentSession != null,
      );
      final stack =
          snapshot.snapshot?.overlayStack ?? const <Map<String, dynamic>>[];
      if (!mounted || stack.isEmpty) return false;
      final overlay = stack.lastWhere(
        (entry) =>
            entry['kind'] == _kCalendarOverlayKindSharedCalendars ||
            entry['kind'] == _kCalendarOverlayKindFlowStudio ||
            entry['kind'] == _kCalendarOverlayKindEventDetail,
        orElse: () => const <String, dynamic>{},
      );
      if (overlay.isEmpty) return false;

      final parentRoute = (overlay['parentRoute'] as String?)?.trim();
      if (parentRoute != null &&
          parentRoute.isNotEmpty &&
          !CalendarPage._isRootRouteLocation(parentRoute)) {
        return false;
      }

      final savedDayView = snapshot.snapshot?.dayView;
      if (_restoreDayViewRouteOnStartup &&
          savedDayView != null &&
          savedDayView.isOpen &&
          !_persistentDayViewRestoreAttempted) {
        return false;
      }

      if (overlay['kind'] == _kCalendarOverlayKindEventDetail) {
        if (savedDayView != null && savedDayView.isOpen) {
          await _clearCalendarEventDetailOverlayState();
          return true;
        }
        final parentSurface = (overlay['parentSurface'] as String?)?.trim();
        if (parentSurface != null &&
            parentSurface.isNotEmpty &&
            parentSurface != _kCalendarParentSurfaceRoot) {
          await _clearCalendarEventDetailOverlayState();
          return true;
        }
        final startupFlight = _startupFlight;
        if (!_restored ||
            !_initialViewportSettled ||
            (startupFlight != null && !startupFlight.isCompleted)) {
          return false;
        }
      }

      final restoreKey = CalendarPage._calendarOverlayRestoreSurfaceKey(
        overlay,
      );
      if (!RestorationCoordinator.instance.claimRestoreSurface(
        restoreKey,
        requireRootTarget: true,
      )) {
        return true;
      }

      _calendarOverlayRestorePresentationStarted = true;
      if (overlay['kind'] == _kCalendarOverlayKindSharedCalendars) {
        await _openSharedCalendarsSheet(restorationState: overlay);
        return true;
      }

      if (overlay['kind'] == _kCalendarOverlayKindFlowStudio) {
        await _restoreFlowStudioOverlay(overlay);
        return true;
      }

      if (overlay['kind'] == _kCalendarOverlayKindEventDetail) {
        return _restoreCalendarEventDetailOverlay(overlay);
      }
      return false;
    } finally {
      _calendarOverlayRestoreInFlight = false;
    }
  }

  Future<void> _restoreFlowStudioOverlay(Map<String, dynamic> overlay) async {
    final mode = (overlay['mode'] as String?)?.trim();
    if (mode == _kFlowStudioModeMyFlows) {
      _openMyFlowsList(
        initialFlowId: (overlay['initialFlowId'] as num?)?.toInt(),
      );
      return;
    }

    if (mode == _kFlowStudioModeEditor) {
      final draft = _FlowStudioDraft.fromJson(
        await AppRestorationService.instance.readEditorState(
          _kFlowStudioDraftEditorKey,
        ),
      );
      final editFlowId =
          draft?.editingFlowId ?? (overlay['editFlowId'] as num?)?.toInt();
      await _openFlowStudioSheet(
        continuityState: <String, dynamic>{
          'mode': _kFlowStudioModeEditor,
          if (editFlowId != null) 'editFlowId': editFlowId,
        },
        rootBuilder: (_) =>
            _FlowStudioPage(existingFlows: _flows, editFlowId: editFlowId),
      );
      return;
    }

    if (mode == _kFlowStudioModeMaatFlows ||
        mode == _kFlowStudioModeMaatTemplate) {
      final templateKey = (overlay['templateKey'] as String?)?.trim();
      await _openFlowStudioSheet(
        continuityState: <String, dynamic>{
          'mode': mode,
          if (templateKey != null && templateKey.isNotEmpty)
            'templateKey': templateKey,
        },
        rootBuilder: _buildFlowStudioHubPage,
        initialRoutesBuilder: (navigator) {
          final hubRoute = MaterialPageRoute<dynamic>(
            builder: (ctx) => _buildFlowStudioHubPage(ctx),
          );
          final listRoute = MaterialPageRoute<dynamic>(
            builder: (ctx) => _buildMaatFlowsListPage(ctx),
          );
          unawaited(
            listRoute.popped.then((_) async {
              if (!mounted ||
                  RestorationCoordinator
                      .instance
                      .shouldPreserveOverlayForLifecycleClose) {
                return;
              }
              await _saveCalendarOverlayState(
                _kCalendarOverlayKindFlowStudio,
                const <String, dynamic>{'mode': _kFlowStudioModeHub},
              );
            }),
          );
          if (mode != _kFlowStudioModeMaatTemplate ||
              templateKey == null ||
              templateKey.isEmpty) {
            return <Route<dynamic>>[hubRoute, listRoute];
          }

          final template = _maatTemplateForKey(templateKey);
          if (template == null) return <Route<dynamic>>[hubRoute, listRoute];

          final detailRoute = MaterialPageRoute<int?>(
            builder: (_) => _MaatFlowTemplateDetailPage(
              template: template,
              addInstance:
                  ({
                    required _MaatFlowTemplate template,
                    DateTime? startDate,
                    bool? useKemetic,
                    TrackSkyTimeZone? trackSkyTimeZone,
                    int? alertMinutesBefore,
                    bool? dawnDiscreetMode,
                    DawnHouseRiteLens? dawnLens,
                    bool? eveningDiscreetMode,
                    EveningThresholdRiteLens? eveningLens,
                    int? eveningFallbackMinutesAfterMidnight,
                    TheWeighingLens? theWeighingLens,
                    OfferingTableLens? offeringTableLens,
                    bool? offeringNoCupMode,
                    TheTendingLens? theTendingLens,
                    KeptWordLens? keptWordLens,
                    CourseLens? courseLens,
                    MoonReturnLens? moonReturnLens,
                    WagLens? wagLens,
                    DecanWatchLens? decanWatchLens,
                    OpenHandLens? openHandLens,
                    DjedLens? djedLens,
                    List<ReadingHouseSitting>? readingHouseSittings,
                    String? eveningThresholdInitialCarry,
                  }) async {
                    final id = await _addMaatFlowInstance(
                      template: template,
                      startDate: startDate,
                      useKemetic: useKemetic ?? false,
                      trackSkyTimeZone: trackSkyTimeZone,
                      alertMinutesBefore:
                          alertMinutesBefore ?? _alertNoneMinutes,
                      dawnDiscreetMode: dawnDiscreetMode ?? false,
                      dawnLens: dawnLens ?? DawnHouseRiteLens.neutral,
                      eveningDiscreetMode: eveningDiscreetMode ?? false,
                      eveningLens:
                          eveningLens ?? EveningThresholdRiteLens.neutral,
                      eveningFallbackMinutesAfterMidnight:
                          eveningFallbackMinutesAfterMidnight ??
                          kEveningThresholdDefaultFallbackMinutes,
                      theWeighingLens:
                          theWeighingLens ?? TheWeighingLens.neutral,
                      offeringTableLens:
                          offeringTableLens ?? OfferingTableLens.neutral,
                      offeringNoCupMode: offeringNoCupMode ?? false,
                      theTendingLens: theTendingLens ?? TheTendingLens.neutral,
                      keptWordLens: keptWordLens ?? KeptWordLens.neutral,
                      courseLens: courseLens ?? CourseLens.neutral,
                      moonReturnLens: moonReturnLens ?? MoonReturnLens.neutral,
                      wagLens: wagLens ?? WagLens.neutral,
                      decanWatchLens: decanWatchLens ?? DecanWatchLens.neutral,
                      openHandLens: openHandLens ?? OpenHandLens.neutral,
                      djedLens: djedLens ?? DjedLens.neutral,
                      readingHouseSittings: readingHouseSittings,
                      eveningThresholdInitialCarry:
                          eveningThresholdInitialCarry,
                    );
                    return id;
                  },
            ),
          );
          unawaited(
            detailRoute.popped.then((importedFlowId) async {
              if (!mounted ||
                  RestorationCoordinator
                      .instance
                      .shouldPreserveOverlayForLifecycleClose) {
                return;
              }
              await _saveCalendarOverlayState(
                _kCalendarOverlayKindFlowStudio,
                const <String, dynamic>{'mode': _kFlowStudioModeMaatFlows},
              );
              if (importedFlowId != null && importedFlowId > 0) {
                CalendarPage._rememberJoinedMaatFlowTemplate(
                  templateKey: template.key,
                  flowId: importedFlowId,
                );
                _myFlowsFilingSnapshotCache = null;
                await _flowsRepo.clearMyFiledFlowsCache();
                await _loadFromDisk();
              }
            }),
          );
          return <Route<dynamic>>[hubRoute, listRoute, detailRoute];
        },
      );
      return;
    }

    _getFlowStudioCallback()(null);
  }

  _MaatFlowTemplate? _maatTemplateForKey(String key) {
    final trimmed = key.trim();
    if (trimmed.isEmpty) return null;
    for (final template in _kMaatFlowTemplates) {
      if (template.key == trimmed) return template;
    }
    return null;
  }

  Future<T?> _pushFlowStudioRoute<T>(
    NavigatorState navigator,
    Route<T> route, {
    required Map<String, dynamic> visibleState,
    required Map<String, dynamic> returnState,
  }) async {
    await _saveCalendarOverlayState(
      _kCalendarOverlayKindFlowStudio,
      visibleState,
    );
    try {
      return await navigator.push<T>(route);
    } finally {
      if (mounted &&
          navigator.mounted &&
          !RestorationCoordinator
              .instance
              .shouldPreserveOverlayForLifecycleClose) {
        await _saveCalendarOverlayState(
          _kCalendarOverlayKindFlowStudio,
          returnState,
        );
      }
    }
  }

  Future<_FlowStudioResult?> _pushFlowStudioEditor(
    NavigatorState navigator, {
    int? editFlowId,
    ImportFlowData? importData,
    required Map<String, dynamic> returnState,
  }) {
    final readingHouseFlow = importData == null
        ? _readingHouseFlowForEditor(editFlowId)
        : null;
    if (readingHouseFlow != null) {
      return _pushFlowStudioRoute<_FlowStudioResult>(
        navigator,
        MaterialPageRoute<_FlowStudioResult>(
          builder: (_) => _ReadingHouseAuthoringPage(
            flow: readingHouseFlow,
            calendar: _calendarSummary(readingHouseFlow.calendarId),
            personalCalendarId: _personalCalendarId,
            sharedCalendarsRepo: _sharedCalendarsRepo,
            onCalendarChanged: _moveReadingHouseFlowToCalendar,
          ),
        ),
        visibleState: <String, dynamic>{
          'mode': _kFlowStudioModeEditor,
          'editFlowId': editFlowId,
          'templateKey': kReadingHouseFlowKey,
        },
        returnState: returnState,
      );
    }

    Future<void> handleResult(_FlowStudioResult result) async {
      await _persistFlowStudioResult(result);
      if (mounted) {
        await _loadFromDisk(source: 'flow_studio_editor_save');
      }
      if (navigator.mounted) {
        navigator.pop();
      }
    }

    return _pushFlowStudioRoute<_FlowStudioResult>(
      navigator,
      MaterialPageRoute<_FlowStudioResult>(
        builder: (_) => _FlowStudioPage(
          existingFlows: _flows,
          editFlowId: editFlowId,
          importData: importData,
          onRouteResult: handleResult,
        ),
      ),
      visibleState: <String, dynamic>{
        'mode': _kFlowStudioModeEditor,
        if (editFlowId != null) 'editFlowId': editFlowId,
      },
      returnState: returnState,
    );
  }

  _Flow? _readingHouseFlowForEditor(int? flowId) {
    if (flowId == null) return null;
    final index = _flows.indexWhere((flow) => flow.id == flowId);
    if (index < 0) return null;
    final flow = _flows[index];
    if (resolveMaatFlowKind(flowNotes: flow.notes) ==
            MaatFlowKind.readingHouse ||
        isReadingHouseFlowReference(
          flowName: flow.name,
          flowNotes: flow.notes,
        )) {
      return flow;
    }
    return null;
  }

