  Map<String, Object?> _calendarSheetTraceState(String sheet, {String? phase}) {
    final stateMounted = mounted;
    return <String, Object?>{
      'sheet': sheet,
      'host': 'calendar',
      if (phase != null) 'phase': phase,
      'mounted': stateMounted,
      'contextMounted': stateMounted ? context.mounted : false,
      'route': stateMounted ? _currentRouteTraceLabel() : '<unmounted>',
      'modalDepth': globalFloatingMenuModalDepthValue,
      'sharedOpening': _sharedCalendarsSheetOpenOrOpening,
      'flowOpening': _flowStudioSheetOpenOrOpening,
    };
  }

  Future<void> _openSharedCalendarsSheet({
    Map<String, dynamic>? restorationState,
  }) async {
    NavigationTrace.instance.record(
      'calendars sheet helper entered',
      state: _calendarSheetTraceState('calendars', phase: 'entered'),
    );
    await _saveCalendarOverlayState(
      _kCalendarOverlayKindSharedCalendars,
      <String, dynamic>{
        'expandedCalendarIds': _stringListFromRestoration(
          restorationState?['expandedCalendarIds'],
        ),
      },
    );
    NavigationTrace.instance.record(
      'calendars sheet overlay state save returned',
      state: _calendarSheetTraceState('calendars', phase: 'overlaySaved'),
    );
    if (!mounted) {
      NavigationTrace.instance.record(
        'calendars sheet open stopped',
        state: _calendarSheetTraceState('calendars', phase: 'unmounted'),
      );
      return;
    }
    if (_sharedCalendarsSheetOpenOrOpening) {
      NavigationTrace.instance.record(
        'calendars sheet open stopped',
        state: _calendarSheetTraceState('calendars', phase: 'alreadyOpening'),
      );
      return;
    }
    _sharedCalendarsSheetOpenOrOpening = true;
    try {
      NavigationTrace.instance.record(
        'sheet open success',
        state: _calendarSheetTraceState('calendars', phase: 'beforeShow'),
      );
      NavigationTrace.instance.record(
        'calendars sheet show requested',
        state: _calendarSheetTraceState('calendars', phase: 'showRequested'),
      );
      final sheetFuture = SharedCalendarsSheet.show(
        context,
        repo: _sharedCalendarsRepo,
        onAddEventRequested: _openCalendarScopedNoteDialog,
        onEventTapRequested:
            (calendar, filedEvent, {calendarEvents = const []}) =>
                CalendarPage.openFiledCalendarEventFromAnyContext(
                  context,
                  calendar: calendar,
                  filedEvent: filedEvent,
                  calendarEvents: calendarEvents,
                ),
        initialExpandedCalendarIds: _stringListFromRestoration(
          restorationState?['expandedCalendarIds'],
        ),
        onContinuityChanged: (state) {
          unawaited(
            _saveCalendarOverlayState(
              _kCalendarOverlayKindSharedCalendars,
              state,
            ),
          );
        },
      );
      NavigationTrace.instance.record(
        'calendars sheet future created',
        state: _calendarSheetTraceState('calendars', phase: 'futureCreated'),
      );
      final changed = await sheetFuture;
      NavigationTrace.instance.record(
        'calendars sheet future completed',
        state: <String, Object?>{
          ..._calendarSheetTraceState('calendars', phase: 'futureCompleted'),
          'changed': changed == true,
        },
      );
      await _clearCalendarOverlayState(_kCalendarOverlayKindSharedCalendars);
      await _loadCalendarState();
      if (changed == true) {
        await _loadFromDisk();
      } else {
        _refreshNoteCacheUi();
      }
    } catch (error, stackTrace) {
      NavigationTrace.instance.recordError(
        'sheet open error',
        error,
        stackTrace,
        state: _calendarSheetTraceState('calendars', phase: 'catch'),
      );
      rethrow;
    } finally {
      _sharedCalendarsSheetOpenOrOpening = false;
      NavigationTrace.instance.record(
        'calendars sheet open finished',
        state: _calendarSheetTraceState('calendars', phase: 'finally'),
      );
    }
  }

  Future<bool> _openCalendarScopedNoteDialog(
    SharedCalendarSummary calendar,
  ) async {
    final calendarId = _normalizeCalendarId(calendar.id);
    if (calendarId == null) return false;
    final lockedCalendar = _calendarSummary(calendarId) ?? calendar;
    if (!lockedCalendar.canEdit) {
      if (!mounted) return false;
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('You can view this calendar, but you cannot edit it.'),
        ),
      );
      return false;
    }

    final controllerTitle = TextEditingController();
    final controllerLocation = TextEditingController();
    final controllerDetail = TextEditingController();

    int selYear = _today.kYear;
    int selMonth = _today.kMonth;
    int selDay = _today.kDay;
    bool showGregorianDates = _showGregorian;

    bool allDay = false;
    TimeOfDay? startTime = const TimeOfDay(hour: 12, minute: 0);
    TimeOfDay? endTime = const TimeOfDay(hour: 13, minute: 0);
    String? selectedCategory;
    int alertMinutesBefore = _alertNoneMinutes;
    final initialColorIndex = _flowPalette.indexWhere(
      (color) => color == lockedCalendar.color,
    );
    int selectedColorIndex = initialColorIndex >= 0 ? initialColorIndex : 0;
    bool isSaving = false;
    String? errorText;

    void setSelectedEventDate(DateTime date) {
      final kemetic = KemeticMath.fromGregorian(DateUtils.dateOnly(date));
      selYear = kemetic.kYear;
      selMonth = kemetic.kMonth;
      selDay = kemetic.kDay;
    }

    Future<void> pickStart(
      BuildContext dialogCtx,
      StateSetter setDialogState,
    ) async {
      final t = await showTimePicker(
        context: dialogCtx,
        initialTime: startTime ?? const TimeOfDay(hour: 12, minute: 0),
        builder: (c, w) => Theme(
          data: Theme.of(c).copyWith(
            colorScheme: const ColorScheme.dark(
              primary: _gold,
              surface: _bg,
              onSurface: Colors.white,
            ),
          ),
          child: w ?? const SizedBox.shrink(),
        ),
      );
      if (t == null) return;
      setDialogState(() {
        startTime = t;
        if (endTime != null && _toMinutes(endTime!) <= _toMinutes(t)) {
          endTime = _addMinutes(t, 60);
        }
      });
    }

    Future<void> pickEnd(
      BuildContext dialogCtx,
      StateSetter setDialogState,
    ) async {
      final t = await showTimePicker(
        context: dialogCtx,
        initialTime:
            endTime ??
            (startTime != null
                ? _addMinutes(startTime!, 60)
                : const TimeOfDay(hour: 13, minute: 0)),
        builder: (c, w) => Theme(
          data: Theme.of(c).copyWith(
            colorScheme: const ColorScheme.dark(
              primary: _gold,
              surface: _bg,
              onSurface: Colors.white,
            ),
          ),
          child: w ?? const SizedBox.shrink(),
        ),
      );
      if (t == null) return;
      setDialogState(() {
        endTime = t;
        if (startTime != null && _toMinutes(t) <= _toMinutes(startTime!)) {
          startTime = _addMinutes(t, -60);
        }
      });
    }

    Widget timeButton({
      required String label,
      required TimeOfDay? value,
      required VoidCallback onTap,
      required bool enabled,
    }) {
      final text = value == null ? '--:--' : _formatTimeOfDay(value);
      return Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text(
            label,
            style: const TextStyle(fontSize: 12, color: Color(0xFFBFC3C7)),
          ),
          const SizedBox(height: 6),
          SizedBox(
            height: 40,
            child: OutlinedButton(
              style: OutlinedButton.styleFrom(
                foregroundColor: Colors.white,
                side: const BorderSide(color: _silver, width: 1),
              ),
              onPressed: enabled ? onTap : null,
              child: Text(text),
            ),
          ),
        ],
      );
    }

    try {
      return await showDialog<bool>(
            context: context,
            barrierDismissible: !isSaving,
            builder: (dialogCtx) {
              final media = MediaQuery.of(dialogCtx);
              return StatefulBuilder(
                builder: (dialogCtx, setDialogState) {
                  final titleG = KemeticMath.toGregorian(
                    selYear,
                    selMonth,
                    selDay,
                  );
                  final titleGradient = showGregorianDates
                      ? whiteGloss
                      : goldGloss;
                  final dateTitleStyle = const TextStyle(
                    color: Colors.white,
                    fontSize: 18,
                    fontWeight: FontWeight.w500,
                    fontFamily: 'GentiumPlus',
                    fontFamilyFallback: [
                      'NotoSans',
                      'Roboto',
                      'Arial',
                      'sans-serif',
                    ],
                  );

                  Widget datePicker() {
                    final dateMode = showGregorianDates
                        ? EventCreateDatePickerMode.gregorian
                        : EventCreateDatePickerMode.kemetic;
                    final monthText = showGregorianDates
                        ? _gregMonthNames[titleG.month]
                        : _monthLabel(selMonth);
                    final dayText = showGregorianDates
                        ? '${titleG.day}'
                        : '$selDay';
                    final subtitle = showGregorianDates
                        ? 'Gregorian Calendar'
                        : 'Kemetic Calendar';

                    return Semantics(
                      button: true,
                      label: 'Change event date',
                      child: InkWell(
                        key: const ValueKey<String>(
                          'event_create_date_picker_trigger',
                        ),
                        borderRadius: BorderRadius.circular(10),
                        onTap: isSaving
                            ? null
                            : () async {
                                final picked = await EventCreateDatePicker.show(
                                  context: dialogCtx,
                                  initialDate: KemeticMath.toGregorian(
                                    selYear,
                                    selMonth,
                                    selDay,
                                  ),
                                  initialMode: dateMode,
                                );
                                if (picked == null || !dialogCtx.mounted) {
                                  return;
                                }
                                setDialogState(() {
                                  setSelectedEventDate(picked.date);
                                  showGregorianDates =
                                      picked.mode ==
                                      EventCreateDatePickerMode.gregorian;
                                });
                              },
                        child: Container(
                          padding: const EdgeInsets.symmetric(
                            horizontal: 12,
                            vertical: 10,
                          ),
                          decoration: BoxDecoration(
                            border: Border.all(color: Colors.white24),
                            borderRadius: BorderRadius.circular(10),
                          ),
                          child: Row(
                            children: [
                              const Icon(
                                Icons.calendar_month_outlined,
                                color: _gold,
                                size: 20,
                              ),
                              const SizedBox(width: 10),
                              Expanded(
                                child: Column(
                                  crossAxisAlignment: CrossAxisAlignment.start,
                                  children: [
                                    Wrap(
                                      alignment: WrapAlignment.start,
                                      crossAxisAlignment:
                                          WrapCrossAlignment.center,
                                      children: [
                                        _GlossyMonthNameText(
                                          text: monthText,
                                          style: dateTitleStyle,
                                          gradient: titleGradient,
                                        ),
                                        GlossyText(
                                          text: ' $dayText • ${titleG.year}',
                                          textAlign: TextAlign.center,
                                          style: dateTitleStyle,
                                          gradient: titleGradient,
                                          maxLines: 1,
                                          softWrap: false,
                                          overflow: TextOverflow.fade,
                                        ),
                                      ],
                                    ),
                                    const SizedBox(height: 2),
                                    Text(
                                      subtitle,
                                      style: const TextStyle(
                                        color: Colors.white54,
                                        fontSize: 11,
                                        letterSpacing: 0.4,
                                      ),
                                    ),
                                  ],
                                ),
                              ),
                              const SizedBox(width: 8),
                              const Icon(
                                Icons.chevron_right,
                                color: Colors.white54,
                                size: 22,
                              ),
                            ],
                          ),
                        ),
                      ),
                    );
                  }

                  Future<void> saveNote() async {
                    final title = controllerTitle.text.trim();
                    final location = controllerLocation.text.trim();
                    final detail = controllerDetail.text.trim();
                    if (title.isEmpty) {
                      setDialogState(() {
                        errorText = 'Title is required.';
                      });
                      return;
                    }
                    if (!allDay && startTime != null && endTime != null) {
                      if (_toMinutes(endTime!) <= _toMinutes(startTime!)) {
                        endTime = _addMinutes(startTime!, 60);
                      }
                    }

                    setDialogState(() {
                      isSaving = true;
                      errorText = null;
                    });
                    try {
                      await _saveSingleNoteOnly(
                        selYear: selYear,
                        selMonth: selMonth,
                        selDay: selDay,
                        title: title,
                        detail: detail.isEmpty ? null : detail,
                        location: location.isEmpty ? null : location,
                        calendarId: calendarId,
                        calendarName: lockedCalendar.name,
                        allDay: allDay,
                        startTime: startTime,
                        endTime: endTime,
                        color: _flowPalette[selectedColorIndex],
                        category: selectedCategory,
                        alertMinutesBefore: alertMinutesBefore,
                      );
                      if (!dialogCtx.mounted) return;
                      Navigator.of(dialogCtx).pop(true);
                      if (!mounted) return;
                      ScaffoldMessenger.of(context).showSnackBar(
                        SnackBar(
                          content: Text('Added to ${lockedCalendar.name}'),
                        ),
                      );
                    } catch (e, stackTrace) {
                      if (kDebugMode) {
                        _calendarDebugPrint(
                          '[CalendarScopedNote] save failed: $e',
                        );
                        _calendarDebugPrint('$stackTrace');
                      }
                      if (!dialogCtx.mounted) return;
                      setDialogState(() {
                        isSaving = false;
                        errorText = 'Failed to save note: $e';
                      });
                    }
                  }

                  final keyboardInset = keyboardInsetOf(dialogCtx);
                  final dialogMaxHeight = math.max(
                    280.0,
                    math.min(
                      media.size.height * 0.66,
                      media.size.height -
                          keyboardInset -
                          media.padding.top -
                          48,
                    ),
                  );
                  const fieldScrollPadding =
                      keyboardManagedTextFieldScrollPadding;

                  return AnimatedPadding(
                    duration: const Duration(milliseconds: 160),
                    curve: Curves.easeOut,
                    padding: EdgeInsets.only(bottom: keyboardInset),
                    child: Dialog(
                      backgroundColor: Colors.transparent,
                      insetPadding: const EdgeInsets.symmetric(
                        horizontal: 18,
                        vertical: 24,
                      ),
                      child: ConstrainedBox(
                        constraints: BoxConstraints(
                          maxWidth: 560,
                          maxHeight: dialogMaxHeight,
                        ),
                        child: Container(
                          decoration: BoxDecoration(
                            color: Colors.black,
                            borderRadius: BorderRadius.circular(18),
                            border: Border.all(
                              color: KemeticGold.base.withValues(alpha: 0.72),
                              width: 1.2,
                            ),
                          ),
                          child: SingleChildScrollView(
                            padding: const EdgeInsets.fromLTRB(16, 12, 16, 14),
                            child: DefaultTextStyle(
                              style: const TextStyle(color: Colors.white),
                              child: Column(
                                mainAxisSize: MainAxisSize.min,
                                children: [
                                  Row(
                                    children: [
                                      Expanded(
                                        child: KemeticGold.text(
                                          'Add note',
                                          style: const TextStyle(
                                            fontSize: 20,
                                            fontWeight: FontWeight.w700,
                                          ),
                                          maxLines: 1,
                                          softWrap: false,
                                          overflow: TextOverflow.fade,
                                        ),
                                      ),
                                      IconButton(
                                        tooltip: 'Close',
                                        onPressed: isSaving
                                            ? null
                                            : () =>
                                                  Navigator.of(dialogCtx).pop(),
                                        icon: const Icon(
                                          Icons.close,
                                          color: Colors.white70,
                                        ),
                                      ),
                                    ],
                                  ),
                                  const SizedBox(height: 4),
                                  datePicker(),
                                  const Divider(
                                    height: 24,
                                    color: Colors.white12,
                                  ),
                                  Align(
                                    alignment: Alignment.centerLeft,
                                    child: const GlossyText(
                                      text: 'Add note',
                                      style: TextStyle(
                                        fontWeight: FontWeight.w600,
                                        fontSize: 16,
                                      ),
                                      gradient: silverGloss,
                                    ),
                                  ),
                                  const SizedBox(height: 8),
                                  TextField(
                                    controller: controllerTitle,
                                    scrollPadding: fieldScrollPadding,
                                    enabled: !isSaving,
                                    style: const TextStyle(color: Colors.white),
                                    decoration: _darkInput('Title'),
                                  ),
                                  const SizedBox(height: 8),
                                  TextField(
                                    controller: controllerLocation,
                                    scrollPadding: fieldScrollPadding,
                                    enabled: !isSaving,
                                    style: const TextStyle(color: Colors.white),
                                    decoration: _darkInput(
                                      'Location or Video Call',
                                      hint: 'e.g., Home • Zoom • https://meet…',
                                    ),
                                  ),
                                  const SizedBox(height: 8),
                                  TextField(
                                    controller: controllerDetail,
                                    scrollPadding: fieldScrollPadding,
                                    enabled: !isSaving,
                                    style: const TextStyle(color: Colors.white),
                                    maxLines: 3,
                                    decoration: _darkInput(
                                      'Details (optional)',
                                    ),
                                  ),
                                  const SizedBox(height: 12),
                                  Align(
                                    alignment: Alignment.centerLeft,
                                    child: Text(
                                      'Category (optional)',
                                      style:
                                          Theme.of(
                                            context,
                                          ).textTheme.bodyMedium?.copyWith(
                                            color: Colors.white,
                                            fontWeight: FontWeight.w600,
                                          ) ??
                                          const TextStyle(
                                            color: Colors.white,
                                            fontWeight: FontWeight.w600,
                                          ),
                                    ),
                                  ),
                                  const SizedBox(height: 8),
                                  Align(
                                    alignment: Alignment.centerLeft,
                                    child: Wrap(
                                      spacing: 8,
                                      runSpacing: 8,
                                      children: [
                                        for (final cat in NoteCategory.all)
                                          ChoiceChip(
                                            label: Text(cat),
                                            selected: selectedCategory == cat,
                                            onSelected: isSaving
                                                ? null
                                                : (_) {
                                                    setDialogState(() {
                                                      selectedCategory = cat;
                                                    });
                                                  },
                                            selectedColor: const Color(
                                              0xFFD4AF37,
                                            ).withValues(alpha: 0.2),
                                            labelStyle: TextStyle(
                                              color: selectedCategory == cat
                                                  ? KemeticGold.base
                                                  : Colors.white,
                                              fontWeight: FontWeight.w600,
                                            ),
                                            backgroundColor: const Color(
                                              0xFF1A1A1A,
                                            ),
                                            side: BorderSide(
                                              color: selectedCategory == cat
                                                  ? KemeticGold.base
                                                  : Colors.white24,
                                            ),
                                          ),
                                        ActionChip(
                                          label: const Text(
                                            'Clear',
                                            style: TextStyle(
                                              color: Colors.white,
                                            ),
                                          ),
                                          avatar: const Icon(
                                            Icons.close,
                                            size: 18,
                                            color: Colors.white70,
                                          ),
                                          onPressed:
                                              selectedCategory == null ||
                                                  isSaving
                                              ? null
                                              : () {
                                                  setDialogState(() {
                                                    selectedCategory = null;
                                                  });
                                                },
                                          backgroundColor: const Color(
                                            0xFF1A1A1A,
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                  const SizedBox(height: 10),
                                  SwitchListTile(
                                    contentPadding: EdgeInsets.zero,
                                    value: allDay,
                                    onChanged: isSaving
                                        ? null
