                                              setDialogState(() => allDay = v),
                                    title: const GlossyText(
                                      text: 'All-day',
                                      style: TextStyle(fontSize: 14),
                                      gradient: silverGloss,
                                    ),
                                    activeThumbColor: _gold,
                                  ),
                                  const SizedBox(height: 6),
                                  Row(
                                    children: [
                                      Expanded(
                                        child: timeButton(
                                          label: 'Starts',
                                          value: startTime,
                                          onTap: () => pickStart(
                                            dialogCtx,
                                            setDialogState,
                                          ),
                                          enabled: !allDay && !isSaving,
                                        ),
                                      ),
                                      const SizedBox(width: 8),
                                      Expanded(
                                        child: timeButton(
                                          label: 'Ends',
                                          value: endTime,
                                          onTap: () => pickEnd(
                                            dialogCtx,
                                            setDialogState,
                                          ),
                                          enabled: !allDay && !isSaving,
                                        ),
                                      ),
                                    ],
                                  ),
                                  const SizedBox(height: 12),
                                  Container(
                                    padding: const EdgeInsets.symmetric(
                                      vertical: 12,
                                    ),
                                    child: Row(
                                      mainAxisAlignment:
                                          MainAxisAlignment.spaceBetween,
                                      children: [
                                        const GlossyText(
                                          text: 'Calendar',
                                          gradient: silverGloss,
                                          style: TextStyle(fontSize: 14),
                                        ),
                                        Flexible(
                                          child: Row(
                                            mainAxisSize: MainAxisSize.min,
                                            children: [
                                              Flexible(
                                                child: Text(
                                                  lockedCalendar.name,
                                                  maxLines: 1,
                                                  overflow: TextOverflow.fade,
                                                  softWrap: false,
                                                  style: TextStyle(
                                                    color: lockedCalendar.color,
                                                    fontSize: 14,
                                                    fontWeight: FontWeight.w600,
                                                  ),
                                                ),
                                              ),
                                              const SizedBox(width: 4),
                                              Icon(
                                                Icons.lock_outline,
                                                size: 16,
                                                color: lockedCalendar.color,
                                              ),
                                            ],
                                          ),
                                        ),
                                      ],
                                    ),
                                  ),
                                  const SizedBox(height: 8),
                                  InkWell(
                                    onTap: isSaving
                                        ? null
                                        : () async {
                                            final picked =
                                                await _pickAlertMinutes(
                                                  dialogCtx,
                                                  alertMinutesBefore,
                                                );
                                            if (picked != null &&
                                                dialogCtx.mounted) {
                                              setDialogState(() {
                                                alertMinutesBefore = picked;
                                              });
                                            }
                                          },
                                    child: Container(
                                      padding: const EdgeInsets.symmetric(
                                        vertical: 12,
                                      ),
                                      child: Row(
                                        mainAxisAlignment:
                                            MainAxisAlignment.spaceBetween,
                                        children: [
                                          const GlossyText(
                                            text: 'Alert',
                                            gradient: silverGloss,
                                            style: TextStyle(fontSize: 14),
                                          ),
                                          Row(
                                            children: [
                                              GlossyText(
                                                text: _alertLabelFor(
                                                  alertMinutesBefore,
                                                ),
                                                gradient: goldGloss,
                                                style: const TextStyle(
                                                  fontSize: 14,
                                                ),
                                              ),
                                              const SizedBox(width: 4),
                                              const Icon(
                                                Icons.chevron_right,
                                                size: 18,
                                                color: Colors.white54,
                                              ),
