                                  const SizedBox(height: 12),
                                  const Align(
                                    alignment: Alignment.centerLeft,
                                    child: GlossyText(
                                      text: 'Color',
                                      gradient: silverGloss,
                                      style: TextStyle(
                                        fontSize: 14,
                                        fontWeight: FontWeight.w600,
