                                            width: 30,
                                            height: 30,
                                            margin: const EdgeInsets.only(
                                              right: 10,
                                            ),
                                            decoration: BoxDecoration(
                                              shape: BoxShape.circle,
                                              gradient: _glossFromColor(color),
                                              border: Border.all(
                                                color: selected
                                                    ? _gold
                                                    : Colors.white24,
                                                width: selected ? 2.0 : 1.0,
                                              ),
                                            ),
                                          ),
                                        );
                                      },
                                    ),
                                  ),
                                  if (errorText != null) ...[
                                    const SizedBox(height: 10),
                                    Align(
                                      alignment: Alignment.centerLeft,
                                      child: Text(
                                        errorText!,
