                                          color: Colors.redAccent,
                                          fontSize: 12,
                                        ),
                                      ),
                                    ),
                                  ],
                                  const SizedBox(height: 14),
                                  Align(
                                    alignment: Alignment.centerRight,
                                    child: ElevatedButton(
                                      style: ElevatedButton.styleFrom(
                                        backgroundColor: _gold,
                                        foregroundColor: Colors.black,
                                      ),
                                      onPressed: isSaving ? null : saveNote,
                                      child: isSaving
                                          ? const SizedBox(
                                              width: 18,
                                              height: 18,
                                              child: CircularProgressIndicator(
                                                strokeWidth: 2,
                                                color: Colors.black,
                                              ),
                                            )
                                          : const Text('Save'),
                                    ),
                                  ),
                                ],
                              ),
                            ),
                          ),
                        ),
                      ),
                    ),
                  );
                },
              );
            },
          ) ??
          false;
    } finally {
      controllerTitle.dispose();
      controllerLocation.dispose();
      controllerDetail.dispose();
    }
  }

  String? _normalizeCalendarId(String? calendarId) {
    final trimmed = calendarId?.trim();
    if (trimmed == null || trimmed.isEmpty) return null;
    return trimmed;
  }

  SharedCalendarSummary? _calendarSummary(String? calendarId) {
    final trimmed = _normalizeCalendarId(calendarId);
    if (trimmed == null) return null;
    return _calendarSummariesById[trimmed];
  }

  String _calendarDisplayName(
    String? calendarId, {
    String fallback = 'My Calendar',
  }) {
    final summary = _calendarSummary(calendarId);
    final name = summary?.name.trim();
    if (name != null && name.isNotEmpty) return name;
    return fallback;
  }

  bool _calendarCanEdit(String? calendarId) {
    final summary = _calendarSummary(calendarId);
    return summary?.canEdit ?? true;
  }

  List<SharedCalendarSummary> _detailSheetCalendarOptions() {
    final calendars = _calendarSummariesById.values.toList();
    calendars.sort((a, b) {
      if (a.isPersonal != b.isPersonal) {
        return a.isPersonal ? -1 : 1;
      }
      return a.name.toLowerCase().compareTo(b.name.toLowerCase());
    });
    return calendars;
  }

  List<SharedCalendarSummary> _editableCalendarsForFlow(
    String? currentCalendarId,
  ) {
    final current = _normalizeCalendarId(currentCalendarId);
    final calendars = _calendarSummariesById.values
        .where((calendar) => calendar.canEdit || calendar.id == current)
        .toList(growable: false);
    calendars.sort((a, b) {
      if (a.isPersonal != b.isPersonal) {
        return a.isPersonal ? -1 : 1;
      }
      return a.name.toLowerCase().compareTo(b.name.toLowerCase());
    });
    return calendars;
  }

  String _detailSheetCalendarActionLabel(SharedCalendarSummary calendar) {
    if (calendar.isPersonal) return 'Calendar';
    final name = calendar.name.trim();
    return name.isEmpty ? 'Calendar' : name;
  }

  String _detailSheetCalendarButtonLabel(EventItem event) {
    final calendarId = _normalizeCalendarId(event.calendarId);
    final personalCalendarId = _normalizeCalendarId(_personalCalendarId);
    if (calendarId == null || calendarId == personalCalendarId) {
      return 'Calendar';
    }
    final summary = _calendarSummary(calendarId);
    final eventName = event.calendarName?.trim();
    if (eventName != null && eventName.isNotEmpty) {
      return eventName;
    }
    if (summary != null) {
      return _detailSheetCalendarActionLabel(summary);
    }
    return 'Calendar';
  }

  String? _detailSheetCalendarEventName(String? calendarId) {
    final summary = _calendarSummary(calendarId);
    final name = summary?.name.trim();
    if (name == null || name.isEmpty) return null;
    return name;
  }

  EventItem _detailSheetEventWithCalendar(EventItem event, String calendarId) {
    return EventItem(
      id: event.id,
      clientEventId: event.clientEventId,
      calendarId: calendarId,
      calendarName: _detailSheetCalendarEventName(calendarId),
      title: event.title,
      detail: event.detail,
      location: event.location,
      startMin: event.startMin,
      endMin: event.endMin,
      flowId: event.flowId,
      color: event.color,
      manualColor: event.manualColor,
      allDay: event.allDay,
      category: event.category,
      isReminder: event.isReminder,
      reminderId: event.reminderId,
      behaviorPayload: event.behaviorPayload,
    );
  }

  DayViewSheetEventTarget _detailSheetTargetWithCalendar(
    DayViewSheetEventTarget target,
    String calendarId,
  ) {
    return DayViewSheetEventTarget(
      ky: target.ky,
      km: target.km,
      kd: target.kd,
      event: _detailSheetEventWithCalendar(target.event, calendarId),
    );
  }

  bool _detailSheetTargetUsesCalendar(
    DayViewSheetEventTarget? target,
    String calendarId,
  ) {
    return _normalizeCalendarId(target?.event.calendarId) ==
        _normalizeCalendarId(calendarId);
  }

  bool _noteMatchesDetailSheetTarget(
    _Note note,
    DayViewSheetEventTarget target,
  ) {
    final flowId = target.event.flowId;
    if (flowId != null && flowId > 0) {
      return note.flowId == flowId;
    }

    final reminderId = target.event.reminderId?.trim();
    if (target.event.isReminder &&
        reminderId != null &&
        reminderId.isNotEmpty) {
      return note.reminderId?.trim() == reminderId;
    }

    final eventId = target.event.id?.trim();
    if (eventId != null && eventId.isNotEmpty) {
      return note.id?.trim() == eventId;
    }

    final clientEventId = target.event.clientEventId?.trim();
    if (clientEventId != null && clientEventId.isNotEmpty) {
      return note.clientEventId?.trim() == clientEventId;
    }

    final noteStartMin = note.allDay
        ? 9 * 60
        : (note.start?.hour ?? 9) * 60 + (note.start?.minute ?? 0);
    final noteEndMin = note.allDay
        ? 17 * 60
        : (note.end?.hour ?? 17) * 60 + (note.end?.minute ?? 0);
    return note.title.trim().toLowerCase() ==
            target.event.title.trim().toLowerCase() &&
        note.allDay == target.event.allDay &&
        noteStartMin == target.event.startMin &&
        noteEndMin == target.event.endMin;
  }

  void _applyDetailSheetCalendarToCache(
    DayViewSheetEventTarget target,
    String calendarId,
  ) {
    final calendarName = _detailSheetCalendarEventName(calendarId);
    var changed = false;
    for (final bucket in _notes.values) {
      for (int i = 0; i < bucket.length; i++) {
        final note = bucket[i];
        if (!_noteMatchesDetailSheetTarget(note, target)) continue;
        if (_normalizeCalendarId(note.calendarId) == calendarId &&
            note.calendarName == calendarName) {
          continue;
        }
        bucket[i] = note.copyWith(
          calendarId: calendarId,
          calendarName: calendarName,
        );
        changed = true;
      }
    }
    if (changed) {
      _bumpDataVersion();
    }
  }

  bool _noteMatchesFlowEvent(_Note note, FlowEventRow event) {
    final eventId = event.id?.trim();
    if (eventId != null && eventId.isNotEmpty) {
      return note.id?.trim() == eventId;
    }

    final clientEventId = event.clientEventId?.trim();
    if (clientEventId != null && clientEventId.isNotEmpty) {
      return note.clientEventId?.trim() == clientEventId;
    }

    final localStart = event.startsAtUtc.toLocal();
    final localEnd = event.endsAtUtc?.toLocal();
    final eventStart = event.allDay ? null : TimeOfDay.fromDateTime(localStart);
    final eventEnd = localEnd == null ? null : TimeOfDay.fromDateTime(localEnd);
    return note.title.trim().toLowerCase() ==
            event.title.trim().toLowerCase() &&
        note.allDay == event.allDay &&
        note.start == eventStart &&
        note.end == eventEnd;
  }

  Future<void> _refreshMovedFlowEventsFromServer({
    required int flowId,
    required String calendarId,
    required String source,
  }) async {
    final events = await UserEventsRepo(
      Supabase.instance.client,
    ).getEventsForFlow(flowId, flowEventsOnly: true);
    if (events.isEmpty) return;

    final fallbackCalendarName = _detailSheetCalendarEventName(calendarId);
    var changed = false;
    for (final bucket in _notes.values) {
      for (var i = 0; i < bucket.length; i++) {
        final note = bucket[i];
        if (note.flowId != flowId) continue;
        FlowEventRow? matchingEvent;
        for (final event in events) {
          if (_noteMatchesFlowEvent(note, event)) {
            matchingEvent = event;
            break;
          }
        }
        if (matchingEvent == null) continue;

        final behaviorPayload = matchingEvent.behaviorPayload == null
            ? note.behaviorPayload
            : Map<String, dynamic>.from(matchingEvent.behaviorPayload!);
        final next = note.copyWith(
          id: matchingEvent.id,
          clientEventId: matchingEvent.clientEventId,
          calendarId: matchingEvent.calendarId ?? calendarId,
          calendarName: matchingEvent.calendarName ?? fallbackCalendarName,
          category: matchingEvent.category,
          actionId: matchingEvent.actionId,
          behaviorPayload: behaviorPayload,
        );
        if (next.id != note.id ||
            next.clientEventId != note.clientEventId ||
            next.calendarId != note.calendarId ||
            next.calendarName != note.calendarName ||
            next.category != note.category ||
            next.actionId != note.actionId ||
            !mapEquals(next.behaviorPayload, note.behaviorPayload)) {
          bucket[i] = next;
          changed = true;
        }
      }
    }

    if (changed) {
      _bumpDataVersion();
      if (kDebugMode) {
        _calendarDebugPrint(
          '[$source] refreshed moved flow event payloads for flow=$flowId',
        );
      }
    }
  }

  bool _canReassignDetailTargetCalendar(EventItem event) {
    if (_isBirthdayOccurrence(
      category: event.category,
      clientEventId: event.clientEventId,
    )) {
      return false;
    }
    final calendars = _detailSheetCalendarOptions();
    if (calendars.isEmpty) return false;
    final fallbackCalendarId =
        _normalizeCalendarId(_personalCalendarId) ??
        (calendars.isNotEmpty ? calendars.first.id : null);
    final currentCalendarId =
        _normalizeCalendarId(event.calendarId) ?? fallbackCalendarId;
    if (currentCalendarId == null || !_calendarCanEdit(currentCalendarId)) {
      return false;
    }
    return calendars.any(
      (calendar) => calendar.canEdit || calendar.id == currentCalendarId,
    );
  }

  Future<DayViewSheetEventTarget?> _showDetailSheetCalendarPicker({
    required BuildContext context,
    required DayViewSheetEventTarget target,
    ValueChanged<DayViewSheetEventTarget>? onOptimisticTargetChanged,
  }) async {
    final calendars = _detailSheetCalendarOptions();
    if (calendars.isEmpty) return null;
    final fallbackCalendarId =
        _normalizeCalendarId(_personalCalendarId) ??
        (calendars.isNotEmpty ? calendars.first.id : null);
    final currentCalendarId =
        _normalizeCalendarId(target.event.calendarId) ?? fallbackCalendarId;
    if (currentCalendarId == null || !_calendarCanEdit(currentCalendarId)) {
      return null;
    }

    final options = calendars
        .where(
          (calendar) => calendar.canEdit || calendar.id == currentCalendarId,
        )
        .toList(growable: false);
    if (options.isEmpty) return null;

    var selectedCalendarId = currentCalendarId;
    String? savingCalendarId;
    String? saveError;

    final updatedTarget = await showModalBottomSheet<DayViewSheetEventTarget?>(
      context: context,
      backgroundColor: Colors.transparent,
      isScrollControlled: true,
      builder: (popupCtx) {
        final width = MediaQuery.sizeOf(popupCtx).width;
        return StatefulBuilder(
          builder: (popupCtx, setModalState) {
            Future<void> selectCalendar(SharedCalendarSummary calendar) async {
              final calendarId = calendar.id;
              final previousCalendarId = selectedCalendarId;
              if (savingCalendarId != null ||
                  calendarId == previousCalendarId) {
                return;
              }
              if (kDebugMode) {
                debugPrint(
                  '[CalendarPicker] tap id=$calendarId name=${calendar.name}',
                );
              }
              final optimisticTarget = _detailSheetTargetWithCalendar(
                target,
                calendarId,
              );
              setModalState(() {
                selectedCalendarId = calendarId;
                savingCalendarId = calendarId;
                saveError = null;
              });
              if (kDebugMode) {
                debugPrint('[CalendarPicker] optimistic selected=$calendarId');
                debugPrint(
                  '[CalendarPicker] save start itemType=${target.event.isReminder ? 'reminder' : (target.event.flowId != null && target.event.flowId! > 0 ? 'flow' : 'event')} calendarId=$calendarId',
                );
              }
              onOptimisticTargetChanged?.call(optimisticTarget);

              final committedTarget = await _reassignDetailTargetCalendar(
                target,
                calendarId,
              );
              if (!popupCtx.mounted) return;
              if (committedTarget == null) {
                if (kDebugMode) {
                  debugPrint(
                    '[CalendarPicker] save failed itemType=${target.event.isReminder ? 'reminder' : (target.event.flowId != null && target.event.flowId! > 0 ? 'flow' : 'event')} calendarId=$calendarId error=returned_null',
                  );
                }
                onOptimisticTargetChanged?.call(
                  _detailSheetTargetWithCalendar(target, previousCalendarId),
                );
                setModalState(() {
                  selectedCalendarId = previousCalendarId;
                  savingCalendarId = null;
                  saveError = 'Unable to change calendar.';
                });
                return;
              }

              if (kDebugMode) {
                debugPrint(
                  '[CalendarPicker] save complete itemType=${target.event.isReminder ? 'reminder' : (target.event.flowId != null && target.event.flowId! > 0 ? 'flow' : 'event')} calendarId=$calendarId',
                );
