  void _showCalendarActionMessage(String message) {
    if (!mounted) return;
    ScaffoldMessenger.of(
      context,
    ).showSnackBar(SnackBar(content: Text(message)));
  }

  ReminderRule? _findReminderRuleForDetail(String reminderId) {
    final trimmed = reminderId.trim();
    if (trimmed.isEmpty) return null;
    for (final rule in _reminderRules) {
      if (rule.id == trimmed) return rule;
    }
    final dbUuid = _dbReminderUuidFromRuleId(trimmed);
    if (dbUuid == null) return null;
    for (final flow in _flows) {
      if (!flow.isReminder || flow.reminderUuid != dbUuid) continue;
      return _reminderRuleFromFlow(flow);
    }
    return null;
  }

  Future<DayViewSheetEventTarget?> _refreshDetailTargetAfterCalendarChange(
    DayViewSheetEventTarget target, {
    required String source,
  }) async {
    await _loadFromDisk(source: source);
    if (!mounted) return null;
    return _resolveCalendarCurrentEventTarget(target);
  }

  Future<DayViewSheetEventTarget?> _moveStandaloneEventToCalendar(
    DayViewSheetEventTarget target,
    String calendarId,
  ) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    var eventId = target.event.id?.trim();
    final clientEventId = target.event.clientEventId?.trim();
    if ((eventId == null || eventId.isEmpty) &&
        clientEventId != null &&
        clientEventId.isNotEmpty) {
      final persisted = await repo.getEventByClientEventId(clientEventId);
      eventId = persisted?.id.trim();
    }
    if (eventId == null || eventId.isEmpty) {
      _showCalendarActionMessage(
        'Save this event first, then change its calendar.',
      );
      return null;
    }

    await repo.update(id: eventId, calendarId: calendarId);
    final optimisticTarget = _detailSheetTargetWithCalendar(target, calendarId);
    _applyDetailSheetCalendarToCache(target, calendarId);
    await _notifySharedCalendarItemAdded(
      calendarId: calendarId,
      itemType: 'event',
      itemId: eventId,
      itemTitle: target.event.title,
      clientEventId: clientEventId,
      eventId: eventId,
      startDate: KemeticMath.toGregorian(target.ky, target.km, target.kd),
      kYear: target.ky,
      kMonth: target.km,
      kDay: target.kd,
    );
    final refreshed = await _refreshDetailTargetAfterCalendarChange(
      optimisticTarget,
      source: 'detail_calendar_move_note',
    );
    return _detailSheetTargetUsesCalendar(refreshed, calendarId)
        ? refreshed
        : optimisticTarget;
  }

  Future<DayViewSheetEventTarget?> _moveFlowEventToCalendar(
    DayViewSheetEventTarget target,
    int flowId,
    String calendarId,
  ) async {
    await _flowsRepo.updateCalendar(id: flowId, calendarId: calendarId);
    await UserEventsRepo(
      Supabase.instance.client,
    ).updateCalendarForFlowEvents(flowId: flowId, calendarId: calendarId);
    await _ensureSharedExperienceForFlow(
      flowId: flowId,
      calendarId: calendarId,
      source: 'detail_calendar_move_flow',
    );
    await _refreshMovedFlowEventsFromServer(
      flowId: flowId,
      calendarId: calendarId,
      source: 'detail_calendar_move_flow',
    );

    String flowName = target.event.title;
    for (final flow in _flows) {
      if (flow.id != flowId) continue;
      flow.calendarId = calendarId;
      flowName = flow.name;
      break;
    }
    final optimisticTarget = _detailSheetTargetWithCalendar(target, calendarId);
    _applyDetailSheetCalendarToCache(target, calendarId);

    await _notifySharedCalendarItemAdded(
      calendarId: calendarId,
      itemType: 'flow',
      itemId: flowId.toString(),
      itemTitle: flowName,
      clientEventId: target.event.clientEventId,
      flowId: flowId,
      startDate: KemeticMath.toGregorian(target.ky, target.km, target.kd),
      kYear: target.ky,
      kMonth: target.km,
      kDay: target.kd,
    );
    final refreshed = await _refreshDetailTargetAfterCalendarChange(
      optimisticTarget,
      source: 'detail_calendar_move_flow',
    );
    return _detailSheetTargetUsesCalendar(refreshed, calendarId)
        ? refreshed
        : optimisticTarget;
  }

  Future<_Flow> _moveFlowToCalendar(
    _Flow flow,
    SharedCalendarSummary calendar, {
    String source = 'flow_detail_calendar_move',
  }) async {
    final calendarId = calendar.id.trim();
    if (calendarId.isEmpty) {
      throw ArgumentError.value(
        calendar.id,
        'calendar.id',
        'Must not be empty.',
      );
    }
    await _flowsRepo.updateCalendar(id: flow.id, calendarId: calendarId);
    await UserEventsRepo(
      Supabase.instance.client,
    ).updateCalendarForFlowEvents(flowId: flow.id, calendarId: calendarId);
    await _ensureSharedExperienceForFlow(
      flowId: flow.id,
      calendarId: calendarId,
      source: source,
    );
    await _refreshMovedFlowEventsFromServer(
      flowId: flow.id,
      calendarId: calendarId,
      source: source,
    );

    _Flow? updated;
    for (var i = 0; i < _flows.length; i++) {
      final existing = _flows[i];
      if (existing.id != flow.id) continue;
      existing.calendarId = calendarId;
      updated = existing;
      break;
    }
    updated ??= flow..calendarId = calendarId;

    final startDate = updated.start == null
        ? null
        : DateUtils.dateOnly(updated.start!);
    final k = startDate == null ? null : KemeticMath.fromGregorian(startDate);
    await _notifySharedCalendarItemAdded(
      calendarId: calendarId,
      itemType: 'flow',
      itemId: updated.id.toString(),
      itemTitle: updated.name,
      flowId: updated.id,
      startDate: startDate,
      kYear: k?.kYear,
      kMonth: k?.kMonth,
      kDay: k?.kDay,
    );
    if (mounted) {
      await _loadFromDisk(source: source);
    }
    return updated;
  }

  Future<_Flow> _moveReadingHouseFlowToCalendar(
    _Flow flow,
    SharedCalendarSummary calendar,
  ) {
    return _moveFlowToCalendar(
      flow,
      calendar,
      source: 'reading_house_shared_calendar_move',
    );
  }

  Future<DayViewSheetEventTarget?> _moveReminderEventToCalendar(
    DayViewSheetEventTarget target,
    String calendarId,
  ) async {
    final reminderId = target.event.reminderId?.trim();
    if (reminderId == null || reminderId.isEmpty) {
      _showCalendarActionMessage('Unable to locate that reminder.');
      return null;
    }
    final rule = _findReminderRuleForDetail(reminderId);
    if (rule == null) {
      _showCalendarActionMessage('Unable to load that reminder.');
      return null;
    }

    await _upsertReminderRule(rule.copyWith(calendarId: calendarId));
    final dbUuid = _dbReminderUuidFromRuleId(rule.id);
    final targetFlowId = target.event.flowId;
    final flowId = targetFlowId != null && targetFlowId > 0
        ? targetFlowId
        : dbUuid == null
        ? null
        : await _findFlowIdByReminderUuid(dbUuid);
    await _notifySharedCalendarItemAdded(
      calendarId: calendarId,
      itemType: 'reminder',
      itemId: (flowId ?? reminderId).toString(),
      itemTitle: rule.title,
      clientEventId: target.event.clientEventId,
      flowId: flowId,
      reminderId: dbUuid ?? reminderId,
      startDate: rule.startLocal,
      endDate: rule.endLocal == null
          ? null
          : DateUtils.dateOnly(rule.endLocal!),
      kYear: target.ky,
      kMonth: target.km,
      kDay: target.kd,
    );
    final optimisticTarget = _detailSheetTargetWithCalendar(target, calendarId);
    _applyDetailSheetCalendarToCache(target, calendarId);
    if (!mounted) return null;
    final refreshed = _resolveCalendarCurrentEventTarget(optimisticTarget);
    return _detailSheetTargetUsesCalendar(refreshed, calendarId)
        ? refreshed
        : optimisticTarget;
  }

  Future<DayViewSheetEventTarget?> _reassignDetailTargetCalendar(
    DayViewSheetEventTarget target,
    String calendarId,
  ) async {
    final nextCalendarId =
        _normalizeCalendarId(calendarId) ??
        _normalizeCalendarId(_personalCalendarId);
    if (nextCalendarId == null) return null;

    final currentCalendarId =
        _normalizeCalendarId(target.event.calendarId) ??
        _normalizeCalendarId(_personalCalendarId);
    if (currentCalendarId == nextCalendarId) {
      return _resolveCalendarCurrentEventTarget(target);
    }
    if (!_calendarCanEdit(currentCalendarId)) {
      _showCalendarActionMessage(
        'You can view this calendar, but you cannot edit it.',
      );
      return null;
    }
    if (!_calendarCanEdit(nextCalendarId)) {
      _showCalendarActionMessage(
        'You can view that calendar, but you cannot save events to it.',
      );
      return null;
    }

    try {
      if (target.event.isReminder) {
        return await _moveReminderEventToCalendar(target, nextCalendarId);
      }
      final flowId = target.event.flowId;
      if (flowId != null && flowId > 0) {
        return await _moveFlowEventToCalendar(target, flowId, nextCalendarId);
      }
      return await _moveStandaloneEventToCalendar(target, nextCalendarId);
    } catch (e) {
      _showCalendarActionMessage('Unable to change calendar: $e');
      return null;
    }
  }

  Future<void> _notifySharedCalendarMembers({
    required String? calendarId,
    required String title,
    String? body,
    String? clientEventId,
    Map<String, dynamic>? data,
  }) async {
    final trimmedCalendarId = _normalizeCalendarId(calendarId);
    if (trimmedCalendarId == null) return;

    final summary = _calendarSummary(trimmedCalendarId);
    if (summary == null || summary.isPersonal) return;

    final memberIds = await _sharedCalendarsRepo.getAcceptedMemberIds(
      trimmedCalendarId,
    );
    if (memberIds.isEmpty) return;

    final payload = <String, dynamic>{
      'kind': 'calendar_event',
      'calendar_id': trimmedCalendarId,
      'calendar_name': summary.name,
      'calendar_color': summary.colorValue,
      if (clientEventId != null && clientEventId.trim().isNotEmpty)
        'client_event_id': clientEventId.trim(),
      if (data != null) ...data,
    };

    await _sharedCalendarsRepo.createCalendarNotifications(
      calendarId: trimmedCalendarId,
      userIds: memberIds,
      kind: 'calendar_event',
      title: title,
      body: body,
      data: payload,
    );

    await _sharedCalendarsRepo.sendCalendarPush(
      userIds: memberIds,
      title: title,
      body: body,
      data: payload,
    );
  }

  Future<void> _notifySharedCalendarItemAdded({
    required String? calendarId,
    required String itemType,
    required String itemId,
    String? itemTitle,
    String? clientEventId,
    int? flowId,
    String? eventId,
    String? noteId,
    String? reminderId,
    String? taskId,
    DateTime? startDate,
    DateTime? endDate,
    int? kYear,
    int? kMonth,
    int? kDay,
  }) async {
    final trimmedCalendarId = _normalizeCalendarId(calendarId);
    if (trimmedCalendarId == null) return;

    await _sharedCalendarsRepo.notifySharedCalendarItemAdded(
      calendarId: trimmedCalendarId,
      itemType: itemType,
      itemId: itemId,
      itemTitle: itemTitle,
      clientEventId: clientEventId,
      flowId: flowId,
      eventId: eventId,
      noteId: noteId,
      reminderId: reminderId,
      taskId: taskId,
      startDate: startDate,
      endDate: endDate,
      kYear: kYear,
      kMonth: kMonth,
      kDay: kDay,
    );
  }

  /// Extract the flow id from a unified clientEventId string. Returns -1 if
  /// parsing fails or no flow id segment is present. This can be used when
  /// reconstructing notes from persisted events.
  int _flowIdFromCid(String cid) {
    return extractFlowIdFromClientEventId(cid) ?? -1;
  }

  String? _reminderRuleIdFromCid(String cid) {
    if (!cid.startsWith('reminder:')) return null;
    final parts = cid.split(':');
    // Format: reminder:RULE_ID:YYYY-MM-DD (rule id may contain colons)
    if (parts.length < 3) return null;
    final ruleId = parts.sublist(1, parts.length - 1).join(':').trim();
    return ruleId.isEmpty ? null : ruleId;
  }

  /// Remove legacy clientEventId formats and replace them with unified ones. This
  /// migration runs once on startup (scheduled via microtask) and rewrites
  /// any lingering events that still use old identifiers. It is idempotent and
  /// safe to run multiple times. If Ma’at notes use a separate namespace,
  /// they can be migrated by adding the appropriate legacy patterns here.
  Future<void> _migrateOldClientEventIds() async {
    await _ensureManualDeleteTombstonesLoaded();
    try {
      final prefs = await SharedPreferences.getInstance();
      final alreadyDone = prefs.getBool(_kCidMigrationPrefKey) ?? false;
      if (alreadyDone) {
        if (kDebugMode) {
          _calendarDebugPrint('[migrate-cid] Skipping; persisted flag is set.');
        }
        return;
      }
      final repo = UserEventsRepo(Supabase.instance.client);
      // Iterate over all notes in memory and rebuild unified ids
      // Iterate over a snapshot of entries to avoid concurrent modifications while iterating.
      final entries = _notes.entries.toList();
      bool migrated = false;
      for (final entry in entries) {
        final key = entry.key;
        // Parse kYear, kMonth, kDay from the map key. Keys are strings generated by _kKey, e.g. "2025-10-8".  We parse by splitting on '-'.
        int ky;
        int km;
        int kd;
        {
          // Fallback: parse from string form. Even if key is int (unlikely), toString() will yield a numeric string. We expect parts length == 3.
          final parts = key.toString().split('-');
          if (parts.length != 3) {
            // If the key is purely numeric, derive ky, km, kd by integer arithmetic as a fallback.
            final maybeInt = int.tryParse(key.toString());
            if (maybeInt != null) {
              ky = maybeInt ~/ 10000;
              km = (maybeInt % 10000) ~/ 100;
              kd = maybeInt % 100;
            } else {
              // Unknown key format; skip this entry.
              continue;
            }
          } else {
            ky = int.tryParse(parts[0]) ?? 0;
            km = int.tryParse(parts[1]) ?? 0;
            kd = int.tryParse(parts[2]) ?? 0;
          }
        }
        for (final note in entry.value) {
          // Build unified cid for this note
          final int fid = note.flowId ?? -1;
          final String unifiedCid = _buildCid(
            ky: ky,
            km: km,
            kd: kd,
            title: note.title,
            startHour: note.start?.hour,
            startMinute: note.start?.minute,
            allDay: note.allDay,
            flowId: fid,
            calendarScopeToken: _calendarScopeToken(note.calendarId),
          );
          if (_isTombstoned(unifiedCid)) {
            if (kDebugMode) {
              _calendarDebugPrint(
                '[migrate-cid] skip tombstoned cid=$unifiedCid',
              );
            }
            continue;
          }
          final startTime = note.allDay
              ? null
              : TimeOfDay(
                  hour: note.start?.hour ?? 9,
                  minute: note.start?.minute ?? 0,
                );
          if (_isPendingDelete(
            id: note.id,
            clientEventId: note.clientEventId,
            kYear: ky,
            kMonth: km,
            kDay: kd,
            title: note.title,
            allDay: note.allDay,
            start: startTime,
            end: note.end,
            flowId: fid,
          )) {
            continue;
          }
          // Determine legacy patterns used previously and remove them
          final String rawTitle = note.title;
          final String hhmm = note.start != null
              ? '${note.start!.hour.toString().padLeft(2, '0')}${note.start!.minute.toString().padLeft(2, '0')}'
              : '';
          final legacyIds = <String>{
            'note:$ky-$km-$kd:${rawTitle.hashCode}',
            'ky=$ky-km=$km-kd=$kd|t=$rawTitle',
            if (hhmm.isNotEmpty) 'note:$ky-$km-$kd:$rawTitle:$hhmm',
          };
          for (final oldId in legacyIds) {
            try {
              await repo.deleteByClientId(oldId);
            } catch (_) {}
          }
          // Upsert unified row (idempotent)
          try {
            final g = KemeticMath.toGregorian(ky, km, kd);
            final DateTime startsAt = DateTime(
              g.year,
              g.month,
              g.day,
              note.start?.hour ?? 9,
              note.start?.minute ?? 0,
            );
            final DateTime? endsAt = note.end == null
                ? null
                : DateTime(
                    g.year,
                    g.month,
                    g.day,
                    note.end!.hour,
                    note.end!.minute,
                  );
            await repo.upsertByClientId(
              clientEventId: unifiedCid,
              title: note.title,
              startsAtUtc: startsAt.toUtc(),
              detail: note.detail?.trim().isEmpty ?? true
                  ? null
                  : note.detail!.trim(),
              location: note.location?.trim().isEmpty ?? true
                  ? null
                  : note.location!.trim(),
              allDay: note.allDay,
              endsAtUtc: endsAt?.toUtc(),
              caller: 'migrate_cid',
            );
            migrated = true;
          } catch (e) {
            _calendarDebugPrint(
              '[migrate-cid] Failed to upsert unified cid: $e',
            );
          }
        }
      }
      await prefs.setBool(_kCidMigrationPrefKey, true);
      _calendarDebugPrint(
        '[migrate-cid] Completed pass. migrated=$migrated flag persisted',
      );
    } catch (e) {
      _calendarDebugPrint('[migrate-cid] Migration failed: $e');
    }
  }

