        kDay.kYear,
        kDay.kMonth,
        kDay.kDay,
        allowDateChange: true,
        persistAsRestoration: false,
        initialShowGregorian: false,
        initialTitle: 'Smoke draft note',
        initialLocation: 'Debug shrine',
        initialDetail: 'Use this draft to inspect Add note fields.',
        initialAllDay: false,
        initialStartTime: const TimeOfDay(hour: 11, minute: 0),
        initialEndTime: const TimeOfDay(hour: 11, minute: 45),
        initialColor: daySheetColorPalette[1],
        initialCategory: NoteCategory.spirit,
        initialCalendarId: _personalCalendarId,
      );
    });
  }

  @override
  void initState() {
    super.initState();
    _calendarDebugPrint('[calendar] initState');
    WidgetsBinding.instance.addObserver(this);
    _onboardingDayRhythmController.addListener(
      _handleOnboardingDayRhythmChanged,
    );

    if (_debugDaySheetSmokeEnabled) {
      _journalController = JournalController(Supabase.instance.client);
      _journalController.onCompletionBadgesRemoved =
          _handleJournalCompletionBadgesRemoved;
      _scrollCtrl.addListener(_onVerticalScroll);
      _configureDebugDaySheetSmokeState();
      _scheduleDebugDaySheetSmoke();
      return;
    }

    if (_onboardingReviewMode) {
      _journalController = JournalController(Supabase.instance.client);
      _journalController.onCompletionBadgesRemoved =
          _handleJournalCompletionBadgesRemoved;
      _scrollCtrl.addListener(_onVerticalScroll);
      _resetOnboardingReviewSessionForRoute();
      _configureOnboardingReviewState();
      _scheduleOnboardingPresentation();
      return;
    }

    // Load local reminders cache and check any due on startup.
    _reminderService.load().then((_) {
      _remindersLoaded = true;
      _floatingReminders = [];
    });
    // We no longer listen to every change to avoid UI loops; checks happen on load/resume/refresh.

    // ✅ Load persisted state first, fallback to today
    _initialPersistedViewStateLoad = _loadPersistedViewState();
    _restoreWarmStartCacheForFirstPaint(reason: 'initState');
    _restoreMyFlowsFilingSnapshotCacheAfterFirstFrame(reason: 'initState');
    calendarPushOpenIntent.addListener(_handleCalendarPushOpenIntent);
    _calendarInvalidationSub = CalendarInvalidationBus.instance.stream.listen(
      _handleCalendarInvalidated,
    );
    _schedulePendingCalendarInvalidationReload();
    _scheduleDaySheetResumeRestore();
    _schedulePushEventResumeRestore();

    _scrollCtrl.addListener(_onVerticalScroll);

    _scheduleOnboardingPresentation();

    // Schedule a one-time migration of clientEventIds to the unified format.
    // Using Future.microtask ensures this runs after the first frame without blocking UI.
    // We guard the migration with the _ranMigration flag so that it executes
    // exactly once per app session and does not collide with subsequent data
    // loading or other migrations.
    Future.microtask(() async {
      if (!_ranMigration) {
        _ranMigration = true;
        try {
          await _migrateOldClientEventIds();
        } catch (_) {
          // ignore errors; migration is best-effort
        }
      }
    });

    _authSub = Supabase.instance.client.auth.onAuthStateChange.listen((data) {
      final event = data.event;
      if (kDebugMode) {
        _calendarDebugPrint('[calendar] auth state change event=${event.name}');
      }
      if (event == AuthChangeEvent.initialSession ||
          event == AuthChangeEvent.signedIn ||
          event == AuthChangeEvent.tokenRefreshed ||
          event == AuthChangeEvent.signedOut) {
        if (!mounted) return;
        unawaited(_maybeResolvePersistedViewStateAfterAuth(event));
      }
      if (event == AuthChangeEvent.initialSession ||
          event == AuthChangeEvent.signedIn) {
        if (!mounted) return;
        unawaited(_loadCalendarState());
        _scheduleOnboardingPresentation();
        _restoreWarmStartCacheForFirstPaint(reason: 'auth:${event.name}');
        _restoreMyFlowsFilingSnapshotCacheAfterFirstFrame(
          reason: 'auth:${event.name}',
        );
        if (widget.initialFlowIdToEdit == null &&
            !widget.openMyFlowsOnLaunch &&
            !_sharedCalendarRealDayViewOpening &&
            CalendarPage._pendingDetachedLaunchAction == null &&
            CalendarPage._pendingDetachedSearchResult == null &&
            CalendarPage._pendingDetachedSearchDay == null) {
          _schedulePersistentOverlayRestore(reason: 'auth-early:${event.name}');
        }
        if (_sharedCalendarRealDayViewOpening) {
          return;
        }
        _scheduleInitialStartupRunAfterFirstFrame(
          reason: 'auth:${event.name}',
          onComplete: () async {
            if (!mounted ||
                widget.initialFlowIdToEdit != null ||
                widget.openMyFlowsOnLaunch) {
              return;
            }
            if (!_schedulePendingDetachedLaunchActionIfAny()) {
              _schedulePersistentOverlayRestore(reason: 'auth:${event.name}');
            }
          },
        );
        return;
      }
      if (event == AuthChangeEvent.tokenRefreshed) {
        if (!mounted) return;
        unawaited(_loadCalendarState());
        return;
      }
      if (event == AuthChangeEvent.signedOut) {
        _initialStartupUserId = null;
        _warmStartSnapshotVisible = false;
        _warmStartCacheRestoredForUserId = null;
        _myFlowsFilingSnapshotCache = null;
        _lastSuccessfulHydrationAt = null;
      }
    });

    // Initialize journal controller
    _journalController = JournalController(Supabase.instance.client);
    _journalController.onCompletionBadgesRemoved =
        _handleJournalCompletionBadgesRemoved;
    _journalController.init().then((_) {
      if (mounted) {
        setState(() => _journalInitialized = true);
        _maybeLoadDecanReflectionPrompt();
      }
    });
    final consumedSharedCalendarIntent =
        _consumePendingSharedCalendarRealDayViewIntentIfAny();
    if (consumedSharedCalendarIntent) {
      return;
    }
    unawaited(_loadCalendarState());
  }

  void _handleCalendarInvalidated(CalendarInvalidated invalidation) {
    if (!mounted) return;
    _schedulePendingCalendarInvalidationReload();
  }

  void _schedulePendingCalendarInvalidationReload() {
    if (!mounted) return;
    final pending = CalendarInvalidationBus.instance.peekPendingAfter(
      _calendarInvalidationScheduledRevision,
    );
    if (pending == null) return;
    _calendarInvalidationScheduledRevision = pending.revision;
    _scheduleCalendarInvalidationReload(
      pending.invalidation.reason,
      revision: pending.revision,
    );
  }

  void _scheduleCalendarInvalidationReload(
    CalendarInvalidationReason reason, {
    int? revision,
  }) {
    _calendarInvalidationReloadPending = true;
    _calendarInvalidationReloadReason = reason;
    if (revision != null) {
      _calendarInvalidationReloadRevision = revision;
    }
    if (_calendarInvalidationReloadInFlight) return;

    _calendarInvalidationReloadDebounce?.cancel();
    _calendarInvalidationReloadDebounce = Timer(
      const Duration(milliseconds: 80),
      _flushCalendarInvalidationReload,
    );
  }

  void _flushCalendarInvalidationReload() {
    _calendarInvalidationReloadDebounce?.cancel();
    _calendarInvalidationReloadDebounce = null;
    if (!mounted || !_calendarInvalidationReloadPending) return;
    if (_sharedCalendarRealDayViewOpening) {
      _calendarInvalidationReloadDebounce = Timer(
        const Duration(milliseconds: 80),
        _flushCalendarInvalidationReload,
      );
      return;
    }
    if (_calendarInvalidationReloadInFlight || _isLoadingFromDisk) {
      _calendarInvalidationReloadDebounce = Timer(
        const Duration(milliseconds: 80),
        _flushCalendarInvalidationReload,
      );
      return;
    }

    final reason = _calendarInvalidationReloadReason;
    final revision = _calendarInvalidationReloadRevision;
    _calendarInvalidationReloadPending = false;
    _calendarInvalidationReloadReason = null;
    _calendarInvalidationReloadRevision = null;
    _calendarInvalidationReloadInFlight = true;
    unawaited(
      _loadFromDisk(
            source: 'invalidation:${reason?.name ?? 'coalesced'}',
            preserveViewport: true,
          )
          .then((_) {
            if (revision != null) {
              CalendarInvalidationBus.instance.markConsumed(revision);
            }
          })
          .catchError((Object e, StackTrace st) {
            if (kDebugMode) {
              _calendarDebugPrint('[calendar] invalidation reload failed: $e');
              _calendarDebugPrint('$st');
            }
          })
          .whenComplete(() {
            _calendarInvalidationReloadInFlight = false;
            if (_calendarInvalidationReloadPending && mounted) {
              _flushCalendarInvalidationReload();
            }
          }),
    );
  }

  void _scheduleDaySheetResumeRestore() {
    if (_daySheetResumeAttempted) return;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_restoreDaySheetIfNeeded());
    });
  }

  void _schedulePushEventResumeRestore() {
    if (_pushEventResumeAttempted) return;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_restorePushEventIfNeeded());
    });
  }

  void _handleCalendarPushOpenIntent() {
    final intent = calendarPushOpenIntent.value;
    if (intent == null) return;
    if (_lastHandledCalendarPushIntentNonce == intent.nonce) return;
    _lastHandledCalendarPushIntentNonce = intent.nonce;
    unawaited(_openCalendarEventFromPush(intent));
  }

  Future<void> _restoreDaySheetIfNeeded([int attempt = 0]) async {
    if (!mounted || _daySheetResumeAttempted) return;
    if (!_restored) {
      if (attempt >= 20) return;
      await Future<void>.delayed(const Duration(milliseconds: 120));
      if (!mounted) return;
      return _restoreDaySheetIfNeeded(attempt + 1);
    }

    _daySheetResumeAttempted = true;
    final pendingPushEvent = await SessionResumeService.readResumeEntry(
      kind: _kSessionResumeKindPushEvent,
      baseRoute: '/',
    );
    if (pendingPushEvent != null) {
      await SessionResumeService.clearResumeEntry(
        kind: _kSessionResumeKindDaySheet,
      );
      return;
    }

    final entry = await SessionResumeService.consumeResumeEntry(
      kind: _kSessionResumeKindDaySheet,
      baseRoute: '/',
    );
    final payload =
        entry?.payload ??
        await AppRestorationService.instance.readDaySheetState();
    if (!mounted || payload == null) return;
    final kYear = (payload['kYear'] as num?)?.toInt();
    final kMonth = (payload['kMonth'] as num?)?.toInt();
    final kDay = (payload['kDay'] as num?)?.toInt();
    if (kYear == null || kMonth == null || kDay == null) {
      return;
    }

    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      _openDaySheet(
        kYear,
        kMonth,
        kDay,
        initialShowGregorian: payload['showGregorianDates'] == true,
        allowDateChange: payload['allowDateChange'] == true,
        initialStartTime: _timeOfDayFromSession(payload, 'start'),
        initialEndTime: _timeOfDayFromSession(payload, 'end'),
        initialAllDay: payload['allDay'] == true,
        initialTitle: payload['title'] as String?,
        initialLocation: payload['location'] as String?,
        initialDetail: payload['detail'] as String?,
        initialColor: _colorFromSessionValue(
          (payload['colorValue'] as num?)?.toInt(),
        ),
        initialCategory: payload['category'] as String?,
        initialAlertMinutes: (payload['alertMinutesBefore'] as num?)?.toInt(),
        initialCalendarId: payload['calendarId'] as String?,
        editingIndex: (payload['editingIndex'] as num?)?.toInt(),
        editingSourceKYear: (payload['editingSourceKYear'] as num?)?.toInt(),
        editingSourceKMonth: (payload['editingSourceKMonth'] as num?)?.toInt(),
        editingSourceKDay: (payload['editingSourceKDay'] as num?)?.toInt(),
      );
    });
  }

  Future<void> _restorePushEventIfNeeded([int attempt = 0]) async {
    if (!mounted || _pushEventResumeAttempted) return;
    if (!_restored) {
      if (attempt >= 20) return;
      await Future<void>.delayed(const Duration(milliseconds: 120));
      if (!mounted) return;
      return _restorePushEventIfNeeded(attempt + 1);
    }

    _pushEventResumeAttempted = true;
    final entry = await SessionResumeService.consumeResumeEntry(
      kind: _kSessionResumeKindPushEvent,
      baseRoute: '/',
    );
    if (!mounted || entry == null) return;

    final intent = CalendarPushOpenIntent.fromNotificationData(entry.payload);
    if (intent == null) {
      return;
    }

    await _openCalendarEventFromPush(intent);
  }

  ({int kYear, int kMonth, int kDay, int index, _Note note})?
  _findNoteLocationByPushIntent(CalendarPushOpenIntent intent) {
    final keys = intent.hasKemeticDate
        ? <String>[_kKey(intent.kYear!, intent.kMonth!, intent.kDay!)]
        : _notes.keys.toList(growable: false);

    for (final key in keys) {
      final notes = _notes[key];
      if (notes == null || notes.isEmpty) continue;
      final index = notes.indexWhere((note) {
        return _noteMatchesCalendarPushIntent(note, intent);
      });
      if (index < 0) continue;

      final parts = key.split('-');
      if (parts.length != 3) continue;
      final kYear = int.tryParse(parts[0]);
      final kMonth = int.tryParse(parts[1]);
      final kDay = int.tryParse(parts[2]);
      if (kYear == null || kMonth == null || kDay == null) continue;

      return (
        kYear: kYear,
        kMonth: kMonth,
        kDay: kDay,
        index: index,
        note: notes[index],
      );
    }

    return null;
  }

  bool _noteMatchesCalendarPushIntent(
    _Note note,
    CalendarPushOpenIntent intent,
  ) {
    final eventId = _trimmedCalendarPushValue(intent.eventId);
    if (eventId != null && (note.id?.trim() ?? '') == eventId) {
      return true;
    }

    final clientEventId = _trimmedCalendarPushValue(intent.clientEventId);
    if (clientEventId != null &&
        (note.clientEventId?.trim() ?? '') == clientEventId) {
      return true;
    }

    final reminderId = _trimmedCalendarPushValue(intent.reminderId);
    if (intent.itemType == calendarPushItemTypeReminder &&
        reminderId != null &&
        note.isReminder &&
        (note.reminderId?.trim() ?? '') == reminderId) {
      return true;
    }

    final flowId = intent.flowId;
    if (intent.itemType == calendarPushItemTypeFlowEvent &&
        flowId != null &&
        flowId > 0 &&
        note.flowId == flowId) {
      return true;
    }

    return false;
  }

  String? _trimmedCalendarPushValue(String? raw) {
    final value = raw?.trim();
    return value == null || value.isEmpty ? null : value;
  }

  EventDetailRestorationState? _eventDetailRestorationStateForPushIntent(
    CalendarPushOpenIntent intent, {
    required int kYear,
    required int kMonth,
    required int kDay,
    _Note? note,
    String? eventId,
    String? clientEventId,
  }) {
    final resolvedClientEventId =
        _trimmedCalendarPushValue(clientEventId) ??
        _trimmedCalendarPushValue(note?.clientEventId) ??
        _trimmedCalendarPushValue(intent.clientEventId);
    if (resolvedClientEventId != null) {
      return EventDetailRestorationState(
        kYear: kYear,
        kMonth: kMonth,
        kDay: kDay,
        identityType: eventDetailIdentityClientEventId,
        identityValue: resolvedClientEventId,
      );
    }

    final resolvedReminderId =
        _trimmedCalendarPushValue(note?.reminderId) ??
        _trimmedCalendarPushValue(intent.reminderId);
    if (resolvedReminderId != null) {
      return EventDetailRestorationState(
        kYear: kYear,
        kMonth: kMonth,
        kDay: kDay,
        identityType: eventDetailIdentityReminderId,
        identityValue: resolvedReminderId,
      );
    }

    final resolvedEventId =
        _trimmedCalendarPushValue(eventId) ??
        _trimmedCalendarPushValue(note?.id) ??
        _trimmedCalendarPushValue(intent.eventId);
    if (resolvedEventId != null) {
      return EventDetailRestorationState(
        kYear: kYear,
        kMonth: kMonth,
        kDay: kDay,
        identityType: eventDetailIdentityEventId,
        identityValue: resolvedEventId,
      );
    }

    return null;
  }

  Future<void> _openCalendarEventFromPush(
    CalendarPushOpenIntent intent, [
    int attempt = 0,
  ]) async {
    if (!mounted) return;
    if (!_restored) {
      if (attempt >= 20) return;
      await Future<void>.delayed(const Duration(milliseconds: 120));
      if (!mounted) return;
      return _openCalendarEventFromPush(intent, attempt + 1);
    }

    final localMatch = _findNoteLocationByPushIntent(intent);
    if (localMatch != null) {
      final note = localMatch.note;
      final detail = _eventDetailRestorationStateForPushIntent(
        intent,
        kYear: localMatch.kYear,
        kMonth: localMatch.kMonth,
        kDay: localMatch.kDay,
        note: note,
      );
      if (detail == null) return;
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!mounted) return;
        _openDayView(
          context,
          localMatch.kYear,
          localMatch.kMonth,
          localMatch.kDay,
          initialEventDetailRestorationState: detail,
        );
      });
      return;
    }

    final clientEventId = _trimmedCalendarPushValue(intent.clientEventId);
    if (clientEventId == null) {
      if (!intent.hasKemeticDate) return;
      final detail = _eventDetailRestorationStateForPushIntent(
        intent,
        kYear: intent.kYear!,
        kMonth: intent.kMonth!,
        kDay: intent.kDay!,
      );
      if (detail == null) return;
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!mounted) return;
        _openDayView(
          context,
          intent.kYear!,
          intent.kMonth!,
          intent.kDay!,
          initialEventDetailRestorationState: detail,
        );
      });
      return;
    }

    final event = await UserEventsRepo(
      Supabase.instance.client,
    ).getEventByClientEventId(clientEventId);
    if (!mounted || event == null) return;

    final localStart = event.startsAt.toLocal();
    final kDate = KemeticMath.fromGregorian(localStart);
    final detail = _eventDetailRestorationStateForPushIntent(
      intent,
      kYear: kDate.kYear,
      kMonth: kDate.kMonth,
      kDay: kDate.kDay,
      eventId: event.id,
      clientEventId: event.clientEventId ?? clientEventId,
    );
    if (detail == null) return;

    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      _openDayView(
        context,
        kDate.kYear,
        kDate.kMonth,
        kDate.kDay,
        initialEventDetailRestorationState: detail,
      );
    });
  }

  TimeOfDay? _timeOfDayFromSession(
    Map<String, dynamic> payload,
    String prefix,
  ) {
    final hour = (payload['${prefix}Hour'] as num?)?.toInt();
    final minute = (payload['${prefix}Minute'] as num?)?.toInt();
    if (hour == null || minute == null) return null;
    return TimeOfDay(hour: hour.clamp(0, 23), minute: minute.clamp(0, 59));
  }

  Color? _colorFromSessionValue(int? colorValue) {
    if (colorValue == null) return null;
    return Color(colorValue);
  }

  void _scheduleOnboardingPresentation() {
    if (_onboardingPresentationScheduled) return;
    _onboardingPresentationScheduled = true;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_maybePresentOnboarding());
    });
  }

  String? get _currentUserId =>
      Supabase.instance.client.auth.currentUser?.id.trim();

  Future<bool> _waitForOnboardingCalendarReady([int attempt = 0]) async {
    if (!mounted) return false;
    if (_restored && _initialViewportSettled) return true;
    if (attempt >= 24) return _restored;
    await Future<void>.delayed(const Duration(milliseconds: 120));
    return _waitForOnboardingCalendarReady(attempt + 1);
  }

  Future<HawCompassCopy> _loadOnboardingCompassCopy() async {
    final copy = await DecanCompassCopyRepo(
      Supabase.instance.client,
    ).loadForDay(kMonth: _today.kMonth, kDay: _today.kDay);
    _onboardingCompassCopy = copy;
    return copy;
  }

  Future<void> _saveOnboardingProgress(OnboardingProgress progress) async {
    final normalized = _withReflectionDecanBaseline(progress);
    _onboardingProgress = normalized;
    if (_onboardingReviewMode) {
      _onboardingReviewSessionProgress = normalized;
      return;
    }
    final userId = _currentUserId;
    if (userId == null || userId.isEmpty) return;
    await _onboardingProgressStorage.save(userId, normalized);
  }

  Future<void> _updateOnboardingProgress(
    OnboardingProgress Function(OnboardingProgress progress) update,
  ) async {
    await _saveOnboardingProgress(update(_onboardingProgress));
  }

  HawOnboardingSlide _hawSlideForProgress(OnboardingProgress progress) {
    switch (progress.currentStep) {
      case TrueOnboardingStep.welcome:
        return HawOnboardingSlide.exhale;
      case TrueOnboardingStep.currentDecanIntro:
        return HawOnboardingSlide.orientation;
      case TrueOnboardingStep.firstMaatFlow:
        return HawOnboardingSlide.recommendedFlow;
      case TrueOnboardingStep.firstFlowCalendarDay:
      case TrueOnboardingStep.firstFlowDayEvent:
      case TrueOnboardingStep.eventDetailObservedJournal:
      case TrueOnboardingStep.menuExplore:
        return HawOnboardingSlide.dayView;
      case TrueOnboardingStep.profileBasics:
      case TrueOnboardingStep.complete:
        return HawOnboardingSlide.exhale;
    }
  }

  TrueOnboardingStep _onboardingStepForHawSlide(HawOnboardingSlide slide) {
    switch (slide) {
      case HawOnboardingSlide.exhale:
      case HawOnboardingSlide.segmentation:
        return TrueOnboardingStep.welcome;
      case HawOnboardingSlide.orientation:
        return TrueOnboardingStep.currentDecanIntro;
      case HawOnboardingSlide.recommendedFlow:
        return TrueOnboardingStep.firstMaatFlow;
      case HawOnboardingSlide.dayView:
        return TrueOnboardingStep.firstFlowDayEvent;
      case HawOnboardingSlide.closing:
        return TrueOnboardingStep.eventDetailObservedJournal;
    }
  }

  void _handleHawSlideChanged(HawOnboardingSlide slide) {
    _activeHawOnboardingSlide = slide;
    if (_onboardingReviewMode) {
      _onboardingReviewSessionSlide = slide;
    }
    final step = _onboardingStepForHawSlide(slide);
    if (_onboardingProgress.currentStep == step &&
        (slide.index < HawOnboardingSlide.orientation.index ||
            _onboardingProgress.hasSeenCurrentDecanIntro)) {
      return;
    }
    unawaited(
      _updateOnboardingProgress(
        (progress) => progress.copyWith(
          currentStep: step,
          hasSeenWelcome: slide != HawOnboardingSlide.exhale,
          hasSeenCurrentDecanIntro:
              slide.index >= HawOnboardingSlide.orientation.index,
        ),
      ),
    );
  }

  Future<OnboardingProgress?> _markOnboardingHelperCompleted(
    String helperId, {
    bool clearActiveHelper = true,
  }) async {
    if (_onboardingReviewMode) {
      if (clearActiveHelper &&
          GuidedOnboardingController.instance.target?.variant ==
              CoachmarkVariant.helperBubble) {
        GuidedOnboardingController.instance.clear();
      }
      return _onboardingProgress;
    }
    final userId = _currentUserId;
    if (userId == null || userId.isEmpty) return null;
    final completion = OnboardingHelperCompletionService.instance
        .markHelperCompleted(userId, helperId);
    if (clearActiveHelper &&
        GuidedOnboardingController.instance.target?.variant ==
            CoachmarkVariant.helperBubble) {
      GuidedOnboardingController.instance.clear();
    }
    final updated = await completion;
    if (mounted) {
      _onboardingProgress = updated;
    }
    return updated;
  }

  String _onboardingContinuationStageKeyForUser(String userId) =>
      '$_onboardingContinuationStageKeyPrefix:$userId';

  String? _encodeOnboardingContinuationStage(
    _OnboardingContinuationStage stage,
  ) {
    switch (stage) {
      case _OnboardingContinuationStage.none:
        return null;
      case _OnboardingContinuationStage.awaitingCalendarReturnToggle:
        return 'awaiting_calendar_return_toggle';
      case _OnboardingContinuationStage.awaitingDayViewReveal:
        return 'awaiting_day_view_reveal';
    }
  }

  _OnboardingContinuationStage _decodeOnboardingContinuationStage(String? raw) {
    switch (raw) {
      case 'awaiting_calendar_return_toggle':
        return _OnboardingContinuationStage.awaitingCalendarReturnToggle;
      case 'awaiting_day_view_reveal':
        return _OnboardingContinuationStage.awaitingDayViewReveal;
      default:
        return _OnboardingContinuationStage.none;
    }
  }

  // ignore: unused_element
  Future<_OnboardingContinuationStage> _loadOnboardingContinuationStage(
    String userId,
  ) async {
    final prefs = await SharedPreferences.getInstance();
    return _decodeOnboardingContinuationStage(
      prefs.getString(_onboardingContinuationStageKeyForUser(userId)),
    );
  }

  Future<void> _persistOnboardingContinuationStage(
    _OnboardingContinuationStage stage,
  ) async {
    if (_onboardingReviewMode || _replayOnboardingOnEveryLaunch) return;

    final userId = Supabase.instance.client.auth.currentUser?.id;
    if (userId == null) return;

    final prefs = await SharedPreferences.getInstance();
    final key = _onboardingContinuationStageKeyForUser(userId);
    final encoded = _encodeOnboardingContinuationStage(stage);
    if (encoded == null) {
      await prefs.remove(key);
    } else {
      await prefs.setString(key, encoded);
    }
  }

  Future<void> _maybePresentOnboarding() async {
    if (!mounted || _showOnboarding) return;

    if (_onboardingReviewMode) {
      if (!_hasPresentedOnboardingThisLaunch) {
        _hasPresentedOnboardingThisLaunch = true;
        _onboardingReviewSessionProgress = const OnboardingProgress();
        _onboardingReviewSessionSlide = HawOnboardingSlide.exhale;
      }
      _onboardingProgress =
          _onboardingReviewSessionProgress ?? const OnboardingProgress();
      if (_onboardingProgress.currentStep == TrueOnboardingStep.complete) {
        return;
      }
      _activeHawOnboardingSlide =
          _onboardingReviewSessionSlide ??
          _hawSlideForProgress(_onboardingProgress);
      _hydrateFirstFlowTargetFromProgress(_onboardingProgress);
      await _waitForOnboardingCalendarReady();
      if (!mounted) return;
      await _loadOnboardingCompassCopy();
      if (!mounted) return;
      GuidedOnboardingController.instance.setExternalOverlaySuppressed(true);
      setState(() => _showOnboarding = true);
      return;
    }

    final userId = _currentUserId;
    if (userId == null) {
      _onboardingPresentationScheduled = false;
      return;
    }

    if (_replayOnboardingOnEveryLaunch) {
      if (_hasPresentedOnboardingThisLaunch) return;
      _hasPresentedOnboardingThisLaunch = true;
      await _saveOnboardingProgress(const OnboardingProgress());
      _activeHawOnboardingSlide = HawOnboardingSlide.exhale;
      await _loadOnboardingCompassCopy();
      GuidedOnboardingController.instance.setExternalOverlaySuppressed(true);
      setState(() => _showOnboarding = true);
      return;
    }

    final progress = _withReflectionDecanBaseline(
      await _onboardingProgressStorage.loadLocalReconciledWithLegacyCompletion(
        userId,
        legacyCompleted: () => _onboardingStorage.hasCompleted(userId),
      ),
    );
    _onboardingProgress = progress;
    _activeHawOnboardingSlide = _hawSlideForProgress(progress);
    _hydrateFirstFlowTargetFromProgress(progress);

    if (shouldPresentFinalOnboardingMenuHandoff(progress)) {
      await _waitForOnboardingCalendarReady();
      if (!mounted) return;
      GuidedOnboardingController.instance.setExternalOverlaySuppressed(true);
      _showMenuExploreCoachmark();
      return;
    }

    if (progress.currentStep == TrueOnboardingStep.eventDetailObservedJournal) {
      await _waitForOnboardingCalendarReady();
      if (!mounted) return;
      if (progress.onboardingDayRhythmState == OnboardingDayRhythmState.idle) {
        unawaited(_showOnboardingDayRhythm());
      } else {
        unawaited(_handleObservedJournalPromptNext());
      }
      return;
    }

    if (progress.completedOnboarding) {
      _onboardingContinuationStage = _OnboardingContinuationStage.none;
      _canShowCalendarToggleCoachmarkOnReturn = false;
      await _persistOnboardingContinuationStage(
        _OnboardingContinuationStage.none,
      );
      unawaited(_maybeShowCalendarHelperAfterOnboarding(progress));
      return;
    }

    await _waitForOnboardingCalendarReady();
    if (!mounted) return;
    await _loadOnboardingCompassCopy();
    if (!mounted) return;
    GuidedOnboardingController.instance.setExternalOverlaySuppressed(true);
    setState(() => _showOnboarding = true);
  }

  Future<void> _dismissOnboarding() async {
    if (!mounted) return;

    GuidedOnboardingController.instance.setExternalOverlaySuppressed(false);
    setState(() {
      _showOnboarding = false;
      _activeHawOnboardingSlide = HawOnboardingSlide.exhale;
    });
  }

  void _handleOnboardingSkip() {
    unawaited(_skipOnboarding(confirm: false));
  }

  void _handleOnboardingComplete() {
    unawaited(_completeHawOnboarding());
  }

  Future<void> _completeHawOnboarding() async {
    GuidedOnboardingController.instance.clear();
    await _dismissOnboarding();
    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        hasSeenWelcome: true,
        hasSeenCurrentDecanIntro: true,
        hasChosenFirstMaatFlow:
            progress.hasChosenFirstMaatFlow || _firstMaatFlowId != null,
        hasTappedFirstFlowDay: true,
        hasOpenedFirstFlowEvent: true,
        hasSeenObservedJournalPrompt: false,
        hasSeenMenuPrompt: false,
        currentStep: TrueOnboardingStep.eventDetailObservedJournal,
        completedOnboarding: false,
      ),
    );
    if (_onboardingReviewMode) {
      if (mounted) {
        setState(() {
          _reflectionPrompt = null;
          _showCalendarToggleCoachmark = false;
          _calendarAfterOnboardingHelperPrompted = false;
        });
      }
    }
    await _showOnboardingDayRhythm();
  }

  Future<void> _handleHawEntryStateSelected(String entryState) async {
    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        hasSeenWelcome: true,
        currentStep: TrueOnboardingStep.currentDecanIntro,
      ),
    );
    final userId = _currentUserId;
    if (!_onboardingReviewMode && userId != null && userId.isNotEmpty) {
      await DailyOrientationRepo(Supabase.instance.client).start(
        userId: userId,
        localDate: DateTime.now(),
        kemeticDayKey: kemeticDayKey(_today.kMonth, _today.kDay),
        entryState: entryState,
        chosenReturn: _onboardingCompassCopy?.dayAlignedReturnKey,
      );
    }
    if (!_onboardingReviewMode) {
      unawaited(
        Events.trackIfAuthed(
          'onboarding_entry_state_selected',
          <String, dynamic>{'entry_state': entryState},
        ),
      );
    }
  }

  Future<void> _handleHawRecommendedFlowJoined(int flowId) async {
    final template = _maatTemplateForKey(kEveningThresholdFlowKey);
    if (!_onboardingReviewMode && template != null) {
      CalendarPage._rememberJoinedMaatFlowTemplate(
        templateKey: template.key,
        flowId: flowId,
      );
      _myFlowsFilingSnapshotCache = null;
      await _flowsRepo.clearMyFiledFlowsCache();
    }
    final stagedTarget = _firstMaatFlowId == flowId
        ? _firstMaatFlowEventKDate
        : null;
    final stagedEvent = stagedTarget == null
        ? null
        : _firstFlowTargetNoteForDay(
            stagedTarget.ky,
            stagedTarget.km,
            stagedTarget.kd,
          );
    final firstEvent = stagedEvent != null && stagedTarget != null
        ? (
            ky: stagedTarget.ky,
            km: stagedTarget.km,
            kd: stagedTarget.kd,
            note: stagedEvent,
          )
        : _firstUpcomingNoteForFlow(flowId);
    final eventDate = firstEvent == null
        ? DateUtils.dateOnly(DateTime.now())
        : DateUtils.dateOnly(
            KemeticMath.toGregorian(
              firstEvent.ky,
              firstEvent.km,
              firstEvent.kd,
            ),
          );
    final kDate = firstEvent == null
        ? KemeticMath.fromGregorian(eventDate)
        : (kYear: firstEvent.ky, kMonth: firstEvent.km, kDay: firstEvent.kd);

    _firstMaatFlowId = flowId;
    _firstMaatFlowEventClientEventId =
        firstEvent?.note.clientEventId ?? _firstMaatFlowEventClientEventId;
    _firstMaatFlowEventKDate = (
      ky: kDate.kYear,
      km: kDate.kMonth,
      kd: kDate.kDay,
    );
    final canonicalDayRhythmIdentity =
        _firstMaatFlowOnboardingDayRhythmIdentity ??
        _onboardingDayRhythmIdentity();

    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        hasChosenFirstMaatFlow: true,
        firstMaatFlowId: flowId.toString(),
        firstMaatFlowTemplateId: kEveningThresholdFlowKey,
        firstMaatFlowEventDate: eventDate,
        firstMaatFlowEventClientEventId: _firstMaatFlowEventClientEventId,
        onboardingDayRhythmDateIdentity:
            progress.onboardingDayRhythmDateIdentity ??
            canonicalDayRhythmIdentity,
        currentStep: TrueOnboardingStep.firstFlowDayEvent,
      ),
    );
    if (mounted) {
      setState(() {});
    }
    if (!_onboardingReviewMode) {
      unawaited(
        Events.trackIfAuthed(
          'onboarding_evening_threshold_joined',
          <String, dynamic>{'flow_id': flowId},
        ),
      );
    }
  }

  Future<int> _addOnboardingReviewEveningThresholdInstance({
    required _MaatFlowTemplate template,
    DateTime? startDate,
    TrackSkyTimeZone? trackSkyTimeZone,
    String? eveningThresholdInitialCarry,
  }) async {
    final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
    final firstGregorian = DateUtils.dateOnly(
      startDate ?? defaultEveningThresholdStartDate(timezone),
    );
    final event = kEveningThresholdEvents.firstWhere(
      (candidate) => candidate.kind == EveningThresholdEventKind.theReturn,
      orElse: () => kEveningThresholdEvents.first,
    );
    final schedule = dailyEveningThresholdScheduleForDate(
      localDate: firstGregorian,
      timezone: timezone,
      event: event,
    );
    final eventDate = DateUtils.dateOnly(schedule.startLocal);
    final kDate = KemeticMath.fromGregorian(eventDate);
    final startTod = TimeOfDay(
      hour: schedule.startLocal.hour,
      minute: schedule.startLocal.minute,
    );
    final endTod = TimeOfDay(
      hour: schedule.endLocal.hour,
      minute: schedule.endLocal.minute,
    );
    final title = eveningThresholdEventTitle(event);
    final detail = eveningThresholdDetailText(event);
    final clientEventId = _buildCid(
      ky: kDate.kYear,
      km: kDate.kMonth,
      kd: kDate.kDay,
      title: title,
      startHour: startTod.hour,
      startMinute: startTod.minute,
      allDay: false,
      flowId: _onboardingReviewFirstFlowId,
    );
    final trimmedCarry = eveningThresholdInitialCarry?.trim();

    _flows.removeWhere((flow) => flow.id == _onboardingReviewFirstFlowId);
    _removeLocalNotesForFlowReplacement(_onboardingReviewFirstFlowId);
    _flows.add(
      _Flow(
        id: _onboardingReviewFirstFlowId,
        calendarId: _personalCalendarId,
        name: template.title,
        color: template.color,
        active: true,
        rules: <FlowRule>[
          _RuleDates(
            dates: <DateTime>{eventDate},
            allDay: false,
            start: startTod,
            end: endTod,
          ),
        ],
        start: eventDate,
        end: eventDate,
        notes: [
          'mode=review',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'review_only=1',
        ].join(';'),
      ),
    );
    _flowTotalEventCounts[_onboardingReviewFirstFlowId] = 1;
    _flowRemainingEventCounts[_onboardingReviewFirstFlowId] = 1;
    _addNote(
      kDate.kYear,
      kDate.kMonth,
      kDate.kDay,
      title,
      detail,
      clientEventId: clientEventId,
      calendarId: _personalCalendarId,
      allDay: false,
      start: startTod,
      end: endTod,
      flowId: _onboardingReviewFirstFlowId,
      category: 'Ritual',
      actionId: eveningThresholdActionId(event),
      behaviorPayload: <String, dynamic>{
        ...eveningThresholdBehaviorPayload(event: event, schedule: schedule),
        'review_mode': true,
        'review_source': 'onboarding_review',
        if (trimmedCarry != null && trimmedCarry.isNotEmpty)
          'review_initial_carry': trimmedCarry,
      },
      notify: false,
    );
    _firstMaatFlowOnboardingDayRhythmIdentity =
        dailyCosmicContextGregorianDateKey(trackSkyNowInZone(timezone));
    _notifyDayViewDataChanged();
    if (mounted) setState(() {});
    return _onboardingReviewFirstFlowId;
  }

  void _stageEveningThresholdOnboardingTarget({
    required _MaatFlowTemplate template,
    required int flowId,
    DateTime? startDate,
    TrackSkyTimeZone? trackSkyTimeZone,
    String? eveningThresholdInitialCarry,
  }) {
    if (flowId <= 0) return;
    final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
    final firstGregorian = DateUtils.dateOnly(
      startDate ?? defaultEveningThresholdStartDate(timezone),
    );
    final event = kEveningThresholdEvents.firstWhere(
      (candidate) => candidate.kind == EveningThresholdEventKind.theReturn,
      orElse: () => kEveningThresholdEvents.first,
    );
    final schedule = dailyEveningThresholdScheduleForDate(
      localDate: firstGregorian,
      timezone: timezone,
      event: event,
    );
    final eventDate = DateUtils.dateOnly(schedule.startLocal);
    final kDate = KemeticMath.fromGregorian(eventDate);
    final startTod = TimeOfDay(
      hour: schedule.startLocal.hour,
      minute: schedule.startLocal.minute,
    );
    final endTod = TimeOfDay(
      hour: schedule.endLocal.hour,
      minute: schedule.endLocal.minute,
    );
    final title = eveningThresholdEventTitle(event);
    final detail = eveningThresholdDetailText(event);
    final clientEventId = _buildCid(
      ky: kDate.kYear,
      km: kDate.kMonth,
      kd: kDate.kDay,
      title: title,
      startHour: startTod.hour,
      startMinute: startTod.minute,
      allDay: false,
      flowId: flowId,
    );
    final trimmedCarry = eveningThresholdInitialCarry?.trim();

    _flows.removeWhere((flow) => flow.id == flowId);
    _removeLocalNotesForFlowReplacement(flowId);
    _flows.add(
      _Flow(
        id: flowId,
        calendarId: _personalCalendarId,
        name: template.title,
        color: template.color,
        active: true,
        rules: <FlowRule>[
          _RuleDates(
            dates: <DateTime>{eventDate},
            allDay: false,
            start: startTod,
            end: endTod,
          ),
        ],
        start: eventDate,
        end: eventDate,
        notes: [
          'mode=onboarding_preview',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'evening_threshold_tz=${timezone.key}',
        ].join(';'),
      ),
    );
    _flowTotalEventCounts[flowId] = 1;
    _flowRemainingEventCounts[flowId] = 1;
    _addNote(
      kDate.kYear,
      kDate.kMonth,
      kDate.kDay,
      title,
      detail,
      clientEventId: clientEventId,
      calendarId: _personalCalendarId,
      allDay: false,
      start: startTod,
      end: endTod,
      flowId: flowId,
      category: 'Ritual',
      actionId: eveningThresholdActionId(event),
      behaviorPayload: <String, dynamic>{
        ...eveningThresholdBehaviorPayload(event: event, schedule: schedule),
        if (trimmedCarry != null && trimmedCarry.isNotEmpty)
          'onboarding_initial_carry': trimmedCarry,
      },
      notify: false,
    );

    _firstMaatFlowId = flowId;
    _firstMaatFlowEventClientEventId = clientEventId;
    _firstMaatFlowEventKDate = (
      ky: kDate.kYear,
      km: kDate.kMonth,
      kd: kDate.kDay,
    );
    _firstMaatFlowOnboardingDayRhythmIdentity =
        dailyCosmicContextGregorianDateKey(trackSkyNowInZone(timezone));
    _rememberPendingOnboardingTargetEvent(
      dayKey: _kKey(kDate.kYear, kDate.kMonth, kDate.kDay),
      flowId: flowId,
      clientEventId: clientEventId,
    );
    _notifyDayViewDataChanged();
    if (mounted) setState(() {});
  }

  Widget _buildHawRecommendedFlow(
    BuildContext context,
    Future<void> Function(int flowId) advance,
  ) {
    final template = _maatTemplateForKey(kEveningThresholdFlowKey);
    if (template == null) {
      return const Center(
        child: Text(
          'The Evening Threshold is not available right now.',
          style: TextStyle(color: Colors.white70),
        ),
      );
    }
    return _MaatFlowTemplateDetailPage(
      template: template,
      showBackButton: false,
      embeddedInOnboarding: true,
      addInstance:
          ({
            required _MaatFlowTemplate template,
            DateTime? startDate,
            bool? useKemetic,
            TrackSkyTimeZone? trackSkyTimeZone,
            int? alertMinutesBefore,
            bool? dawnDiscreetMode,
            DawnHouseRiteLens? dawnLens,
            bool? eveningDiscreetMode,
            EveningThresholdRiteLens? eveningLens,
            int? eveningFallbackMinutesAfterMidnight,
            TheWeighingLens? theWeighingLens,
            OfferingTableLens? offeringTableLens,
            bool? offeringNoCupMode,
            TheTendingLens? theTendingLens,
            KeptWordLens? keptWordLens,
            CourseLens? courseLens,
            MoonReturnLens? moonReturnLens,
            WagLens? wagLens,
            DecanWatchLens? decanWatchLens,
            OpenHandLens? openHandLens,
            DjedLens? djedLens,
            List<ReadingHouseSitting>? readingHouseSittings,
            String? eveningThresholdInitialCarry,
          }) {
            if (_onboardingReviewMode) {
              return _addOnboardingReviewEveningThresholdInstance(
                template: template,
                startDate: startDate,
                trackSkyTimeZone: trackSkyTimeZone,
                eveningThresholdInitialCarry: eveningThresholdInitialCarry,
              );
            }
            final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
            return _addMaatFlowInstance(
              template: template,
              startDate: startDate,
              useKemetic: useKemetic ?? false,
              trackSkyTimeZone: timezone,
              alertMinutesBefore: alertMinutesBefore ?? _alertNoneMinutes,
              dawnDiscreetMode: dawnDiscreetMode ?? false,
              dawnLens: dawnLens ?? DawnHouseRiteLens.neutral,
              eveningDiscreetMode: eveningDiscreetMode ?? false,
              eveningLens: eveningLens ?? EveningThresholdRiteLens.neutral,
              eveningFallbackMinutesAfterMidnight:
                  eveningFallbackMinutesAfterMidnight ??
                  kEveningThresholdDefaultFallbackMinutes,
              theWeighingLens: theWeighingLens ?? TheWeighingLens.neutral,
              offeringTableLens: offeringTableLens ?? OfferingTableLens.neutral,
              offeringNoCupMode: offeringNoCupMode ?? false,
              theTendingLens: theTendingLens ?? TheTendingLens.neutral,
              keptWordLens: keptWordLens ?? KeptWordLens.neutral,
              courseLens: courseLens ?? CourseLens.neutral,
              moonReturnLens: moonReturnLens ?? MoonReturnLens.neutral,
              wagLens: wagLens ?? WagLens.neutral,
              decanWatchLens: decanWatchLens ?? DecanWatchLens.neutral,
              openHandLens: openHandLens ?? OpenHandLens.neutral,
              djedLens: djedLens ?? DjedLens.neutral,
              readingHouseSittings: readingHouseSittings,
              eveningThresholdInitialCarry: eveningThresholdInitialCarry,
              deferEveningThresholdRemainingEvents: true,
              reloadAfterHeadlessJoin: false,
            ).then((flowId) {
              if (flowId > 0) {
                _stageEveningThresholdOnboardingTarget(
                  template: template,
                  flowId: flowId,
                  startDate: startDate,
                  trackSkyTimeZone: timezone,
                  eveningThresholdInitialCarry: eveningThresholdInitialCarry,
                );
              }
              return flowId;
            });
          },
      onJoined: (flowId) async {
        await _handleHawRecommendedFlowJoined(flowId);
        await advance(flowId);
      },
    );
  }

  Widget _buildHawDayView(
    BuildContext context,
    VoidCallback onEventOpened,
    VoidCallback onClosingComplete,
  ) {
    final target =
        _firstMaatFlowEventKDate ??
        (ky: _today.kYear, km: _today.kMonth, kd: _today.kDay);
    final targetNote = _firstFlowTargetNoteForDay(
      target.ky,
      target.km,
      target.kd,
    );
    final focusEvent = targetNote == null ? null : _noteToEventItem(targetNote);
    final isolateOnboardingTarget =
        _showOnboarding &&
        !_onboardingProgress.completedOnboarding &&
        _activeHawOnboardingSlide.index >= HawOnboardingSlide.dayView.index;

    List<NoteData> notesForDayFn(int y, int m, int d) {
      if (_onboardingReviewMode || isolateOnboardingTarget) {
        if (targetNote == null ||
            y != target.ky ||
            m != target.km ||
            d != target.kd) {
          return const <NoteData>[];
        }
        return <NoteData>[_noteDataFromNote(targetNote)];
      }
      return _noteDataForDay(y, m, d);
    }

    return DayViewPage(
      initialKy: target.ky,
      initialKm: target.km,
      initialKd: target.kd,
      showGregorian: _showGregorian,
      notesForDay: notesForDayFn,
      flowIndex: _buildCalendarFlowChromeIndex(),
      flowIndexBuilder: _buildCalendarFlowChromeIndex,
      activeLedgerFlowIds: _buildActiveLedgerFlowIds(),
      activeLedgerFlowIdsBuilder: _buildActiveLedgerFlowIds,
      dataVersion: _dayViewDataVersion,
      getMonthName: (km) => getMonthById(km).displayFull,
      initialFirstVisibleMinute: focusEvent == null
          ? null
          : (focusEvent.startMin - 60).clamp(0, 24 * 60 - 1).toInt(),
      focusStartMin: focusEvent?.startMin,
      focusFlowId: focusEvent?.flowId,
      focusTitle: focusEvent?.title,
      eventDetailRequestListenable: _dayViewEventDetailRequest,
      onEventDetailRequestHandled: () {
        if (_dayViewEventDetailRequest.value != null) {
          _dayViewEventDetailRequest.value = null;
        }
      },
      onClose: () {},
      onManageFlows: (flowId) => _getMyFlowsCallback()(flowId),
      onOpenQuickAdd: (_) => _openQuickAddSheet(),
      onOpenSearch: (ctx) async => _openSearchForContext(ctx),
      onOpenProfile: (ctx) => _openProfile(ctx),
      onDeleteNote: (ky, km, kd, evt) async {
        await _deleteNoteByEvent(ky, km, kd, evt);
      },
      onEditNote: (ky, km, kd, evt) async {
        await _editNoteByEvent(ky, km, kd, evt);
      },
      onMoveEventTime: _moveEventInDayView,
      onShareNote: (evt) async {
        await _shareNoteSimple(evt);
      },
      onAddNote: (ky, km, kd) =>
          _openDaySheet(ky, km, kd, allowDateChange: true),
      onOpenAddNoteWithTime:
          (
            ky,
            km,
            kd, {
            TimeOfDay? start,
            TimeOfDay? end,
            bool allDay = false,
          }) {
            _openDaySheet(
              ky,
              km,
              kd,
              allowDateChange: true,
              initialStartTime: start,
              initialEndTime: end,
              initialAllDay: allDay,
            );
          },
      onCreateTimedEvent: _handleCreateTimedEvent,
      onEndFlow: (id) => _endFlow(id),
      onEditReminder: (id) => _editReminderById(id),
      onEndReminder: (id) => _endReminderRule(id),
      onShareReminder: (evt) => _shareNoteSimple(evt),
      onAppendToJournal: _appendToJournalAndRefresh,
      onWriteJournalResponse: _writeMaatJournalResponseBlockAndRefresh,
      onSaveFlow: _saveFlowById,
      loadCompletedClientEventIds: _loadCompletedClientEventIds,
      onRecordCompletion:
          ({
            required String clientEventId,
            required int flowId,
            required DateTime completedOnDate,
            Map<String, dynamic>? metadata,
          }) => _recordEventCompletion(
            clientEventId: clientEventId,
            flowId: flowId,
            completedOnDate: completedOnDate,
            metadata: metadata,
          ),
      onUnrecordCompletion: _unrecordEventCompletion,
      onRemoveCompletionBadge: _removeCompletionBadgeAndRefresh,
      onboardingEventClientEventId: _firstMaatFlowEventClientEventId,
      onboardingEventTargetKey: _firstFlowEventBlockKey,
      onOnboardingEventOpened: () {
        _onboardingProgress = _onboardingProgress.copyWith(
          hasOpenedFirstFlowEvent: true,
          currentStep: TrueOnboardingStep.eventDetailObservedJournal,
        );
        final userId = _currentUserId;
        if (!_onboardingReviewMode && userId != null) {
          unawaited(
            _onboardingProgressStorage.save(userId, _onboardingProgress),
          );
        }
        onEventOpened();
      },
      onboardingClosingBannerBuilder: (sheetContext) =>
          HawOnboardingClosingBanner(
            onComplete: () {
              Navigator.of(sheetContext).maybePop();
              onClosingComplete();
            },
          ),
      shouldPreserveEventDetailRestorationOnClose: () => false,
    );
  }

  Future<void> _skipOnboarding({required bool confirm}) async {
    if (confirm && mounted) {
      final shouldSkip = await showDialog<bool>(
        context: context,
        builder: (dialogContext) {
          return AlertDialog(
            backgroundColor: const Color(0xFF090909),
            title: const Text(
              'Skip setup?',
              style: TextStyle(color: Colors.white),
            ),
            content: const Text(
              'You can still create Ma’at Flows later from the Flows page.',
              style: TextStyle(color: Colors.white70),
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.of(dialogContext).pop(false),
                child: const Text('Stay'),
              ),
              FilledButton(
                onPressed: () => Navigator.of(dialogContext).pop(true),
                child: const Text('Skip'),
              ),
            ],
          );
        },
      );
      if (shouldSkip != true) return;
    }

    GuidedOnboardingController.instance.clear();
    await _dismissOnboarding();
    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        currentStep: TrueOnboardingStep.complete,
        completedOnboarding: true,
        skippedOnboarding: true,
      ),
    );
    final userId = _currentUserId;
    if (!_onboardingReviewMode && userId != null && userId.isNotEmpty) {
      await DailyOrientationRepo(
        Supabase.instance.client,
      ).skip(userId: userId, localDate: DateTime.now());
    }
    if (!_onboardingReviewMode) {
      unawaited(
        Events.trackIfAuthed('onboarding_skipped', const <String, dynamic>{}),
      );
    }
    await _markOnboardingCompletedIfNeeded();
    if (mounted) {
      context.go('/');
    }
  }

  Future<void> _markOnboardingCompletedIfNeeded() async {
    if (_onboardingReviewMode) return;
    if (_replayOnboardingOnEveryLaunch) return;

    _onboardingContinuationStage = _OnboardingContinuationStage.none;
    _canShowCalendarToggleCoachmarkOnReturn = false;
    final userId = Supabase.instance.client.auth.currentUser?.id;
    if (userId == null) return;
    await _persistOnboardingContinuationStage(
      _OnboardingContinuationStage.none,
    );
    final completeProgress = markOnboardingProgressComplete(
      _onboardingProgress,
    );
    final currentDecan = _currentOnboardingDecanIdentity();
    _onboardingProgress =
        completeProgress.reflectionSignupDecanIdentity?.trim().isNotEmpty ==
            true
        ? completeProgress
        : (currentDecan == null
              ? completeProgress
              : completeProgress.copyWith(
                  reflectionSignupDecanIdentity: currentDecan.wireName,
                ));
    await _onboardingProgressStorage.save(userId, _onboardingProgress);
    await _onboardingStorage.markCompleted(userId);
  }

  void _hydrateFirstFlowTargetFromProgress(OnboardingProgress progress) {
    _firstMaatFlowId = int.tryParse(progress.firstMaatFlowId ?? '');
    _firstMaatFlowEventClientEventId = progress.firstMaatFlowEventClientEventId;
    _firstMaatFlowOnboardingDayRhythmIdentity =
        progress.onboardingDayRhythmDateIdentity;
    final eventDate = progress.firstMaatFlowEventDate;
    if (eventDate == null) {
      _firstMaatFlowEventKDate = null;
    } else {
      final kDate = KemeticMath.fromGregorian(DateUtils.dateOnly(eventDate));
      _firstMaatFlowEventKDate = (
        ky: kDate.kYear,
        km: kDate.kMonth,
        kd: kDate.kDay,
      );
    }
  }

  // ignore: unused_element
  Future<void> _presentTrueOnboardingStep(TrueOnboardingStep step) async {
    if (!mounted) return;
    if (step != TrueOnboardingStep.complete) {
      GuidedOnboardingController.instance.setExternalOverlaySuppressed(true);
    }
    switch (step) {
      case TrueOnboardingStep.welcome:
        setState(() => _showOnboarding = true);
        return;
      case TrueOnboardingStep.currentDecanIntro:
        _showCurrentDecanIntroCoachmark();
        return;
      case TrueOnboardingStep.profileBasics:
        await _routeToProfileBasics();
        return;
      case TrueOnboardingStep.firstMaatFlow:
        unawaited(_openFirstMaatFlowOnboardingSheet());
        return;
      case TrueOnboardingStep.firstFlowCalendarDay:
        _hydrateFirstFlowTargetFromProgress(_onboardingProgress);
        _alignCalendarToFirstFlowEvent();
        _showFirstFlowCalendarDayCoachmark();
        return;
      case TrueOnboardingStep.firstFlowDayEvent:
        _showFirstFlowDayEventCoachmark();
        return;
      case TrueOnboardingStep.eventDetailObservedJournal:
        return;
      case TrueOnboardingStep.menuExplore:
        _showMenuExploreCoachmark();
        return;
      case TrueOnboardingStep.complete:
        return;
    }
  }

  String _currentDecanName({bool expanded = true}) {
    return DecanMetadata.decanNameFor(
      kMonth: _today.kMonth.clamp(1, 12).toInt(),
      kDay: _today.kDay,
      expanded: expanded,
    );
  }

  String _currentDecanSynopsis() {
    final dayKey = _getKemeticDayKey(_today.kYear, _today.kMonth, _today.kDay);
    final info = KemeticDayData.getInfoForDay(dayKey);
    final context = info?.cosmicContext.trim();
    if (context != null && context.isNotEmpty) {
      final sentences = context
          .split(RegExp(r'(?<=[.!?])\s+'))
          .where((part) => part.trim().isNotEmpty)
          .take(2)
          .join(' ');
      if (sentences.trim().isNotEmpty) return sentences.trim();
    }
    return 'This ten-day rhythm gives you a place to observe, return, and realign. Use it to notice what is rising in your life and what needs to be brought back into order.';
  }

  void _showCurrentDecanIntroCoachmark() {
    if (!mounted || _showingCurrentDecanIntroCoachmark) return;
    _showingCurrentDecanIntroCoachmark = true;
    final decanIndex = decanForDay(_today.kDay) - 1;
    final targetKey = keyForCurrentDecanHeader(
      _today.kYear,
      _today.kMonth.clamp(1, 12).toInt(),
      decanIndex.clamp(0, 2).toInt(),
    );
    _setView(_today.kYear, _today.kMonth, kd: _today.kDay);
    _centerMonth(_today.kYear, _today.kMonth);
    GuidedOnboardingController.instance.show(
      CoachmarkTarget(
        key: targetKey,
        title: 'You are in ${_currentDecanName()}.',
        body: _currentDecanSynopsis(),
        instruction: 'Tap the decan name to learn more about its meaning.',
        placement: CoachmarkPlacement.below,
        allowBackgroundInteraction: true,
        showNextButton: true,
        showSkipButton: true,
        onSkip: () => unawaited(_skipOnboarding(confirm: true)),
        onNext: () => unawaited(_handleCurrentDecanNext()),
      ),
    );
    if (!_onboardingReviewMode) {
      unawaited(
        Events.trackIfAuthed('onboarding_current_decan_seen', <String, dynamic>{
          'decan': _currentDecanName(expanded: false),
        }),
      );
    }
  }

  Future<void> _handleCurrentDecanNext() async {
    _showingCurrentDecanIntroCoachmark = false;
    GuidedOnboardingController.instance.clear();
    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        hasSeenCurrentDecanIntro: true,
        currentStep: TrueOnboardingStep.profileBasics,
      ),
    );
    if (!mounted) return;
    await _routeToProfileBasics();
  }

  Future<bool> _hasCompletedProfileBasics() async {
    final userId = _currentUserId;
    if (userId == null || userId.isEmpty) return false;
    final profile =
        await ProfileRepo(Supabase.instance.client).getMyProfile() ??
        UserProfile(
          id: userId,
          isDiscoverable: true,
          allowIncomingShares: true,
        );
    return hasCompletedProfileBasics(
      avatarGlyphIds: profile.avatarGlyphIds,
      displayName: profile.displayName,
      handle: profile.handle,
    );
  }

  Future<void> _routeToProfileBasics() async {
    if (!mounted) return;
    GuidedOnboardingController.instance.setExternalOverlaySuppressed(true);
    final complete = await _hasCompletedProfileBasics();
    if (!mounted) return;
    if (complete) {
      context.go('/profile/me?onboarding=1');
    } else {
      context.go('/profile/me/edit?requireCompletion=1&onboarding=1');
    }
  }

  Future<void> _openFirstMaatFlowOnboardingSheet() async {
    if (!mounted || _firstMaatFlowSheetOpenOrOpening) return;
    _firstMaatFlowSheetOpenOrOpening = true;
    GuidedOnboardingController.instance.clear();
    unawaited(
      Events.trackIfAuthed(
        'onboarding_first_maat_flow_sheet_opened',
        const <String, dynamic>{},
      ),
    );

    try {
      await _loadFromDisk(source: 'onboarding_first_maat_flow');
      if (!mounted) return;
      await showModalBottomSheet<void>(
        context: context,
        useSafeArea: true,
        isScrollControlled: true,
        backgroundColor: Colors.transparent,
        builder: (sheetContext) {
          return _FirstMaatFlowOnboardingSheet(
            templates: _kMaatFlowTemplates,
            onAddFlow: (template) async {
              final id = await _addMaatFlowInstance(
                template: template,
                startDate: DateTime.now(),
              );
              if (id <= 0) return;
              if (sheetContext.mounted) {
                Navigator.of(sheetContext).pop();
              }
              await _handleFirstMaatFlowAdded(template, id);
            },
          );
        },
      );
    } finally {
      _firstMaatFlowSheetOpenOrOpening = false;
    }
  }

  Future<void> _handleFirstMaatFlowAdded(
    _MaatFlowTemplate template,
    int flowId,
  ) async {
    CalendarPage._rememberJoinedMaatFlowTemplate(
      templateKey: template.key,
      flowId: flowId,
    );
    _myFlowsFilingSnapshotCache = null;
    await _flowsRepo.clearMyFiledFlowsCache();
    await _loadFromDisk(source: 'onboarding_first_maat_flow_added');
    final firstEvent = _firstUpcomingNoteForFlow(flowId);
    final eventDate = firstEvent == null
        ? DateUtils.dateOnly(DateTime.now())
        : DateUtils.dateOnly(
            KemeticMath.toGregorian(
              firstEvent.ky,
              firstEvent.km,
              firstEvent.kd,
            ),
          );
    final kDate = firstEvent == null
        ? KemeticMath.fromGregorian(eventDate)
        : (kYear: firstEvent.ky, kMonth: firstEvent.km, kDay: firstEvent.kd);

    _firstMaatFlowId = flowId;
    _firstMaatFlowEventClientEventId = firstEvent?.note.clientEventId;
    _firstMaatFlowEventKDate = (
      ky: kDate.kYear,
      km: kDate.kMonth,
      kd: kDate.kDay,
    );
    final canonicalDayRhythmIdentity =
        _firstMaatFlowOnboardingDayRhythmIdentity ??
        _onboardingDayRhythmIdentity();

    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        hasChosenFirstMaatFlow: true,
        firstMaatFlowId: flowId.toString(),
        firstMaatFlowTemplateId: template.key,
        firstMaatFlowEventDate: eventDate,
        firstMaatFlowEventClientEventId: firstEvent?.note.clientEventId,
        onboardingDayRhythmDateIdentity:
            progress.onboardingDayRhythmDateIdentity ??
            canonicalDayRhythmIdentity,
        currentStep: TrueOnboardingStep.firstFlowCalendarDay,
      ),
    );
    unawaited(
      Events.trackIfAuthed(
        'onboarding_first_maat_flow_added',
        <String, dynamic>{'flow_id': flowId, 'template_key': template.key},
      ),
    );
    if (!mounted) return;
    context.go('/');
    _alignCalendarToFirstFlowEvent();
    _showFirstFlowCalendarDayCoachmark();
  }

  ({int ky, int km, int kd, _Note note})? _firstUpcomingNoteForFlow(
    int flowId,
  ) {
    final today = DateUtils.dateOnly(DateTime.now());
    final candidates =
        <({int ky, int km, int kd, DateTime date, _Note note})>[];
    for (final entry in _notes.entries) {
      final parts = entry.key.split('-');
      if (parts.length != 3) continue;
      final ky = int.tryParse(parts[0]);
      final km = int.tryParse(parts[1]);
      final kd = int.tryParse(parts[2]);
      if (ky == null || km == null || kd == null) continue;
      final date = DateUtils.dateOnly(KemeticMath.toGregorian(ky, km, kd));
      for (final note in entry.value) {
        if (note.flowId == flowId) {
          candidates.add((ky: ky, km: km, kd: kd, date: date, note: note));
        }
      }
    }
    if (candidates.isEmpty) return null;
    candidates.sort((a, b) {
      final aFuture = !a.date.isBefore(today);
      final bFuture = !b.date.isBefore(today);
      if (aFuture != bFuture) return aFuture ? -1 : 1;
      final byDate = a.date.compareTo(b.date);
      if (byDate != 0) return byDate;
      final aStart = a.note.allDay
          ? 0
          : (a.note.start?.hour ?? 9) * 60 + (a.note.start?.minute ?? 0);
      final bStart = b.note.allDay
          ? 0
          : (b.note.start?.hour ?? 9) * 60 + (b.note.start?.minute ?? 0);
      return aStart.compareTo(bStart);
    });
    final first = candidates.first;
    return (ky: first.ky, km: first.km, kd: first.kd, note: first.note);
  }

  ({int ky, int km, int kd, _Note note})?
  _focusCalendarOnFirstUpcomingFlowEvent(int flowId) {
    final firstEvent = _firstUpcomingNoteForFlow(flowId);
    if (firstEvent == null) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[maatFlowJoin] no hydrated event found for flow $flowId after join',
        );
      }
      return null;
    }
    _setView(firstEvent.ky, firstEvent.km, kd: firstEvent.kd);
    _centerMonth(firstEvent.ky, firstEvent.km);
    return firstEvent;
  }

  _Note? _firstFlowTargetNoteForDay(int ky, int km, int kd) {
    final notes = _notes['$ky-$km-$kd'] ?? const <_Note>[];
    final targetClientEventId = _firstMaatFlowEventClientEventId?.trim();
    if (targetClientEventId != null && targetClientEventId.isNotEmpty) {
      for (final note in notes) {
        if (note.clientEventId == targetClientEventId) return note;
      }
    }
    final flowId = _firstMaatFlowId;
    if (flowId != null) {
      for (final note in notes) {
        if (note.flowId == flowId) return note;
      }
    }
    return notes.isEmpty ? null : notes.first;
  }

