  DateTime? _dateFromDayRhythmIdentity(String? identity) {
    final trimmed = identity?.trim();
    if (trimmed == null || trimmed.isEmpty) return null;
    final pieces = trimmed.split('-');
    if (pieces.length != 3) return null;
    final year = int.tryParse(pieces[0]);
    final month = int.tryParse(pieces[1]);
    final day = int.tryParse(pieces[2]);
    if (year == null || month == null || day == null) return null;
    return DateTime(year, month, day);
  }

  DateTime _onboardingDayRhythmDate() {
    return DateUtils.dateOnly(
      _dateFromDayRhythmIdentity(
            _onboardingProgress.onboardingDayRhythmDateIdentity,
          ) ??
          trackSkyNowInZone(detectTrackSkyTimeZone()),
    );
  }

  String _onboardingDayRhythmIdentity() {
    return dailyCosmicContextGregorianDateKey(_onboardingDayRhythmDate());
  }

  Future<void> _showOnboardingDayRhythm() async {
    if (!mounted) return;
    final rhythmState = _onboardingProgress.onboardingDayRhythmState;
    if (rhythmState == OnboardingDayRhythmState.completed) {
      if (_onboardingProgress.lastSatisfiedDayRhythmIdentity == null) {
        final identity =
            _onboardingProgress.onboardingDayRhythmDateIdentity ??
            _onboardingDayRhythmIdentity();
        await _updateOnboardingProgress(
          (progress) => progress.copyWith(
            onboardingDayRhythmDateIdentity:
                progress.onboardingDayRhythmDateIdentity ?? identity,
            lastSatisfiedDayRhythmIdentity: identity,
          ),
        );
        final userId = _currentUserId;
        if (!_onboardingReviewMode &&
            userId != null &&
            userId.trim().isNotEmpty) {
          await DailyCosmicContextPrefs().markShown(userId.trim(), identity);
        }
      }
      await _handleObservedJournalPromptNext();
      return;
    }
    if (rhythmState == OnboardingDayRhythmState.scheduled ||
        rhythmState == OnboardingDayRhythmState.visible) {
      return;
    }

    final rhythmDate = _onboardingDayRhythmDate();
    final rhythmIdentity = dailyCosmicContextGregorianDateKey(rhythmDate);
    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        currentStep: TrueOnboardingStep.eventDetailObservedJournal,
        completedOnboarding: false,
        hasSeenObservedJournalPrompt: false,
        hasSeenMenuPrompt: false,
        onboardingDayRhythmState: OnboardingDayRhythmState.scheduled,
        onboardingDayRhythmDateIdentity: rhythmIdentity,
      ),
    );
    if (!mounted) return;
    GuidedOnboardingController.instance.clear();
    GuidedOnboardingController.instance.setExternalOverlaySuppressed(true);

    final badge = dailyCosmicContextBadgeForDate(rhythmDate);
    if (badge == null) {
      await _handleOnboardingDayRhythmDismissed();
      return;
    }

    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        onboardingDayRhythmState: OnboardingDayRhythmState.visible,
        onboardingDayRhythmDateIdentity: badge.gregorianDateKey,
      ),
    );
    if (!mounted) return;
    _onboardingDayRhythmController.showOnboardingBadge(
      badge,
      onDismissed: () => unawaited(_handleOnboardingDayRhythmDismissed()),
    );
  }

  Future<void> _handleOnboardingDayRhythmDismissed() async {
    final identity =
        _onboardingProgress.onboardingDayRhythmDateIdentity ??
        _onboardingDayRhythmIdentity();
    if (_onboardingProgress.onboardingDayRhythmState !=
            OnboardingDayRhythmState.completed ||
        _onboardingProgress.lastSatisfiedDayRhythmIdentity != identity) {
      await _updateOnboardingProgress(
        (progress) => progress.copyWith(
          onboardingDayRhythmState: OnboardingDayRhythmState.completed,
          onboardingDayRhythmDateIdentity:
              progress.onboardingDayRhythmDateIdentity ?? identity,
          lastSatisfiedDayRhythmIdentity: identity,
        ),
      );
    }
    final userId = _currentUserId;
    if (!_onboardingReviewMode && userId != null && userId.trim().isNotEmpty) {
      await DailyCosmicContextPrefs().markShown(userId.trim(), identity);
    }
    await _handleObservedJournalPromptNext();
  }

  Future<void> _handleObservedJournalPromptNext() async {
    if (_onboardingProgress.currentStep == TrueOnboardingStep.complete) {
      return;
    }
    if (_onboardingProgress.currentStep == TrueOnboardingStep.menuExplore ||
        _onboardingProgress.hasSeenObservedJournalPrompt) {
      _showMenuExploreCoachmark();
      return;
    }
    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        hasSeenObservedJournalPrompt: true,
        hasSeenMenuPrompt: false,
        currentStep: TrueOnboardingStep.menuExplore,
        completedOnboarding: false,
      ),
    );
    _showMenuExploreCoachmark();
  }

  void _showMenuExploreCoachmark() {
    if (!mounted) return;
    unawaited(_showMenuExploreCoachmarkWhenReady());
  }

  Future<void> _showMenuExploreCoachmarkWhenReady() async {
    await _waitForCoachmarkTargetReady(globalMenuButtonKey);
    if (!mounted) return;
    if (!shouldPresentFinalOnboardingMenuHandoff(_onboardingProgress)) {
      return;
    }
    const helper = OnboardingHelperRegistry.calendarMenuExplore;
    final helperUserId = (_currentUserId?.trim().isNotEmpty ?? false)
        ? _currentUserId!.trim()
        : 'onboarding-review';
    GuidedOnboardingController.instance.show(
      CoachmarkTarget(
        key: globalMenuButtonKey,
        title: helper.title,
        body: helper.body,
        placement: CoachmarkPlacement.above,
        variant: CoachmarkVariant.helperBubble,
        showDismissButton: true,
        dismissLabel: 'Got it',
        allowBackgroundInteraction: true,
        helperId: helper.id,
        helperUserId: helperUserId,
        sourceWidget: helper.sourceWidget,
        showWhenHelperCompleted: true,
        onDismiss: () => unawaited(_completeTrueOnboarding()),
      ),
      externalOverlaySuppressed: false,
    );
  }

  Future<void> _waitForCoachmarkTargetReady(
    GlobalKey key, {
    int maxFrames = 12,
  }) async {
    for (var frame = 0; frame < maxFrames; frame += 1) {
      await WidgetsBinding.instance.endOfFrame;
      if (!mounted) return;
      final renderObject = key.currentContext?.findRenderObject();
      if (renderObject is RenderBox &&
          renderObject.hasSize &&
          !renderObject.size.isEmpty) {
        return;
      }
    }
  }

  Future<void> _completeTrueOnboarding() async {
    GuidedOnboardingController.instance.clear();
    GuidedOnboardingController.instance.setExternalOverlaySuppressed(false);
    await _updateOnboardingProgress(
      (progress) => progress.copyWith(
        hasSeenMenuPrompt: true,
        currentStep: TrueOnboardingStep.complete,
        completedOnboarding: true,
      ),
    );
    final userId = _currentUserId;
    if (!_onboardingReviewMode && userId != null && userId.isNotEmpty) {
      await DailyOrientationRepo(Supabase.instance.client).complete(
        userId: userId,
        localDate: DateTime.now(),
        chosenReturn: _onboardingCompassCopy?.dayAlignedReturnKey,
        badgeLabel: 'this is ḥꜣw',
      );
    }
    await _markOnboardingCompletedIfNeeded();
    if (!_onboardingReviewMode) {
      unawaited(
        Events.trackIfAuthed('onboarding_completed', const <String, dynamic>{}),
      );
    }
  }

  Future<void> _maybeShowCalendarHelperAfterOnboarding(
    OnboardingProgress progress,
  ) async {
    if (_onboardingReviewMode ||
        CalendarPage.debugSuppressCalendarOnboardingHelpers) {
      return;
    }
    final userId = _currentUserId;
    if (!mounted ||
        _calendarAfterOnboardingHelperPrompted ||
        !progress.completedOnboarding ||
        userId == null ||
        userId.isEmpty) {
      return;
    }

    final helperService = OnboardingHelperCompletionService.instance;
    final hydratedProgress = await helperService.hydrateUser(userId);
    if (!mounted || !hydratedProgress.completedOnboarding) return;

    final helper = _nextCalendarHelper(userId);
    if (helper == null) return;
    _calendarAfterOnboardingHelperPrompted = true;

    await Future<void>.delayed(const Duration(milliseconds: 700));
    if (!mounted) return;
    if (!helperService.shouldShowHelperSync(userId, helper.definition.id)) {
      _calendarAfterOnboardingHelperPrompted = false;
      return;
    }
    NavigationTrace.instance.record(
      'helper overlay shown',
      state: <String, Object?>{
        'destination': 'calendar',
        'helperId': helper.definition.id,
      },
    );
    GuidedOnboardingController.instance.show(
      CoachmarkTarget(
        key: helper.key,
        title: helper.definition.title,
        body: helper.definition.body,
        placement: helper.placement,
        variant: CoachmarkVariant.helperBubble,
        showDismissButton: true,
        dismissLabel: 'Got it',
        helperId: helper.definition.id,
        helperUserId: userId,
        sourceWidget: helper.definition.sourceWidget,
        onDismiss: () async {
          final completion = _markOnboardingHelperCompleted(
            helper.definition.id,
          );
          _calendarAfterOnboardingHelperPrompted = false;
          final updated = await completion;
          unawaited(
            _maybeShowCalendarHelperAfterOnboarding(
              updated ?? _onboardingProgress,
            ),
          );
        },
      ),
    );
    unawaited(
      Events.trackIfAuthed(
        helper.definition.analyticsEvent,
        const <String, dynamic>{},
      ),
    );
  }

  ({
    OnboardingHelperDefinition definition,
    GlobalKey key,
    CoachmarkPlacement placement,
  })?
  _nextCalendarHelper(String userId) {
    final helperService = OnboardingHelperCompletionService.instance;
    const calendarToggle = OnboardingHelperRegistry.calendarToggle;
    if (helperService.shouldShowHelperSync(userId, calendarToggle.id)) {
      return (
        definition: calendarToggle,
        key: _calendarToggleKey,
        placement: CoachmarkPlacement.below,
      );
    }
    const monthDetails = OnboardingHelperRegistry.monthDetails;
    if (helperService.shouldShowHelperSync(userId, monthDetails.id)) {
      final decanIndex = decanForDay(_today.kDay) - 1;
      return (
        definition: monthDetails,
        key: keyForCurrentDecanHeader(
          _today.kYear,
          _today.kMonth.clamp(1, 12).toInt(),
          decanIndex.clamp(0, 2).toInt(),
        ),
        placement: CoachmarkPlacement.below,
      );
    }
    const dayCardLongPress = OnboardingHelperRegistry.dayCardLongPress;
    if (helperService.shouldShowHelperSync(userId, dayCardLongPress.id)) {
      return (
        definition: dayCardLongPress,
        key: _todayDayKey,
        placement: CoachmarkPlacement.above,
      );
    }
    return null;
  }

  // ignore: unused_element
  Future<bool> _requireProfileSetupAfterOnboarding() async {
    final userId = Supabase.instance.client.auth.currentUser?.id;
    if (userId == null || !mounted) return false;

    final repo = ProfileRepo(Supabase.instance.client);
    final profile =
        await repo.getMyProfile() ??
        UserProfile(
          id: userId,
          isDiscoverable: true,
          allowIncomingShares: true,
        );

    if (!mounted) return false;

    final hasDisplayName = (profile.displayName?.trim().isNotEmpty ?? false);
    final hasHandle = (profile.handle?.trim().isNotEmpty ?? false);
    final isProfileComplete = hasDisplayName && hasHandle;
    final shouldReplayPrompts = _replayOnboardingOnEveryLaunch;
    if (isProfileComplete && !shouldReplayPrompts) return true;
    final requireCompletion = !isProfileComplete;
    context.go(
      '/profile/me/edit?requireCompletion=${requireCompletion ? 1 : 0}',
    );
    return shouldReplayPrompts && !requireCompletion;
  }

  // ignore: unused_element
  Future<void> _promptForNotificationsAfterOnboarding() async {
    final currentUser = Supabase.instance.client.auth.currentUser;
    if (currentUser == null) return;

    final prefs = await SharedPreferences.getInstance();
    final shouldReplayPrompts = _replayOnboardingOnEveryLaunch;
    if (!shouldReplayPrompts &&
        SettingsPrefs.realTimeAlertsEnabledFrom(prefs)) {
      return;
    }

    final push = PushNotifications.instance(Supabase.instance.client);
    final diagnostics = await push.getDiagnostics();
    if (!mounted) return;

    if (!shouldReplayPrompts &&
        diagnostics.permissionGranted &&
        diagnostics.databaseRegistered) {
      await prefs.setBool(SettingsPrefs.realTimeAlertsKey, true);
      await Notify.syncLocalDeliveryMode();
      return;
    }

    var requesting = false;
    String? status =
        shouldReplayPrompts &&
            diagnostics.permissionGranted &&
            diagnostics.databaseRegistered
        ? 'Notifications are already enabled on this device. This prompt is being replayed for onboarding review.'
        : null;

    await showModalBottomSheet<void>(
      context: context,
      useSafeArea: true,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (sheetContext) {
        return StatefulBuilder(
          builder: (context, setSheetState) {
            Future<void> enableNotifications() async {
              if (requesting) return;
              setSheetState(() {
                requesting = true;
                status =
                    'Requesting permission and linking this device for push alerts...';
              });

              final token = await push.requestAndRegisterToken();
              final success = token != null;
              await prefs.setBool(SettingsPrefs.realTimeAlertsKey, success);
              await Notify.syncLocalDeliveryMode();

              if (!mounted || !sheetContext.mounted) return;

              final message = success
                  ? 'Push alerts enabled on this device.'
                  : (push.lastRegistrationError ??
                        'Push permission was denied or this device could not be linked for notifications.');

              ScaffoldMessenger.of(context).showSnackBar(
                SnackBar(
                  content: Text(message),
                  backgroundColor: success
                      ? Colors.green.shade700
                      : Colors.red.shade700,
                ),
              );

              if (success) {
                Navigator.of(sheetContext).pop();
                return;
              }

              setSheetState(() {
                requesting = false;
                status = message;
              });
            }

            return SafeArea(
              top: false,
              child: Padding(
                padding: EdgeInsets.fromLTRB(
                  16,
                  0,
                  16,
                  16 + MediaQuery.of(sheetContext).viewInsets.bottom,
                ),
                child: Container(
                  padding: const EdgeInsets.all(20),
                  decoration: BoxDecoration(
                    color: const Color(0xFF090909),
                    borderRadius: BorderRadius.circular(24),
                    border: Border.all(
                      color: KemeticGold.base.withValues(alpha: 0.24),
                    ),
                  ),
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      const Text(
                        'Turn on notifications',
                        style: TextStyle(
                          color: Colors.white,
                          fontSize: 20,
                          fontWeight: FontWeight.w700,
                        ),
                      ),
                      const SizedBox(height: 8),
                      Text(
                        'Stay on top of reminders, reflections, and shared activity. You can skip this for now and change it later in Settings.',
                        style: TextStyle(
                          color: Colors.white.withValues(alpha: 0.72),
                          height: 1.4,
                        ),
                      ),
                      if (status != null) ...[
                        const SizedBox(height: 12),
                        Text(
                          status!,
                          style: TextStyle(
                            color: Colors.white.withValues(alpha: 0.78),
                            height: 1.35,
                          ),
                        ),
                      ],
                      const SizedBox(height: 20),
                      SizedBox(
                        width: double.infinity,
                        child: ElevatedButton(
                          style: ElevatedButton.styleFrom(
                            backgroundColor: KemeticGold.base,
                            foregroundColor: Colors.black,
                            padding: const EdgeInsets.symmetric(vertical: 14),
                            shape: RoundedRectangleBorder(
                              borderRadius: BorderRadius.circular(16),
                            ),
                          ),
                          onPressed: requesting ? null : enableNotifications,
                          child: requesting
                              ? const SizedBox(
                                  width: 20,
                                  height: 20,
                                  child: CircularProgressIndicator(
                                    strokeWidth: 2,
                                    valueColor: AlwaysStoppedAnimation<Color>(
                                      Colors.black,
                                    ),
                                  ),
                                )
                              : const Text(
                                  'Turn on notifications',
                                  style: TextStyle(fontWeight: FontWeight.w600),
                                ),
                        ),
                      ),
                      const SizedBox(height: 10),
                      SizedBox(
                        width: double.infinity,
                        child: OutlinedButton(
                          style: OutlinedButton.styleFrom(
                            foregroundColor: Colors.white,
                            side: const BorderSide(color: Color(0xFF343434)),
                            padding: const EdgeInsets.symmetric(vertical: 14),
                            shape: RoundedRectangleBorder(
                              borderRadius: BorderRadius.circular(16),
                            ),
                          ),
                          onPressed: requesting
                              ? null
                              : () => Navigator.of(sheetContext).pop(),
                          child: const Text('Not now'),
                        ),
                      ),
                    ],
                  ),
                ),
              ),
            );
          },
        );
      },
    );
  }

  // ignore: unused_element
  Future<void> _showCalendarMonthCoachmarkAfterOnboarding() async {
    if (!mounted) return;
    await Future<void>.delayed(const Duration(milliseconds: 1500));
    if (!mounted) return;

    final targetKy = _lastViewKy ?? _today.kYear;
    final rawTargetKm = _lastViewKm ?? _today.kMonth;
    final targetKm = rawTargetKm < 1
        ? 1
        : (rawTargetKm > 12 ? 12 : rawTargetKm);

    setState(() {
      _calendarMonthCoachmarkKy = targetKy;
      _calendarMonthCoachmarkKm = targetKm;
      _showCalendarMonthCoachmark = true;
    });
  }

  Future<void> _maybePresentCalendarToggleCoachmarkAfterReturn() async {
    if (!mounted ||
        _onboardingContinuationStage !=
            _OnboardingContinuationStage.awaitingCalendarReturnToggle ||
        !_canShowCalendarToggleCoachmarkOnReturn ||
        !_calendarToggleCoachmarkArmedForReturn ||
        _showOnboarding ||
        _showCalendarMonthCoachmark ||
        _showCalendarToggleCoachmark) {
      return;
    }

    await Future<void>.delayed(const Duration(milliseconds: 280));
    if (!mounted ||
        _onboardingContinuationStage !=
            _OnboardingContinuationStage.awaitingCalendarReturnToggle ||
        !_canShowCalendarToggleCoachmarkOnReturn ||
        !_calendarToggleCoachmarkArmedForReturn ||
        _showOnboarding ||
        _showCalendarMonthCoachmark ||
        _showCalendarToggleCoachmark) {
      return;
    }

    setState(() {
      _calendarToggleCoachmarkArmedForReturn = false;
      _showCalendarToggleCoachmark = true;
      _onboardingContinuationStage =
          _OnboardingContinuationStage.awaitingDayViewReveal;
      _canShowCalendarToggleCoachmarkOnReturn = false;
    });
    unawaited(
      _persistOnboardingContinuationStage(
        _OnboardingContinuationStage.awaitingDayViewReveal,
      ),
    );
    unawaited(_autoDismissCalendarToggleCoachmark());
  }

  Future<void> _autoDismissCalendarToggleCoachmark() async {
    await Future<void>.delayed(const Duration(seconds: 4));
    if (!mounted || !_showCalendarToggleCoachmark) return;
    setState(() => _showCalendarToggleCoachmark = false);
  }

  void _handleCalendarToggleTapped() {
    if (!mounted) return;

    _restorationInteractedSinceBoot = true;
    unawaited(
      _markOnboardingHelperCompleted(
        OnboardingHelperRegistry.calendarToggle.id,
      ),
    );
    setState(() {
      _showGregorian = !_showGregorian;
      _showCalendarToggleCoachmark = false;
      _calendarToggleCoachmarkArmedForReturn = false;
    });
    _scheduleCalendarRestorationSave(reason: 'calendar_toggle_changed');
  }

  GlobalKey? get _calendarMonthCoachmarkTargetKey {
    final targetKy = _calendarMonthCoachmarkKy;
    final targetKm = _calendarMonthCoachmarkKm;
    if (targetKy == null || targetKm == null) return null;
    return keyForMonthHeader(targetKy, targetKm);
  }

  MaterialPageRoute<void> _buildMonthDetailRoute(
    int kYear,
    int kMonth, {
    int? decanIndex,
  }) {
    final todayMonth = kYear == _today.kYear ? _today.kMonth : null;
    final todayDay = kYear == _today.kYear ? _today.kDay : null;

    return MaterialPageRoute<void>(
      settings: const RouteSettings(name: calendarMonthDetailRouteName),
      builder: (_) => _MonthDetailPage(
        kYear: kYear,
        kMonth: kMonth,
        todayMonth: todayMonth,
        todayDay: todayDay,
        showGregorian: _showGregorian,
        notesGetter: (m, d) => _getNotes(kYear, m, d),
        flowColorsGetter: (ky, km, kd) => getFlowColorsForDay(ky, km, kd),
        onDayTap: (c, m, d) => _openDayView(c, kYear, m, d),
        noteColorResolver: _noteColor,
        flowNameGetter: _flowName,
        onManageFlows: _getMyFlowsCallback(),
        onEditNote: (ky, km, kd, evt) async =>
            _editNoteByEvent(ky, km, kd, evt),
        onDeleteNote: (ky, km, kd, evt) async =>
            _deleteNoteByEvent(ky, km, kd, evt),
        onShareNote: (evt) async => _shareNoteSimple(evt),
        onEditReminder: (id) async => _editReminderById(id),
        onEndReminder: (id) async => _endReminderRule(id),
        onShareReminder: (evt) async => _shareNoteSimple(evt),
        onEndFlow: (id) => _endFlow(id),
        onAppendToJournal: _appendToJournalAndRefresh,
        decanIndex: decanIndex,
      ),
    );
  }

  void _openMonthInfo(
    BuildContext navigatorContext,
    int kYear,
    int kMonth, {
    int? decanIndex,
  }) {
    Navigator.of(
      navigatorContext,
    ).push(_buildMonthDetailRoute(kYear, kMonth, decanIndex: decanIndex));
  }

  void _handleMonthHeaderTapped(
    BuildContext navigatorContext,
    int kYear,
    int kMonth,
  ) {
    if (!mounted) return;
    unawaited(
      _markOnboardingHelperCompleted(OnboardingHelperRegistry.monthDetails.id),
    );

    final shouldFinalizeOnboarding =
        _showCalendarMonthCoachmark &&
        _calendarMonthCoachmarkKy == kYear &&
        _calendarMonthCoachmarkKm == kMonth;

    if (shouldFinalizeOnboarding) {
      setState(() {
        _onboardingContinuationStage =
            _OnboardingContinuationStage.awaitingCalendarReturnToggle;
        _canShowCalendarToggleCoachmarkOnReturn = true;
        _showCalendarMonthCoachmark = false;
        _calendarMonthCoachmarkKy = null;
        _calendarMonthCoachmarkKm = null;
      });
      unawaited(
        _persistOnboardingContinuationStage(
          _OnboardingContinuationStage.awaitingCalendarReturnToggle,
        ),
      );
    }

    _openMonthInfo(navigatorContext, kYear, kMonth);
  }

  void _handleDecanHeaderTapped(
    BuildContext navigatorContext,
    int kYear,
    int kMonth,
    int decanIndex,
  ) {
    if (!mounted) return;
    unawaited(
      _markOnboardingHelperCompleted(OnboardingHelperRegistry.monthDetails.id),
    );
    _openMonthInfo(navigatorContext, kYear, kMonth, decanIndex: decanIndex);
  }

  void _handleCalendarMonthCoachmarkTargetTap() {
    final targetKy = _calendarMonthCoachmarkKy;
    final targetKm = _calendarMonthCoachmarkKm;
    if (targetKy == null || targetKm == null) return;
    _handleMonthHeaderTapped(context, targetKy, targetKm);
  }

  bool get _shouldShowDayCardRevealCoachmarkFromOnboarding => false;

  Future<void> _handleDayCardRevealCoachmarkCompletedFromOnboarding() async {
    if (_onboardingContinuationStage !=
        _OnboardingContinuationStage.awaitingDayViewReveal) {
      return;
    }

    if (mounted) {
      setState(() {
        _onboardingContinuationStage = _OnboardingContinuationStage.none;
        _canShowCalendarToggleCoachmarkOnReturn = false;
      });
    }

    await _markOnboardingCompletedIfNeeded();
  }

  CalendarRestorationState? _legacyCalendarRestorationState(
    Map<String, dynamic>? savedState,
  ) {
    final savedKy = (savedState?['kYear'] as num?)?.toInt();
    final savedKm = (savedState?['kMonth'] as num?)?.toInt();
    final savedKd = (savedState?['kDay'] as num?)?.toInt();
    final savedSchemaVersion =
        (savedState?['schemaVersion'] as num?)?.toInt() ?? 0;
    final savedExpansion = savedState?['expansion'] as String?;
    if (savedSchemaVersion != _kCalendarViewStateSchemaVersion ||
        savedKy == null ||
        savedKm == null ||
        savedKm < 1 ||
        savedKm > 13) {
      return null;
    }

    final maxDay = _maxDayForMonth(savedKy, savedKm);
    final clampedDay = (savedKd != null && savedKd >= 1 && savedKd <= maxDay)
        ? savedKd
        : 1;
    return CalendarRestorationState(
      kYear: savedKy,
      kMonth: savedKm,
      kDay: clampedDay,
      showGregorian: false,
      expansion:
          savedExpansion ??
          _expansionToString(_monthExpansionLevelForRestoration()),
    );
  }

  MonthExpansionLevel _monthExpansionLevelForRestoration() {
    return monthExpansionRestorationLevelForTesting(
      currentLevel: _monthExpansion,
      settleTarget: _monthExpansionRestorationTarget,
      isPinching: _isPinching,
      pinchProgress: _pinchExpansionValue,
      pinchStartLevel: _pinchStartLevel,
    );
  }

  CalendarRestorationState _buildCalendarRestorationState({
    int? overrideKy,
    int? overrideKm,
    int? overrideKd,
    double? overrideScrollOffset,
  }) {
    final ky = overrideKy ?? _lastViewKy ?? _today.kYear;
    final km = overrideKm ?? _lastViewKm ?? _today.kMonth;
    final maxDay = _maxDayForMonth(ky, km);
    final kd = (overrideKd ?? _lastViewKd ?? _today.kDay).clamp(1, maxDay);
    final scrollOffset =
        overrideScrollOffset ??
        (_scrollCtrl.hasClients ? _scrollCtrl.position.pixels : null) ??
        _lastKnownCalendarScrollOffset;
    final viewportAnchor = _currentViewportCalendarAnchor();
    return CalendarRestorationState(
      kYear: ky,
      kMonth: km,
      kDay: kd,
      showGregorian: _showGregorian,
      expansion: _expansionToString(_monthExpansionLevelForRestoration()),
      anchorTarget: viewportAnchor?.target,
      anchorAlignment: viewportAnchor?.alignment,
      viewportHeight: _currentViewportHeight(),
      layoutRevision: _kCalendarRestorationLayoutRevision,
      scrollOffset: scrollOffset,
    );
  }

  Future<void> _persistCalendarRestorationState(
    CalendarRestorationState state, {
    required String reason,
  }) async {
    _lastKnownCalendarScrollOffset = state.scrollOffset;
    await AppRestorationService.instance.saveCalendarState(state);
    await SessionResumeService.saveScopedState(_kSessionScopeCalendarView, {
      'schemaVersion': _kCalendarViewStateSchemaVersion,
      'kYear': state.kYear,
      'kMonth': state.kMonth,
      'kDay': state.kDay,
      'expansion': state.expansion,
    });
    if (kDebugMode) {
      _calendarDebugPrint(
        '[restoration] saved calendar reason=$reason '
        'ky=${state.kYear} km=${state.kMonth} kd=${state.kDay} '
        'scroll=${state.scrollOffset?.toStringAsFixed(1)}',
      );
    }
  }

  void _maybePersistCalendarRestorationDuringScroll() {
    if (!_rememberLastView ||
        !_restored ||
        _calendarProgressSaveInFlight ||
        !_scrollCtrl.hasClients) {
      return;
    }
    final nowMs = DateTime.now().millisecondsSinceEpoch;
    if (nowMs - _lastCalendarProgressSaveAtMs <
        _calendarProgressSaveIntervalMs) {
      return;
    }
    _lastCalendarProgressSaveAtMs = nowMs;
    _calendarProgressSaveInFlight = true;
    unawaited(
      _saveCalendarRestorationNow(
        reason: 'calendar_scroll_progress',
      ).whenComplete(() {
        _calendarProgressSaveInFlight = false;
      }),
    );
  }

  Future<void> _saveCalendarRestorationNow({
    String reason = 'manual',
    int? overrideKy,
    int? overrideKm,
    int? overrideKd,
  }) async {
    if (!_rememberLastView) return;
    final state = _buildCalendarRestorationState(
      overrideKy: overrideKy,
      overrideKm: overrideKm,
      overrideKd: overrideKd,
    );
    await _persistCalendarRestorationState(state, reason: reason);
  }

  Future<void> _flushPendingCalendarRestorationSave({
    required String reason,
  }) async {
    final hadPendingWrite = _calendarRestorationDebounce?.isActive ?? false;
    _calendarRestorationDebounce?.cancel();
    _calendarRestorationDebounce = null;
    if (!_rememberLastView || !_restored) {
      return;
    }
    await _saveCalendarRestorationNow(
      reason: hadPendingWrite ? '$reason:flush' : reason,
    );
  }

  void _scheduleCalendarRestorationSave({String reason = 'debounced'}) {
    if (!_rememberLastView || !_restored) return;
    _calendarRestorationDebounce?.cancel();
    _calendarRestorationDebounce = Timer(_restorationWriteDebounce, () {
      unawaited(_saveCalendarRestorationNow(reason: reason));
    });
  }

  Future<void> _persistDayViewState(
    DayViewRestorationState state, {
    required String reason,
    int? writeSessionId,
  }) async {
    if (!_dayViewRestorationWriteGate.shouldPersist(
      isOpen: state.isOpen,
      sessionId: writeSessionId,
    )) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[restoration] ignored stale day_view reason=$reason '
          'open=${state.isOpen}',
        );
      }
      return;
    }
    _activeDayViewRestorationState = state;
    await AppRestorationService.instance.saveDayViewState(state);
    if (kDebugMode) {
      _calendarDebugPrint(
        '[restoration] saved day_view reason=$reason '
        'open=${state.isOpen} ky=${state.kYear} km=${state.kMonth} '
        'kd=${state.kDay} scroll=${state.scrollOffset?.toStringAsFixed(1)}',
      );
    }
  }

  void _suppressPendingRestoresForUserNavigation() {
    _pendingPersistentDayViewState = null;
    _persistentDayViewRestoreAttempted = true;
    _calendarOverlayRestoreAttempted = true;
    _dayViewRestorationWriteGate.markActiveClosed();
    final dayViewState = _activeDayViewRestorationState;
    if (dayViewState != null && dayViewState.isOpen) {
      final closedState = dayViewState.copyWith(
        isOpen: false,
        clearEventDetail: true,
      );
      _activeDayViewRestorationState = closedState;
      unawaited(_persistDayViewState(closedState, reason: 'today_command'));
    }
  }

  void _schedulePersistentDayViewRestore() {
    if (!_restoreDayViewRouteOnStartup) {
      _persistentDayViewRestoreAttempted = true;
      return;
    }
    if (!_canRestorePersistentDayViewRouteForCurrentViewport()) {
      _persistentDayViewRestoreAttempted = true;
      _pendingPersistentDayViewState = null;
      return;
    }
    if (!RestorationCoordinator.instance.canRestoreSurface(
      RestorationCoordinator.calendarDayViewSurface,
      requireRootTarget: true,
    )) {
      _persistentDayViewRestoreAttempted = true;
      _pendingPersistentDayViewState = null;
      return;
    }
    if (_persistentDayViewRestoreAttempted ||
        _pendingPersistentDayViewState == null) {
      return;
    }
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_restorePersistentDayViewIfNeeded());
    });
  }

  Future<void> _restorePersistentDayViewIfNeeded([int attempt = 0]) async {
    if (!mounted || _persistentDayViewRestoreAttempted) return;
    if (!_restoreDayViewRouteOnStartup) {
      _persistentDayViewRestoreAttempted = true;
      return;
    }
    if (!_canRestorePersistentDayViewRouteForCurrentViewport()) {
      _persistentDayViewRestoreAttempted = true;
      _pendingPersistentDayViewState = null;
      return;
    }
    if (!RestorationCoordinator.instance.canRestoreSurface(
      RestorationCoordinator.calendarDayViewSurface,
      requireRootTarget: true,
    )) {
      _persistentDayViewRestoreAttempted = true;
      _pendingPersistentDayViewState = null;
      return;
    }
    final state = _pendingPersistentDayViewState;
    if (state == null || !state.isOpen) {
      _persistentDayViewRestoreAttempted = true;
      return;
    }
    if (!_restored || !_initialViewportSettled) {
      if (attempt >= 20) {
        _persistentDayViewRestoreAttempted = true;
        return;
      }
      await Future<void>.delayed(const Duration(milliseconds: 120));
      if (!mounted) return;
      return _restorePersistentDayViewIfNeeded(attempt + 1);
    }

    final pendingPush = await SessionResumeService.readResumeEntry(
      kind: _kSessionResumeKindPushEvent,
      baseRoute: '/',
    );
    if (pendingPush != null) {
      _persistentDayViewRestoreAttempted = true;
      return;
    }

    final pendingSheet = await SessionResumeService.readResumeEntry(
      kind: _kSessionResumeKindDaySheet,
      baseRoute: '/',
    );
    if (pendingSheet != null) {
      _persistentDayViewRestoreAttempted = true;
      return;
    }

    _persistentDayViewRestoreAttempted = true;
    if (!mounted) return;
    if (!RestorationCoordinator.instance.claimRestoreSurface(
      RestorationCoordinator.calendarDayViewSurface,
      requireRootTarget: true,
    )) {
      _pendingPersistentDayViewState = null;
      return;
    }
    final detail = state.eventDetail;
    final openKy = detail?.kYear ?? state.kYear;
    final openKm = detail?.kMonth ?? state.kMonth;
    final openKd = detail?.kDay ?? state.kDay;
    final restoreScrollForOpenDay =
        detail == null ||
        (detail.kYear == state.kYear &&
            detail.kMonth == state.kMonth &&
            detail.kDay == state.kDay);
    if (detail != null) {
      await _clearCalendarEventDetailOverlayState();
      if (!mounted) return;
    }
    _openDayView(
      context,
      openKy,
      openKm,
      openKd,
      initialFirstVisibleMinute: restoreScrollForOpenDay
          ? state.firstVisibleMinute
          : null,
      initialScrollOffset: restoreScrollForOpenDay ? state.scrollOffset : null,
      initialShowGregorian: state.showGregorian,
      initialEventDetailRestorationState: detail,
    );
  }

  bool _canRestorePersistentDayViewRouteForCurrentViewport() {
    final media = MediaQuery.maybeOf(context);
    if (media == null) return true;
    return media.size.shortestSide < 600;
  }

  void _applyTodayFallbackAfterRestore({required String reason}) {
    if (kDebugMode) {
      _calendarDebugPrint(
        '[restoration] calendar fallback=today reason=$reason',
      );
    }
    _setView(_today.kYear, _today.kMonth, kd: _today.kDay);
    _scheduleInitialViewportRestore();
    if (!mounted) {
      _pendingAuthResolutionForRestore = false;
      _tentativeRestorationUserId = null;
      _pendingPersistentDayViewState = null;
      _persistentDayViewRestoreAttempted = false;
      _restoredCalendarAnchorTarget = null;
      _restoredCalendarAnchorAlignment = null;
      _restoredCalendarScrollOffset = null;
      _restorationInteractedSinceBoot = false;
      _restored = true;
      return;
    }
    setState(() {
      _pendingAuthResolutionForRestore = false;
      _tentativeRestorationUserId = null;
      _pendingPersistentDayViewState = null;
      _persistentDayViewRestoreAttempted = false;
      _restoredCalendarAnchorTarget = null;
      _restoredCalendarAnchorAlignment = null;
      _restoredCalendarScrollOffset = null;
      _restorationInteractedSinceBoot = false;
      _restored = true;
    });
  }

  void _applyTodayNavigationCommand({
    required bool animate,
    required String reason,
  }) {
    _suppressPendingRestoresForUserNavigation();
    _applyTodayFallbackAfterRestore(reason: reason);
    _scrollToToday(animate: animate);
  }

  bool _consumePendingTodayNavigationCommand({required String trigger}) {
    if (!CalendarPage._pendingTodayNavigationCommand) return false;
    NavigationTrace.instance.record(
      'CalendarPage consumed pending Today command',
      state: <String, Object?>{'trigger': trigger},
    );
    CalendarPage._pendingTodayNavigationCommand = false;
    _applyTodayNavigationCommand(
      animate: false,
      reason: 'today_command:$trigger',
    );
    unawaited(CalendarPage._recordCalendarTodayCommandState(this));
    return true;
  }

  Future<void> _maybeResolvePersistedViewStateAfterAuth(
    AuthChangeEvent event,
  ) async {
    if (!_pendingAuthResolutionForRestore || !mounted) {
      return;
    }

    final authUserId = Supabase.instance.client.auth.currentUser?.id.trim();
    final hasResolvedUser = authUserId != null && authUserId.isNotEmpty;
    final tentativeUserId = _tentativeRestorationUserId;
    final userMismatch =
        hasResolvedUser &&
        tentativeUserId != null &&
        tentativeUserId != authUserId;
    final authResolvedWithoutUser =
        (event == AuthChangeEvent.initialSession ||
            event == AuthChangeEvent.signedOut) &&
        !hasResolvedUser;

    if (_restorationInteractedSinceBoot &&
        !userMismatch &&
        !authResolvedWithoutUser) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[restoration] auth resolution kept current view '
          'event=${event.name} user=$authUserId',
        );
      }
      if (mounted) {
        setState(() {
          _pendingAuthResolutionForRestore = false;
          _tentativeRestorationUserId = null;
        });
      } else {
        _pendingAuthResolutionForRestore = false;
        _tentativeRestorationUserId = null;
      }
      return;
    }

    if (authResolvedWithoutUser) {
      _applyTodayFallbackAfterRestore(
        reason: 'auth_resolved_without_user:${event.name}',
      );
      return;
    }

    if (!hasResolvedUser) {
      return;
    }

    if (kDebugMode) {
      _calendarDebugPrint(
        '[restoration] retrying persisted view restore '
        'event=${event.name} user=$authUserId mismatch=$userMismatch',
      );
    }
    await _loadPersistedViewState(trigger: 'auth:${event.name}');
  }

  /// ✅ Load persisted view state from permanent per-window restoration first.
  Future<void> _loadPersistedViewState({String trigger = 'startup'}) async {
    if (_consumePendingTodayNavigationCommand(trigger: trigger)) {
      return;
    }
    if (!_rememberLastView) {
      _applyTodayFallbackAfterRestore(reason: 'remember_last_view_disabled');
      return;
    }
    try {
      final readResult = await AppRestorationService.instance
          .readBestSnapshot();
      if (readResult.isAwaitingAuth) {
        _pendingAuthResolutionForRestore = true;
        _tentativeRestorationUserId = null;
        if (kDebugMode) {
          _calendarDebugPrint(
            '[restoration] calendar awaiting auth '
            'trigger=$trigger window=${readResult.windowId}',
          );
        }
        return;
      }

      final snapshot = readResult.snapshot;
      var savedCalendar = snapshot?.calendar;
      final savedDayView = snapshot?.dayView;
      final shouldRestoreDayViewRoute =
          _restoreDayViewRouteOnStartup &&
          !readResult.isTentative &&
          RestorationCoordinator.instance.canRestoreSurface(
            RestorationCoordinator.calendarDayViewSurface,
            requireRootTarget: true,
          );

      if (savedCalendar == null && !readResult.isTentative) {
        final legacyState = await SessionResumeService.readScopedState(
          _kSessionScopeCalendarView,
        );
        savedCalendar = _legacyCalendarRestorationState(legacyState);
      }

      if (savedCalendar == null && savedDayView != null) {
        savedCalendar = CalendarRestorationState(
          kYear: savedDayView.kYear,
          kMonth: savedDayView.kMonth,
          kDay: savedDayView.kDay,
          showGregorian: savedDayView.showGregorian,
          expansion: _expansionToString(_monthExpansion),
        );
      }

      if (savedCalendar != null) {
        final today = KemeticMath.fromGregorian(DateTime.now());

        if (savedCalendar.kYear > today.kYear + 2) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '⚠️ [CALENDAR] Future persisted date '
              '${savedCalendar.kYear}/${savedCalendar.kMonth} '
              '— defaulting to today',
            );
          }
          _applyTodayFallbackAfterRestore(reason: 'future_persisted_date');
          return;
        }

        final maxDay = _maxDayForMonth(
          savedCalendar.kYear,
          savedCalendar.kMonth,
        );
        final clampedDay = savedCalendar.kDay.clamp(1, maxDay);

        if (kDebugMode) {
          _calendarDebugPrint(
            '📂 [CALENDAR] Restored '
            '${savedCalendar.kYear}/${savedCalendar.kMonth}/$clampedDay',
          );
        }

        setState(() {
          _lastViewKy = savedCalendar!.kYear;
          _lastViewKm = savedCalendar.kMonth;
          _lastViewKd = clampedDay;
          _showGregorian = savedCalendar.showGregorian;
          _monthExpansion = _parseExpansion(savedCalendar.expansion);
          _restoredCalendarAnchorTarget = savedCalendar.anchorTarget;
          _restoredCalendarAnchorAlignment = savedCalendar.anchorAlignment;
          _restoredCalendarScrollOffset = savedCalendar.scrollOffset;
          _pendingPersistentDayViewState =
              shouldRestoreDayViewRoute &&
                  savedDayView != null &&
                  savedDayView.isOpen
              ? savedDayView
              : null;
          _persistentDayViewRestoreAttempted = !shouldRestoreDayViewRoute;
          _pendingAuthResolutionForRestore = readResult.isTentative;
          _tentativeRestorationUserId = readResult.isTentative
              ? snapshot?.userId
              : null;
          _restorationInteractedSinceBoot = false;
          _restored = true;
        });
      } else {
        if (kDebugMode) {
          _calendarDebugPrint(
            '📂 [CALENDAR] No persisted state — defaulting to today',
          );
        }
        _applyTodayFallbackAfterRestore(reason: 'no_persisted_state');
        return;
      }

      if (_hasWarmStartSnapshotVisibleForCurrentUser()) {
        _settleInitialViewportWithoutStartupJump();
      } else {
        _scheduleInitialViewportRestore();
      }
      if (shouldRestoreDayViewRoute) {
        _schedulePersistentDayViewRestore();
      }
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '⚠️ [CALENDAR] Persist load error — defaulting to today: $e',
        );
      }
      _applyTodayFallbackAfterRestore(reason: 'persist_load_error');
    }
  }

  /// ✅ Helper: Calculate max days in a Kemetic month
  int _maxDayForMonth(int ky, int km) {
    if (km == 13) {
      return KemeticMath.isLeapKemeticYear(ky) ? 6 : 5;
    }
    return 30;
  }

  /// ✅ Central writer for view state - single source of truth
  void _setView(int ky, int km, {int? kd}) {
    if (_lastViewKy == ky &&
        _lastViewKm == km &&
        (kd == null || _lastViewKd == kd)) {
      return;
    }

    _lastViewKy = ky;
    _lastViewKm = km;
    if (kd != null) _lastViewKd = kd;

    if (_rememberLastView) {
      _scheduleCalendarRestorationSave(reason: 'centered_month_changed');
    }
    setState(() {}); // keep headers/UI in sync
  }

  /// ✅ Save view state immediately to permanent restoration and legacy fallback.
  Future<void> _saveViewState(int ky, int km, [int? kd]) async {
    if (!_rememberLastView) return; // persistence disabled
    try {
      final maxDay = _maxDayForMonth(ky, km);
      final clampedDay = (kd ?? _lastViewKd ?? 1).clamp(1, maxDay);
      await _saveCalendarRestorationNow(
        reason: 'save_view_state',
        overrideKy: ky,
        overrideKm: km,
        overrideKd: clampedDay,
      );
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('⚠️  [CALENDAR] Error saving view state: $e');
      }
    }
  }

  void _scheduleInitialViewportRestore() {
    if (_initialJumpScheduled) return;
    _initialJumpScheduled = true;

    void finishRestore() {
      _initialViewportSettled = true;
      _initialJumpScheduled = false;
    }

    void attemptRestore(int tries) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!mounted) {
          finishRestore();
          return;
        }
        bool ok = false;
        final restoredAnchorTarget = _restoredCalendarAnchorTarget;
        final restoredAlignment = _restoredCalendarAnchorAlignment;
        if (restoredAlignment != null) {
          ok = _jumpToCalendarAnchorAtAlignmentNow(
            restoredAnchorTarget,
            restoredAlignment,
            animate: false,
          );
          if (ok && _scrollCtrl.hasClients) {
            _lastKnownCalendarScrollOffset = _scrollCtrl.position.pixels;
            _restoredCalendarAnchorTarget = null;
            _restoredCalendarAnchorAlignment = null;
          }
        }
        final restoredOffset = _restoredCalendarScrollOffset;
        if (!ok &&
            restoredOffset != null &&
            _scrollCtrl.hasClients &&
            _scrollCtrl.position.hasContentDimensions) {
          final position = _scrollCtrl.position;
          final clamped = restoredOffset.clamp(
            position.minScrollExtent,
            position.maxScrollExtent,
          );
          _scrollCtrl.jumpTo(clamped);
          _lastKnownCalendarScrollOffset = clamped.toDouble();
          _restoredCalendarAnchorTarget = null;
          _restoredCalendarAnchorAlignment = null;
          _restoredCalendarScrollOffset = null;
          ok = true;
        }
        ok = ok || _jumpToCurrentViewNow(animate: false);
        if (ok || tries >= 20) {
          _restoredCalendarAnchorTarget = null;
          _restoredCalendarAnchorAlignment = null;
          _restoredCalendarScrollOffset = null;
          finishRestore();
        } else {
          attemptRestore(tries + 1);
        }
      });
    }

    attemptRestore(0);
  }

  void _settleInitialViewportWithoutStartupJump() {
    _restoredCalendarAnchorTarget = null;
    _restoredCalendarAnchorAlignment = null;
    _restoredCalendarScrollOffset = null;
    _initialJumpScheduled = false;
    _initialViewportSettled = true;
  }

  int _sessionDayForMonth(int ky, int km) {
    final maxDay = _maxDayForMonth(ky, km);
    if (ky == _today.kYear && km == _today.kMonth) {
      return _today.kDay.clamp(1, maxDay);
    }
    return (_lastViewKd ?? 1).clamp(1, maxDay);
  }

  void _commitVisiblePortraitMonthForRotation() {
    if (!_scrollCtrl.hasClients) {
      return;
    }
    final centered = _computeCenteredMonthPrecisely();
    _lastKnownCalendarScrollOffset = _scrollCtrl.position.pixels;
    _lastViewKy = centered.$1;
    _lastViewKm = centered.$2;
    _lastViewKd = _sessionDayForMonth(centered.$1, centered.$2);
  }

  void _scheduleEventDetailOrientationHandoff() {
    if (_eventDetailOrientationHandoffScheduled ||
        !CalendarEventDetailSheetCoordinator.isOpenOrOpening ||
        _activeCalendarEventDetailRestoration == null) {
      return;
    }
    _eventDetailOrientationHandoffScheduled = true;
    _preserveEventDetailOverlayForOrientationHandoff = true;

    WidgetsBinding.instance.addPostFrameCallback((_) async {
      if (!mounted) {
        _eventDetailOrientationHandoffScheduled = false;
        _preserveEventDetailOverlayForOrientationHandoff = false;
        return;
      }
      try {
        final navigator = Navigator.of(context, rootNavigator: true);
        if (navigator.canPop()) {
          await navigator.maybePop();
        }
      } catch (_) {
        // The route may already be closing during an orientation rebuild.
      } finally {
        if (mounted) {
          final preservedState = _activeCalendarEventDetailRestoration;
          final media = MediaQuery.maybeOf(context);
          final useLandscapeGrid =
              media != null &&
              media.orientation == Orientation.landscape &&
              media.size.shortestSide < 600;
          setState(() {
            _eventDetailOrientationHandoffScheduled = false;
            _preserveEventDetailOverlayForOrientationHandoff = false;
          });
          if (!useLandscapeGrid &&
              preservedState != null &&
              !CalendarEventDetailSheetCoordinator.isOpenOrOpening) {
            final target = _calendarEventDetailTargetFromState(preservedState);
            if (target != null) {
              await _openCalendarEventDetailSheet(target);
            }
          }
        } else {
          _eventDetailOrientationHandoffScheduled = false;
          _preserveEventDetailOverlayForOrientationHandoff = false;
        }
      }
    });
  }

  void _scheduleOrientationJumpToCurrentView() {
    if (_orientationJumpScheduled) return;
    _orientationJumpScheduled = true;
    void attempt(int tries) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        if (!mounted) {
          _orientationJumpScheduled = false;
          return;
        }
        final ok =
            _jumpToCurrentViewNow(animate: false) ||
            _jumpToTodayNow(animate: false);
        if (ok || tries >= 2) {
          _orientationJumpScheduled = false;
        } else {
          attempt(tries + 1);
        }
      });
    }

    attempt(0);
  }

  void _ensurePortraitCentered() {
    _scheduleOrientationJumpToCurrentView();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      _portraitRecenterPending = false;
      if (mounted) setState(() {});
    });
  }

  BuildContext? _currentViewTargetContext() {
    return _calendarAnchorContextForTarget(_kCalendarAnchorTargetDayChip) ??
        _calendarAnchorContextForTarget(_kCalendarAnchorTargetMonthBody);
  }

  BuildContext? _currentViewDayAnchorContext() {
    final viewKy = _lastViewKy;
    final viewKm = _lastViewKm;
    final viewKd = _lastViewKd;
    if (viewKy != null && viewKm != null && viewKd != null) {
      if (viewKy == _today.kYear &&
          viewKm == _today.kMonth &&
          viewKd == _today.kDay) {
        return _todayDayKey.currentContext;
      }
      return _viewDayAnchorKey.currentContext;
    }
    return _todayDayKey.currentContext;
  }

  BuildContext? _calendarAnchorContextForTarget(String? target) {
    final viewKy = _lastViewKy ?? _today.kYear;
    final viewKm = _lastViewKm ?? _today.kMonth;
    switch (target) {
      case _kCalendarAnchorTargetDayChip:
        return _currentViewDayAnchorContext() ??
            keyForMonthHeader(viewKy, viewKm).currentContext ??
            keyForMonth(viewKy, viewKm).currentContext;
      case _kCalendarAnchorTargetMonthHeader:
        return keyForMonthHeader(viewKy, viewKm).currentContext ??
            keyForMonth(viewKy, viewKm).currentContext;
      case _kCalendarAnchorTargetMonthBody:
        return keyForMonth(viewKy, viewKm).currentContext ??
            keyForMonthHeader(viewKy, viewKm).currentContext;
      default:
        return _currentViewDayAnchorContext() ??
            keyForMonth(viewKy, viewKm).currentContext;
    }
  }

  ({BuildContext context, String target, double alignment, double distance})?
  _visibleCalendarAnchorCandidate(String target, BuildContext? targetCtx) {
    if (targetCtx == null) return null;

    final scrollableState = Scrollable.maybeOf(targetCtx);
    if (scrollableState == null) return null;

    final viewportBox =
        scrollableState.context.findRenderObject() as RenderBox?;
    final targetBox = targetCtx.findRenderObject() as RenderBox?;
    if (viewportBox == null ||
        targetBox == null ||
        !viewportBox.hasSize ||
        !targetBox.hasSize ||
        viewportBox.size.height <= 0) {
      return null;
    }

    final targetTopLeft = targetBox.localToGlobal(
      Offset.zero,
      ancestor: viewportBox,
    );
    final targetTop = targetTopLeft.dy;
    final targetBottom = targetTop + targetBox.size.height;
    final visibleTop = targetTop.clamp(0.0, viewportBox.size.height);
    final visibleBottom = targetBottom.clamp(0.0, viewportBox.size.height);
    final visibleHeight = visibleBottom - visibleTop;
    if (visibleHeight <= 0) {
      return null;
    }
    final targetCenterY = targetTopLeft.dy + targetBox.size.height / 2;
    final alignment = (targetCenterY / viewportBox.size.height)
        .clamp(0.0, 1.0)
        .toDouble();
    return (
      context: targetCtx,
      target: target,
      alignment: alignment,
      distance: (targetCenterY - (viewportBox.size.height / 2)).abs(),
    );
  }

  bool _isTodayDayAnchorVisibleInCalendarViewport() {
    final targetCtx = _todayDayKey.currentContext;
    if (targetCtx == null) return false;

    final scrollableState = Scrollable.maybeOf(targetCtx);
    if (scrollableState == null) return false;

    final viewportBox =
        scrollableState.context.findRenderObject() as RenderBox?;
    final targetBox = targetCtx.findRenderObject() as RenderBox?;
    if (viewportBox == null ||
        targetBox == null ||
        !viewportBox.hasSize ||
        !targetBox.hasSize ||
        viewportBox.size.height <= 0) {
      return false;
    }

    final targetTopLeft = targetBox.localToGlobal(
      Offset.zero,
      ancestor: viewportBox,
    );
    final targetTop = targetTopLeft.dy;
    final targetBottom = targetTop + targetBox.size.height;
    return targetBottom > 0 && targetTop < viewportBox.size.height;
  }

  void _refreshCurrentDecanViewportAnchor() {
    if (!mounted || !_initialViewportSettled) return;
    final next = _isTodayDayAnchorVisibleInCalendarViewport();
    if (next == _currentDecanVisibleInViewport) return;
    setState(() => _currentDecanVisibleInViewport = next);
  }

  ({BuildContext context, String target, double alignment})?
  _currentViewportCalendarAnchor() {
    final candidates =
        <
          ({
            BuildContext context,
            String target,
            double alignment,
            double distance,
          })?
        >[
          _visibleCalendarAnchorCandidate(
            _kCalendarAnchorTargetDayChip,
            _calendarAnchorContextForTarget(_kCalendarAnchorTargetDayChip),
          ),
          _visibleCalendarAnchorCandidate(
            _kCalendarAnchorTargetMonthHeader,
            _calendarAnchorContextForTarget(_kCalendarAnchorTargetMonthHeader),
          ),
          _visibleCalendarAnchorCandidate(
            _kCalendarAnchorTargetMonthBody,
            _calendarAnchorContextForTarget(_kCalendarAnchorTargetMonthBody),
          ),
        ];
    ({BuildContext context, String target, double alignment, double distance})?
    best;
    for (final candidate in candidates) {
      if (candidate == null) continue;
      if (best == null || candidate.distance < best.distance) {
        best = candidate;
      }
    }
    if (best == null) return null;
    return (
      context: best.context,
      target: best.target,
      alignment: best.alignment,
    );
  }

  double? _currentViewportHeight() {
    final targetCtx =
        _currentViewportCalendarAnchor()?.context ??
        _currentViewTargetContext();
    if (targetCtx == null) return null;
    final scrollableState = Scrollable.maybeOf(targetCtx);
    final viewportBox =
        scrollableState?.context.findRenderObject() as RenderBox?;
    if (viewportBox == null || !viewportBox.hasSize) {
      return null;
    }
    return viewportBox.size.height > 0 ? viewportBox.size.height : null;
  }

  double? _scrollOffsetForContext(
    BuildContext? targetCtx, {
    double alignment = 0.5,
  }) {
    if (targetCtx == null || !_scrollCtrl.hasClients) return null;

    final scrollableState = Scrollable.maybeOf(targetCtx);
    if (scrollableState == null) return null;

    final position = scrollableState.position;
    final targetRenderObject = targetCtx.findRenderObject();
    if (targetRenderObject == null) return null;

    final viewport = RenderAbstractViewport.maybeOf(targetRenderObject);
    if (viewport == null) return null;

    final reveal = viewport.getOffsetToReveal(targetRenderObject, alignment);
    return reveal.offset
        .clamp(position.minScrollExtent, position.maxScrollExtent)
        .toDouble();
  }

  bool _jumpToCurrentViewNow({bool animate = true}) {
    return _jumpToCurrentViewAtAlignmentNow(0.5, animate: animate);
  }

  bool _jumpToCalendarAnchorAtAlignmentNow(
    String? anchorTarget,
    double alignment, {
    bool animate = true,
  }) {
    final targetCtx =
        _calendarAnchorContextForTarget(anchorTarget) ??
        _currentViewTargetContext();
    final targetPixels = _scrollOffsetForContext(
      targetCtx,
      alignment: alignment,
    );
    if (targetPixels == null) return false;

    final position = _scrollCtrl.position;

    if (animate) {
      position.animateTo(
        targetPixels,
        duration: const Duration(milliseconds: 320),
        curve: Curves.easeOutCubic,
      );
    } else {
      position.jumpTo(targetPixels);
    }
    return true;
  }

  bool _jumpToCurrentViewAtAlignmentNow(
    double alignment, {
    bool animate = true,
  }) {
    return _jumpToCalendarAnchorAtAlignmentNow(
      _kCalendarAnchorTargetDayChip,
      alignment,
      animate: animate,
    );
  }

  bool _jumpToTodayNow({bool animate = true}) {
    final targetCtx =
        _todayDayKey.currentContext ??
        keyForMonth(_today.kYear, _today.kMonth).currentContext;
    final targetPixels = _centeredScrollOffsetForContext(targetCtx);
    if (targetPixels == null) return false;

    final position = _scrollCtrl.position;

    if (animate) {
      position.animateTo(
        targetPixels,
        duration: const Duration(milliseconds: 320),
        curve: Curves.easeOutCubic,
      );
    } else {
      position.jumpTo(targetPixels);
    }
    return true;
  }

  double? _centeredScrollOffsetForContext(BuildContext? targetCtx) {
    return _scrollOffsetForContext(targetCtx, alignment: 0.5);
  }

  @override
  void dispose() {
    // ✅ Unsubscribe from RouteObserver
    if (_isSubscribed) {
      routeObserver.unsubscribe(this);
    }
    WidgetsBinding.instance.removeObserver(this);
    calendarPushOpenIntent.removeListener(_handleCalendarPushOpenIntent);
    _reminderSub?.cancel();
    _authSub?.cancel();
    _calendarInvalidationSub?.cancel();
    _calendarInvalidationReloadDebounce?.cancel();
    _reminderSyncGate.dispose();
    _reminderService.dispose();
    unawaited(_journalController.forceSave());
    _journalController.onCompletionBadgesRemoved = null;
    _journalController.dispose();
    _calendarRestorationDebounce?.cancel();
    _warmStartCacheDebounceTimer?.cancel();
    unawaited(_flushPendingWarmStartCacheSave(reason: 'dispose'));
    unawaited(_flushPendingCalendarRestorationSave(reason: 'dispose'));
    final dayViewState = _activeDayViewRestorationState;
    if (dayViewState != null) {
      unawaited(_persistDayViewState(dayViewState, reason: 'calendar_dispose'));
    }
    _scrollCtrl.dispose();
    _dayViewDataVersion.dispose();
    _dayViewEventDetailRequest.dispose();
    _onboardingDayRhythmController.removeListener(
      _handleOnboardingDayRhythmChanged,
    );
    _onboardingDayRhythmController.dispose();
    if (_onboardingReviewMode) {
      _hasPresentedOnboardingThisLaunch = false;
      _onboardingReviewSessionProgress = null;
      _onboardingReviewSessionSlide = null;
    }
    GuidedOnboardingController.instance.setExternalOverlaySuppressed(false);
    super.dispose();
  }

  // ✅ Called when we pop back to Calendar from another page
  @override
  void didPopNext() {
    unawaited(_handleCalendarReturnFromAnotherPage());
  }

  @override
  void didPushNext() {
    unawaited(_flushPendingCalendarRestorationSave(reason: 'did_push_next'));
    if (!_canShowCalendarToggleCoachmarkOnReturn) return;
    _calendarToggleCoachmarkArmedForReturn = true;
  }

  // ✅ Fallback: app comes back to foreground
  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    if (kDebugMode) {
      _calendarDebugPrint('[calendar] lifecycle state=${state.name}');
    }
    switch (state) {
      case AppLifecycleState.inactive:
      case AppLifecycleState.hidden:
      case AppLifecycleState.paused:
      case AppLifecycleState.detached:
        _lastBackgroundedAt = DateTime.now();
        unawaited(_journalController.forceSave());
        unawaited(
          _flushPendingWarmStartCacheSave(reason: 'lifecycle:${state.name}'),
        );
        unawaited(
          _flushPendingCalendarRestorationSave(
            reason: 'lifecycle:${state.name}',
          ),
        );
        final dayViewState = _activeDayViewRestorationState;
        if (dayViewState != null) {
          unawaited(
            _persistDayViewState(
              dayViewState,
              reason: 'lifecycle:${state.name}',
            ),
          );
        }
        break;
      case AppLifecycleState.resumed:
        final now = DateTime.now();
        final startupInFlight =
            !_initOnce ||
            _pendingInitialHydration ||
            (_startupFlight != null && !(_startupFlight!.isCompleted));
        if (!startupInFlight &&
            (_lastRefreshTime == null ||
                now.difference(_lastRefreshTime!) >
                    const Duration(seconds: 2))) {
          unawaited(_refreshAfterReturn(reason: 'lifecycle_resumed'));
        } else if (kDebugMode && startupInFlight) {
          _calendarDebugPrint(
            '[calendar] skipped foreground refresh while startup is still running',
          );
        }
        _checkDueReminders();
        unawaited(
          _maybeLoadDecanReflectionPrompt(
            force: _shouldRefreshAfterForegroundResume(now),
          ),
        );
        break;
    }
  }

  // ✅ Refresh when returning to this page
  Future<void> _handleCalendarReturnFromAnotherPage() async {
    if (!mounted) return;
    try {
      await _journalController.reloadToday();
      if (mounted) {
        setState(() => _journalInitialized = true);
      }
    } catch (error, stackTrace) {
      debugPrint('[calendar] journal reload after return failed: $error');
      debugPrint('$stackTrace');
    }
    if (!mounted) return;
    await _maybePresentCalendarToggleCoachmarkAfterReturn();
  }

  bool _shouldRefreshAfterForegroundResume(DateTime now) {
    final lastHydrationAt = _lastSuccessfulHydrationAt;
    if (lastHydrationAt == null) {
      return true;
    }
    if (now.difference(lastHydrationAt) >= _foregroundRefreshThreshold) {
      return true;
    }
    final backgroundedAt = _lastBackgroundedAt;
    if (backgroundedAt == null) {
      return false;
    }
    return now.difference(backgroundedAt) >= _foregroundRefreshThreshold;
  }

  Future<void> _refreshAfterReturn({
    String reason = 'resume',
    bool force = false,
  }) async {
    if (!mounted) return;
    final refreshStartedAt = DateTime.now();
    if (!force && !_shouldRefreshAfterForegroundResume(refreshStartedAt)) {
      _lastRefreshTime = refreshStartedAt;
      if (kDebugMode) {
        _calendarDebugPrint(
          '[calendar] skipped foreground refresh reason=$reason',
        );
      }
      return;
    }

    // Small delay to make sure any DB writes (like imports) are done
    await Future.delayed(const Duration(milliseconds: 200));
    if (!mounted) return;

    try {
      await ShareRepo(
        Supabase.instance.client,
      ).syncAcceptedInviteCalendarImports();
      await _loadFromDisk(source: 'foreground:$reason', preserveViewport: true);
      _lastRefreshTime = DateTime.now();
      if (mounted) setState(() {});
      _checkDueReminders();
      await _maybeLoadDecanReflectionPrompt(force: true);
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[CalendarPage] Error refreshing: $e');
      }
    }
  }

  Future<void> _checkDueReminders() async {
    if (!_remindersEnabled) return;
    if (!_remindersLoaded || !mounted) return;
    try {
      final nowUtc = DateTime.now().toUtc();
      // Use local cache only for now to avoid id mismatches causing reappearing chips
      List<Reminder> due = _reminderService.dueReminders(nowUtc);
      if (due.isEmpty) {
        if (_floatingReminders.isNotEmpty && mounted) {
          setState(() => _floatingReminders = []);
        }
        return;
      }

      // Mark as shown locally so they stop re-queuing
      for (final r in due) {
        _reminderService.markStatus(r.id, ReminderStatus.shownInApp);
      }

      // De-dupe and update overlay
      final seen = <String>{};
      // Cap to at most 5 to avoid UI overload
      setState(() {
        _floatingReminders = [
          for (final r in due)
            if (seen.add(r.id)) r,
        ].take(5).toList();
      });
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[Reminders] _checkDueReminders failed: $e');
      }
    }
  }

  List<ReminderRule> _dedupeReminderRules(List<ReminderRule> rules) {
    String sig(ReminderRule r) {
      final weekdays = r.repeat.weekdays.toList()..sort();
      final monthDays = r.repeat.monthDays.toList()..sort();
      final decanDays = r.repeat.decanDays.toList()..sort();
      final kMonthDays = r.repeat.kemeticMonthDays.toList()..sort();
      return [
        r.title.trim().toLowerCase(),
        r.startLocal.toIso8601String(),
        r.allDay ? 'allDay' : 'timed',
        r.color.toARGB32().toString(),
        r.category ?? '',
        r.active ? 'active' : 'inactive',
        r.repeat.kind.name,
        r.repeat.interval,
        weekdays.join(','),
        r.repeat.monthDay ?? '',
        monthDays.join(','),
        decanDays.join(','),
        kMonthDays.join(','),
      ].join('|');
    }

    final byId = <String, ReminderRule>{};
    for (final r in rules) {
      byId.putIfAbsent(r.id, () => r);
    }

    final bySig = <String, ReminderRule>{};
    for (final r in byId.values) {
      bySig.putIfAbsent(sig(r), () => r);
    }

    return bySig.values.toList();
  }

  Future<void> _loadEndedReminderIds() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final list = prefs.getStringList(_endedReminderPrefsKey) ?? const [];
      _endedReminderIds
        ..clear()
        ..addAll(list);
    } catch (_) {
      // ignore
    }
  }

  Future<void> _saveEndedReminderIds() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setStringList(
        _endedReminderPrefsKey,
        _endedReminderIds.toList(),
      );
    } catch (_) {
      // ignore
    }
  }

  Future<void> _loadReminderRules() async {
    if (_reminderRulesLoaded) return;
    try {
      await _loadEndedReminderIds();
      final metaRules = await _hydrateReminderRulesFromMeta();
      final occRules = await _hydrateReminderRulesFromOccurrences();

      final byId = <String, ReminderRule>{};
      for (final r in metaRules) {
        if (_endedReminderIds.contains(r.id)) continue;
        byId[r.id] = r;
      }
      for (final r in occRules) {
        if (_endedReminderIds.contains(r.id)) continue;
        // Only add if we didn't already get a meta-backed rule.
        byId.putIfAbsent(r.id, () => r);
      }

      List<ReminderRule> source = byId.values.toList();
      if (source.isEmpty) {
        source = await _reminderRuleStore.load();
      }

      final merged = _dedupeReminderRules(
        source.where((r) => !_endedReminderIds.contains(r.id)).toList(),
      );

      // Ensure meta rows exist for all merged rules so other devices can hydrate.
      for (final r in merged) {
        await _ensureReminderRuleMeta(r);
      }

      if (mounted) {
        setState(() {
          _reminderRules
            ..clear()
            ..addAll(merged);
          _reminderRulesLoaded = true;
        });
      } else {
        _reminderRules
          ..clear()
          ..addAll(merged);
        _reminderRulesLoaded = true;
      }

      // Persist merged set so the latest server-state is cached locally, but
      // do not repopulate if we intentionally keep the list empty.
      if (merged.isNotEmpty) {
        await _saveReminderRules();
      } else {
        await _reminderRuleStore.saveAll(const []);
      }
    } catch (_) {
      _reminderRulesLoaded = true;
    }
  }

  Future<void> _primeReminderRulesFromFlows(Iterable<_Flow> flows) async {
    try {
      await _loadEndedReminderIds();
      var source = flows
          .where((flow) => flow.isReminder)
          .map(_reminderRuleFromFlow)
          .whereType<ReminderRule>()
          .where((rule) => !_endedReminderIds.contains(rule.id))
          .toList(growable: false);
      if (source.isEmpty) {
        source = await _reminderRuleStore.load();
      }

      final merged = _dedupeReminderRules(
        source.where((rule) => !_endedReminderIds.contains(rule.id)).toList(),
      );
      _reminderRules
        ..clear()
        ..addAll(merged);
      _reminderRulesLoaded = true;

      if (merged.isNotEmpty) {
        await _saveReminderRules();
      } else {
        await _reminderRuleStore.saveAll(const []);
      }
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[reminders] prime from loaded flows failed: $e');
      }
    }
  }

  // Load reminder rules from meta events stored in user_events with prefix "reminder:rule:".
  Future<List<ReminderRule>> _hydrateReminderRulesFromMeta() async {
    try {
      // With flow-backed reminders, hydrate from flows instead of reminder meta events.
      final repo = UserEventsRepo(Supabase.instance.client);
      final flows = await repo.getAllFlows();
      final reminderFlows = flows.where((f) => f.isReminder).toList();
      if (reminderFlows.isEmpty) return const [];

      final List<ReminderRule> rebuilt = [];
      for (final f in reminderFlows) {
        if (f.reminderUuid == null || f.notes == null) continue;
        final rawNotes = f.notes!.trim();
        if (rawNotes.isEmpty) continue;
        try {
          final decoded = jsonDecode(rawNotes);
          final map = Map<String, dynamic>.from(decoded as Map);
          final parsed = ReminderRule.fromJson(map);
          final rule = parsed.copyWith(
            calendarId: parsed.calendarId ?? f.calendarId,
            endLocal: parsed.endLocal ?? f.endDate,
          );
          if (_endedReminderIds.contains(rule.id)) continue;
          rebuilt.add(rule);
        } catch (_) {
          continue;
        }
      }
      return rebuilt;
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[reminders] hydrate meta failed: $e');
      }
      return const [];
    }
  }

  // Fallback: rebuild rules from occurrences if no meta is present (bootstrap for PWA/first run).
  Future<List<ReminderRule>> _hydrateReminderRulesFromOccurrences() async {
    // With flow-backed reminders, occurrences are derived from flows; no direct reminder:* bootstrap.
    return const [];
  }

  Future<void> _ensureReminderRuleMeta(ReminderRule rule) async {
    // No-op: reminder rules are persisted via flow rows with isReminder/reminderUuid.
  }

  Future<void> _saveReminderRules() async {
    final deduped = _dedupeReminderRules(_reminderRules);
    _reminderRules
      ..clear()
      ..addAll(deduped);
    await _reminderRuleStore.saveAll(_reminderRules);
  }

  void _upsertDebugDaySheetSmokeReminderRule(ReminderRule rule) {
    assert(_debugDaySheetSmokeEnabled);
    _endedReminderIds.remove(rule.id);

    final idx = _reminderRules.indexWhere((r) => r.id == rule.id);
    if (idx >= 0) {
      _reminderRules[idx] = rule;
    } else {
      _reminderRules.add(rule);
    }
    final deduped = _dedupeReminderRules(_reminderRules);
    _reminderRules
      ..clear()
      ..addAll(deduped);
    _reminderRulesLoaded = true;

    var changed = _pruneReminderNotes(rule.id, fromDate: null);
    final windowStart = DateUtils.dateOnly(rule.startLocal);
    final windowEnd = _reminderWindowEnd(windowStart, [rule]);
    changed =
        _materializeReminderLocally(
          rule: rule,
          occurrences: _generateReminderOccurrences(
            rule,
            windowStart,
            windowEnd,
          ),
          notify: false,
        ) ||
        changed;
    if (changed) {
      _refreshNoteCacheUi();
    }
    if (mounted) {
      setState(() {});
      _bumpDataVersion();
    }
  }

  void _deleteDebugDaySheetSmokeReminderRule(String id) {
    assert(_debugDaySheetSmokeEnabled);
    _endedReminderIds.add(id);
    _reminderRules.removeWhere((r) => r.id == id);
    final changed = _pruneReminderNotes(id, fromDate: null);
    if (changed) {
      _refreshNoteCacheUi();
    }
    if (mounted) {
      setState(() {});
      _bumpDataVersion();
    }
  }

  bool _isUuid(String s) {
    final re = RegExp(
      r'^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$',
    );
    return re.hasMatch(s);
  }

  String? _dbReminderUuidFromRuleId(String ruleId) {
    if (ruleId.startsWith('nutrition:')) {
      final suffix = ruleId.substring('nutrition:'.length);
      return _isUuid(suffix) ? suffix : null;
    }
    return _isUuid(ruleId) ? ruleId : null;
  }

  Future<void> _upsertReminderRule(ReminderRule rule) async {
    final effectiveCalendarId =
        _normalizeCalendarId(rule.calendarId) ??
        _normalizeCalendarId(_personalCalendarId);
    final effectiveRule = effectiveCalendarId == null
        ? rule
        : rule.copyWith(calendarId: effectiveCalendarId);
    final effectiveEndDate = effectiveRule.endLocal == null
        ? null
        : DateUtils.dateOnly(effectiveRule.endLocal!);
    final dbUuid = _dbReminderUuidFromRuleId(rule.id);
    if (rule.id.startsWith('nutrition:') && dbUuid == null) {
      throw StateError(
        'Invalid nutrition rule id (expected uuid suffix): ${rule.id}',
      );
    }
    if (_debugDaySheetSmokeEnabled) {
      _upsertDebugDaySheetSmokeReminderRule(effectiveRule);
      return;
    }

    // If a reminder is recreated with the same id, clear any tombstone flag.
    if (_endedReminderIds.remove(rule.id)) {
      await _saveEndedReminderIds();
    }
    try {
      final flowsRepo = FlowsRepo(Supabase.instance.client);
      final existingReminderFlowId = dbUuid == null
          ? null
          : await _findFlowIdByReminderUuid(dbUuid);
      final isNewReminderFlow = existingReminderFlowId == null;
      final rulesJson =
          <Map<String, dynamic>>[]; // reminder recurrence handled separately
      FlowRow saved;
      if (rule.id.isNotEmpty) {
        // Try to find existing flow by reminder UUID
        if (existingReminderFlowId != null) {
          saved = await flowsRepo.upsert(
            id: existingReminderFlowId,
            name: effectiveRule.title,
            color: effectiveRule.color.toARGB32() & 0x00FFFFFF,
            active: effectiveRule.active,
            calendarId: effectiveCalendarId,
            startDate: DateUtils.dateOnly(effectiveRule.startLocal),
            endDate: effectiveEndDate,
            notes: jsonEncode(effectiveRule.toJson()),
            rulesJson: rulesJson,
            isReminder: true,
            reminderUuid: dbUuid,
          );
        } else {
          saved = await flowsRepo.upsert(
            name: effectiveRule.title,
            color: effectiveRule.color.toARGB32() & 0x00FFFFFF,
            active: effectiveRule.active,
            calendarId: effectiveCalendarId,
            startDate: DateUtils.dateOnly(effectiveRule.startLocal),
            endDate: effectiveEndDate,
            notes: jsonEncode(effectiveRule.toJson()),
            rulesJson: rulesJson,
            isReminder: true,
            reminderUuid: dbUuid,
          );
        }
      } else {
        saved = await flowsRepo.upsert(
          name: effectiveRule.title,
          color: effectiveRule.color.toARGB32() & 0x00FFFFFF,
          active: effectiveRule.active,
          calendarId: effectiveCalendarId,
          startDate: DateUtils.dateOnly(effectiveRule.startLocal),
          endDate: effectiveEndDate,
          notes: jsonEncode(effectiveRule.toJson()),
          rulesJson: rulesJson,
          isReminder: true,
          reminderUuid: dbUuid,
        );
      }
      // Keep local copy in sync
      final idx = _reminderRules.indexWhere((r) => r.id == rule.id);
      if (idx >= 0) {
        _reminderRules[idx] = effectiveRule;
      } else {
        _reminderRules.add(effectiveRule);
      }
      await _saveReminderRules();
      if (mounted) setState(() {});
      // Write reminder occurrences so pills show immediately.
      await _syncReminderEvents(refreshUi: false);
      // Refresh flows/reminders
      await _loadFromDisk();
      if (effectiveCalendarId != null && isNewReminderFlow) {
        final windowStart = DateUtils.dateOnly(DateTime.now());
        final windowEnd = _reminderWindowEnd(windowStart, [effectiveRule]);
        final occurrences = _generateReminderOccurrences(
          effectiveRule,
          windowStart,
          windowEnd,
        );
        String? clientEventId;
        if (occurrences.isNotEmpty) {
          final firstDate = occurrences.first;
          final cidDate =
              '${firstDate.year.toString().padLeft(4, '0')}-${firstDate.month.toString().padLeft(2, '0')}-${firstDate.day.toString().padLeft(2, '0')}';
          clientEventId = 'reminder:${effectiveRule.id}:$cidDate';
        }
        await _notifySharedCalendarItemAdded(
          calendarId: effectiveCalendarId,
          itemType: 'reminder',
          itemId: saved.id.toString(),
          itemTitle: effectiveRule.title,
          clientEventId: clientEventId,
          flowId: saved.id,
          reminderId: dbUuid ?? effectiveRule.id,
          startDate: effectiveRule.startLocal,
          endDate: effectiveEndDate,
        );
      }
    } catch (e, st) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[reminders] upsert via flow failed: $e (${e.runtimeType})\n$st',
        );
        if (e is PostgrestException) {
          _calendarDebugPrint(
            '[reminders] PostgrestException code=${e.code} message=${e.message} details=${e.details} hint=${e.hint}',
          );
        }
      }
      rethrow;
    }
  }

  Future<void> _deleteReminderRule(String id) async {
    if (_debugDaySheetSmokeEnabled) {
      _deleteDebugDaySheetSmokeReminderRule(id);
      return;
    }
    _endedReminderIds.add(id);
    await _saveEndedReminderIds();

    final eventsRepo = UserEventsRepo(Supabase.instance.client);
    final cidPrefix = 'reminder:$id:';
    try {
      await eventsRepo.deleteByClientIdPrefix(cidPrefix);
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[reminders] delete reminder events failed ($cidPrefix): $e',
        );
      }
    }
    try {
      await eventsRepo.deleteByClientId('reminder:rule:$id');
      await eventsRepo.recordDeletionTombstone(
        clientEventId: 'reminder:$id',
        reason: 'delete_reminder_rule',
      );
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[reminders] record reminder tombstone failed: $e');
      }
    }

    try {
      final flowsRepo = FlowsRepo(Supabase.instance.client);
      final dbUuid = _dbReminderUuidFromRuleId(id);
      final existingId = dbUuid == null
          ? null
          : await _findFlowIdByReminderUuid(dbUuid);
      if (existingId != null) {
        try {
          await eventsRepo.deleteByFlowId(existingId);
        } catch (e) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[reminders] delete reminder flow events failed: $e',
            );
          }
        }
        await flowsRepo.delete(existingId);
      }
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[reminders] delete via flow failed: $e');
      }
    }
    // Remove from local rule list
    _reminderRules.removeWhere((r) => r.id == id);
    // Prune any cached notes so calendar UI updates immediately
    _pruneReminderNotes(
      id,
      fromDate: null,
    ); // remove all cached notes for this reminder
    if (mounted) {
      setState(() {});
      _bumpDataVersion();
    }
    await _saveReminderRules();
    await _loadFromDisk();
  }

  Set<int> _monthDayTargets(ReminderRepeat repeat, DateTime startLocal) {
    if (repeat.monthDays.isNotEmpty) {
      return repeat.monthDays.map((d) => d.clamp(1, 31)).toSet();
    }
    final fallback = (repeat.monthDay ?? startLocal.day).clamp(1, 31);
    return {fallback};
  }

  Set<int> _decanDayTargets(ReminderRepeat repeat, DateTime startLocal) {
    if (repeat.decanDays.isNotEmpty) {
      return repeat.decanDays.map((d) => d.clamp(1, 10)).toSet();
    }
    final base = startLocal.day % 10;
    final fallback = base == 0 ? 10 : base;
    return {fallback};
  }

  Set<int> _kemeticMonthDayTargets(ReminderRepeat repeat, DateTime startLocal) {
    if (repeat.kemeticMonthDays.isNotEmpty) {
      return repeat.kemeticMonthDays.map((d) => d.clamp(1, 30)).toSet();
    }
    final fallback = (repeat.monthDay ?? startLocal.day).clamp(1, 30);
    return {fallback};
  }

  Set<int> _parseDayCsv(String raw, {required int min, required int max}) {
    return raw
        .split(',')
        .map((p) => int.tryParse(p.trim()))
        .whereType<int>()
        .where((n) => n >= min && n <= max)
        .toSet();
  }

  String _encodeReminderDetail(ReminderRule rule) {
    final repeatJson = jsonEncode(rule.repeat.toJson());
    final meta = 'repeat=$repeatJson;';
    return _encodeDetailWithMeta(
          meta,
          color: rule.color,
          alertMinutes: rule.alertOffsetMinutes,
        ) ??
        meta;
  }

  List<DateTime> _generateReminderOccurrences(
    ReminderRule rule,
    DateTime windowStart,
    DateTime windowEnd,
  ) {
    final dates = <DateTime>[];
    final startDate = DateUtils.dateOnly(rule.startLocal);
    final endDate = rule.endLocal == null
        ? null
        : DateUtils.dateOnly(rule.endLocal!);
    if (endDate != null && endDate.isBefore(startDate)) {
      return const [];
    }
    final from = windowStart.isAfter(startDate) ? windowStart : startDate;
    final effectiveWindowEnd = endDate == null || endDate.isAfter(windowEnd)
        ? windowEnd
        : endDate;
    if (effectiveWindowEnd.isBefore(from)) {
      return const [];
    }

    int safeInterval(int value) => value <= 0 ? 1 : value;

    switch (rule.repeat.kind) {
      case ReminderRepeatKind.none:
        if (!startDate.isBefore(windowStart) &&
            !startDate.isAfter(effectiveWindowEnd)) {
          dates.add(startDate);
        }
        break;

      case ReminderRepeatKind.everyNDays:
        final step = safeInterval(rule.repeat.interval);
        DateTime cur = startDate;
        while (cur.isBefore(from)) {
          cur = cur.add(Duration(days: step));
        }
        while (!cur.isAfter(effectiveWindowEnd)) {
          if (!cur.isBefore(from)) dates.add(cur);
          cur = cur.add(Duration(days: step));
        }
        break;

      case ReminderRepeatKind.weekly:
        final weekdays = rule.repeat.weekdays.isEmpty
            ? {from.weekday}
            : rule.repeat.weekdays;
        DateTime cur = from;
        while (!cur.isAfter(effectiveWindowEnd)) {
          if (!cur.isBefore(startDate) && weekdays.contains(cur.weekday)) {
            dates.add(cur);
          }
          cur = cur.add(const Duration(days: 1));
        }
        break;

      case ReminderRepeatKind.monthlyDay:
        final targets = _monthDayTargets(rule.repeat, rule.startLocal);
        DateTime cursor = DateTime(from.year, from.month, 1);
        if (cursor.isBefore(startDate)) {
          cursor = DateTime(startDate.year, startDate.month, 1);
        }
        while (!cursor.isAfter(effectiveWindowEnd)) {
          final daysInMonth = DateUtils.getDaysInMonth(
            cursor.year,
            cursor.month,
          );
          for (final t in targets) {
            final day = t.clamp(1, daysInMonth);
            final occ = DateTime(cursor.year, cursor.month, day);
            if (!occ.isBefore(from) &&
                !occ.isBefore(startDate) &&
                !occ.isAfter(effectiveWindowEnd)) {
              dates.add(occ);
            }
          }
          cursor = DateTime(cursor.year, cursor.month + 1, 1);
        }
        break;

      case ReminderRepeatKind.kemeticEveryNDecans:
        final step = safeInterval(rule.repeat.interval) * 10;
        DateTime cur = startDate;
        while (cur.isBefore(from)) {
          cur = cur.add(Duration(days: step));
        }
        while (!cur.isAfter(effectiveWindowEnd)) {
          if (!cur.isBefore(startDate)) dates.add(cur);
          cur = cur.add(Duration(days: step));
        }
        break;

      case ReminderRepeatKind.kemeticDecanDay:
        final targets = _decanDayTargets(rule.repeat, rule.startLocal);
        DateTime cur = from.isBefore(startDate) ? startDate : from;
        while (!cur.isAfter(effectiveWindowEnd)) {
          final k = KemeticMath.fromGregorian(cur);
          if (k.kMonth != 13) {
            final dInDecan = ((k.kDay - 1) % 10) + 1;
            if (targets.contains(dInDecan)) {
              dates.add(cur);
            }
          }
          cur = cur.add(const Duration(days: 1));
        }
        break;

      case ReminderRepeatKind.kemeticMonthDay:
        final targets = _kemeticMonthDayTargets(rule.repeat, rule.startLocal);
        DateTime cur = from.isBefore(startDate) ? startDate : from;
        while (!cur.isAfter(effectiveWindowEnd)) {
          final k = KemeticMath.fromGregorian(cur);
          if (k.kMonth != 13 && targets.contains(k.kDay)) {
            dates.add(cur);
          }
          cur = cur.add(const Duration(days: 1));
        }
        break;
    }

    final deduped = dates.toSet().toList()..sort((a, b) => a.compareTo(b));
    return deduped;
  }

  String _reminderRepeatLabel(ReminderRule rule) {
    String ordinal(int n) {
      if (n >= 11 && n <= 13) return '${n}th';
      switch (n % 10) {
        case 1:
          return '${n}st';
        case 2:
          return '${n}nd';
        case 3:
          return '${n}rd';
        default:
          return '${n}th';
      }
    }

    switch (rule.repeat.kind) {
      case ReminderRepeatKind.none:
        return 'One-time';
      case ReminderRepeatKind.everyNDays:
        return 'Every ${rule.repeat.interval}d';
      case ReminderRepeatKind.weekly:
        if (rule.repeat.weekdays.isEmpty) return 'Weekly';
        const labels = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
        final parts = rule.repeat.weekdays.toList()..sort();
        final joined = parts.map((d) => labels[(d - 1).clamp(0, 6)]).join('/');
        return 'Weekly $joined';
      case ReminderRepeatKind.monthlyDay:
        final days = _monthDayTargets(rule.repeat, rule.startLocal).toList()
          ..sort();
        final labels = days.map(ordinal).join(', ');
        return 'Monthly $labels – G';
      case ReminderRepeatKind.kemeticEveryNDecans:
        final iv = rule.repeat.interval <= 0 ? 1 : rule.repeat.interval;
        return iv == 1 ? 'Every Decan' : 'Every $iv Decans';
      case ReminderRepeatKind.kemeticDecanDay:
        final ds = _decanDayTargets(rule.repeat, rule.startLocal).toList()
          ..sort();
        return 'Each Decan · Day ${ds.join(', ')}';
      case ReminderRepeatKind.kemeticMonthDay:
        final ds = _kemeticMonthDayTargets(
          rule.repeat,
          rule.startLocal,
        ).toList()..sort();
        final ords = ds.map((d) => ordinal(d)).join(', ');
        return 'Monthly $ords – K';
    }
  }

  List<ReminderRule> _calendarSheetReminderRulesForDay(
    int kYear,
    int kMonth,
    int kDay,
    List<EventItem> dayEvents,
  ) {
    final day = DateUtils.dateOnly(
      KemeticMath.toGregorian(kYear, kMonth, kDay),
    );
    final rulesByKey = <String, ReminderRule>{};
    final fallbackKeys = <String>{};

    for (final rule in _dedupeReminderRules(_reminderRules)) {
      if (_endedReminderIds.contains(rule.id)) continue;
      final occurrences = _generateReminderOccurrences(rule, day, day);
      final occursOnDay = occurrences.any((occurrence) {
        final normalized = DateUtils.dateOnly(occurrence);
        return normalized.year == day.year &&
            normalized.month == day.month &&
            normalized.day == day.day;
      });
      if (!occursOnDay) continue;

      rulesByKey.putIfAbsent(
        _calendarSheetReminderRuleDedupKey(rule),
        () => rule,
      );
      fallbackKeys.add(_calendarSheetReminderFallbackKeyForRule(rule));
    }

    for (final event in dayEvents) {
      if (!event.isReminder) continue;
      final range = _calendarSheetLocalRangeForEvent(
        kYear,
        kMonth,
        kDay,
        event,
      );
      final fallbackKey = _calendarSheetReminderFallbackKeyForEvent(
        event,
        range.start,
      );
      if (fallbackKeys.contains(fallbackKey)) continue;
      final eventKey = _calendarSheetReminderEventDedupKey(event, range.start);
      if (rulesByKey.containsKey(eventKey)) continue;
      final rule = _calendarSheetReminderRuleFromVisibleEvent(
        event,
        range.start,
      );
      if (rule == null) continue;
      rulesByKey[eventKey] = rule;
      fallbackKeys.add(fallbackKey);
    }

    final rules = rulesByKey.values.toList();
    rules.sort((a, b) {
      final aMinutes = a.allDay
          ? -1
          : a.startLocal.hour * 60 + a.startLocal.minute;
      final bMinutes = b.allDay
          ? -1
          : b.startLocal.hour * 60 + b.startLocal.minute;
      final timeCompare = aMinutes.compareTo(bMinutes);
      if (timeCompare != 0) return timeCompare;
      return a.title.toLowerCase().compareTo(b.title.toLowerCase());
    });
    return rules;
  }

  static const String _kCalendarSheetVisibleReminderRulePrefix =
      'visible-day-reminder:';

  bool _isCalendarSheetVisibleReminderRule(ReminderRule rule) =>
      rule.id.startsWith(_kCalendarSheetVisibleReminderRulePrefix);

  String _calendarSheetReminderRuleDedupKey(ReminderRule rule) {
    final id = rule.id.trim();
    if (id.isNotEmpty &&
        !id.startsWith(_kCalendarSheetVisibleReminderRulePrefix)) {
      return 'rid:$id';
    }
    return _calendarSheetReminderFallbackKeyForRule(rule);
  }

  String _calendarSheetReminderEventDedupKey(
    EventItem event,
    DateTime startLocal,
  ) {
    final reminderId = event.reminderId?.trim();
    if (reminderId != null && reminderId.isNotEmpty) {
      return 'rid:$reminderId';
    }

    final clientEventId = event.clientEventId?.trim();
    if (clientEventId != null && clientEventId.isNotEmpty) {
      return 'cid:$clientEventId';
    }

    final eventId = event.id?.trim();
    if (eventId != null && eventId.isNotEmpty) {
      return 'event:$eventId';
    }

    return _calendarSheetReminderFallbackKeyForEvent(event, startLocal);
  }

  String _calendarSheetReminderFallbackKey({
    required String? calendarId,
    required String title,
    required bool allDay,
    required DateTime startLocal,
  }) {
    final normalizedCalendar = (calendarId ?? '').trim().toLowerCase();
    final normalizedTitle = title.trim().toLowerCase();
    final minute = allDay ? -1 : startLocal.hour * 60 + startLocal.minute;
    return 'fallback:$normalizedCalendar|$normalizedTitle|$allDay|$minute';
  }

  String _calendarSheetReminderFallbackKeyForRule(ReminderRule rule) {
    return _calendarSheetReminderFallbackKey(
      calendarId: rule.calendarId,
      title: rule.title,
      allDay: rule.allDay,
      startLocal: rule.startLocal,
    );
  }

  String _calendarSheetReminderFallbackKeyForEvent(
    EventItem event,
    DateTime startLocal,
  ) {
    return _calendarSheetReminderFallbackKey(
      calendarId: event.calendarId,
      title: event.title,
      allDay: event.allDay,
      startLocal: startLocal,
    );
  }

  ReminderRepeat _calendarSheetReminderRepeatFromVisibleEvent(EventItem event) {
    final payload = event.behaviorPayload;
    final payloadRepeat = payload == null
        ? null
        : (payload['repeat'] ?? payload['reminder_repeat']);
    if (payloadRepeat is Map) {
      return ReminderRepeat.fromJson(Map<String, dynamic>.from(payloadRepeat));
    }

    final rawDetail = event.detail;
    if (rawDetail == null || rawDetail.isEmpty) {
      return const ReminderRepeat();
    }
    const marker = 'repeat=';
    final start = rawDetail.indexOf(marker);
    if (start < 0) return const ReminderRepeat();
    final valueStart = start + marker.length;
    final valueEnd = rawDetail.indexOf(';', valueStart);
    if (valueEnd <= valueStart) return const ReminderRepeat();
    try {
      final decoded = jsonDecode(rawDetail.substring(valueStart, valueEnd));
      if (decoded is Map) {
        return ReminderRepeat.fromJson(Map<String, dynamic>.from(decoded));
      }
    } catch (_) {
      return const ReminderRepeat();
    }
    return const ReminderRepeat();
  }

  String _calendarSheetVisibleReminderRuleId(EventItem event) {
    final reminderId = event.reminderId?.trim();
    if (reminderId != null && reminderId.isNotEmpty) return reminderId;

    final clientEventId = event.clientEventId?.trim();
    if (clientEventId != null && clientEventId.isNotEmpty) {
      return '$_kCalendarSheetVisibleReminderRulePrefix'
          'cid:${Uri.encodeComponent(clientEventId)}';
    }

    final eventId = event.id?.trim();
    if (eventId != null && eventId.isNotEmpty) {
      return '$_kCalendarSheetVisibleReminderRulePrefix'
          'event:${Uri.encodeComponent(eventId)}';
    }

    return '$_kCalendarSheetVisibleReminderRulePrefix'
        'fallback:${Uri.encodeComponent(_calendarSheetEventIdentityKey(event))}';
  }

  ReminderRule? _calendarSheetReminderRuleFromVisibleEvent(
    EventItem event,
    DateTime startLocal,
  ) {
    if (!event.isReminder) return null;
    final title = event.title.trim();
    final decodedDetail = _decodeDetailMetadata(event.detail);
    return ReminderRule(
      id: _calendarSheetVisibleReminderRuleId(event),
      calendarId: event.calendarId,
      title: title.isEmpty ? 'Reminder' : title,
      startLocal: startLocal,
      allDay: event.allDay,
      color: event.manualColor ?? event.color,
      category: event.category,
      active: true,
      repeat: _calendarSheetReminderRepeatFromVisibleEvent(event),
      alertOffsetMinutes: decodedDetail.alertMinutes ?? _alertNoneMinutes,
    );
  }

  ({String primary, String? subline}) _daySheetReminderRuleLines(
    ReminderRule rule,
  ) {
    final label = _reminderRepeatLabel(rule);
    if (label.contains(' · ')) {
      final parts = label.split(' · ');
      return (primary: parts.first, subline: parts.skip(1).join(' · '));
    }
    if (label.contains(' – ')) {
      final parts = label.split(' – ');
      return (primary: parts.first, subline: parts.skip(1).join(' – '));
    }
    return (primary: label, subline: null);
  }

  bool _pruneReminderNotes(String ruleId, {DateTime? fromDate}) {
    var changed = false;
    final keysToRemove = <String>[];
    _notes.forEach((k, list) {
      final before = list.length;
      list.removeWhere((n) {
        final isTarget = n.isReminder && n.reminderId == ruleId;
        final isOverride =
            n.detail?.contains(_kReminderManualOverrideMarker) == true;
        if (isOverride) return false;
        if (!isTarget) return false;
        if (fromDate == null) return true;
        final parts = k.split('-');
        if (parts.length != 3) return true;
        final ky = int.tryParse(parts[0]) ?? 0;
        final km = int.tryParse(parts[1]) ?? 0;
        final kd = int.tryParse(parts[2]) ?? 0;
        try {
          final g = KemeticMath.toGregorian(ky, km, kd);
          return !g.isBefore(fromDate);
        } catch (_) {
          return true;
        }
      });
      if (list.length != before) {
        changed = true;
      }
      if (list.isEmpty) keysToRemove.add(k);
    });
    for (final k in keysToRemove) {
      _notes.remove(k);
    }
    if (keysToRemove.isNotEmpty) {
      changed = true;
    }
    return changed;
  }

  bool _materializeReminderLocally({
    required ReminderRule rule,
    required List<DateTime> occurrences,
    int? flowId,
    bool notify = true,
  }) {
    var changed = false;
    final calendarName = _calendarSummary(rule.calendarId)?.name;
    for (final day in occurrences) {
      final k = KemeticMath.fromGregorian(day);
      final cidDate =
          '${day.year.toString().padLeft(4, '0')}-${day.month.toString().padLeft(2, '0')}-${day.day.toString().padLeft(2, '0')}';
      final clientEventId = 'reminder:${rule.id}:$cidDate';
      final startTime = rule.allDay
          ? null
          : TimeOfDay(
              hour: rule.startLocal.hour,
              minute: rule.startLocal.minute,
            );
      final endTime = rule.allDay
          ? null
          : TimeOfDay.fromDateTime(day.add(const Duration(minutes: 30)));
      // Skip if a canonical DB-backed note already exists for this flow/time/title.
      if (flowId != null && flowId > 0) {
        final key = _kKey(k.kYear, k.kMonth, k.kDay);
        final bucket = _notes[key];
        if (bucket != null) {
          final targetTitle = rule.title.trim().toLowerCase();
          final hasCanonical = bucket.any((n) {
            if ((n.flowId ?? -1) != flowId) return false;
            if ((n.id ?? '').trim().isEmpty) return false;
            if (rule.allDay != n.allDay) return false;
            if (!rule.allDay) {
              if (n.start == null ||
                  n.start!.hour != startTime?.hour ||
                  n.start!.minute != startTime?.minute) {
                return false;
              }
            }
            return n.title.trim().toLowerCase() == targetTitle;
          });
          if (hasCanonical) {
            continue;
          }
        }
      }
      changed =
          _addNote(
            k.kYear,
            k.kMonth,
            k.kDay,
            rule.title,
            null,
            clientEventId: clientEventId,
            calendarId: rule.calendarId,
            calendarName: calendarName,
            allDay: rule.allDay,
            start: startTime,
            end: endTime,
            manualColor: rule.color,
            category: rule.category,
            isReminder: true,
            reminderId: rule.id,
            flowId: flowId,
            alertOffsetMinutes: rule.alertOffsetMinutes,
            notify: false,
          ) ||
          changed;
    }

    if (changed && notify) {
      _refreshNoteCacheUi();
    }
    return changed;
  }

  Future<void> _syncReminderEvents({
    bool refreshUi = false,
    bool updateLocalCache = true,
  }) async {
    _pendingReminderSyncRefreshUi = _pendingReminderSyncRefreshUi || refreshUi;
    _pendingReminderSyncUpdateLocalCache =
        _pendingReminderSyncUpdateLocalCache || updateLocalCache;

    await _reminderSyncGate.runCoalesced(() async {
      final shouldRefreshUi = _pendingReminderSyncRefreshUi;
      final shouldUpdateLocalCache = _pendingReminderSyncUpdateLocalCache;
      _pendingReminderSyncRefreshUi = false;
      _pendingReminderSyncUpdateLocalCache = false;

      await _performReminderSync(
        refreshUi: shouldRefreshUi,
        updateLocalCache: shouldUpdateLocalCache,
      );
    });
  }

  static const int _reminderSyncYieldBatchSize = 8;

  Future<void> _yieldReminderSyncBatchIfNeeded(int processedWrites) async {
    if (processedWrites <= 0 ||
        processedWrites % _reminderSyncYieldBatchSize != 0) {
      return;
    }
    await Future<void>.delayed(Duration.zero);
    await _reminderSyncGate.waitForOrientationCriticalSection();
  }

  Future<void> _performReminderSync({
    bool refreshUi = false,
    bool updateLocalCache = true,
  }) async {
    await _reminderSyncGate.waitForOrientationCriticalSection();
    await _loadReminderRules();
    if (_reminderRules.isEmpty) return;
    final repo = UserEventsRepo(Supabase.instance.client);
    final today = DateUtils.dateOnly(DateTime.now());

    final windowEnd = _reminderWindowEnd(today, _reminderRules);
    var localCacheChanged = false;
    var processedOccurrenceWrites = 0;
    var desiredOccurrenceWrites = 0;
    var skippedUnchangedOccurrenceWrites = 0;
    var completedOccurrenceWrites = 0;

    for (final rule in _reminderRules) {
      await _reminderSyncGate.waitForOrientationCriticalSection();
      // Persist meta before generating occurrences to keep server source-of-truth in sync.
      await _ensureReminderRuleMeta(rule);
      final overriddenDates = <String>{};
      List<_ReminderOccurrenceRow> existingRows = [];
      try {
        existingRows = await repo.getReminderOccurrenceRows(
          'reminder:${rule.id}:',
          fromUtc: today,
        );
        for (final row in existingRows) {
          final cid = row.clientEventId ?? '';
          final parts = cid.split(':');
          final datePart = parts.isNotEmpty ? parts.last.trim() : '';
          final hasOverride =
              row.detail?.contains(_kReminderManualOverrideMarker) == true;
          if (hasOverride && datePart.isNotEmpty) {
            overriddenDates.add(datePart);
          }
        }
      } catch (_) {}
      final existingRowsByClientEventId = <String, _ReminderOccurrenceRow>{
        for (final row in existingRows)
          if ((row.clientEventId ?? '').isNotEmpty) row.clientEventId!: row,
      };

      // If inactive, skip regeneration entirely.
      if (!rule.active) {
        final inactiveIdsToDelete = existingRows
            .where(
              (row) =>
                  row.detail?.contains(_kReminderManualOverrideMarker) != true,
            )
            .map((row) => row.id)
            .toList();
        await _deleteReminderOccurrenceRows(
          repo,
          inactiveIdsToDelete,
          semantic: 'reminder_inactive_prune',
          suppressesClient: false,
          sourceFeature: 'CalendarPage._syncReminderEvents.inactive',
        );
        continue;
      }

      final occurrences = _generateReminderOccurrences(rule, today, windowEnd);
      final desiredDates = <String>{
        for (final day in occurrences)
          '${day.year.toString().padLeft(4, '0')}-${day.month.toString().padLeft(2, '0')}-${day.day.toString().padLeft(2, '0')}',
      };
      final staleIdsToDelete = <String>[];
      for (final row in existingRows) {
        final cid = row.clientEventId ?? '';
        final parts = cid.split(':');
        final datePart = parts.isNotEmpty ? parts.last.trim() : '';
        final hasOverride =
            row.detail?.contains(_kReminderManualOverrideMarker) == true;
        if (hasOverride) continue;
        if (datePart.isEmpty || !desiredDates.contains(datePart)) {
          staleIdsToDelete.add(row.id);
        }
      }
      await _reminderSyncGate.waitForOrientationCriticalSection();
      await _deleteReminderOccurrenceRows(
        repo,
        staleIdsToDelete,
        semantic: 'reminder_generated_prune',
        suppressesClient: false,
        sourceFeature: 'CalendarPage._syncReminderEvents.stale',
      );

      final flowIdForReminder = await _findFlowIdByReminderUuid(
        rule.id,
      ); // may be null/nonexistent
      if (updateLocalCache) {
        // Update local cache first so UI reflects immediately even if network fails.
        localCacheChanged =
            _pruneReminderNotes(rule.id, fromDate: today) || localCacheChanged;
        localCacheChanged =
            _materializeReminderLocally(
              rule: rule,
              occurrences: occurrences,
              flowId: flowIdForReminder,
              notify: false,
            ) ||
            localCacheChanged;
      }

      if (!rule.id.startsWith('nutrition:')) {
        for (final day in occurrences) {
          await _reminderSyncGate.waitForOrientationCriticalSection();
          await _yieldReminderSyncBatchIfNeeded(processedOccurrenceWrites);

          final start = rule.allDay
              ? DateTime(day.year, day.month, day.day, 9, 0)
              : DateTime(
                  day.year,
                  day.month,
                  day.day,
                  rule.startLocal.hour,
                  rule.startLocal.minute,
                );
          final end = rule.allDay
              ? null
              : start.add(const Duration(minutes: 30));
          final cidDate =
              '${day.year.toString().padLeft(4, '0')}-${day.month.toString().padLeft(2, '0')}-${day.day.toString().padLeft(2, '0')}';
          final cid = 'reminder:${rule.id}:$cidDate';
          final encodedDetail = _encodeReminderDetail(rule);
          final kDate = KemeticMath.fromGregorian(day);
          final startTod = rule.allDay
              ? null
              : TimeOfDay(
                  hour: rule.startLocal.hour,
                  minute: rule.startLocal.minute,
                );
          final endTod = end == null ? null : TimeOfDay.fromDateTime(end);

          if (overriddenDates.contains(cidDate)) {
            continue;
          }
          if (_isTombstoned(cid) ||
              _isPendingDelete(
                clientEventId: cid,
                kYear: kDate.kYear,
                kMonth: kDate.kMonth,
                kDay: kDate.kDay,
                title: rule.title,
                allDay: rule.allDay,
                start: startTod,
                end: endTod,
                flowId: flowIdForReminder,
              )) {
            continue;
          }
          desiredOccurrenceWrites += 1;
          final desiredOccurrence = ReminderOccurrencePayload(
            clientEventId: cid,
            title: rule.title,
            detail: encodedDetail,
            location: null,
            startsAtUtc: start.toUtc(),
            endsAtUtc: end?.toUtc(),
            allDay: rule.allDay,
            calendarId: rule.calendarId,
            category: rule.category,
            flowLocalId: (flowIdForReminder != null && flowIdForReminder > 0)
                ? flowIdForReminder
                : null,
          );
          final existingRow = existingRowsByClientEventId[cid];
          if (existingRow != null &&
              reminderOccurrencePayloadMatches(
                desired: desiredOccurrence,
                existing: ReminderOccurrencePayload(
                  clientEventId: existingRow.clientEventId ?? '',
                  title: existingRow.title,
                  detail: existingRow.detail,
                  location: existingRow.location,
                  startsAtUtc: existingRow.startsAtUtc,
                  endsAtUtc: existingRow.endsAtUtc,
                  allDay: existingRow.allDay,
                  calendarId: existingRow.calendarId,
                  category: existingRow.category,
                  flowLocalId: existingRow.flowLocalId,
                ),
              )) {
            skippedUnchangedOccurrenceWrites += 1;
            continue;
          }
          try {
            final savedEvent = await repo.upsertByClientId(
              clientEventId: cid,
              title: rule.title,
              startsAtUtc: start.toUtc(),
              detail: encodedDetail,
              location: null,
              allDay: rule.allDay,
              endsAtUtc: end?.toUtc(),
              calendarId: rule.calendarId,
              category: rule.category,
              flowLocalId: (flowIdForReminder != null && flowIdForReminder > 0)
                  ? flowIdForReminder
                  : null,
              caller: 'reminder_sync',
            );

            final cleanedDetail = _cleanDetail(encodedDetail);
            final note = _Note(
              calendarId: rule.calendarId,
              calendarName: _calendarSummary(rule.calendarId)?.name,
              title: rule.title,
              detail: cleanedDetail.isEmpty ? null : cleanedDetail,
              location: null,
              allDay: rule.allDay,
              start: startTod,
              end: endTod,
              flowId: flowIdForReminder,
              category: rule.category,
              isReminder: true,
              reminderId: rule.id,
              alertOffsetMinutes: rule.alertOffsetMinutes,
            );

            await _reminderSyncGate.waitForOrientationCriticalSection();
            await _scheduleAlertForEvent(
              note: note,
              ky: kDate.kYear,
              km: kDate.kMonth,
              kd: kDate.kDay,
              clientEventId: savedEvent.clientEventId ?? cid,
              eventId: savedEvent.id,
            );
            processedOccurrenceWrites += 1;
            completedOccurrenceWrites += 1;
          } catch (_) {
            // non-fatal for individual reminders; local cache already updated
          }
        }
      }
    }

    await _reminderSyncGate.waitForOrientationCriticalSection();
    if (refreshUi) {
      await _loadFromDisk();
    } else if (updateLocalCache && localCacheChanged) {
      _refreshNoteCacheUi();
    }
    if (kDebugMode) {
      _calendarDebugPrint(
        '[reminder_sync] completed rules=${_reminderRules.length} desired=$desiredOccurrenceWrites upserted=$completedOccurrenceWrites skippedUnchanged=$skippedUnchangedOccurrenceWrites refreshUi=$refreshUi updateLocalCache=$updateLocalCache',
      );
    }
  }

  Future<void> _deleteReminderOccurrenceRows(
    UserEventsRepo repo,
    List<String> idsToDelete, {
    required String semantic,
    required bool suppressesClient,
    required String sourceFeature,
  }) async {
    if (idsToDelete.isEmpty) return;
    List<String> filteredIds = idsToDelete;
    // Guard: ensure we only delete rows whose CID starts with reminder: to avoid nuking standalones.
    try {
      final cids = await repo.getClientEventIdsByIds(idsToDelete);
      final mismatched = <String>[];
      if (kDebugMode && cids.isNotEmpty) {
        _calendarDebugPrint(
          '[syncReminderEvents] stale reminder occurrences (id:cid) ${cids.map((r) => '${r.id}:${r.clientEventId ?? ''}').join(', ')}',
        );
      }
      filteredIds = cids
          .where((row) => (row.clientEventId ?? '').startsWith('reminder:'))
          .map((row) => row.id)
          .toList();
      mismatched.addAll(
        cids
            .where((row) => !(row.clientEventId ?? '').startsWith('reminder:'))
            .map((row) => '${row.id}:${row.clientEventId ?? ''}'),
      );
      if (kDebugMode && mismatched.isNotEmpty) {
        _calendarDebugPrint(
          '[syncReminderEvents] Skipping delete for non-reminder rows: ${mismatched.join(", ")}',
        );
      }
    } catch (_) {}
    if (filteredIds.isNotEmpty) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[syncReminderEvents] Deleting stale reminder occurrences ids=${filteredIds.join(", ")}',
        );
      }
      await repo.deleteByIds(
        filteredIds,
        semantic: semantic,
        suppressesClient: suppressesClient,
        sourceFeature: sourceFeature,
        deleteScope: 'reminder_occurrence_prune',
      );
    }
  }

  DateTime _reminderWindowEnd(DateTime today, List<ReminderRule> rules) {
    // Aim for ~12 months ahead (365 days) and ensure late-start rules are covered.
    DateTime latestStart = today;
    for (final r in rules) {
      final start = DateUtils.dateOnly(r.startLocal);
      if (start.isAfter(latestStart)) {
        latestStart = start;
      }
    }
    final baseEnd = today.add(const Duration(days: 365)); // ~12 months
    final startAlignedEnd = latestStart.add(const Duration(days: 365));
    return baseEnd.isAfter(startAlignedEnd) ? baseEnd : startAlignedEnd;
  }

  Future<void> _previewReminderLocally(
    ReminderRule rule,
    DateTime today,
    DateTime windowEnd,
  ) async {
    // Show new/edited reminder immediately in list + calendar while sync completes.
    var changed = _pruneReminderNotes(rule.id, fromDate: today);
    final occurrences = _generateReminderOccurrences(rule, today, windowEnd);
    final flowId = await _findFlowIdByReminderUuid(rule.id);
    changed =
        _materializeReminderLocally(
          rule: rule,
          occurrences: occurrences,
          flowId: flowId,
          notify: false,
        ) ||
        changed;
    if (changed) {
      _refreshNoteCacheUi();
    }
  }

  Future<bool> _regenReminderNotes({bool notify = true}) async {
    await _loadReminderRules();
    if (_reminderRules.isEmpty) return false;
    final today = DateUtils.dateOnly(DateTime.now());
    final windowEnd = _reminderWindowEnd(today, _reminderRules);
    var changed = false;
    // Clear existing reminder notes
    for (final r in _reminderRules) {
      changed = _pruneReminderNotes(r.id, fromDate: null) || changed;
    }
    for (final r in _reminderRules) {
      final occs = _generateReminderOccurrences(r, today, windowEnd);
      final flowId = await _findFlowIdByReminderUuid(r.id);
      changed =
          _materializeReminderLocally(
            rule: r,
            occurrences: occs,
            flowId: flowId,
            notify: false,
          ) ||
          changed;
    }
    if (changed && notify) {
      _refreshNoteCacheUi();
    }
    return changed;
  }

  void _rebuildReminderRulesFromFlowsIfMissing() {
    final rebuiltById = <String, ReminderRule>{};
    for (final f in _flows.where(
      (f) =>
          f.isReminder &&
          isFlowScheduleOpenLocally(active: f.active, endDate: f.end) &&
          !f.isHidden,
    )) {
      final rr = _reminderRuleFromFlow(f);
      if (rr != null && !_endedReminderIds.contains(rr.id)) {
        rebuiltById[rr.id] = rr;
      }
    }

    final nextRules = <ReminderRule>[];
    final includedIds = <String>{};

    for (final existing in _reminderRules) {
      final replacement = rebuiltById[existing.id];
      if (replacement == null) {
        continue;
      }
      nextRules.add(replacement);
      includedIds.add(existing.id);
    }

    for (final rebuilt in rebuiltById.values) {
      if (includedIds.add(rebuilt.id)) {
        nextRules.add(rebuilt);
      }
    }

    final currentSignature = _reminderRules
        .map((rule) => jsonEncode(rule.toJson()))
        .join('|');
    final nextSignature = nextRules
        .map((rule) => jsonEncode(rule.toJson()))
        .join('|');
    if (currentSignature == nextSignature) {
      return;
    }

    _reminderRules
      ..clear()
      ..addAll(nextRules);
    _reminderRulesLoaded = true;
    unawaited(_saveReminderRules());
  }

  Future<bool> _openReminderEditor({
    ReminderRule? existing,
    DateTime? initialDate,
  }) async {
    await _loadReminderRules();
    final now = DateTime.now();
    final defaultDate = DateUtils.dateOnly(initialDate ?? now);
    final defaultStart = DateTime(
      defaultDate.year,
      defaultDate.month,
      defaultDate.day,
      now.hour,
      0,
    );
    final availableCalendars =
        _calendarSummariesById.values
            .where(
              (calendar) =>
                  calendar.canEdit || existing?.calendarId == calendar.id,
            )
            .toList()
          ..sort((a, b) {
            if (a.isPersonal && !b.isPersonal) return -1;
            if (!a.isPersonal && b.isPersonal) return 1;
            return a.name.toLowerCase().compareTo(b.name.toLowerCase());
          });
    final titleCtrl = TextEditingController(text: existing?.title ?? '');
    DateTime startLocal = existing?.startLocal ?? defaultStart;
    DateTime? endLocal = existing?.endLocal;
    if (endLocal != null) {
      endLocal = DateUtils.dateOnly(endLocal);
    }
    bool allDay = existing?.allDay ?? false;
    Color selectedColor = existing?.color ?? daySheetColorPalette.first;
    String? category = existing?.category;
    ReminderRepeat repeat = existing?.repeat ?? const ReminderRepeat();
    bool active = existing?.active ?? true;
    EventCreateDatePickerMode reminderDateMode =
        EventCreateDatePickerMode.kemetic;
    int alertMinutesBefore = existing?.alertOffsetMinutes ?? _alertNoneMinutes;
    String? selectedCalendarId =
        existing?.calendarId ??
        _personalCalendarId ??
        (availableCalendars.isNotEmpty ? availableCalendars.first.id : null);

    if (!mounted) {
      return false;
    }

    bool saved = false;

    try {
      final result = await showModalBottomSheet<bool>(
        context: context,
        isScrollControlled: true,
        backgroundColor: Colors.transparent,
        shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(22)),
        ),
        builder: (ctx) {
          final media = MediaQuery.of(ctx);
          final keyboardInset = keyboardInsetOf(ctx);
          final sheetHeight = keyboardInset > 0
              ? math.min(
                  media.size.height * 0.85,
                  math.max(
                    280.0,
                    media.size.height - keyboardInset - media.padding.top - 12,
                  ),
                )
              : media.size.height * 0.85;
          return Container(
            height: sheetHeight,
            decoration: const BoxDecoration(
              color: DaySheetTokens.bg,
              borderRadius: BorderRadius.vertical(top: Radius.circular(22)),
              border: Border(
                top: BorderSide(color: DaySheetTokens.hair, width: 1),
              ),
            ),
            child: SafeArea(
              top: false,
              child: Padding(
                padding: EdgeInsets.only(
                  left: 22,
                  right: 22,
                  bottom: media.padding.bottom + 12,
                  top: 10,
                ),
                child: StatefulBuilder(
                  builder: (sheetCtx, setModalState) {
                    final selectedCalendar = _calendarSummary(
                      selectedCalendarId,
                    );
                    final selectedCalendarLabel = _calendarDisplayName(
                      selectedCalendarId,
                    );
                    final canEditSelectedCalendar =
                        selectedCalendar?.canEdit ?? true;
                    const fieldScrollPadding =
                        keyboardManagedTextFieldScrollPadding;

                    String dateLabel(DateTime d) =>
                        '${d.month.toString().padLeft(2, '0')}/${d.day.toString().padLeft(2, '0')}/${d.year}';
                    String endDateLabel() =>
                        endLocal == null ? 'Never' : dateLabel(endLocal!);
                    String timeLabel(TimeOfDay t) {
                      final h = t.hourOfPeriod == 0 ? 12 : t.hourOfPeriod;
                      final m = t.minute.toString().padLeft(2, '0');
                      final ap = t.period == DayPeriod.am ? 'AM' : 'PM';
                      return '$h:$m $ap';
                    }

                    Widget repeatField() {
                      final kind = repeat.kind;
                      switch (kind) {
                        case ReminderRepeatKind.everyNDays:
                          return TextFormField(
                            keyboardType: TextInputType.number,
                            initialValue: repeat.interval.toString(),
                            scrollPadding: fieldScrollPadding,
                            decoration: const InputDecoration(
                              labelText: 'Every N days',
                              labelStyle: TextStyle(color: Colors.white70),
                              enabledBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: Colors.white24),
                              ),
                              focusedBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: _gold),
                              ),
                            ),
                            style: const TextStyle(color: Colors.white),
                            onChanged: (v) {
                              final n = int.tryParse(v) ?? 1;
                              setModalState(() {
                                repeat = repeat.copyWith(
                                  interval: n.clamp(1, 365),
                                );
                              });
                            },
                          );

                        case ReminderRepeatKind.weekly:
                          const labels = [
                            'Mon',
                            'Tue',
                            'Wed',
                            'Thu',
                            'Fri',
                            'Sat',
                            'Sun',
                          ];
                          return Wrap(
                            spacing: 8,
                            children: List.generate(7, (i) {
                              final wd = i + 1;
                              final selected = repeat.weekdays.contains(wd);
                              return ChoiceChip(
                                label: Text(labels[i]),
                                selected: selected,
                                onSelected: (_) {
                                  final next = {...repeat.weekdays};
                                  if (selected) {
                                    next.remove(wd);
                                  } else {
                                    next.add(wd);
                                  }
                                  setModalState(() {
                                    repeat = repeat.copyWith(weekdays: next);
                                  });
                                },
                              );
                            }),
                          );

                        case ReminderRepeatKind.monthlyDay:
                          return TextFormField(
                            keyboardType: TextInputType.text,
                            initialValue: (_monthDayTargets(
                              repeat,
                              startLocal,
                            ).toList()..sort()).join(', '),
                            scrollPadding: fieldScrollPadding,
                            decoration: const InputDecoration(
                              labelText: 'Day of month (1-31, comma-separated)',
                              labelStyle: TextStyle(color: Colors.white70),
                              enabledBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: Colors.white24),
                              ),
                              focusedBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: _gold),
                              ),
                            ),
                            style: const TextStyle(color: Colors.white),
                            onChanged: (v) {
                              final values = _parseDayCsv(v, min: 1, max: 31);
                              setModalState(() {
                                repeat = repeat.copyWith(monthDays: values);
                              });
                            },
                          );

                        case ReminderRepeatKind.kemeticEveryNDecans:
                          return TextFormField(
                            keyboardType: TextInputType.number,
                            initialValue: repeat.interval.toString(),
                            scrollPadding: fieldScrollPadding,
                            decoration: const InputDecoration(
                              labelText: 'Every N decans',
                              labelStyle: TextStyle(color: Colors.white70),
                              enabledBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: Colors.white24),
                              ),
                              focusedBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: _gold),
                              ),
                            ),
                            style: const TextStyle(color: Colors.white),
                            onChanged: (v) {
                              final n = int.tryParse(v) ?? 1;
                              setModalState(() {
                                repeat = repeat.copyWith(
                                  interval: n.clamp(1, 36),
                                );
                              });
                            },
                          );

                        case ReminderRepeatKind.kemeticDecanDay:
                          return TextFormField(
                            keyboardType: TextInputType.text,
                            initialValue: (_decanDayTargets(
                              repeat,
                              startLocal,
                            ).toList()..sort()).join(', '),
                            scrollPadding: fieldScrollPadding,
                            decoration: const InputDecoration(
                              labelText: 'Day of decan (1-10, comma-separated)',
                              labelStyle: TextStyle(color: Colors.white70),
                              enabledBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: Colors.white24),
                              ),
                              focusedBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: _gold),
                              ),
                            ),
                            style: const TextStyle(color: Colors.white),
                            onChanged: (v) {
                              final values = _parseDayCsv(v, min: 1, max: 10);
                              setModalState(() {
                                repeat = repeat.copyWith(decanDays: values);
                              });
                            },
                          );

                        case ReminderRepeatKind.kemeticMonthDay:
                          return TextFormField(
                            keyboardType: TextInputType.text,
                            initialValue: (_kemeticMonthDayTargets(
                              repeat,
                              startLocal,
                            ).toList()..sort()).join(', '),
                            scrollPadding: fieldScrollPadding,
                            decoration: const InputDecoration(
                              labelText:
                                  'Day of Kemetic month (1-30, comma-separated)',
                              labelStyle: TextStyle(color: Colors.white70),
                              enabledBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: Colors.white24),
                              ),
                              focusedBorder: UnderlineInputBorder(
                                borderSide: BorderSide(color: _gold),
                              ),
                            ),
                            style: const TextStyle(color: Colors.white),
                            onChanged: (v) {
                              final values = _parseDayCsv(v, min: 1, max: 30);
                              setModalState(() {
                                repeat = repeat.copyWith(
                                  kemeticMonthDays: values,
                                );
                              });
                            },
                          );

                        case ReminderRepeatKind.none:
                          return const SizedBox.shrink();
                      }
                    }

                    return SingleChildScrollView(
                      padding: EdgeInsets.only(
                        bottom: keyboardInset + media.padding.bottom + 180,
                      ),
