  Future<void> _openProfile(BuildContext context) async {
    NavigationTrace.instance.record('calendar profile open entered');
    final userId = Supabase.instance.client.auth.currentUser?.id;
    NavigationTrace.instance.record(
      'current user id resolved',
      state: <String, Object?>{'hasUserId': userId != null},
    );
    if (userId == null) {
      NavigationTrace.instance.record(
        'profile route stopped',
        state: const <String, Object?>{'reason': 'missingUserId'},
      );
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Please log in to view your profile')),
      );
      return;
    }
    if (_profileNavigationInFlight || !mounted) {
      NavigationTrace.instance.record(
        'profile route stopped',
        state: <String, Object?>{
          'reason': _profileNavigationInFlight ? 'inFlight' : 'unmounted',
          'mounted': mounted,
        },
      );
      return;
    }
    _profileNavigationInFlight = true;
    try {
      NavigationTrace.instance.record(
        'profile feed continuity clear scheduled',
      );
      CalendarPage._clearProfileFeedContinuityWithoutBlocking(userId);
      if (!mounted || !context.mounted) {
        NavigationTrace.instance.record(
          'profile route stopped',
          state: <String, Object?>{
            'reason': 'contextUnmountedAfterContinuity',
            'mounted': mounted,
            'contextMounted': context.mounted,
          },
        );
        return;
      }
      NavigationTrace.instance.record('/profile/me route command issued');
      NavigationTrace.instance.record(
        'profile route push requested',
        state: <String, Object?>{
          ...CalendarPage._profileNavigationTraceState(
            context,
            phase: 'beforePush',
            targetRoute: '/profile/me',
          ),
        },
      );
      try {
        unawaited(openDetailRoute<void>(context, '/profile/me'));
        NavigationTrace.instance.record(
          'profile route push completed/current uri',
          state: <String, Object?>{
            ...CalendarPage._profileNavigationTraceState(
              context,
              phase: 'afterPush',
              targetRoute: '/profile/me',
            ),
          },
        );
      } catch (error, stackTrace) {
        NavigationTrace.instance.recordError(
          'profile route push error',
          error,
          stackTrace,
          state: <String, Object?>{
            ...CalendarPage._profileNavigationTraceState(
              context,
              phase: 'goCatch',
              targetRoute: '/profile/me',
            ),
          },
        );
        rethrow;
      }
    } finally {
      _profileNavigationInFlight = false;
    }
  }

