      }

      final repo = UserEventsRepo(Supabase.instance.client);
      try {
        for (var i = 0; i < kKeptWordEvents.length; i++) {
          final event = kKeptWordEvents[i];
          final occurrence = occurrences[i];
          final kyKmKd = KemeticMath.fromGregorian(
            DateUtils.dateOnly(occurrence.startLocal),
          );
          final startTod = TimeOfDay(
            hour: occurrence.startLocal.hour,
            minute: occurrence.startLocal.minute,
          );
          final endTod = TimeOfDay(
            hour: occurrence.endLocal.hour,
            minute: occurrence.endLocal.minute,
          );
          final title = keptWordEventTitle(event);
          final detail = keptWordDetailText(event, lens: keptWordLens);
          final behaviorPayload = keptWordBehaviorPayload(
            event: event,
            schedule: occurrence,
            lens: keptWordLens,
          );
          final clientEventId = _buildCid(
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            title: title,
            startHour: startTod.hour,
            startMinute: startTod.minute,
            allDay: false,
            flowId: serverFlowId,
          );
          final note = _Note(
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            title: title,
            detail: detail,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: keptWordActionId(event),
            behaviorPayload: behaviorPayload,
          );

          _addNote(
            kyKmKd.kYear,
            kyKmKd.kMonth,
            kyKmKd.kDay,
            title,
            detail,
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: keptWordActionId(event),
            behaviorPayload: behaviorPayload,
          );

          await repo.upsertByClientId(
            clientEventId: clientEventId,
            title: title,
            startsAtUtc: occurrence.startUtc,
            detail: detail,
            calendarId: _personalCalendarId,
            allDay: false,
            endsAtUtc: occurrence.endUtc,
            category: 'Ritual',
            flowLocalId: serverFlowId,
            actionId: keptWordActionId(event),
            behaviorPayload: behaviorPayload,
            caller: 'the_kept_word_join',
          );

          await _scheduleAlertForEvent(
            note: note,
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            clientEventId: clientEventId,
          );
        }
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint('[keptWord] event creation failed: $e');
          _calendarDebugPrint('$st');
        }
        _flows.removeWhere((flow) => flow.id == serverFlowId);
        final emptyKeys = <String>[];
        _notes.forEach((key, notes) {
          notes.removeWhere((note) => note.flowId == serverFlowId);
          if (notes.isEmpty) emptyKeys.add(key);
        });
        for (final key in emptyKeys) {
          _notes.remove(key);
        }
        if (mounted) {
          setState(() {});
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text('Could not create The Kept Word.')),
          );
        }
        try {
          await repo.deleteFlow(serverFlowId);
        } catch (_) {}
        return -1;
      }

      setState(() {});
      return serverFlowId;
    }

    if (template.kind == _MaatFlowTemplateKind.theCourse) {
      final timezone = trackSkyTimeZone ?? detectTrackSkyTimeZone();
      final firstG = DateUtils.dateOnly(
        startDate ?? defaultTheCourseStartDate(timezone),
      );
      final joinedK = KemeticMath.fromGregorian(firstG);
      final occurrences = <CourseOccurrenceSchedule>[
        for (final event in kTheCourseEvents)
          courseScheduleForDate(
            event,
            firstG.add(Duration(days: event.flowDay - 1)),
            timezone,
          ),
      ];
      final dates = <DateTime>{
        for (final occurrence in occurrences)
          DateUtils.dateOnly(occurrence.startLocal),
      };
      final orderedDates = dates.toList()..sort();

      final flow = _Flow(
        id: -1,
        calendarId: _personalCalendarId,
        name: template.title,
        color: template.color,
        active: true,
        rules: [_RuleDates(dates: dates)],
        start: orderedDates.first,
        end: firstG.add(const Duration(days: 29)),
        notes: [
          'mode=gregorian',
          'split=1',
          if (template.overview.trim().isNotEmpty)
            'ov=${Uri.encodeComponent(template.overview.trim())}',
          'maat=${template.key}',
          'course_tz=${timezone.key}',
          'course_lens=${courseLens.key}',
          'course_midday_hour=$kTheCourseDefaultMiddayHour',
          'course_midday_minute=$kTheCourseDefaultMiddayMinute',
          'joined_ky=${joinedK.kYear}',
          'joined_km=${joinedK.kMonth}',
          'joined_kd=${joinedK.kDay}',
        ].join(';'),
      );

      final serverFlowId = await _saveNewFlow(flow);
      if (serverFlowId == null) {
        if (kDebugMode) {
          _calendarDebugPrint('[theCourse] Aborting - flow insert failed');
        }
        return -1;
      }

      final repo = UserEventsRepo(Supabase.instance.client);
      try {
        for (var i = 0; i < kTheCourseEvents.length; i++) {
          final event = kTheCourseEvents[i];
          final occurrence = occurrences[i];
          final dayOnly = DateUtils.dateOnly(occurrence.startLocal);
          final kyKmKd = KemeticMath.fromGregorian(dayOnly);
          final courseContext = courseContextForKemeticDate(
            kYear: kyKmKd.kYear,
            kMonth: kyKmKd.kMonth,
            kDay: kyKmKd.kDay,
          );
          final startTod = TimeOfDay(
            hour: occurrence.startLocal.hour,
            minute: occurrence.startLocal.minute,
          );
          final endTod = TimeOfDay(
            hour: occurrence.endLocal.hour,
            minute: occurrence.endLocal.minute,
          );
          final title = courseEventTitle(event);
          final detail = courseDetailText(
            event,
            lens: courseLens,
            context: courseContext,
          );
          final behaviorPayload = courseBehaviorPayload(
            event: event,
            schedule: occurrence,
            lens: courseLens,
            context: courseContext,
          );
          final clientEventId = _buildCid(
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            title: title,
            startHour: startTod.hour,
            startMinute: startTod.minute,
            allDay: false,
            flowId: serverFlowId,
          );
          final note = _Note(
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            title: title,
            detail: detail,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: courseActionId(event),
            behaviorPayload: behaviorPayload,
          );

          _addNote(
            kyKmKd.kYear,
            kyKmKd.kMonth,
            kyKmKd.kDay,
            title,
            detail,
            clientEventId: clientEventId,
            calendarId: _personalCalendarId,
            allDay: false,
            start: startTod,
            end: endTod,
            flowId: serverFlowId,
            category: 'Ritual',
            alertOffsetMinutes: 0,
            actionId: courseActionId(event),
            behaviorPayload: behaviorPayload,
          );

          await repo.upsertByClientId(
            clientEventId: clientEventId,
            title: title,
            startsAtUtc: occurrence.startUtc,
            detail: detail,
            calendarId: _personalCalendarId,
            allDay: false,
            endsAtUtc: occurrence.endUtc,
            category: 'Ritual',
            flowLocalId: serverFlowId,
            actionId: courseActionId(event),
            behaviorPayload: behaviorPayload,
            caller: 'the_course_join',
          );

          await _scheduleAlertForEvent(
            note: note,
            ky: kyKmKd.kYear,
            km: kyKmKd.kMonth,
            kd: kyKmKd.kDay,
            clientEventId: clientEventId,
          );
        }
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint('[theCourse] event creation failed: $e');
          _calendarDebugPrint('$st');
        }
        _flows.removeWhere((flow) => flow.id == serverFlowId);
        final emptyKeys = <String>[];
        _notes.forEach((key, notes) {
          notes.removeWhere((note) => note.flowId == serverFlowId);
          if (notes.isEmpty) emptyKeys.add(key);
        });
        for (final key in emptyKeys) {
          _notes.remove(key);
        }
        if (mounted) {
          setState(() {});
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text('Could not create The Course.')),
          );
        }
        try {
          await repo.deleteFlow(serverFlowId);
        } catch (_) {}
        return -1;
      }

      setState(() {});
      return serverFlowId;
    }

    // Current Ma'at templates must use explicit branches above; legacy sequence
    // templates used to continue through `if (startDate == null)` and then
    // fire-and-forget persistence. They now fail closed before creating rows.
    if (kDebugMode) {
      _calendarDebugPrint(
        "[maatTemplate] Unsupported mounted Ma'at template "
        'kind=${template.kind} key=${template.key} '
        'title=<redacted chars=${template.title.length}>',
      );
    }
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('${template.title} is not available right now.'),
        ),
      );
    }
    return -1;
  }

  /// End Flow removes the current user's local calendar copy of the flow by
  /// deleting every matched materialized row from that calendar in the
  /// canonical RPC. Previously shared, posted, or saved copies live in their
  /// own records and are not removed by this action.
  //// === FLOW LIFECYCLE: END FLOW ===
  Future<EndFlowActionResult> _endFlowFromEventTarget(
    DayViewSheetEventTarget target,
  ) async {
    final flowId = target.event.flowId;
    if (flowId == null) return EndFlowActionResult.notHandled;
    return _endFlow(flowId);
  }

  Future<bool> _makeTodoFromEventTarget(DayViewSheetEventTarget target) async {
    final event = target.event;
    final flow = _calendarChromeFlowDataForId(event.flowId);
    final eventDate = KemeticMath.toGregorian(target.ky, target.km, target.kd);
    final dueDate = DateTime(eventDate.year, eventDate.month, eventDate.day);
    final dueTime = event.allDay ? null : _timeOfDayFromMinute(event.startMin);
    final source = EventTodoSource(
      title: event.title,
      detail: event.detail,
      location: event.location,
      flowName: flow?.name,
      isFlow: event.flowId != null && !event.isReminder,
      isReminder: event.isReminder,
    );
    final sourceMetadata = <String, dynamic>{
      'source': 'calendar_event_make_todo',
      'source_title': event.title,
      'source_kemetic_date': '${target.ky}-${target.km}-${target.kd}',
      if (event.id?.trim().isNotEmpty == true) 'event_id': event.id!.trim(),
      if (event.clientEventId?.trim().isNotEmpty == true)
        'client_event_id': event.clientEventId!.trim(),
      if (event.flowId != null) 'flow_id': event.flowId,
      if (flow?.name.trim().isNotEmpty == true) 'flow_name': flow!.name.trim(),
      if (event.reminderId?.trim().isNotEmpty == true)
        'reminder_id': event.reminderId!.trim(),
      if (event.isReminder) 'is_reminder': true,
    };
    final result = await makeEventTodos(
      source: source,
      dueDate: dueDate,
      dueTime: dueTime,
      metadata: sourceMetadata,
      insertTodos: _rhythmRepo.insertTodos,
    );
    if (!mounted) return false;
    if (!result.success || result.plannerLocation == null) {
      _showMakeTodoError(result.errorMessage ?? 'Could not add to-do.');
      return false;
    }
    _openPlannerTodoList(result.plannerLocation!);
    return true;
  }

  TimeOfDay _timeOfDayFromMinute(int minuteOfDay) {
    final clamped = minuteOfDay.clamp(0, 23 * 60 + 59).toInt();
    return TimeOfDay(hour: clamped ~/ 60, minute: clamped % 60);
  }

  void _showMakeTodoError(String message) {
    if (!mounted) return;
    ScaffoldMessenger.of(
      context,
    ).showSnackBar(SnackBar(content: Text(message)));
  }

  void _openPlannerTodoList(String location) {
    if (!mounted) return;
    final rootNavigator = Navigator.of(context, rootNavigator: true);
    if (rootNavigator.canPop()) {
      rootNavigator.popUntil((route) => route.isFirst);
    }
    if (!mounted) return;
    context.go(location);
  }

  Future<EndFlowActionResult> _endFlow(
    int flowId, {
    DateTime? endedAtLocal,
  }) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    final effectiveEndedAtLocal = endedAtLocal ?? DateTime.now();
    if (kDebugMode) {
      _calendarDebugPrint(
        '[endFlow] flowId=$flowId endedAtLocal='
        '${effectiveEndedAtLocal.toIso8601String()}',
      );
    }

    try {
      final result = await repo.endFlow(
        flowId: flowId,
        endedAtLocal: effectiveEndedAtLocal,
        deleteAllMaterialized: true,
      );
      if (kDebugMode) {
        _calendarDebugPrint(
          '[endFlow] ✓ rpc flowId=${result.flowId} endedOn=${result.endedOn} '
          'deletedEvents=${result.deletedEventCount} '
          'retiredNotifications=${result.retiredNotificationCount} '
          'deletedCompletions=${result.deletedCompletionCount}',
        );
      }
    } catch (e, st) {
      if (kDebugMode) {
        _calendarDebugPrint('[endFlow] ✗ flowId=$flowId error=$e');
        _calendarDebugPrint('$st');
      }
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text('Could not end this flow right now.')),
        );
      }
      return EndFlowActionResult.failed;
    }

    // End Flow removes the local materialized calendar copy only. Shared,
    // posted, and saved copies are separate records and remain available.
    CalendarPage._forgetRememberedJoinedMaatFlow(flowId);
    await _loadFromDisk(source: 'end_flow');
    if (mounted) {
      ScaffoldMessenger.of(
        context,
      ).showSnackBar(const SnackBar(content: Text('Flow ended.')));
    }
    return EndFlowActionResult.success;
  }
  //// === END END FLOW ===

  /* ───── Day View Navigation ───── */

  void _openDayView(
    BuildContext ctx,
    int kYear,
    int kMonth,
    int kDay, {
    EventItem? focusEvent,
    int? initialFirstVisibleMinute,
    double? initialScrollOffset,
    bool? initialShowGregorian,
    EventDetailRestorationState? initialEventDetailRestorationState,
    String? debugOpenSource,
  }) {
    _restorationInteractedSinceBoot = true;
    unawaited(
      _markOnboardingHelperCompleted(
        OnboardingHelperRegistry.dayCardLongPress.id,
      ),
    );
    final shouldShowDayCardRevealCoachmark =
        _shouldShowDayCardRevealCoachmarkFromOnboarding;
    final isFirstFlowOnboardingDay =
        _onboardingProgress.currentStep ==
            TrueOnboardingStep.firstFlowCalendarDay &&
        _matchesFirstMaatFlowEventDate(kYear, kMonth, kDay);
    final onboardingFocusNote = isFirstFlowOnboardingDay
        ? _firstFlowTargetNoteForDay(kYear, kMonth, kDay)
        : null;
    final resolvedFocusEvent =
        focusEvent ??
        (onboardingFocusNote == null
            ? null
            : _noteToEventItem(onboardingFocusNote));
    if (isFirstFlowOnboardingDay) {
      _showingFirstFlowDayCoachmark = false;
      GuidedOnboardingController.instance.clear();
      _onboardingProgress = _onboardingProgress.copyWith(
        hasTappedFirstFlowDay: true,
        currentStep: TrueOnboardingStep.firstFlowDayEvent,
      );
      final userId = _currentUserId;
      if (!_onboardingReviewMode && userId != null) {
        unawaited(_onboardingProgressStorage.save(userId, _onboardingProgress));
      }
      unawaited(
        Events.trackIfAuthed(
          'onboarding_first_flow_day_opened',
          const <String, dynamic>{},
        ),
      );
    }
    final shouldPassFirstFlowOnboardingTargets =
        _onboardingProgress.currentStep == TrueOnboardingStep.firstFlowDayEvent;
    final resolvedShowGregorian = initialShowGregorian ?? _showGregorian;
    final resolvedInitialFirstVisibleMinute =
        initialFirstVisibleMinute ??
        initialScrollOffset?.floor().clamp(0, 24 * 60 - 1).toInt();
    final initialDayViewState = DayViewRestorationState(
      isOpen: true,
      kYear: kYear,
      kMonth: kMonth,
      kDay: kDay,
      showGregorian: resolvedShowGregorian,
      firstVisibleMinute: resolvedInitialFirstVisibleMinute,
      scrollOffset: initialScrollOffset,
      eventDetail: initialEventDetailRestorationState,
    );
    final dayViewWriteSession = _dayViewRestorationWriteGate.beginOpen();
    _activeDayViewRestorationState = initialDayViewState;
    unawaited(_saveCalendarRestorationNow(reason: 'before_day_view_open'));
    unawaited(
      _persistDayViewState(
        initialDayViewState,
        reason: 'day_view_open',
        writeSessionId: dayViewWriteSession,
      ),
    );
    var dayViewUserCloseReported = false;
    Future<void> persistUserClosedDayView() async {
      dayViewUserCloseReported = true;
      _dayViewRestorationWriteGate.markClosed(dayViewWriteSession);
      final closedState =
          (_activeDayViewRestorationState ?? initialDayViewState).copyWith(
            isOpen: false,
            clearEventDetail: true,
          );
      _activeDayViewRestorationState = closedState;
      await _persistDayViewState(closedState, reason: 'day_view_user_closed');
    }

    // Adapter: Convert _Note to NoteData. Reminder writes stay in save/schedule
    // paths so orientation builds can read calendar state without side effects.
    List<NoteData> notesForDayFn(int y, int m, int d) =>
        _noteDataForDay(y, m, d);

    // Adapter: Convert _Flow to FlowData
    final flowIndex = _buildCalendarFlowChromeIndex();
    final activeLedgerFlowIds = _buildActiveLedgerFlowIds();

    // Get month name function
    String getMonthName(int km) => getMonthById(km).displayFull;

    // Navigate to Day View
    if (kDebugMode && debugOpenSource != null) {
      _calendarDebugPrint(
        '[$debugOpenSource] Day View route push requested '
        'k=$kYear-$kMonth-$kDay detailIdentity='
        '${initialEventDetailRestorationState?.identityType}:'
        '${initialEventDetailRestorationState?.identityValue}',
      );
    }
    Navigator.push(
      ctx,
      MaterialPageRoute(
        builder: (context) => DayViewPage(
          initialKy: kYear,
          initialKm: kMonth,
          initialKd: kDay,
          showGregorian: resolvedShowGregorian,
          notesForDay: notesForDayFn,
          flowIndex: flowIndex,
          flowIndexBuilder: _buildCalendarFlowChromeIndex,
          activeLedgerFlowIds: activeLedgerFlowIds,
          activeLedgerFlowIdsBuilder: _buildActiveLedgerFlowIds,
          dataVersion: _dayViewDataVersion,
          getMonthName: getMonthName,
          initialFirstVisibleMinute: resolvedInitialFirstVisibleMinute,
          initialScrollOffset: initialScrollOffset,
          focusStartMin: resolvedFocusEvent?.startMin,
          focusFlowId: resolvedFocusEvent?.flowId,
          focusTitle: resolvedFocusEvent?.title,
          initialEventDetailRestorationState:
              initialEventDetailRestorationState,
          eventDetailRequestListenable: _dayViewEventDetailRequest,
          onEventDetailRequestHandled: () {
            if (_dayViewEventDetailRequest.value != null) {
              _dayViewEventDetailRequest.value = null;
            }
          },
          onClose: () => Navigator.of(context).pop(),
          onUserClose: persistUserClosedDayView,
          onManageFlows: (flowId) => _getMyFlowsCallback()(flowId),
          onOpenQuickAdd: (_) => _openQuickAddSheet(),
          onOpenSearch: (ctx) async => _openSearchForContext(ctx),
          onOpenProfile: (ctx) => _openProfile(ctx),
          onDeleteNote: (ky, km, kd, evt) async {
            await _deleteNoteByEvent(ky, km, kd, evt);
          },
          onEditNote: (ky, km, kd, evt) async {
            await _editNoteByEvent(ky, km, kd, evt);
          },
          onMoveEventTime: _moveEventInDayView,
          onShareNote: (evt) async {
            await _shareNoteSimple(evt);
          },
          onAddNote: (ky, km, kd) =>
              _openDaySheet(ky, km, kd, allowDateChange: true),
          onOpenAddNoteWithTime:
              (
                ky,
                km,
                kd, {
                TimeOfDay? start,
                TimeOfDay? end,
                bool allDay = false,
              }) {
                _openDaySheet(
                  ky,
                  km,
                  kd,
                  allowDateChange: true,
                  initialStartTime: start,
                  initialEndTime: end,
                  initialAllDay: allDay,
                );
              },
          onCreateTimedEvent: _handleCreateTimedEvent,
          onEndFlow: (id) => _endFlow(id),
          onEditReminder: (id) => _editReminderById(id),
          onEndReminder: (id) => _endReminderRule(id),
          onShareReminder: (evt) => _shareNoteSimple(evt),
          onAppendToJournal: _appendToJournalAndRefresh,
          onWriteJournalResponse: _writeMaatJournalResponseBlockAndRefresh,
          showDayCardRevealCoachmarkForOnboarding:
              shouldShowDayCardRevealCoachmark,
          onDayCardRevealCoachmarkCompleted: shouldShowDayCardRevealCoachmark
              ? () => unawaited(
                  _handleDayCardRevealCoachmarkCompletedFromOnboarding(),
                )
              : null,
          shouldPreserveEventDetailRestorationOnClose: () =>
              _preserveEventDetailOverlayForOrientationHandoff ||
              RestorationCoordinator
                  .instance
                  .shouldPreserveOverlayForLifecycleClose,
          onSaveFlow: _saveFlowById,
          loadCompletedClientEventIds: _loadCompletedClientEventIds,
          onRecordCompletion:
              ({
                required String clientEventId,
                required int flowId,
                required DateTime completedOnDate,
                Map<String, dynamic>? metadata,
              }) => _recordEventCompletion(
                clientEventId: clientEventId,
                flowId: flowId,
                completedOnDate: completedOnDate,
                metadata: metadata,
              ),
          onUnrecordCompletion: _unrecordEventCompletion,
          onRemoveCompletionBadge: _removeCompletionBadgeAndRefresh,
          onboardingEventClientEventId: shouldPassFirstFlowOnboardingTargets
              ? _firstMaatFlowEventClientEventId
              : null,
          onboardingEventTargetKey: shouldPassFirstFlowOnboardingTargets
              ? _firstFlowEventBlockKey
              : null,
          onboardingObservedKey: shouldPassFirstFlowOnboardingTargets
              ? _firstFlowObservedKey
              : null,
          onboardingJournalKey: shouldPassFirstFlowOnboardingTargets
              ? _firstFlowJournalKey
              : null,
          onOnboardingEventOpened: shouldPassFirstFlowOnboardingTargets
              ? () {
                  unawaited(_handleFirstFlowEventOpened());
                }
              : null,
          onOnboardingObservedJournalNext: shouldPassFirstFlowOnboardingTargets
              ? () {
                  unawaited(_handleObservedJournalPromptNext());
                }
              : null,
          onRestorationStateChanged:
              ({
                required int kYear,
                required int kMonth,
                required int kDay,
                required bool showGregorian,
                int? firstVisibleMinute,
                double? scrollOffset,
                EventDetailRestorationState? eventDetail,
              }) {
                if (dayViewUserCloseReported) {
                  return;
                }
                if (!_dayViewRestorationWriteGate.canAcceptOpenWrite(
                  dayViewWriteSession,
                )) {
                  return;
                }
                final state = DayViewRestorationState(
                  isOpen: true,
                  kYear: kYear,
                  kMonth: kMonth,
                  kDay: kDay,
                  showGregorian: showGregorian,
                  firstVisibleMinute: firstVisibleMinute,
                  scrollOffset: scrollOffset,
                  eventDetail: eventDetail,
                );
                unawaited(
                  _persistDayViewState(
                    state,
                    reason: 'day_view_state_changed',
                    writeSessionId: dayViewWriteSession,
                  ),
                );
              },
        ),
      ),
    ).then((_) {
      final preserveForLifecycle =
          !mounted ||
          RestorationCoordinator
              .instance
              .shouldPreserveOverlayForLifecycleClose;
      if (!preserveForLifecycle &&
          (_activeDayViewRestorationState?.isOpen ?? true)) {
        _dayViewRestorationWriteGate.markClosed(dayViewWriteSession);
        final closedState =
            (_activeDayViewRestorationState ?? initialDayViewState).copyWith(
              isOpen: false,
              clearEventDetail: true,
            );
        _activeDayViewRestorationState = closedState;
        unawaited(_persistDayViewState(closedState, reason: 'day_view_closed'));
      }
      // ✅ Save state when returning from day view
      if (mounted) {
        final ky = _lastViewKy ?? kYear;
        final km = _lastViewKm ?? kMonth;
        final kd = _lastViewKd ?? kDay;
        _saveViewState(ky, km, kd);

        if (kDebugMode) {
          _calendarDebugPrint(
            '💾 [CALENDAR] Saved state on day view close: $ky-$km-$kd',
          );
        }
      }
    });
    if (kDebugMode && debugOpenSource != null) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        _calendarDebugPrint(
          '[$debugOpenSource] Day View visible k=$kYear-$kMonth-$kDay',
        );
      });
    }
    if (isFirstFlowOnboardingDay) {
      _showFirstFlowDayEventCoachmark();
    }
  }

  void _openDaySheetEventDetailInHostDayView({
    required BuildContext sheetCtx,
    required int kYear,
    required int kMonth,
    required int kDay,
    required EventItem event,
  }) {
    final target = DayViewSheetEventTarget(
      ky: kYear,
      km: kMonth,
      kd: kDay,
      event: event,
    );
    final detail = eventDetailRestorationStateForTarget(
      target,
      parentSurface: 'day_sheet',
    );
    final hasActiveDayView = _activeDayViewRestorationState?.isOpen ?? false;

    if (Navigator.canPop(sheetCtx)) {
      Navigator.of(sheetCtx).pop();
    }

    if (hasActiveDayView) {
      if (detail == null) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[day_sheet_note_tap] skipped host Day View detail request '
            'because event has no stable identity: ${event.title}',
          );
        }
        return;
      }
      _dayViewEventDetailRequest.value = target;
      return;
    }

    _openDayView(
      context,
      kYear,
      kMonth,
      kDay,
      focusEvent: event,
      initialEventDetailRestorationState: detail,
      debugOpenSource: 'day_sheet_note_tap_fallback',
    );
  }

  /* ───── Day Sheet ───── */

  static const int _flowHydrationLookbackDays = 365; // 12 months back
  static const int _flowHydrationLookaheadDays = 540; // ~18 months ahead
  static const Duration _flowHydrationPadding = Duration(days: 14);

  ({DateTime startUtc, DateTime endUtc}) _computeFlowHydrationWindow(
    Set<int> activeFlowIds,
    Map<int, _Flow> flowIndex,
  ) {
    final today = DateUtils.dateOnly(DateTime.now());
    DateTime? minStart;
    DateTime? maxEnd;

    for (final fid in activeFlowIds) {
      final flow = flowIndex[fid];
      if (flow == null) continue;
      final s = flow.start != null ? DateUtils.dateOnly(flow.start!) : null;
      final e = flow.end != null ? DateUtils.dateOnly(flow.end!) : null;
      if (s != null && (minStart == null || s.isBefore(minStart))) {
        minStart = s;
      }
      if (e != null && (maxEnd == null || e.isAfter(maxEnd))) {
        maxEnd = e;
      }
    }

    final startFloor = today.subtract(
      const Duration(days: _flowHydrationLookbackDays),
    );
    DateTime start = minStart == null
        ? startFloor
        : (minStart.isBefore(startFloor) ? startFloor : minStart);

    final endCeiling = today.add(
      const Duration(days: _flowHydrationLookaheadDays),
    );
    DateTime end;
    if (maxEnd == null) {
      end = endCeiling;
    } else {
      end = maxEnd.isAfter(endCeiling) ? endCeiling : maxEnd;
    }

    start = start.subtract(_flowHydrationPadding);
    end = end.add(_flowHydrationPadding);

    final exclusiveEnd = end.add(const Duration(days: 1));
    return (startUtc: start.toUtc(), endUtc: exclusiveEnd.toUtc());
  }

  ({DateTime startUtc, DateTime endUtc}) _computeStandaloneHydrationWindow(
    List<_Flow> flows,
  ) {
    // Load a wide but bounded slice of standalone notes so we do not depend on
    // "first N" ordering. Baseline is ±_standaloneHydrationWindowYears around
    // today, widened to cover the visible flow horizon.
    final today = DateUtils.dateOnly(DateTime.now());
    final span = Duration(days: 365 * _standaloneHydrationWindowYears);

    DateTime start = today.subtract(span);
    DateTime end = today.add(span);

    for (final flow in flows) {
      final flowStart = flow.start != null
          ? DateUtils.dateOnly(flow.start!)
          : null;
      final flowEnd = flow.end != null ? DateUtils.dateOnly(flow.end!) : null;
      if (flowStart != null && flowStart.isBefore(start)) start = flowStart;
      if (flowEnd != null && flowEnd.isAfter(end)) end = flowEnd;
    }

    start = start.subtract(_standaloneHydrationPadding);
    end = end.add(_standaloneHydrationPadding);

    // Treat end as exclusive so the final day is fully included.
    final endExclusive = end.add(const Duration(days: 1));
    return (startUtc: start.toUtc(), endUtc: endExclusive.toUtc());
  }

  Future<void> _handleCreateTimedEvent(
    int ky,
    int km,
    int kd, {
    required String title,
    String? detail,
    String? location,
    required TimeOfDay start,
    required TimeOfDay end,
    bool allDay = false,
  }) async {
    try {
      await _saveSingleNoteOnly(
        selYear: ky,
        selMonth: km,
        selDay: kd,
        title: title,
        detail: detail,
        location: location,
        allDay: allDay,
        startTime: allDay ? null : start,
        endTime: allDay ? null : end,
        color: null,
      );
    } catch (e, st) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] Failed to save timed event: $e');
        _calendarDebugPrint('$st');
      }
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text('Failed to save event: $e'),
            backgroundColor: Colors.red,
          ),
        );
      }
    }
  }

  Future<void> _recordEventCompletion({
    required String clientEventId,
    required int flowId,
    required DateTime completedOnDate,
    Map<String, dynamic>? metadata,
  }) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    try {
      await repo.recordEventCompletion(
        clientEventId: clientEventId,
        flowId: flowId,
        completedOnDate: completedOnDate,
        metadata: metadata,
      );
      if (resolveMaatFlowKind(behaviorPayload: metadata) ==
          MaatFlowKind.decanWatch) {
        unawaited(_ensureDecanWatchHorizon(flowId));
      }
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] recordEventCompletion failed: $e');
      }
      rethrow;
    }
  }

  Future<void> _ensureDecanWatchHorizon(int flowId) async {
    final flowIndex = _flows.indexWhere((flow) => flow.id == flowId);
    if (flowIndex < 0) return;
    final flow = _flows[flowIndex];
    if (!flow.active) return;
    if (resolveMaatFlowKind(flowNotes: flow.notes) != MaatFlowKind.decanWatch) {
      return;
    }

    final timezone =
        _trackSkyTimeZoneFromKey(_flowNoteToken(flow.notes, 'dw_tz=')) ??
        detectTrackSkyTimeZone();
    final lens = decanWatchLensFromNotes(flow.notes);
    final hour =
        int.tryParse(_flowNoteToken(flow.notes, 'dw_hour=') ?? '') ??
        kDecanWatchDefaultHour;
    final minute =
        int.tryParse(_flowNoteToken(flow.notes, 'dw_minute=') ?? '') ??
        kDecanWatchDefaultMinute;
    final occurrences = upcomingDecanWatchOccurrences(
      timezone: timezone,
      count: 3,
      hour: hour,
      minute: minute,
    );
    if (occurrences.isEmpty) return;

    final repo = UserEventsRepo(Supabase.instance.client);
    final ruleDates = <DateTime>{};
    for (final rule in flow.rules) {
      if (rule is _RuleDates) {
        ruleDates.addAll(rule.dates.map(DateUtils.dateOnly));
      }
    }

    for (final occurrence in occurrences) {
      final dayOnly = DateUtils.dateOnly(occurrence.startLocal);
      final kyKmKd = KemeticMath.fromGregorian(dayOnly);
      final context = courseContextForKemeticDate(
        kYear: occurrence.kYear,
        kMonth: occurrence.kMonth,
        kDay: occurrence.decanStartDay,
      );
      final title = decanWatchEventTitle(occurrence);
      final detail = decanWatchDetailText(
        occurrence,
        lens: lens,
        context: context,
      );
      final behaviorPayload = decanWatchBehaviorPayload(
        occurrence: occurrence,
        lens: lens,
      );
      final clientEventId = decanWatchClientEventId(
        flowId: flowId,
        occurrence: occurrence,
      );
      final startTod = TimeOfDay(
        hour: occurrence.startLocal.hour,
        minute: occurrence.startLocal.minute,
      );
      final endTod = TimeOfDay(
        hour: occurrence.endLocal.hour,
        minute: occurrence.endLocal.minute,
      );
      final note = _Note(
        clientEventId: clientEventId,
        calendarId: flow.calendarId ?? _personalCalendarId,
        title: title,
        detail: detail,
        allDay: false,
        start: startTod,
        end: endTod,
        flowId: flowId,
        category: 'Ritual',
        alertOffsetMinutes: 0,
        actionId: decanWatchActionId(occurrence),
        behaviorPayload: behaviorPayload,
      );
      try {
        await repo.upsertByClientId(
          clientEventId: clientEventId,
          title: title,
          startsAtUtc: occurrence.startUtc,
          detail: detail,
          calendarId: flow.calendarId ?? _personalCalendarId,
          allDay: false,
          endsAtUtc: occurrence.endUtc,
          category: 'Ritual',
          flowLocalId: flowId,
          actionId: decanWatchActionId(occurrence),
          behaviorPayload: behaviorPayload,
          caller: 'decan_watch_horizon',
        );
        ruleDates.add(dayOnly);

        _addNote(
          kyKmKd.kYear,
          kyKmKd.kMonth,
          kyKmKd.kDay,
          title,
          detail,
          clientEventId: clientEventId,
          calendarId: flow.calendarId ?? _personalCalendarId,
          allDay: false,
          start: startTod,
          end: endTod,
          flowId: flowId,
          category: 'Ritual',
          alertOffsetMinutes: 0,
          actionId: decanWatchActionId(occurrence),
          behaviorPayload: behaviorPayload,
          notify: false,
        );
        await _scheduleAlertForEvent(
          note: note,
          ky: kyKmKd.kYear,
          km: kyKmKd.kMonth,
          kd: kyKmKd.kDay,
          clientEventId: clientEventId,
        );
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[decanWatchHorizon] event creation failed '
            'flowId=$flowId cid=$clientEventId: $e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }

    final orderedDates = ruleDates.toList()..sort();
    if (orderedDates.isNotEmpty) {
      flow.rules
        ..clear()
        ..add(_RuleDates(dates: ruleDates));
      flow.start = orderedDates.first;
      flow.end = orderedDates.last;
      try {
        await repo.upsertFlow(
          id: flow.id,
          name: flow.name,
          color: flow.color.toARGB32(),
          active: flow.active,
          calendarId: flow.calendarId,
          startDate: flow.start,
          endDate: flow.end,
          notes: flow.notes,
          rules: jsonEncode(
            flow.rules.map(CalendarPageState.ruleToJson).toList(),
          ),
          originType: 'template',
        );
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[decanWatchHorizon] flow rule update failed flowId=$flowId: $e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }
    if (mounted) {
      setState(() {});
      _notifyDayViewDataChanged();
    }
  }

  String? _flowNoteToken(String? notes, String prefix) {
    if (notes == null || notes.isEmpty) return null;
    for (final token in notes.split(';')) {
      final trimmed = token.trim();
      if (trimmed.startsWith(prefix)) {
        return trimmed.substring(prefix.length);
      }
    }
    return null;
  }

  TrackSkyTimeZone? _trackSkyTimeZoneFromKey(String? key) {
    switch (key?.trim().toLowerCase()) {
      case 'pacific':
        return TrackSkyTimeZone.pacific;
      case 'mountain':
        return TrackSkyTimeZone.mountain;
      case 'central':
        return TrackSkyTimeZone.central;
      case 'eastern':
        return TrackSkyTimeZone.eastern;
    }
    return null;
  }

  Future<void> _unrecordEventCompletion(String clientEventId) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    try {
      await repo.unrecordEventCompletion(clientEventId);
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] unrecordEventCompletion failed: $e');
      }
      rethrow;
    }
  }

  Future<void> _handleJournalCompletionBadgesRemoved(
    List<EventBadgeToken> badges,
  ) async {
    final clearedClientEventIds = <String>{};
    var changed = false;
    for (final badge in badges) {
      final identity = badge.completionSourceIdentity;
      if (identity != null && identity.isNotEmpty) {
        await const CalendarCompletionLocalStore().save(
          identity: identity,
          status: CompletionStatus.none,
        );
        changed = true;
      }

      final clientEventId = badge.completionClientEventId;
      if (clientEventId == null ||
          clientEventId.isEmpty ||
          !clearedClientEventIds.add(clientEventId)) {
        continue;
      }
      await _unrecordEventCompletion(clientEventId);
      changed = true;
    }

    if (changed) {
      _notifyDayViewDataChanged();
    }
  }

  Future<Set<String>> _loadCompletedClientEventIds({
    int? flowId,
    DateTime? completedOnDate,
  }) async {
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) return {};
    try {
      final client = Supabase.instance.client;
      var query = client
          .from('user_event_completions')
          .select('client_event_id')
          .eq('user_id', user.id);
      if (flowId != null) {
        query = query.eq('flow_id', flowId);
      }
      if (completedOnDate != null) {
        final dateStr =
            '${completedOnDate.year}-${completedOnDate.month.toString().padLeft(2, '0')}-${completedOnDate.day.toString().padLeft(2, '0')}';
        query = query.eq('completed_on', dateStr);
      }
      final rows = await query;
      final ids = <String>{};
      for (final row in (rows as List)) {
        final cid = (row as Map<String, dynamic>)['client_event_id'] as String?;
        if (cid != null && cid.isNotEmpty) {
          ids.add(cid);
        }
      }
      return ids;
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DayView] loadCompletedClientEventIds failed: $e');
      }
      return {};
    }
  }

  void _openDaySheet(
    int kYear,
    int kMonth,
    int kDay, {
    bool allowDateChange = false,
    bool? initialShowGregorian,
    bool persistAsRestoration = true,
    TimeOfDay? initialStartTime,
    TimeOfDay? initialEndTime,
    bool initialAllDay = false,
    String? initialTitle,
    String? initialLocation,
    String? initialDetail,
    Color? initialColor,
    String? initialCategory,
    int? initialAlertMinutes,
    String? initialCalendarId,
    int? editingIndex,
    int? editingSourceKYear,
    int? editingSourceKMonth,
    int? editingSourceKDay,
  }) {
    if (_daySheetOpenOrOpening) return;
    _daySheetOpenOrOpening = true;
    // Ensure reminder rules are loaded before building the sheet so the list is populated.
    _loadReminderRules();
    _calendarDebugPrint('');
    _calendarDebugPrint('┌─────────────────────────────────────┐');
    _calendarDebugPrint('│ 📝 OPENING DAY SHEET                │');
    _calendarDebugPrint('├─────────────────────────────────────┤');
    _calendarDebugPrint('│ Date: $kYear/$kMonth/$kDay');
    _calendarDebugPrint('│ allowDateChange: $allowDateChange');
    _calendarDebugPrint('│ Context mounted: ${context.mounted}');
    _calendarDebugPrint('│ Context widget: ${context.widget.runtimeType}');
    _calendarDebugPrint('└─────────────────────────────────────┘');
    _calendarDebugPrint('');

    int selYear = kYear;
    int selMonth = kMonth;
    int selDay = kDay;
    bool showGregorianDates = initialShowGregorian ?? _showGregorian;

    int maxDayFor(int year, int month) =>
        (month == 13) ? (KemeticMath.isLeapKemeticYear(year) ? 6 : 5) : 30;
    final sourceEditingKYear = editingSourceKYear ?? kYear;
    final sourceEditingKMonth = editingSourceKMonth ?? kMonth;
    final sourceEditingKDay = editingSourceKDay ?? kDay;
    final initialEditingBucketKey = _kKey(
      sourceEditingKYear,
      sourceEditingKMonth,
      sourceEditingKDay,
    );
    final initialEditingNote =
        editingIndex != null &&
            _notes[initialEditingBucketKey] != null &&
            editingIndex < _notes[initialEditingBucketKey]!.length
        ? _notes[initialEditingBucketKey]![editingIndex]
        : null;
    final initialEditingRepeatingFlow = _repeatingNoteFlowForId(
      initialEditingNote?.flowId,
    );
    final editingRepeatingNote = initialEditingRepeatingFlow != null;
    final availableCalendars =
        _calendarSummariesById.values
            .where(
              (calendar) =>
                  calendar.canEdit ||
                  initialEditingNote?.calendarId == calendar.id,
            )
            .toList()
          ..sort((a, b) {
            if (a.isPersonal && !b.isPersonal) return -1;
            if (!a.isPersonal && b.isPersonal) return 1;
            return a.name.toLowerCase().compareTo(b.name.toLowerCase());
          });
    final normalizedInitialCalendarId = _normalizeCalendarId(initialCalendarId);
    final initialCalendarCanEdit =
        normalizedInitialCalendarId != null &&
        availableCalendars.any(
          (calendar) => calendar.id == normalizedInitialCalendarId,
        );

    final rawInitialDetail = initialDetail ?? '';
    final strippedInitialDetail = _stripCidLines(rawInitialDetail);
    final initialCidMetadata = _extractCidMetadata(rawInitialDetail);

    final controllerTitle = TextEditingController(text: initialTitle ?? '');
    final controllerLocation = TextEditingController(
      text: initialLocation ?? '',
    );
    final controllerDetail = TextEditingController(text: strippedInitialDetail);

    bool allDay = initialAllDay;
    TimeOfDay? startTime =
        initialStartTime ?? const TimeOfDay(hour: 12, minute: 0);
    TimeOfDay? endTime = initialEndTime ?? const TimeOfDay(hour: 13, minute: 0);
    String? selectedCategory = initialCategory;
    int alertMinutesBefore = initialAlertMinutes ?? _alertNoneMinutes;
    String? selectedCalendarId =
        initialEditingNote?.calendarId ??
        (initialCalendarCanEdit ? normalizedInitialCalendarId : null) ??
        _personalCalendarId ??
        (availableCalendars.isNotEmpty ? availableCalendars.first.id : null);
    String? selectedCalendarName =
        initialEditingNote?.calendarName ??
        _calendarSummariesById[selectedCalendarId]?.name;

    // Repeat state
    NoteRepeatOption repeatOption = NoteRepeatOption.never;
    NoteRepeatEndType endType = NoteRepeatEndType.never;
    SimpleRecurrenceFrequency customFrequency = SimpleRecurrenceFrequency.daily;
    int customInterval = 1;
    DateTime? endDate;
    int endCount = 10;

    Color selectedColor = initialColor ?? daySheetColorPalette.first;
    bool sheetClosing = false;
    bool sheetControllersDisposed = false;

    Map<String, dynamic> daySheetSessionPayload() {
      return <String, dynamic>{
        'kYear': selYear,
        'kMonth': selMonth,
        'kDay': selDay,
        'showGregorianDates': showGregorianDates,
        'allowDateChange': allowDateChange,
        'title': controllerTitle.text,
        'location': controllerLocation.text,
        'detail': controllerDetail.text,
        'allDay': allDay,
        'startHour': startTime?.hour,
        'startMinute': startTime?.minute,
        'endHour': endTime?.hour,
        'endMinute': endTime?.minute,
        'colorValue': selectedColor.toARGB32(),
        'category': selectedCategory,
        'alertMinutesBefore': alertMinutesBefore,
        'calendarId': selectedCalendarId,
        'editingIndex': editingIndex,
        'editingSourceKYear': editingIndex == null ? null : sourceEditingKYear,
        'editingSourceKMonth': editingIndex == null
            ? null
            : sourceEditingKMonth,
        'editingSourceKDay': editingIndex == null ? null : sourceEditingKDay,
      };
    }

    void persistDaySheetSession() {
      if (sheetClosing || sheetControllersDisposed) return;
      if (persistAsRestoration) {
        unawaited(
          AppRestorationService.instance.saveDaySheetState(
            daySheetSessionPayload(),
          ),
        );
      }
      unawaited(
        SessionResumeService.saveResumeEntry(
          baseRoute: '/',
          kind: _kSessionResumeKindDaySheet,
          payload: daySheetSessionPayload(),
        ),
      );
    }

    controllerTitle.addListener(persistDaySheetSession);
    controllerLocation.addListener(persistDaySheetSession);
    controllerDetail.addListener(persistDaySheetSession);
    persistDaySheetSession();

    void disposeDaySheetControllers() {
      if (sheetControllersDisposed) return;
      sheetControllersDisposed = true;
      controllerTitle.removeListener(persistDaySheetSession);
      controllerLocation.removeListener(persistDaySheetSession);
      controllerDetail.removeListener(persistDaySheetSession);
      controllerTitle.dispose();
      controllerLocation.dispose();
      controllerDetail.dispose();
    }

    try {
      _calendarDebugPrint('🚀 Attempting to show modal bottom sheet...');
      showModalBottomSheet(
        context: context,
        isScrollControlled: true,
        backgroundColor: Colors.transparent, // ✅ More stable like Flow Studio
        useSafeArea: true,
        // iPad/tablet: allow swipe-to-close + backdrop tap to avoid trapped sheets.
        isDismissible: true,
        enableDrag: true,
        shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(16)),
        ),
        builder: (sheetCtx) {
          bool showReminders = _noteSheetShowReminders;
          bool scheduledFlowsExpanded = false;
          bool dayNotesExpanded = false;

          final daySheetContent = StatefulBuilder(
            builder: (sheetCtx, setSheetState) {
              // Clamp before any toGregorian
              int dayCount = maxDayFor(selYear, selMonth);
              if (selDay > dayCount) {
                selDay = dayCount;
              }

              final titleG = KemeticMath.toGregorian(
                selYear,
                selMonth,
                selDay,
              ); // safe
              final dayEvents = _calendarSheetEventsForDay(
                selYear,
                selMonth,
                selDay,
              );
              final dayFlowRows = _calendarSheetScheduledFlowsForDay(
                selYear,
                selMonth,
                selDay,
                dayEvents,
              );
              final dayReminderRules = _calendarSheetReminderRulesForDay(
                selYear,
                selMonth,
                selDay,
                dayEvents,
              );
              final editingNote = initialEditingNote;
              final selectedCalendar = selectedCalendarId == null
                  ? null
                  : _calendarSummariesById[selectedCalendarId];
              final selectedCalendarLabel =
                  selectedCalendar?.name ??
                  selectedCalendarName ??
                  'My Calendar';

              Future<void> pickStart() async {
                final t = await showTimePicker(
                  context: sheetCtx,
                  initialTime:
                      startTime ?? const TimeOfDay(hour: 12, minute: 0),
                  builder: (c, w) => Theme(
                    data: Theme.of(c).copyWith(
                      colorScheme: const ColorScheme.dark(
                        primary: _gold,
                        surface: _bg,
                        onSurface: Colors.white,
                      ),
                    ),
                    child: w ?? const SizedBox.shrink(),
                  ),
                );
                if (t == null) return;
                setSheetState(() {
                  startTime = t;
                  if (endTime != null &&
                      _toMinutes(endTime!) <= _toMinutes(t)) {
                    endTime = _addMinutes(t, 60);
                  }
                });
                persistDaySheetSession();
              }

              Future<void> pickEnd() async {
                final t = await showTimePicker(
                  context: sheetCtx,
                  initialTime:
                      endTime ??
                      (startTime != null
                          ? _addMinutes(startTime!, 60)
                          : const TimeOfDay(hour: 13, minute: 0)),
                  builder: (c, w) => Theme(
                    data: Theme.of(c).copyWith(
                      colorScheme: const ColorScheme.dark(
                        primary: _gold,
                        surface: _bg,
                        onSurface: Colors.white,
                      ),
                    ),
                    child: w ?? const SizedBox.shrink(),
                  ),
                );
                if (t == null) return;
                setSheetState(() {
                  endTime = t;
                  if (startTime != null &&
                      _toMinutes(t) <= _toMinutes(startTime!)) {
                    startTime = _addMinutes(t, -60);
                  }
                });
                persistDaySheetSession();
              }

              Widget datePicker() {
                final seed = DateUtils.dateOnly(titleG);
                final kSeed = KemeticMath.fromGregorian(seed);
                final dateMode = showGregorianDates
                    ? EventCreateDatePickerMode.gregorian
                    : EventCreateDatePickerMode.kemetic;
                final stoneMode = showGregorianDates
                    ? StoneDatePickerCalendarMode.gregorian
                    : StoneDatePickerCalendarMode.kemetic;
                return Padding(
                  padding: const EdgeInsets.only(top: 6, bottom: 4),
                  child: StoneRegisterDateField<EventCreateDatePickerValue>(
                    key: const ValueKey<String>('day_sheet_date_picker_field'),
                    value: EventCreateDatePickerValue(
                      date: seed,
                      mode: dateMode,
                    ),
                    adapter: EventCreateDatePickerAdapter(
                      gregorianYearStart: seed.year - 200,
                      kemeticYearStart: kSeed.kYear - 200,
                    ),
                    mode: stoneMode,
                    label: 'Day',
                    title: 'Day sheet date',
                    enabled: allowDateChange,
                    showCalendarIcon: false,
                    onChanged: (picked) {
                      final selected = KemeticMath.fromGregorian(picked.date);
                      setSheetState(() {
                        selYear = selected.kYear;
                        selMonth = selected.kMonth;
                        selDay = selected.kDay;
