  void _repairDawnHouseRiteLoadedDetail({
    required UserEventsRepo repo,
    required FlowEventRow event,
    required String canonicalDetail,
    required Color? color,
    required int? alertMinutes,
  }) {
    final id = event.id;
    if (id == null || id.isEmpty) return;
    final updatedDetail = _encodeDetailWithMeta(
      canonicalDetail,
      color: color,
      alertMinutes: alertMinutes,
    );
    if (updatedDetail == null || updatedDetail == event.detail) return;

    unawaited(() async {
      try {
        await repo.update(id: id, detail: updatedDetail);
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[dawnHouseRite] detail repair failed id=$id: $e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }());
  }

  ScrollPosition? _singleCalendarScrollPosition() {
    if (!_scrollCtrl.hasClients) return null;
    final positions = _scrollCtrl.positions;
    if (positions.length != 1) return null;
    return positions.single;
  }

  double? _calendarScrollOffsetForPreservation() {
    return _singleCalendarScrollPosition()?.pixels ??
        _lastKnownCalendarScrollOffset;
  }

  Future<void> _loadFromDisk({
    String source = 'manual',
    bool preserveViewport = false,
  }) async {
    if (_isLoadingFromDisk) {
      return;
    }
    _isLoadingFromDisk = true;

    try {
      if (kDebugMode) {
        _calendarDebugPrint('=== _loadFromDisk START ($source) ===');
      }

      final currentUser = Supabase.instance.client.auth.currentUser;
      if (currentUser == null) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[loadFromDisk] Skipping load: no authenticated user',
          );
        }
        return;
      }
      final preservedScrollOffset = preserveViewport
          ? _calendarScrollOffsetForPreservation()
          : null;
      await _ensureManualDeleteTombstonesLoaded();
      final warmStartBackfillMode = source.startsWith('startup_backfill:');
      final keepWarmStartSnapshotVisible =
          warmStartBackfillMode && _hasWarmStartSnapshotVisibleForCurrentUser();
      final hasPaintedStandaloneLaneAtLoadStart = _hasPaintedStandaloneLane(
        _notes,
      );
      final hasPaintedEventSnapshotAtLoadStart = _hasPaintedEventSnapshot(
        _notes,
      );
      final deferColdSnapshotPublication =
          source.startsWith('startup_cold_authoritative:') &&
          !_hasUsableCalendarSnapshotForPaint();
      final repo = UserEventsRepo(Supabase.instance.client);

      // Flow-first: load flows, then events; join only to known active flows
      final List<_Flow> newFlows = [];
      final Map<String, List<_Note>> newNotes = {};
      int nextFlowId = _nextFlowId;

      // Load flows into _flows list
      final serverFlows = await repo.getAllFlows();
      if (kDebugMode) {
        _calendarDebugPrint(
          '[loadFromDisk] getAllFlows count: ${serverFlows.length}',
        );
      }
      for (final f in serverFlows) {
        final repMeta = _decodeRepeatingNoteMetadata(f.notes);
        final derivedHidden =
            f.isHidden ||
            repMeta.detail != null ||
            repMeta.location != null ||
            repMeta.category != null;
        if (kDebugMode && derivedHidden) {
          final fromDb = f.isHidden;
          final fromRepMeta =
              repMeta.detail != null ||
              repMeta.location != null ||
              repMeta.category != null;
          _calendarDebugPrint(
            '[loadFromDisk] hidden flow id=${f.id} '
            'name=<redacted chars=${f.name.length}> '
            'fromDb=$fromDb fromRepMeta=$fromRepMeta',
          );
        }
        final flow = _Flow(
          id: f.id,
          calendarId: f.calendarId,
          name: f.name,
          color: Color(rgbToArgb(f.color)),
          active: f.active,
          isSaved: f.isSaved,
          savedAt: f.savedAt,
          rules: _parseRules(f.rules),
          start: f.startDate,
          end: f.endDate,
          notes: f.notes,
          shareId: f.shareId, // NEW: Load share_id
          isHidden: derivedHidden,
          isReminder: f.isReminder,
          reminderUuid: f.reminderUuid,
        );
        newFlows.add(flow);
        // 🔍 DEBUG: Log what color came from database for ALL custom flows
        // Log flows with ID greater than 156 to catch all user-created flows
        if (kDebugMode && f.id > 156) {
          _calendarDebugPrint(
            '[loadFlows] Flow ${f.id} loaded with '
            'name=<redacted chars=${f.name.length}> '
            'color=${f.color} (0x${f.color.toRadixString(16)})',
          );
        }
        if (flow.id >= nextFlowId) nextFlowId = flow.id + 1;
      }

      // Ensure reminder rules are present from loaded reminder flows if they didn't load earlier.
      // (Run after commit to use new flow state.)
      if (kDebugMode) {
        final hiddenCount = newFlows.where((f) => f.isHidden).length;
        final activeCount = newFlows.where((f) => f.active).length;
        final expiredCount = newFlows
            .where(
              (f) =>
                  f.active &&
                  !isFlowScheduleOpenLocally(active: f.active, endDate: f.end),
            )
            .length;
        _calendarDebugPrint(
          '[loadFromDisk] newFlows: total=${newFlows.length} hidden=$hiddenCount active=$activeCount expired=$expiredCount',
        );
      }

      // Reuse the just-loaded flow rows for reminder bootstrapping so startup
      // does not pay for a second full flow fetch before note hydration.
      await _primeReminderRulesFromFlows(newFlows);

      // Build index/maps for later use
      final Map<int, _Flow> flowIndex = {for (final f in newFlows) f.id: f};
      final flowOwnersById = <int, FlowRecordSnapshot>{
        for (final f in newFlows)
          f.id: FlowRecordSnapshot(
            id: f.id,
            active: f.active,
            isHidden: f.isHidden,
            isReminder: f.isReminder,
            isSaved: f.isSaved,
            notes: f.notes,
          ),
      };

      // Materialized history is wider than live schedule hydration: ended
      // non-saved flows keep their past `user_events`, while saved inactive
      // templates and backend deleted rows stay out of the calendar.
      final hydrationFlowIds = newFlows
          .where((f) {
            return shouldHydrateMaterializedUserEvents(flowOwnersById[f.id]!);
          })
          .map((f) => f.id)
          .toSet(); // 👈 Set for O(1) contains() lookups
      if (kDebugMode) {
        _calendarDebugPrint(
          '[loadFromDisk] hydrationFlowIds count: ${hydrationFlowIds.length}',
        );
        if (hydrationFlowIds.isNotEmpty) {
          for (final fid in hydrationFlowIds) {
            final flow = flowIndex[fid];
            if (flow == null) continue;
            final rn = _decodeRepeatingNoteMetadata(flow.notes);
            final looksLikeRepeatingNote =
                rn.detail != null || rn.location != null || rn.category != null;
            _calendarDebugPrint(
              '[loadFromDisk] flow id=$fid '
              'name=<redacted chars=${flow.name.length}> '
              'isReminder=${flow.isReminder} hidden=${flow.isHidden} '
              'notesLikeRepeatingNote=$looksLikeRepeatingNote',
            );
          }
        }
      }

      ({DateTime startUtc, DateTime endUtc})? flowWindow;
      if (hydrationFlowIds.isNotEmpty) {
        flowWindow = _computeFlowHydrationWindow(hydrationFlowIds, flowIndex);
        if (kDebugMode) {
          _calendarDebugPrint(
            '[loadFromDisk] flow hydration window '
            '${flowWindow.startUtc.toIso8601String()} → ${flowWindow.endUtc.toIso8601String()}',
          );
        }
      }

      var flowHydrationComplete = true;
      var standaloneHydrationComplete = false;

      Future<Map<int, List<FlowEventRow>>> loadFlowEvents() async {
        final eventsByFlowId = <int, List<FlowEventRow>>{};
        if (hydrationFlowIds.isEmpty) {
          return eventsByFlowId;
        }

        try {
          final batchedEvents = await repo.getEventsForFlowIds(
            hydrationFlowIds,
            startUtc: flowWindow?.startUtc,
            endUtc: flowWindow?.endUtc,
          );
          for (final evt in batchedEvents) {
            final fid = evt.flowLocalId;
            if (fid == null || !hydrationFlowIds.contains(fid)) continue;
            eventsByFlowId.putIfAbsent(fid, () => <FlowEventRow>[]).add(evt);
          }
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] getEventsForFlowIds count=${batchedEvents.length} flows=${eventsByFlowId.length}',
            );
          }
        } catch (err, st) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] batched flow event fetch failed: $err',
            );
            _calendarDebugPrint('$st');
          }
        }

        if (eventsByFlowId.isNotEmpty) {
          if (kDebugMode) {
            eventsByFlowId.forEach((fid, events) {
              _calendarDebugPrint(
                '[loadFromDisk] flow $fid events (batched) count: ${events.length}',
              );
            });
          }
          return eventsByFlowId;
        }

        var fallbackHadError = false;
        for (final flowId in hydrationFlowIds) {
          try {
            final flowEvents = await repo.getEventsForFlow(
              flowId,
              startUtc: flowWindow?.startUtc,
              endUtc: flowWindow?.endUtc,
              flowEventsOnly: true,
            );
            eventsByFlowId[flowId] = flowEvents;
            if (kDebugMode) {
              _calendarDebugPrint(
                '[loadFromDisk] getEventsForFlow($flowId) count: ${flowEvents.length} (fallback)',
              );
            }
          } catch (err, st) {
            fallbackHadError = true;
            if (kDebugMode) {
              _calendarDebugPrint(
                '[loadFromDisk] failed to hydrate events for flow $flowId: $err',
              );
              _calendarDebugPrint('$st');
            }
          }
        }
        if (fallbackHadError) {
          flowHydrationComplete = false;
        }

        return eventsByFlowId;
      }

      final standaloneWindow = _computeStandaloneHydrationWindow(newFlows);
      final flowEventsFuture = loadFlowEvents();
      final standaloneFuture = repo.getStandaloneEventsForDateRangeAll(
        startUtc: standaloneWindow.startUtc,
        endUtc: standaloneWindow.endUtc,
        pageSize: 1000,
        flowOwnersById: flowOwnersById,
      );
      final flowEventCountsFuture = _flowsRepo.loadMyFlowEventCounts(
        flowIds: newFlows.map((flow) => flow.id),
      );
      final eventsByFlowId = await flowEventsFuture;

      int flowAddedCount = 0;
      bool committedVisibleCalendar = false;
      bool deferredColdSnapshotReady = false;

      void commitVisibleCalendarState(
        String phase, {
        bool loadComplete = false,
      }) {
        if (!mounted) return;
        final preservedOnboardingTargetCount =
            _mergePendingOnboardingTargetInto(
              newNotes,
              source: source,
              phase: phase,
            );
        if (phase == 'complete' &&
            !shouldPublishCompletedVisibleCalendarSnapshot(
              loadComplete: loadComplete,
            )) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] skipped incomplete complete commit '
              'source=$source '
              'paintedEvents=$hasPaintedEventSnapshotAtLoadStart '
              'flowComplete=$flowHydrationComplete '
              'standaloneComplete=$standaloneHydrationComplete',
            );
          }
          return;
        }
        final preservePaintedStandaloneLane =
            shouldPreservePaintedStandaloneLaneForHydrationCommit(
              source: source,
              commitPhase: phase,
              hasPaintedStandaloneLane: hasPaintedStandaloneLaneAtLoadStart,
              standaloneLaneAuthoritative: !keepWarmStartSnapshotVisible,
            );
        final preservedStandaloneCount = preservePaintedStandaloneLane
            ? _mergePaintedStandaloneLaneInto(newNotes)
            : 0;
        final hydratedTrackSkyFlowIds = newFlows
            .where((flow) => _isTrackSkyFlowName(flow.name))
            .map((flow) => flow.id)
            .where((flowId) => flowId > 0)
            .toSet();
        final dedupedNotes = <String, List<_Note>>{};
        newNotes.forEach((key, notes) {
          final cleaned = _dedupeVisibleDayNotes(
            notes,
            trackSkyFlowIds: hydratedTrackSkyFlowIds,
          );
          if (cleaned.isNotEmpty) {
            dedupedNotes[key] = cleaned;
          }
        });

        _flows
          ..clear()
          ..addAll(newFlows);
        _notes
          ..clear()
          ..addAll(dedupedNotes);
        _nextFlowId = nextFlowId;
        CalendarPage._reconcileRememberedMaatJoinsFromLiveFlows(_flows);

        if (kDebugMode) {
          _calendarDebugPrint(
            '[loadFromDisk] committed phase=$phase '
            '_flows.length=${_flows.length} _notes keys=${_notes.length} '
            'preservedStandalone=$preservedStandaloneCount '
            'preservedOnboardingTarget=$preservedOnboardingTargetCount',
          );
        }

        _rebuildReminderRulesFromFlowsIfMissing();
        _lastSuccessfulHydrationAt = DateTime.now();
        _warmStartCacheRestoredForUserId = _activeWarmStartUserId();
        _warmStartCacheRestoredForProjectRef = _activeWarmStartProjectRef();
        if (deferColdSnapshotPublication && loadComplete) {
          deferredColdSnapshotReady = true;
          committedVisibleCalendar = true;
          return;
        }
        if (loadComplete) {
          _hasPublishedCalendarSnapshot = true;
          _publishedCalendarSnapshotUserId = _activeWarmStartUserId();
          _publishedCalendarSnapshotProjectRef = _activeWarmStartProjectRef();
          _initialCalendarLoadFinished = true;
        }
        if (loadComplete || !hasPaintedEventSnapshotAtLoadStart) {
          _warmStartSnapshotVisible = false;
        }
        _bumpDataVersion();
        if (!committedVisibleCalendar &&
            preserveViewport &&
            preservedScrollOffset != null) {
          _lastKnownCalendarScrollOffset = preservedScrollOffset;
          WidgetsBinding.instance.addPostFrameCallback((_) {
            final position = _singleCalendarScrollPosition();
            if (!mounted ||
                position == null ||
                !position.hasContentDimensions) {
              return;
            }
            final clamped = preservedScrollOffset.clamp(
              position.minScrollExtent,
              position.maxScrollExtent,
            );
            position.jumpTo(clamped);
            _lastKnownCalendarScrollOffset = clamped.toDouble();
          });
        }
        committedVisibleCalendar = true;
      }

      for (final flowId in hydrationFlowIds) {
        try {
          final flowEvents = eventsByFlowId[flowId] ?? const <FlowEventRow>[];
          final owningFlow = flowIndex[flowId];
          final isTrackSkyFlow = _isTrackSkyFlowName(owningFlow?.name);

          for (final evt in flowEvents) {
            // Convert DB UTC timestamps -> device local -> Kemetic date
            var localStart = evt.startsAtUtc.toLocal();
            var localEnd = evt.endsAtUtc?.toLocal();
            var allDay = evt.allDay;

            if (isTrackSkyFlow) {
              final normalized = normalizeTrackSkyLocalWindow(
                title: evt.title,
                category: evt.category,
                startLocal: localStart,
                endLocal: localEnd,
                allDay: allDay,
              );
              localStart = normalized.startLocal;
              localEnd = normalized.endLocal;
              allDay = normalized.allDay;
            }

            final kDate = KemeticMath.fromGregorian(localStart);

            // Build _Note, same shape the rest of the app expects
            // 👈 SAFETY NET: Skip events for flows that don't exist or are inactive.
            final ownerSnapshot = flowOwnersById[flowId];
            final flowEligible =
                owningFlow != null &&
                ownerSnapshot != null &&
                shouldHydrateMaterializedUserEvents(ownerSnapshot);
            if (!flowEligible) {
              // Skip backend deleted rows and saved inactive templates.
              continue;
            }

            final startTime = allDay
                ? null
                : TimeOfDay.fromDateTime(localStart);
            final endTime = localEnd == null
                ? null
                : TimeOfDay.fromDateTime(localEnd);
            if ((evt.category ?? '') == 'tombstone') {
              continue;
            }

            final meta = _decodeDetailMetadata(evt.detail);
            final storedCleanDetail = _cleanDetail(meta.detail);
            final canonicalDawnDetail =
                _canonicalDawnHouseRiteDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalTheWeighingDetail =
                _canonicalTheWeighingDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalOfferingTableDetail =
                _canonicalOfferingTableDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalTheTendingDetail =
                _canonicalTheTendingDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalKeptWordDetail =
                _canonicalKeptWordDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalCourseDetail = _canonicalCourseDetailForLoadedEvent(
              flow: owningFlow,
              event: evt,
              localStart: localStart,
            );
            final canonicalWagDetail = _canonicalWagDetailForLoadedEvent(
              flow: owningFlow,
              event: evt,
            );
            final canonicalOpenHandDetail =
                _canonicalOpenHandDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalDjedDetail = _canonicalDjedDetailForLoadedEvent(
              flow: owningFlow,
              event: evt,
            );
            final canonicalReadingHouseDetail =
                _canonicalReadingHouseDetailForLoadedEvent(
                  flow: owningFlow,
                  event: evt,
                );
            final canonicalDetail =
                canonicalDawnDetail ??
                canonicalTheWeighingDetail ??
                canonicalOfferingTableDetail ??
                canonicalTheTendingDetail ??
                canonicalKeptWordDetail ??
                canonicalCourseDetail ??
                canonicalWagDetail ??
                canonicalOpenHandDetail ??
                canonicalDjedDetail ??
                canonicalReadingHouseDetail;
            final cleanedDetail = canonicalDetail ?? storedCleanDetail;
            if (canonicalDetail != null &&
                canonicalDetail != storedCleanDetail) {
              _repairDawnHouseRiteLoadedDetail(
                repo: repo,
                event: evt,
                canonicalDetail: canonicalDetail,
                color: meta.color,
                alertMinutes: meta.alertMinutes,
              );
            }

            if (_isTombstoned(evt.clientEventId)) {
              continue;
            }
            if (_isPendingDelete(
              id: evt.id,
              clientEventId: evt.clientEventId,
              kYear: kDate.kYear,
              kMonth: kDate.kMonth,
              kDay: kDate.kDay,
              title: evt.title,
              allDay: allDay,
              start: startTime,
              end: endTime,
              flowId: flowId,
            )) {
              continue;
            }

            final note = _Note(
              id: evt.id,
              clientEventId: evt.clientEventId,
              calendarId: evt.calendarId,
              calendarName: evt.calendarName,
              title: _cleanTitle(evt.title),
              detail: cleanedDetail, // Clean the flowLocalId prefix
              location: evt.location,
              allDay: allDay,
              start: startTime,
              end: endTime,
              flowId: flowId,
              category: evt.category,
              isReminder: owningFlow.isReminder,
              reminderId: owningFlow.isReminder
                  ? owningFlow.reminderUuid
                  : null,
              manualColor: meta.color,
              alertOffsetMinutes: meta.alertMinutes,
              actionId: evt.actionId,
              behaviorPayload: evt.behaviorPayload,
            );

            final key = _kKey(kDate.kYear, kDate.kMonth, kDate.kDay);
            final bucket = newNotes.putIfAbsent(key, () => <_Note>[]);

            final noteStartMinute = note.allDay
                ? null
                : note.start == null
                ? null
                : note.start!.hour * 60 + note.start!.minute;
            final noteEndMinute = note.allDay
                ? null
                : note.end == null
                ? null
                : note.end!.hour * 60 + note.end!.minute;
            final incomingDedupeKey = buildMaterializedFlowEventDedupeKey(
              flowId: flowId,
              allDay: note.allDay,
              eventId: evt.id,
              clientEventId: note.clientEventId,
              title: note.title,
              startMinute: noteStartMinute,
              endMinute: noteEndMinute,
            );
            final already = bucket.any((existing) {
              if ((existing.flowId ?? -1) != flowId) return false;
              final existingStartMinute = existing.allDay
                  ? null
                  : existing.start == null
                  ? null
                  : existing.start!.hour * 60 + existing.start!.minute;
              final existingEndMinute = existing.allDay
                  ? null
                  : existing.end == null
                  ? null
                  : existing.end!.hour * 60 + existing.end!.minute;
              final existingDedupeKey = buildMaterializedFlowEventDedupeKey(
                flowId: flowId,
                allDay: existing.allDay,
                eventId: existing.id,
                clientEventId: existing.clientEventId,
                title: existing.title,
                startMinute: existingStartMinute,
                endMinute: existingEndMinute,
              );
              return existingDedupeKey == incomingDedupeKey;
            });

            if (!already) {
              bucket.add(note);
              flowAddedCount++;
            }
          }
        } catch (err, st) {
          flowHydrationComplete = false;
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] failed to hydrate events for flow $flowId: $err',
            );
            _calendarDebugPrint('$st');
          }
        }
      }

      if (kDebugMode) {
        _calendarDebugPrint(
          '[loadFromDisk] flow notes added to newNotes: $flowAddedCount',
        );
      }
      if (kDebugMode && flowAddedCount > 0) {
        _calendarDebugPrint(
          '[loadFromDisk] staged flow events until all lanes complete '
          'source=$source keepWarmStart=$keepWarmStartSnapshotVisible',
        );
      }

      // Load filing-backed standalone calendar events: notes, reminders, and
      // nutrition rows. Flow rows stay in the flow hydration path above.
      try {
        final standaloneResult = await standaloneFuture;
        final standaloneEvents = standaloneResult.events;
        final ghostStandaloneIds = standaloneResult.ghostEventIds;

        if (ghostStandaloneIds.isNotEmpty) {
          unawaited(() async {
            try {
              await repo.deleteByIds(
                ghostStandaloneIds,
                semantic: 'calendar_hydration_ghost_cleanup',
                suppressesClient: false,
                sourceFeature: 'CalendarPage._loadFromDisk',
                deleteScope: 'standalone_ghost_cleanup',
              );
            } catch (e, st) {
              if (kDebugMode) {
                _calendarDebugPrint(
                  '[_loadFromDisk] standalone ghost cleanup failed: $e',
                );
                _calendarDebugPrint('$st');
              }
            }
          }());
        }

        int standaloneAddedCount = 0;

        for (final evt in standaloneEvents) {
          try {
            final cid = evt.clientEventId ?? '';
            final rawDetail = evt.detail ?? '';
            final flowDecision = classifyFlowEvent(
              event: FlowEventSnapshot(
                flowLocalId: evt.flowLocalId,
                clientEventId: evt.clientEventId,
                detail: evt.detail,
                category: evt.category,
              ),
              flowOwnersById: flowOwnersById,
            );

            final isReminderBackboneEvent =
                evt.isReminder ||
                cid.startsWith('reminder:') ||
                cid.startsWith('nutrition:');

            // Filing-backed reminder rows may carry their canonical reminder
            // flow id for color/identity. Keep them in the standalone calendar
            // lane while still rejecting non-reminder flow ghosts.
            if (!flowDecision.isStandaloneVisible && !isReminderBackboneEvent) {
              continue;
            }

            // 🚫 HARD GUARD 4b: Reminder instances whose rule no longer exists (or was ended/deleted).
            if (cid.startsWith('reminder:')) {
              final rid = _reminderRuleIdFromCid(cid);
              final exists =
                  rid != null && _reminderRules.any((r) => r.id == rid);
              final ended = rid != null && _endedReminderIds.contains(rid);
              if (!exists || ended) {
                continue;
              }
            }

            // ✅ Nutrition: treat as reminder if a matching rule exists
            bool isReminderEvent =
                evt.isReminder || cid.startsWith('reminder:');
            String? reminderRuleId = _reminderRuleIdFromCid(cid);
            if (cid.startsWith('nutrition:')) {
              final parts = cid.split(':');
              if (parts.length >= 3) {
                final itemId = parts.sublist(1, parts.length - 1).join(':');
                final rid = 'nutrition:$itemId';
                final exists =
                    _reminderRules.any((r) => r.id == rid) &&
                    !_endedReminderIds.contains(rid);
                if (exists) {
                  isReminderEvent = true;
                  reminderRuleId = rid;
                }
              }
            }

            final positiveFiledFlowId =
                evt.flowLocalId != null && evt.flowLocalId! > 0
                ? evt.flowLocalId
                : null;
            final noteFlowId = isReminderEvent ? positiveFiledFlowId ?? -1 : -1;
            final reminderFlow = isReminderEvent && positiveFiledFlowId != null
                ? flowIndex[positiveFiledFlowId]
                : null;
            final reminderFlowColor = reminderFlow == null
                ? null
                : _displayFlowColor(reminderFlow.name, reminderFlow.color);

            // ✅ If it passed all guards → this is a true standalone note
            final localStart = evt.startsAtUtc.toLocal();
            final kDate = KemeticMath.fromGregorian(localStart);
            final decoded = _decodeDetailMetadata(rawDetail);
            final cleanedDetail = _cleanDetail(decoded.detail);

            final startTime = evt.allDay
                ? null
                : TimeOfDay.fromDateTime(localStart);
            final endTime = evt.endsAtUtc == null
                ? null
                : TimeOfDay.fromDateTime(evt.endsAtUtc!.toLocal());
            if ((evt.category ?? '') == 'tombstone') {
              continue;
            }

            if (_isTombstoned(evt.clientEventId)) {
              continue;
            }
            if (_isPendingDelete(
              id: evt.id,
              clientEventId: evt.clientEventId,
              kYear: kDate.kYear,
              kMonth: kDate.kMonth,
              kDay: kDate.kDay,
              title: evt.title,
              allDay: evt.allDay,
              start: startTime,
              end: endTime,
              flowId: noteFlowId,
            )) {
              continue;
            }

            final note = _Note(
              id: evt.id,
              clientEventId: evt.clientEventId,
              calendarId: evt.calendarId,
              calendarName: evt.calendarName,
              title: _cleanTitle(evt.title),
              detail: cleanedDetail,
              location: evt.location,
              allDay: evt.allDay,
              start: startTime,
              end: endTime,
              flowId: noteFlowId,
              manualColor:
                  decoded.color ??
                  reminderFlowColor ??
                  (evt.calendarIsPersonal
                      ? null
                      : (evt.calendarColor != null
                            ? Color(evt.calendarColor!)
                            : null)),
              category: evt.category,
              isReminder: isReminderEvent,
              reminderId: reminderRuleId,
              alertOffsetMinutes: decoded.alertMinutes,
            );

            final key = _kKey(kDate.kYear, kDate.kMonth, kDate.kDay);
            final bucket = newNotes.putIfAbsent(key, () => <_Note>[]);

            bool skip = false;
            int? replaceIndex;
            final incomingKey = _standaloneDedupeKey(note);
            final incomingPriority = _standalonePriority(note.clientEventId);

            for (int i = 0; i < bucket.length; i++) {
              final existing = bucket[i];
              if ((existing.flowId ?? -1) != -1 &&
                  !existing.isReminder &&
                  !note.isReminder) {
                continue; // skip flow-driven non-reminder rows
              }

              if (existing.clientEventId != null &&
                  note.clientEventId != null &&
                  existing.clientEventId == note.clientEventId) {
                skip = true;
                break;
              }

              if (existing.isReminder || note.isReminder) {
                if (existing.isReminder &&
                    note.isReminder &&
                    existing.reminderId == note.reminderId &&
                    existing.start?.hour == note.start?.hour &&
                    existing.start?.minute == note.start?.minute) {
                  skip = true;
                  break;
                }
                continue;
              }

              final existingKey = _standaloneDedupeKey(existing);
              if (existingKey == incomingKey) {
                final existingPriority = _standalonePriority(
                  existing.clientEventId,
                );
                if (incomingPriority > existingPriority) {
                  replaceIndex = i;
                } else {
                  skip = true;
                }
                break;
              }
            }

            if (skip) {
              continue;
            }

            if (replaceIndex != null) {
              bucket[replaceIndex] = note;
            } else {
              bucket.add(note);
              standaloneAddedCount++; // ✅ important: track how many actually added
            }
          } catch (rowErr) {
            _calendarDebugPrint(
              '[_loadFromDisk] ⚠️ standalone row skipped: $rowErr (id=${evt.id} cid=${evt.clientEventId})',
            );
            continue;
          }
        }

        if (kDebugMode) {
          _calendarDebugPrint(
            '[_loadFromDisk] loaded $standaloneAddedCount standalone events after filtering '
            '(${standaloneWindow.startUtc.toIso8601String()} → ${standaloneWindow.endUtc.toIso8601String()})',
          );
        }
        standaloneHydrationComplete = true;
      } catch (err, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[loadFromDisk] failed to load standalone events: $err',
          );
          _calendarDebugPrint('$st');
        }
      }

      commitVisibleCalendarState(
        'complete',
        loadComplete: flowHydrationComplete && standaloneHydrationComplete,
      );

      Future<void> finishEventLanePostProcessing() async {
        try {
          final changed = await _regenReminderNotes(notify: false);
          if (changed && !deferredColdSnapshotReady) {
            _refreshNoteCacheUi();
          }
        } catch (err, st) {
          if (kDebugMode) {
            _calendarDebugPrint('[loadFromDisk] reminder regen failed: $err');
            _calendarDebugPrint('$st');
          }
        }
      }

      if (committedVisibleCalendar) {
        await finishEventLanePostProcessing();
      }
      if (deferredColdSnapshotReady && mounted) {
        _hasPublishedCalendarSnapshot = true;
        _publishedCalendarSnapshotUserId = _activeWarmStartUserId();
        _publishedCalendarSnapshotProjectRef = _activeWarmStartProjectRef();
        _initialCalendarLoadFinished = true;
        _warmStartSnapshotVisible = false;
        _bumpDataVersion();
      }

      Future<void> finishNonCriticalPostProcessing() async {
        try {
          final flowEventCounts = await flowEventCountsFuture;
          if (mounted) {
            setState(() {
              _flowTotalEventCounts
                ..clear()
                ..addAll(flowEventCounts.total);
              _flowRemainingEventCounts
                ..clear()
                ..addAll(flowEventCounts.remaining);
            });
          } else {
            _flowTotalEventCounts
              ..clear()
              ..addAll(flowEventCounts.total);
            _flowRemainingEventCounts
              ..clear()
              ..addAll(flowEventCounts.remaining);
          }
          _scheduleWarmStartCacheSave();
        } catch (err, st) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[loadFromDisk] failed to load flow activity counts: $err',
            );
            _calendarDebugPrint('$st');
          }
        }
      }

      await finishNonCriticalPostProcessing();
    } catch (e, stackTrace) {
      if (kDebugMode) {
        _calendarDebugPrint('Supabase sync FAILED: $e');
        _calendarDebugPrint('Stack: $stackTrace');
      }
    } finally {
      _isLoadingFromDisk = false;
    }

    if (kDebugMode) {
      _calendarDebugPrint('=== _loadFromDisk END ($source) ===');
      if (source.startsWith('shared_calendar_event_tap')) {
        _calendarDebugPrint(
          '[SharedCalendarEventTap] hydration complete source=$source',
        );
      }
    }
  }

  /// Allows other screens (e.g., Settings) to trigger a fresh sync of flows/notes.
  Future<void> reloadFromOutside() =>
      _refreshAfterReturn(reason: 'external_request', force: true);

  static Map<String, dynamic> ruleToJson(FlowRule r) {
    if (r is _RuleWeek) {
      return {
        'type': 'week',
        'weekdays': r.weekdays.toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    if (r is _RuleDecan) {
      return {
        'type': 'decan',
        'months': r.months.toList(),
        'decans': r.decans.toList(),
        'daysInDecan': r.daysInDecan.toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    if (r is _RuleDates) {
      return {
        'type': 'dates',
        'dates': r.dates.map((d) => d.millisecondsSinceEpoch).toList(),
        'allDay': r.allDay,
        if (r.start != null) 'startHour': r.start!.hour,
        if (r.start != null) 'startMinute': r.start!.minute,
        if (r.end != null) 'endHour': r.end!.hour,
        if (r.end != null) 'endMinute': r.end!.minute,
      };
    }
    throw ArgumentError('Unknown rule type');
  }

  List<FlowRule> _parseRules(String rulesJson) {
    if (rulesJson.isEmpty) return [];
    try {
      final parsed = jsonDecode(rulesJson) as List;
      return parsed
          .map((j) => CalendarPage.ruleFromJson(j as Map<String, dynamic>))
          .toList();
    } catch (_) {
      return [];
    }
  }

  List<FlowRule> _parseFlowRowRules(List<dynamic> rules) {
    if (rules.isEmpty) return const [];
    final parsed = <FlowRule>[];
    for (final raw in rules) {
      if (raw is! Map) continue;
      try {
        parsed.add(CalendarPage.ruleFromJson(Map<String, dynamic>.from(raw)));
      } catch (_) {
        // Skip malformed rows from older records without dropping the flow.
      }
    }
    return parsed;
  }

  _Flow _flowFromFiledRow(FlowRow row) {
    return _Flow(
      id: row.id,
      calendarId: row.calendarId,
      name: row.name,
      color: Color(rgbToArgb(row.color)),
      active: row.active,
      isSaved: row.isSaved,
      savedAt: row.savedAt,
      rules: _parseFlowRowRules(row.rules),
      start: row.startDate?.toLocal(),
      end: row.endDate?.toLocal(),
      notes: row.notes,
      shareId: row.shareId,
      isHidden: row.isHidden,
      isReminder: row.isReminder,
      reminderUuid: row.reminderUuid,
    );
  }

  _MyFlowsFilingSnapshot _myFlowsFilingSnapshotFromRows(List<FlowRow> rows) {
    final flows = <_Flow>[];
    final activeIds = <int>{};
    final savedIds = <int>{};
    final totalCounts = <int, int>{};
    final remainingCounts = <int, int>{};

    for (final row in rows) {
      flows.add(_flowFromFiledRow(row));
      if (row.visibleInActiveList) activeIds.add(row.id);
      if (row.visibleInSavedList) savedIds.add(row.id);
      totalCounts[row.id] = row.totalEventCount;
      remainingCounts[row.id] = row.remainingLiveEventCount;
    }

    if (kDebugMode) {
      _calendarDebugPrint(
        '[MyFlowsFiling] rows=${rows.length} active=${activeIds.length} saved=${savedIds.length}',
      );
    }

    return _MyFlowsFilingSnapshot(
      flows: List<_Flow>.unmodifiable(flows),
      activeFlowIds: Set<int>.unmodifiable(activeIds),
      savedFlowIds: Set<int>.unmodifiable(savedIds),
      totalEventCounts: Map<int, int>.unmodifiable(totalCounts),
      remainingEventCounts: Map<int, int>.unmodifiable(remainingCounts),
    );
  }

  _MyFlowsFilingSnapshot? _cachedMyFlowsFilingSnapshot() {
    final cached = _myFlowsFilingSnapshotCache;
    if (cached != null) return cached;
    final cachedRows = _flowsRepo.cachedMyFiledFlowsSync();
    if (cachedRows == null) return null;
    final snapshot = _myFlowsFilingSnapshotFromRows(cachedRows);
    _myFlowsFilingSnapshotCache = snapshot;
    return snapshot;
  }

  Future<void> _restoreMyFlowsFilingSnapshotCache({
    String reason = 'restore',
  }) async {
    if (_myFlowsFilingSnapshotCache != null) return;
    final rows = await _flowsRepo.restoreCachedFiledFlows();
    if (rows == null || !mounted) return;
    _myFlowsFilingSnapshotCache = _myFlowsFilingSnapshotFromRows(rows);
    if (kDebugMode) {
      _calendarDebugPrint(
        '[MyFlowsFiling] restored cache reason=$reason rows=${rows.length}',
      );
    }
  }

  Future<_MyFlowsFilingSnapshot> _loadMyFlowsFilingSnapshot() async {
    final inFlight = _myFlowsFilingSnapshotLoadInFlight;
    if (inFlight != null) return inFlight;

    final load = () async {
      final rows = await _flowsRepo.refreshMyFiledFlows();
      final snapshot = _myFlowsFilingSnapshotFromRows(rows);
      _myFlowsFilingSnapshotCache = snapshot;
      CalendarPage._reconcileRememberedMaatJoinsFromLiveSnapshot(snapshot);
      return snapshot;
    }();
    _myFlowsFilingSnapshotLoadInFlight = load;
    try {
      return await load;
    } finally {
      if (identical(_myFlowsFilingSnapshotLoadInFlight, load)) {
        _myFlowsFilingSnapshotLoadInFlight = null;
      }
    }
  }

  void _primeMyFlowsFilingSnapshotCache({String reason = 'prime'}) {
    if (_myFlowsFilingSnapshotLoadInFlight != null) return;
    unawaited(() async {
      try {
        await _restoreMyFlowsFilingSnapshotCache(reason: reason);
        await _loadMyFlowsFilingSnapshot();
      } catch (e, st) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[MyFlowsFiling] prime failed reason=$reason error=$e',
          );
          _calendarDebugPrint('$st');
        }
      }
    }());
  }

  Future<int?> _findFlowIdByReminderUuid(String reminderUuid) async {
    final dbUuid = _dbReminderUuidFromRuleId(reminderUuid);
    if (dbUuid == null) return null;
    try {
      final repo = FlowsRepo(Supabase.instance.client);
      return await repo.getFlowIdByReminderUuid(dbUuid);
    } catch (_) {
      return null;
    }
  }

  bool _rulesEqual(List<dynamic> oldRulesJson, List<FlowRule> newRules) {
    if (oldRulesJson.length != newRules.length) return false;
    List<Map<String, dynamic>> normalize(List<Map<String, dynamic>> list) {
      list.sort(
        (a, b) =>
            (a['type'] as String? ?? '').compareTo(b['type'] as String? ?? ''),
      );
      return list;
    }

    final oldNormalized = normalize(
      oldRulesJson.map((r) => Map<String, dynamic>.from(r as Map)).toList(),
    );
    final newNormalized = normalize(
      newRules
          .map(ruleToJson)
          .map((r) => Map<String, dynamic>.from(r))
          .toList(),
    );
    return jsonEncode(oldNormalized) == jsonEncode(newNormalized);
  }

  bool _isColorOnlyChange(FlowRow oldFlow, _Flow newFlow) {
    if (oldFlow.name != newFlow.name) return false;
    if (oldFlow.notes != newFlow.notes) return false;
    if (oldFlow.startDate != newFlow.start) return false;
    if (oldFlow.endDate != newFlow.end) return false;
    if (!_rulesEqual(oldFlow.rules, newFlow.rules)) return false;
    return oldFlow.color != newFlow.color.toARGB32();
  }

  Future<NotificationScheduleResult?> _scheduleAlertForEvent({
    required _Note note,
    required int ky,
    required int km,
    required int kd,
    required String clientEventId,
    String? eventId,
  }) async {
    if (note.alertOffsetMinutes == _alertNoneMinutes) {
      try {
        await Notify.cancelNotificationForEvent(clientEventId);
      } catch (_) {
        // Ignore cancellation failures; nothing else to do.
      }
      return null;
    }

    final alertAtLocal = _alertDateTimeLocal(
      note: note,
      kYear: ky,
      kMonth: km,
      kDay: kd,
    );
    final effectiveMinutes = _effectiveAlertMinutes(note.alertOffsetMinutes);
    if (alertAtLocal == null || effectiveMinutes == null) return null;

    final cleanedDetail = _cleanDetail(note.detail);
    final bodyLines = <String>[
      if ((note.location ?? '').trim().isNotEmpty) note.location!.trim(),
      if (cleanedDetail.isNotEmpty) cleanedDetail,
    ];
    final body = bodyLines.isEmpty ? null : bodyLines.join('\n');
    final itemType = note.isReminder
        ? calendarPushItemTypeReminder
        : ((note.flowId != null && note.flowId! > 0)
              ? calendarPushItemTypeFlowEvent
              : calendarPushItemTypeNote);

    final result = await Notify.scheduleAlertWithPersistenceResult(
      clientEventId: clientEventId,
      scheduledAt: alertAtLocal,
      title: note.title,
      body: body,
      payload: CalendarPage._calendarNotificationPayloadJson(
        itemType: itemType,
        kYear: ky,
        kMonth: km,
        kDay: kd,
        eventId: eventId ?? note.id,
        clientEventId: clientEventId,
        reminderId: note.reminderId,
        flowId: note.flowId,
      ),
    );

    final reminderId = _reminderIdForNote(note, alertAtLocal.toUtc());
    await _reminderService.addOrUpdate(
      Reminder(
        id: reminderId,
        eventId: eventId,
        title: note.title,
        detail: cleanedDetail.isEmpty ? null : cleanedDetail,
        alertAtUtc: alertAtLocal.toUtc(),
        flowId: note.flowId?.toString(),
        createdAt: DateTime.now().toUtc(),
        updatedAt: DateTime.now().toUtc(),
      ),
    );
    return result;
  }

  void _showNotificationScheduleWarning(String? message) {
    final text = message?.trim();
    if (!mounted || text == null || text.isEmpty) return;
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(content: Text(text), backgroundColor: Colors.orange.shade800),
    );
  }

  // Persist flows + planned notes coming back from Flow Studio
  // AFTER
  Future<int?> _persistFlowStudioResult(_FlowStudioResult r) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    final isNewFlowSave = r.savedFlow != null && r.savedFlow!.id <= 0;

    // 1) Deletes take precedence
    final deleteId = r.deleteFlowId;
    if (deleteId != null) {
      if (kDebugMode) {
        _calendarDebugPrint('[persistFlowStudio] Deleting flowId=$deleteId');
      }
      // 🔧 KEY FIX: Delete ALL notes for this flow (not just future ones)
      try {
        await repo.deleteByFlowId(deleteId);
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ✓ Deleted ALL notes for flow',
          );
        }
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ⚠️ Failed to delete notes: $e',
          );
        }
        rethrow; // bubble up so we don't silently keep the flow
      }
      try {
        await repo.deleteFlow(deleteId);
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ✓ Deleted flow from database',
          );
        }
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ⚠️ Failed to delete flow: $e',
          );
        }
        rethrow; // bubble up and avoid thinking it was removed
      }
      // Remove the flow from memory
      _flows.removeWhere((f) => f.id == deleteId);
      setState(() {});
      _notifyDayViewDataChanged();
      if (kDebugMode) {
        _calendarDebugPrint('[persistFlowStudio] ✓ Flow deletion complete');
      }
      return deleteId;
    }

    // 2) Save/create flow if provided
    _Flow? saved;
    FlowRow? oldFlowRow;
    if (r.savedFlow != null) {
      // Capture previous state for change detection (best-effort)
      if (r.savedFlow!.id > 0) {
        try {
          oldFlowRow = await _flowsRepo.getFlowById(r.savedFlow!.id);
        } catch (_) {
          oldFlowRow = null;
        }
      }

      // ✅ For imported flows (with plannedNotes), clear rules to prevent rule-based rescheduling
      // The rules are already cleared in _save() when widget.importData != null,
      // but we also check here as a safety measure
      final bool hasSnapshotEvents = r.plannedNotes.isNotEmpty;
      final bool isAiLocal = r.savedFlow?.shareId == 'ai-local';
      final rulesJson = (hasSnapshotEvents && !isAiLocal)
          ? jsonEncode([])
          : jsonEncode(r.savedFlow!.rules.map(ruleToJson).toList());

      final savedId = await repo.upsertFlow(
        id: r.savedFlow!.id > 0 ? r.savedFlow!.id : null,
        name: r.savedFlow!.name,
        color: r.savedFlow!.color.toARGB32(),
        active: r.savedFlow!.active,
        calendarId: r.savedFlow!.calendarId,
        startDate: r.savedFlow!.start,
        endDate: r.savedFlow!.end,
        notes: r.savedFlow!.notes,
        rules: rulesJson,
        isHidden: r.savedFlow!.isHidden,
        isSaved: r.savedFlow!.isSaved,
        originType: r.originType,
        originFlowId: r.originFlowId,
        originShareId: r.originShareId ?? r.savedFlow!.shareId,
        originGenerationId: r.originGenerationId,
        rootFlowId: r.rootFlowId,
        aiMetadata: r.aiMetadata,
      );

      saved = _Flow(
        id: savedId,
        calendarId: r.savedFlow!.calendarId,
        name: r.savedFlow!.name,
        color: r.savedFlow!.color,
        active: r.savedFlow!.active,
        isSaved: r.savedFlow!.isSaved,
        savedAt: r.savedFlow!.savedAt,
        rules: r.savedFlow!.rules,
        start: r.savedFlow!.start,
        end: r.savedFlow!.end,
        notes: r.savedFlow!.notes,
        shareId: r.savedFlow!.shareId,
        isHidden: r.savedFlow!.isHidden, // Preserve hidden status
      );

      final idx = _flows.indexWhere((f) => f.id == savedId);
      if (idx >= 0) {
        _flows[idx] = saved;
      } else {
        _flows.add(saved);
        if (savedId >= _nextFlowId) _nextFlowId = savedId + 1;
      }

      // Add verification logging
      if (kDebugMode) {
        _calendarDebugPrint(
          '[persistFlowStudio] Saved flow $savedId "${saved.name}" with color=${saved.color.toARGB32().toRadixString(16)} to database',
        );
      }
    }

    // 3) Apply planned notes locally
    final flowId = saved?.id ?? r.savedFlow?.id ?? -1;
    final flowCalendarId = saved?.calendarId ?? r.savedFlow?.calendarId;
    final flowCalendarName = _calendarSummary(flowCalendarId)?.name;
    final aiGenerated = oldFlowRow?.aiMetadata == null
        ? null
        : oldFlowRow!.aiMetadata?['generated'];
    final isAIFlow = aiGenerated is bool && aiGenerated;
    String? firstClientEventId;
    String? notificationWarning;
    bool flowAdditionNotified = false;
    bool generationCommitted = false;

    Future<void> commitGenerationIfNeeded() async {
      if (generationCommitted ||
          r.originGenerationId == null ||
          saved == null) {
        return;
      }
      generationCommitted = true;
      try {
        await repo.flowCommit(
          generationId: r.originGenerationId!,
          flowId: saved.id,
        );
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] flow_commit failed for generation ${r.originGenerationId}: $e',
          );
        }
      }
    }

    Future<void> rollbackNewFlowSave(
      Object error,
      StackTrace stackTrace,
    ) async {
      if (!isNewFlowSave || saved == null) return;
      final savedFlow = saved;
      if (kDebugMode) {
        _calendarDebugPrint(
          '[persistFlowStudio] Rolling back new flow ${savedFlow.id} after planned-note save failed: $error',
        );
        _calendarDebugPrint('$stackTrace');
      }
      try {
        await repo.deleteByFlowId(
          savedFlow.id,
          semantic: 'flow_save_rollback',
          suppressesClient: false,
          sourceFeature: 'CalendarPage._persistFlowStudioResult',
          deleteScope: 'failed_new_flow_save',
        );
      } catch (rollbackError) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] rollback deleteByFlowId failed: $rollbackError',
          );
        }
      }
      try {
        await repo.deleteFlow(savedFlow.id);
      } catch (rollbackError) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] rollback deleteFlow failed: $rollbackError',
          );
        }
      }
      _removeLocalNotesForFlowReplacement(savedFlow.id);
      _flows.removeWhere((flow) => flow.id == savedFlow.id);
      if (mounted) setState(() {});
      _notifyDayViewDataChanged();
    }

    Future<void> notifyFlowAdditionIfNeeded() async {
      if (flowAdditionNotified || !isNewFlowSave || saved == null) return;
      flowAdditionNotified = true;
      await _notifySharedCalendarItemAdded(
        calendarId: saved.calendarId,
        itemType: 'flow',
        itemId: saved.id.toString(),
        itemTitle: saved.name,
        clientEventId: firstClientEventId,
        flowId: saved.id,
        startDate: saved.start,
        endDate: saved.end,
      );
    }

    Future<void> ensureSharedExperienceIfNeeded() async {
      final savedFlow = saved;
      if (savedFlow == null) return;
      await _ensureSharedExperienceForFlow(
        flowId: savedFlow.id,
        calendarId: savedFlow.calendarId,
        source: 'CalendarPage._persistFlowStudioResult',
      );
    }

    if (r.plannedNotes.isNotEmpty) {
      final repo2 = UserEventsRepo(Supabase.instance.client);

      // Concrete planned-note edits replace the occurrence set. The CIDs include
      // event time, so stale rows must be retired before new times are written.
      if (flowId > 0) {
        try {
          await repo2.deleteByFlowId(
            flowId,
            semantic: 'flow_replace',
            suppressesClient: false,
            sourceFeature: 'CalendarPage._persistFlowStudioResult',
            deleteScope: isAIFlow ? 'ai_flow_replace' : 'planned_flow_replace',
          );
          final removedLocal = _removeLocalNotesForFlowReplacement(flowId);
          if (kDebugMode) {
            _calendarDebugPrint(
              '[persistFlowStudio] Cleared existing events for planned-note flow $flowId before replacement (localRemoved=$removedLocal)',
            );
          }
        } catch (e) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[persistFlowStudio] Failed to clear events for AI flow $flowId: $e',
            );
          }
        }
      }

      try {
        for (final p in r.plannedNotes) {
          final n = p.note;
          final noteFlowId = n.flowId ?? flowId;

          // Add to in-memory notes
          _addNote(
            p.ky,
            p.km,
            p.kd,
            n.title,
            n.detail,
            calendarId: flowCalendarId,
            calendarName: flowCalendarName,
            location: n.location,
            allDay: n.allDay,
            start: n.start,
            end: n.end,
            flowId: noteFlowId >= 0 ? noteFlowId : null,
            category: n.category,
            alertOffsetMinutes: n.alertOffsetMinutes,
          );

          // Persist to database
          final cid = EventCidUtil.buildClientEventId(
            ky: p.ky,
            km: p.km,
            kd: p.kd,
            title: n.title,
            startHour: n.start?.hour ?? 9,
            startMinute: n.start?.minute ?? 0,
            allDay: n.allDay,
            flowId: noteFlowId,
          );

          final gDay = KemeticMath.toGregorian(p.ky, p.km, p.kd);
          final startsAt = DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            n.start?.hour ?? 9,
            n.start?.minute ?? 0,
          );

          DateTime? endsAt;
          if (!n.allDay && n.end != null) {
            endsAt = DateTime(
              gDay.year,
              gDay.month,
              gDay.day,
              n.end!.hour,
              n.end!.minute,
            );
          } else if (!n.allDay) {
            endsAt = startsAt.add(const Duration(hours: 1));
          }

          final trimmedDetail = (n.detail ?? '').trim();
          final baseDetail = trimmedDetail.isEmpty ? null : trimmedDetail;
          final detailWithMeta = _encodeDetailWithMeta(
            baseDetail,
            alertMinutes: n.alertOffsetMinutes,
          );
          final detailToSave = detailWithMeta ?? baseDetail;

          final savedEvent = await repo2.upsertByClientId(
            clientEventId: cid,
            title: n.title,
            startsAtUtc: startsAt.toUtc(),
            detail: detailToSave,
            location: (n.location ?? '').trim().isEmpty ? null : n.location,
            allDay: n.allDay,
            endsAtUtc: endsAt?.toUtc(),
            calendarId: flowCalendarId,
            flowLocalId: noteFlowId >= 0 ? noteFlowId : null,
            category: n.category,
            actionId: n.actionId,
            behaviorPayload: n.behaviorPayload,
            caller: 'persist_flow_studio',
          );
          firstClientEventId ??= savedEvent.clientEventId ?? cid;

          final scheduleResult = await _scheduleAlertForEvent(
            note: n.copyWith(
              calendarId: flowCalendarId,
              calendarName: flowCalendarName,
            ),
            ky: p.ky,
            km: p.km,
            kd: p.kd,
            clientEventId: savedEvent.clientEventId ?? cid,
            eventId: savedEvent.id,
          );
          if (scheduleResult?.needsUserVisibleWarning == true) {
            notificationWarning ??= scheduleResult?.message;
          }
        }
      } catch (error, stackTrace) {
        await rollbackNewFlowSave(error, stackTrace);
        rethrow;
      }
    }

    // Use shared scheduler for flow notes if we have a saved flow
    if (saved != null && saved.active && saved.rules.isNotEmpty) {
      // If we have planned notes, skip rule-based scheduling to preserve titles/times.
      if (r.plannedNotes.isNotEmpty) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ✅ Skipping scheduleFlowNotes - using plannedNotes with individual titles',
          );
        }
        await commitGenerationIfNeeded();
        await ensureSharedExperienceIfNeeded();
        await notifyFlowAdditionIfNeeded();
        setState(() {});
        _notifyDayViewDataChanged();
        _showNotificationScheduleWarning(notificationWarning);
        return saved.id;
      }
      // If rules list was cleared (e.g., snapshot-only imports), skip scheduling.
      if (saved.rules.isEmpty) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ✅ Skipping scheduleFlowNotes - flow has no rules (snapshot-only)',
          );
        }
        await commitGenerationIfNeeded();
        setState(() {});
        _notifyDayViewDataChanged();
        return saved.id;
      }
      try {
        // Check if this is an AI-generated flow before scheduling
        // (AI flows already have individually-titled events that shouldn't be regenerated)
        final flowRow = await _flowsRepo.getFlowById(saved.id);

        // Defensive type checking for ai_metadata.generated field
        final aiGenerated = flowRow?.aiMetadata?['generated'];
        final isAIFlow = aiGenerated is bool && aiGenerated == true;

        if (isAIFlow) {
          if (kDebugMode) {
            _calendarDebugPrint(
              '[persistFlowStudio] ✅ Skipping scheduleFlowNotes for AI-generated flow ${saved.id} (preserving individual note titles)',
            );
          }

          // TODO: Add analytics once analytics service is integrated
          // Example: _analyticsService.logEvent('ai_flow_schedule_skipped', {'flowId': saved.id});
        } else {
          // Imported flow with only color change? Skip reschedule.
          if (saved.shareId != null &&
              oldFlowRow != null &&
              _isColorOnlyChange(oldFlowRow, saved)) {
            if (kDebugMode) {
              _calendarDebugPrint(
                '[persistFlowStudio] ⚠️ Skipping reschedule for color-only change on imported flow ${saved.id}',
              );
            }
          } else {
            // Only regenerate notes for manually-created flows with recurring rules
            await scheduleFlowNotes(
              flowId: saved.id,
              rules: saved.rules,
              flowNotes: saved.notes,
              startDate: saved.start,
              endDate: saved.end,
            );

            if (kDebugMode) {
              _calendarDebugPrint(
                '[persistFlowStudio] ✅ Scheduled recurring notes for flow ${saved.id}',
              );
            }
            if (firstClientEventId == null) {
              try {
                final events = await repo.getEventsForFlow(saved.id);
                if (events.isNotEmpty) {
                  firstClientEventId = events.first.clientEventId;
                }
              } catch (_) {}
            }
          }

          // TODO: Add analytics once analytics service is integrated
          // Example: _analyticsService.logEvent('flow_notes_scheduled', {
          //   'flowId': saved.id,
          //   'ruleCount': saved.rules.length,
          //   'dateRange': '${saved.start} to ${saved.end}',
          // });
        }
      } catch (e, stackTrace) {
        // Log error but don't crash - flow is already saved
        if (kDebugMode) {
          _calendarDebugPrint(
            '[persistFlowStudio] ⚠️ Failed to check/schedule flow notes: $e',
          );
          _calendarDebugPrint('Stack trace: $stackTrace');
        }

        // TODO: Add error tracking once analytics service is integrated
        // Example: _analyticsService.logError('flow_schedule_error', e, stackTrace);
      }
    }

    if (saved != null) {
      await commitGenerationIfNeeded();
      await ensureSharedExperienceIfNeeded();
    }

    if (saved != null && isNewFlowSave) {
      await notifyFlowAdditionIfNeeded();
    } else if (saved != null) {
      await _notifySharedCalendarMembers(
        calendarId: saved.calendarId,
        title: _calendarDisplayName(saved.calendarId),
        body: 'Flow updated: ${saved.name}',
        clientEventId: firstClientEventId,
        data: <String, dynamic>{'flow_id': saved.id},
      );
    }

    setState(() {});
    _notifyDayViewDataChanged();
    _showNotificationScheduleWarning(notificationWarning);
    return saved?.id;
  }

  /// Schedules all note occurrences for a flow to the calendar
  /// This is the shared logic used by both Flow Studio and Inbox imports
  // Save a single (non-repeating) note only
  Future<({String clientEventId, String eventId})> _saveSingleNoteOnly({
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    String? calendarId,
    String? calendarName,
    required bool allDay,
    TimeOfDay? startTime,
    TimeOfDay? endTime,
    Color? color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
    bool notifyShared = true,
  }) async {
    // Compute event start + alert time
    final gDay = KemeticMath.toGregorian(selYear, selMonth, selDay);
    final startLocal = allDay
        ? DateTime(gDay.year, gDay.month, gDay.day, 9, 0) // default 9:00 AM
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            startTime!.hour,
            startTime.minute,
          );
    final note = _Note(
      calendarId: calendarId,
      calendarName: calendarName,
      title: title,
      detail: detail,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      flowId: -1,
      manualColor: color,
      category: category,
      alertOffsetMinutes: alertMinutesBefore,
    );

    // Build canonical clientEventId for this manual note
    final String unifiedCid = _buildCid(
      ky: selYear,
      km: selMonth,
      kd: selDay,
      title: title,
      startHour: (allDay || startTime == null) ? null : startTime.hour,
      startMinute: (allDay || startTime == null) ? null : startTime.minute,
      allDay: allDay,
      flowId: -1,
      calendarScopeToken: _calendarScopeToken(calendarId),
    );

    await _ensureManualDeleteTombstonesLoaded();
    await _clearManualTombstone(unifiedCid);

    final encodedDetail = _encodeDetailWithMeta(
      detail,
      color: color,
      alertMinutes: alertMinutesBefore,
    );

    // Sync to Supabase and persist id/clientEventId
    final repo = UserEventsRepo(Supabase.instance.client);
    try {
      final endsAtUtc = (allDay || endTime == null)
          ? null
          : DateTime(
              gDay.year,
              gDay.month,
              gDay.day,
              endTime.hour,
              endTime.minute,
            ).toUtc();

      final updated = await repo.upsertByClientId(
        clientEventId: unifiedCid,
        title: title,
        startsAtUtc: startLocal.toUtc(),
        detail: encodedDetail,
        location: location,
        allDay: allDay,
        endsAtUtc: endsAtUtc,
        category: category,
        calendarId: calendarId,
        caller: 'save_single',
      );

      if (updated.id.isEmpty) {
        throw StateError('Supabase upsert returned empty id for $unifiedCid');
      }

      final savedClientEventId = updated.clientEventId ?? unifiedCid;

      _addNote(
        selYear,
        selMonth,
        selDay,
        title,
        detail,
        id: updated.id,
        clientEventId: savedClientEventId,
        calendarId: calendarId,
        calendarName: calendarName,
        location: location,
        allDay: allDay,
        start: startTime,
        end: endTime,
        manualColor: color,
        category: category,
        alertOffsetMinutes: alertMinutesBefore,
      );

      final scheduleResult = await _scheduleAlertForEvent(
        note: note.copyWith(
          id: updated.id,
          clientEventId: updated.clientEventId,
          calendarId: calendarId,
          calendarName: calendarName,
        ),
        ky: selYear,
        km: selMonth,
        kd: selDay,
        clientEventId: updated.clientEventId ?? unifiedCid,
        eventId: updated.id,
      );
      if (scheduleResult?.needsUserVisibleWarning == true) {
        _showNotificationScheduleWarning(scheduleResult?.message);
      }

      if (notifyShared) {
        await _notifySharedCalendarItemAdded(
          calendarId: updated.calendarId ?? calendarId,
          itemType: 'event',
          itemId: updated.id,
          itemTitle: title,
          clientEventId: savedClientEventId,
          eventId: updated.id,
          startDate: gDay,
          endDate: endsAtUtc?.toLocal(),
          kYear: selYear,
          kMonth: selMonth,
          kDay: selDay,
        );
      }

      // Also log to app_events for analytics
      try {
        await repo.track(
          event: 'note_created',
          properties: {
            'title': title,
            if (detail != null && detail.isNotEmpty) 'body': detail,
            if (location != null && location.isNotEmpty) 'location': location,
            'all_day': allDay,
          },
          source: 'client',
        );
      } catch (e) {
        if (kDebugMode) {
          _calendarDebugPrint('[SaveSingleNote] failed to log app_events: $e');
        }
      }
      return (clientEventId: savedClientEventId, eventId: updated.id);
    } catch (e, st) {
      try {
        await Notify.cancelNotificationForEvent(unifiedCid);
      } catch (cancelErr) {
        _calendarDebugPrint(
          '[SaveSingleNote] failed to cancel notification for $unifiedCid after error: $cancelErr',
        );
      }
      _calendarDebugPrint(
        '[SaveSingleNote] failed to save standalone note (cid=$unifiedCid): $e',
      );
      if (kDebugMode) {
        _calendarDebugPrint('$st');
      }
      rethrow;
    }
  }

  Future<({String clientEventId, String eventId})> _updateSingleNoteOnly({
    required String existingEventId,
    required String? previousClientEventId,
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    String? calendarId,
    String? calendarName,
    required bool allDay,
    TimeOfDay? startTime,
    TimeOfDay? endTime,
    Color? color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    final gDay = KemeticMath.toGregorian(selYear, selMonth, selDay);
    final startLocal = allDay
        ? DateTime(gDay.year, gDay.month, gDay.day, 9, 0)
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            startTime!.hour,
            startTime.minute,
          );
    final note = _Note(
      id: existingEventId,
      clientEventId: previousClientEventId,
      calendarId: calendarId,
      calendarName: calendarName,
      title: title,
      detail: detail,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      flowId: -1,
      manualColor: color,
      category: category,
      alertOffsetMinutes: alertMinutesBefore,
    );
    final bodyLines = <String>[
      if (location != null && location.isNotEmpty) location,
      if (detail != null && detail.isNotEmpty) detail,
    ];

    final unifiedCid = _buildCid(
      ky: selYear,
      km: selMonth,
      kd: selDay,
      title: title,
      startHour: (allDay || startTime == null) ? null : startTime.hour,
      startMinute: (allDay || startTime == null) ? null : startTime.minute,
      allDay: allDay,
      flowId: -1,
      calendarScopeToken: _calendarScopeToken(calendarId),
    );

    await _ensureManualDeleteTombstonesLoaded();
    await _clearManualTombstone(unifiedCid);

    final encodedDetail = _encodeDetailWithMeta(
      detail,
      color: color,
      alertMinutes: alertMinutesBefore,
    );

    final repo = UserEventsRepo(Supabase.instance.client);
    final importedDeviceEvent = isImportedDeviceCalendarEvent(
      clientEventId: previousClientEventId,
      category: category,
    );
    final effectiveCategory = _editableStandaloneCategory(
      detachImportedDeviceEvent: importedDeviceEvent,
      category: category,
    );
    final endsAtUtc = (allDay || endTime == null)
        ? null
        : DateTime(
            gDay.year,
            gDay.month,
            gDay.day,
            endTime.hour,
            endTime.minute,
          ).toUtc();

    final updated = await repo.replace(
      id: existingEventId,
      clientEventId: unifiedCid,
      calendarId: calendarId,
      title: title,
      detail: encodedDetail,
      location: location,
      allDay: allDay,
      startsAt: startLocal,
      endsAt: endsAtUtc,
      category: effectiveCategory,
    );

    final savedClientEventId = updated.clientEventId ?? unifiedCid;
    if (previousClientEventId != null &&
        previousClientEventId != savedClientEventId) {
      try {
        await Notify.cancelNotificationForEvent(previousClientEventId);
      } catch (_) {}
    }
    if (importedDeviceEvent) {
      await _suppressImportedDeviceEventSource(previousClientEventId);
    }

    _addNote(
      selYear,
      selMonth,
      selDay,
      title,
      detail,
      id: updated.id,
      clientEventId: savedClientEventId,
      calendarId: calendarId,
      calendarName: calendarName,
      location: location,
      allDay: allDay,
      start: startTime,
      end: endTime,
      manualColor: color,
      category: effectiveCategory,
      alertOffsetMinutes: alertMinutesBefore,
    );

    final scheduleResult = await _scheduleAlertForEvent(
      note: note.copyWith(id: updated.id, clientEventId: savedClientEventId),
      ky: selYear,
      km: selMonth,
      kd: selDay,
      clientEventId: savedClientEventId,
      eventId: updated.id,
    );
    if (scheduleResult?.needsUserVisibleWarning == true) {
      _showNotificationScheduleWarning(scheduleResult?.message);
    }

    await _notifySharedCalendarMembers(
      calendarId: calendarId,
      title: _calendarDisplayName(calendarId),
      body: 'Updated event: $title',
      clientEventId: savedClientEventId,
      data: <String, dynamic>{
        'event_id': updated.id,
        if (bodyLines.isNotEmpty) 'preview': bodyLines.join('\n'),
      },
    );

    return (clientEventId: savedClientEventId, eventId: updated.id);
  }

  // Save a repeating note as a hidden micro-flow
  Future<void> _saveRepeatingNoteAsHiddenFlow({
    required int selYear,
    required int selMonth,
    required int selDay,
    required String title,
    String? detail,
    String? location,
    String? calendarId,
    String? calendarName,
    required bool allDay,
    required TimeOfDay? startTime,
    required TimeOfDay? endTime,
    required NoteRepeatOption repeatOption,
    required SimpleRecurrenceFrequency customFrequency,
    required int customInterval,
    required NoteRepeatEndType endType,
    required DateTime? endDate,
    required int endCount,
    required Color color,
    String? category,
    int alertMinutesBefore = _alertNoneMinutes,
  }) async {
    // 1. First occurrence = selected Kemetic day -> Gregorian
    final DateTime firstOccurrence = KemeticMath.toGregorian(
      selYear,
      selMonth,
      selDay,
    );

    // 2. Determine horizon for recurrence generation and flow.end.
    late final DateTime horizonEnd;
    if (endType == NoteRepeatEndType.onDate && endDate != null) {
      horizonEnd = DateUtils.dateOnly(endDate);
    } else if (endType == NoteRepeatEndType.afterCount) {
      // Rough upper bound: assume worst-case yearly interval * count.
      horizonEnd = firstOccurrence.add(Duration(days: 365 * endCount));
    } else {
      // Never ends: use a sane horizon (e.g. 1 year out).
      horizonEnd = firstOccurrence.add(const Duration(days: 365));
    }

    // 3. Generate `_RuleDates` with Kemetic-aware recurrence logic.
    final _RuleDates rule = _buildNoteRuleDates(
      firstOccurrenceDate: firstOccurrence,
      repeatOption: repeatOption,
      customFrequency: customFrequency,
      customInterval: customInterval,
      endType: endType,
      endDate: endDate,
      endCount: endCount,
      allDay: allDay,
      startTime: startTime,
      endTime: endTime,
      horizonEnd: horizonEnd,
    );

    // 4. Guard: if we somehow got no dates, fall back to single note.
    if (rule.dates.isEmpty) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[RepeatNote] Empty date set for repeating note "$title"; falling back to single note.',
        );
      }
      await _saveSingleNoteOnly(
        selYear: selYear,
        selMonth: selMonth,
        selDay: selDay,
        title: title,
        detail: detail,
        location: location,
        calendarId: calendarId,
        calendarName: calendarName,
        allDay: allDay,
        startTime: startTime,
        endTime: endTime,
        color: color,
        category: category,
        alertMinutesBefore: alertMinutesBefore,
      );
      return;
    }

    // 5. Create a hidden flow object in memory (micro-flow just for this note pattern).
    final flow = _Flow(
      id: -1, // Will be replaced by DB id
      calendarId: calendarId,
      name: title,
      color: color, // Use selected color
      active: true,
      rules: [rule],
      start: firstOccurrence,
      end: horizonEnd,
      notes: _encodeRepeatingNoteMetadata(
        detail: detail,
        location: location,
        category: category,
        alertMinutes: alertMinutesBefore,
        keepMarker: true,
      ),
      shareId: null,
      isHidden: true, // Critical: these never show in Flow Studio lists
    );

    final repo = UserEventsRepo(Supabase.instance.client);

    // 6. Persist the flow row to Supabase, storing rules as JSON.
    final rulesJson = jsonEncode([CalendarPageState.ruleToJson(rule)]);

    final int flowId = await repo.upsertFlow(
      id: null,
      name: flow.name,
      color: flow.color.toARGB32(),
      active: flow.active,
      calendarId: flow.calendarId,
      startDate: flow.start,
      endDate: flow.end,
      notes: flow.notes,
      rules: rulesJson,
      isHidden: flow.isHidden,
    );

    // 7. Insert into in-memory _flows list with correct ID.
    final savedFlow = _Flow(
      id: flowId,
      calendarId: flow.calendarId,
      name: flow.name,
      color: flow.color,
      active: flow.active,
      rules: flow.rules,
      start: flow.start,
      end: flow.end,
      notes: flow.notes,
      shareId: flow.shareId,
      isHidden: flow.isHidden,
    );

    _flows.add(savedFlow);
    if (flowId >= _nextFlowId) {
      _nextFlowId = flowId + 1;
    }

    // 8. Trigger materialization of events into user_events via the shared engine.
    await _triggerFlowSchedule(flowId);

    String? firstClientEventId;
    String? firstEventId;
    try {
      final events = await repo.getEventsForFlow(flowId);
      if (events.isNotEmpty) {
        firstClientEventId = events.first.clientEventId;
        firstEventId = events.first.id;
      }
    } catch (_) {}

    if (firstEventId != null) {
      await _notifySharedCalendarItemAdded(
        calendarId: flow.calendarId,
        itemType: 'note',
        itemId: firstEventId,
        itemTitle: title,
        clientEventId: firstClientEventId,
        flowId: flowId,
        noteId: firstEventId,
        startDate: firstOccurrence,
      );
    } else {
      await _notifySharedCalendarItemAdded(
        calendarId: flow.calendarId,
        itemType: 'flow',
        itemId: flowId.toString(),
        itemTitle: title,
        flowId: flowId,
        startDate: firstOccurrence,
      );
    }

    // 9. Refresh local caches so the new repeating note series shows up immediately.
    unawaited(_loadFromDisk(source: 'repeat_note_save'));
  }

  /// Trigger function: central place to (re)schedule events for a flow.
  ///
  /// This is the only method that should call `scheduleFlowNotes` directly.
  /// It is used by:
  ///  - Flow Studio saves/updates
  ///  - Repeating notes (hidden micro-flows)
  Future<void> _triggerFlowSchedule(int flowId) async {
    _Flow flow;

    try {
      flow = _flows.firstWhere((f) => f.id == flowId);
    } catch (_) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[triggerFlowSchedule] Flow $flowId not found in _flows; skipping schedule.',
        );
      }
      return;
    }

    // If flow is inactive or has no rules, just clear its events.
    if (!flow.active || flow.rules.isEmpty) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[triggerFlowSchedule] Flow $flowId inactive or has no rules; deleting events.',
        );
      }
      final repo = UserEventsRepo(Supabase.instance.client);
      await repo.deleteByFlowId(flowId);
      return;
    }

    if (kDebugMode) {
      _calendarDebugPrint(
        '[triggerFlowSchedule] Scheduling flow $flowId with ${flow.rules.length} rules',
      );
    }

    await scheduleFlowNotes(
      flowId: flow.id,
      rules: flow.rules,
      flowNotes: flow.notes,
      startDate: flow.start,
      endDate: flow.end,
    );
  }

  Future<void> scheduleFlowNotes({
    required int flowId,
    required List<FlowRule> rules,
    required String? flowNotes,
    DateTime? startDate,
    DateTime? endDate,
  }) async {
    final repo = UserEventsRepo(Supabase.instance.client);
    final scheduleStart = startDate ?? DateTime.now();
    final scheduleEnd =
        endDate ??
        scheduleStart.add(const Duration(days: 90)); // Default 90 days

    if (kDebugMode) {
      _calendarDebugPrint(
        '[scheduleFlowNotes] Starting for flowId=$flowId from $scheduleStart to $scheduleEnd',
      );
    }

    // Look up flow object for name and metadata
    _Flow? flow;
    try {
      flow = _flows.firstWhere((f) => f.id == flowId);
    } catch (_) {
      flow = null;
    }

    final flowStart = flow?.start ?? DateTime(1970);
    final flowEnd = flow?.end ?? DateTime(2100);
    final hasOverlap =
        !flowEnd.isBefore(scheduleStart) && !flowStart.isAfter(scheduleEnd);
    if (!hasOverlap) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] ⚠️ No overlap: flow ($flowStart-$flowEnd) vs schedule ($scheduleStart-$scheduleEnd)',
        );
      }
      return;
    }

    String noteTitle = flow?.name ?? 'Flow Event';
    final flowCalendarId = flow?.calendarId;
    final flowCalendarName = _calendarSummary(flowCalendarId)?.name;
    String? noteDetail;
    String? noteLocation;
    String? noteCategory;
    int? noteAlertMinutes;

    // Decode flow.notes to extract detail and location for repeating notes
    if (flowNotes != null && flowNotes.isNotEmpty) {
      try {
        // Try JSON first (for repeating notes)
        final meta = jsonDecode(flowNotes) as Map<String, dynamic>;
        if (meta['kind'] == 'repeating_note') {
          noteDetail = (meta['detail'] as String?)?.trim();
          noteLocation = (meta['location'] as String?)?.trim();
          noteCategory = (meta['category'] as String?)?.trim();
          noteAlertMinutes = (meta['alertMinutes'] as num?)?.toInt();
        } else {
          // Legacy flowNotes format - try notesDecode
          try {
            final decoded = notesDecode(flowNotes);
            if (decoded.overview.isNotEmpty) noteDetail = decoded.overview;
          } catch (_) {
            // Ignore if decode fails
          }
        }
      } catch (_) {
        // Not JSON, try legacy format
        try {
          final decoded = notesDecode(flowNotes);
          if (decoded.overview.isNotEmpty) noteDetail = decoded.overview;
        } catch (_) {
          // Ignore if both fail
        }
      }
    }

    // Build candidate events first; only delete/insert if we have any.
    final candidateEvents = <_CandidateEvent>[];
    try {
      var date = scheduleStart;
      while (!date.isAfter(scheduleEnd)) {
        final kDate = KemeticMath.fromGregorian(date);

        for (final rule in rules) {
          if (rule.matches(
            ky: kDate.kYear,
            km: kDate.kMonth,
            kd: kDate.kDay,
            g: date,
          )) {
            final startHour = rule.allDay ? 9 : (rule.start?.hour ?? 9);
            final startMinute = rule.allDay ? 0 : (rule.start?.minute ?? 0);

            final detailWithMeta = _encodeDetailWithMeta(
              noteDetail,
              alertMinutes: noteAlertMinutes,
            );

            final cid = _buildCid(
              ky: kDate.kYear,
              km: kDate.kMonth,
              kd: kDate.kDay,
              title: noteTitle,
              startHour: startHour,
              startMinute: startMinute,
              allDay: rule.allDay,
              flowId: flowId,
            );

            final startsAt = DateTime(
              date.year,
              date.month,
              date.day,
              startHour,
              startMinute,
            );

            DateTime? endsAt;
            if (!rule.allDay) {
              if (rule.end != null) {
                endsAt = DateTime(
                  date.year,
                  date.month,
                  date.day,
                  rule.end!.hour,
                  rule.end!.minute,
                );
              } else {
                // Default to 1 hour if end is missing
                endsAt = DateTime(
                  date.year,
                  date.month,
                  date.day,
                  startHour,
                  startMinute,
                ).add(const Duration(hours: 1));
              }
            }

            candidateEvents.add(
              _CandidateEvent(
                clientEventId: cid,
                title: noteTitle,
                startsAtUtc: startsAt.toUtc(),
                endsAtUtc: endsAt?.toUtc(),
                calendarId: flowCalendarId,
                detail: detailWithMeta ?? noteDetail,
                location: noteLocation,
                allDay: rule.allDay,
                flowLocalId: flowId,
                category: noteCategory,
              ),
            );
          }
        }

        date = date.add(const Duration(days: 1));
      }
    } catch (e, stack) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] ⚠️ Generation failed for flowId=$flowId: $e',
        );
        _calendarDebugPrint(stack.toString());
      }
      return;
    }

    if (candidateEvents.isEmpty) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] ⚠️ No events generated for flowId=$flowId; skipping delete.',
        );
      }
      return;
    }

    try {
      // Clear existing scheduled notes for this flow after successful generation
      await repo.deleteByFlowId(
        flowId,
        fromDate: scheduleStart.toUtc(),
        semantic: 'flow_reschedule',
        suppressesClient: false,
        sourceFeature: 'CalendarPage.scheduleFlowNotes',
        deleteScope: 'flow_reschedule',
      );
      await repo.track(
        event: 'flow_rescheduled',
        properties: {'flow_id': flowId, 'v': kAppEventsSchemaVersion},
      );

      for (final ev in candidateEvents) {
        final savedEvent = await repo.upsertByClientId(
          clientEventId: ev.clientEventId,
          title: ev.title,
          startsAtUtc: ev.startsAtUtc,
          detail: ev.detail,
          location: ev.location,
          allDay: ev.allDay,
          endsAtUtc: ev.endsAtUtc,
          calendarId: ev.calendarId,
          flowLocalId: ev.flowLocalId,
          category: ev.category,
          caller: 'schedule_flow_notes',
        );

        final decodedMeta = _decodeDetailMetadata(ev.detail);
        final localStart = ev.startsAtUtc.toLocal();
        final kDate = KemeticMath.fromGregorian(localStart);
        final note = _Note(
          calendarId: flowCalendarId,
          calendarName: flowCalendarName,
          title: ev.title,
          detail: decodedMeta.detail ?? ev.detail,
          location: ev.location,
          allDay: ev.allDay,
          start: ev.allDay ? null : TimeOfDay.fromDateTime(localStart),
          end: ev.endsAtUtc == null
              ? null
              : TimeOfDay.fromDateTime(ev.endsAtUtc!.toLocal()),
          flowId: ev.flowLocalId,
          category: ev.category,
          alertOffsetMinutes: decodedMeta.alertMinutes ?? _alertNoneMinutes,
        );

        await _scheduleAlertForEvent(
          note: note,
          ky: kDate.kYear,
          km: kDate.kMonth,
          kd: kDate.kDay,
          clientEventId: savedEvent.clientEventId ?? ev.clientEventId,
          eventId: savedEvent.id,
        );
      }

      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] Scheduled ${candidateEvents.length} notes for flowId=$flowId',
        );
      }
    } catch (e, stack) {
      if (kDebugMode) {
        _calendarDebugPrint(
          '[scheduleFlowNotes] ⚠️ CRITICAL: delete/insert failed for flowId=$flowId: $e',
        );
        _calendarDebugPrint(stack.toString());
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    final routeIsCurrent = ModalRoute.of(context)?.isCurrent ?? true;
    final routeShouldRemainRendered =
        routeIsCurrent ||
        CalendarPage._hasCalendarOwnedTransientOverlayOpenOrOpening;
    if (!routeShouldRemainRendered) {
      return const Scaffold(backgroundColor: _bg, body: SizedBox.shrink());
    }

    if (!_hasUsableCalendarSnapshotForPaint() &&
        !_initialCalendarLoadFinished) {
      return _buildInitialCalendarLoadingScaffold();
    }

    final media = MediaQuery.of(context);
    final orientation = media.orientation;
    _landscapeTodayAction = null;

    // ========================================
    // DEBUG: Log orientation changes
    // ========================================
    final previousOrientation = _lastOrientation;
    if (previousOrientation != null && previousOrientation != orientation) {
      _beginOrientationCriticalReminderSyncDeferral('calendar_build');
      if (kDebugMode) {
        _calendarDebugPrint('\n${'🔄' * 30}');
        _calendarDebugPrint('ORIENTATION CHANGED!');
        _calendarDebugPrint('From: $previousOrientation → To: $orientation');
        _calendarDebugPrint('Navigator canPop: ${Navigator.canPop(context)}');
        _calendarDebugPrint('Modal route active: $routeIsCurrent');
        _calendarDebugPrint('${'🔄' * 30}\n');
      }

      if (previousOrientation == Orientation.portrait &&
          orientation == Orientation.landscape) {
        _commitVisiblePortraitMonthForRotation();
      }
      _scheduleEventDetailOrientationHandoff();

      if (orientation == Orientation.portrait) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '📜 [CALENDAR] Preserving month for portrait: $_lastViewKy-$_lastViewKm',
          );
        }
        _portraitRecenterPending = true;
      }
    }
    _lastOrientation = orientation;

    final scaffold = Scaffold(
      backgroundColor: _bg,
      appBar: _buildCalendarAppBar(useLandscapeGrid: false),
      body: _buildBodyWithJournal(),
    );

    Widget content = scaffold;

    final calendarMonthCoachmarkTargetKey = _calendarMonthCoachmarkTargetKey;
    if (_showCalendarMonthCoachmark &&
        calendarMonthCoachmarkTargetKey != null) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: CalendarMonthCoachmark(
              targetKey: calendarMonthCoachmarkTargetKey,
              onTargetTap: _handleCalendarMonthCoachmarkTargetTap,
            ),
          ),
        ],
      );
    }

    if (_showCalendarToggleCoachmark) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: CalendarToggleCoachmark(
              targetKey: _calendarToggleKey,
              onTargetTap: _handleCalendarToggleTapped,
            ),
          ),
        ],
      );
    }

    if (_showOnboarding) {
      content = Stack(
        children: [
          content,
          Positioned.fill(
            child: OnboardingOverlay(
              compassCopy:
                  _onboardingCompassCopy ??
                  DecanCompassCopyRepo.fallbackForDay(
                    kMonth: _today.kMonth,
                    kDay: _today.kDay,
                  ),
              recommendedFlowBuilder: _buildHawRecommendedFlow,
              dayViewBuilder: _buildHawDayView,
              dayViewEventTargetKey: _firstFlowEventBlockKey,
              initialSlide: _activeHawOnboardingSlide,
              onSlideChanged: _handleHawSlideChanged,
              onEntryStateSelected: _handleHawEntryStateSelected,
              onSkip: _handleOnboardingSkip,
              onComplete: _handleOnboardingComplete,
            ),
          ),
        ],
      );
    }

    if (_onboardingDayRhythmController.hasVisibleBadge) {
      content = Stack(
        children: [
          content,
          DailyCosmicContextOverlayHost(
            controller: _onboardingDayRhythmController,
          ),
        ],
      );
    }

    return content;
  }

  Widget _buildInitialCalendarLoadingScaffold() {
    return Scaffold(
      backgroundColor: _bg,
      appBar: _buildCalendarAppBar(useLandscapeGrid: false),
      body: const Center(child: CircularProgressIndicator(color: _gold)),
    );
  }

  Widget _buildBodyWithJournal() {
    final isPortrait =
        MediaQuery.of(context).orientation == Orientation.portrait;
    final allowTouchPinchGestures = useExpandedTouchTargets(context);
    final allowGlobalScaleGestures = useGlobalScaleGestures(context);
    if (_portraitRecenterPending && isPortrait) {
      _ensurePortraitCentered();
    }

    final scrollView = _buildCalendarScrollView();

    final content = PinchGestureSurface(
      enableTouchPinch: allowTouchPinchGestures,
      enableGlobalScaleGestures: allowGlobalScaleGestures,
      onScaleStart: _onScaleStart,
      onScaleUpdate: _onScaleUpdate,
      onScaleEnd: _onScaleEnd,
      child: scrollView,
    );

    return Stack(
      children: [
        content,
        if (!CalendarPage.debugSuppressPendingEventInviteOverlay)
          const PendingEventInviteOverlay(),
        if (_reflectionPrompt != null) _buildReflectionBadge(),
      ],
    );
  }

  /* ───────────── Decan Reflection Badge & Archive ───────────── */

  Widget _buildReflectionBadge() {
    final prompt = _reflectionPrompt;
    if (prompt == null) return const SizedBox.shrink();

    final media = MediaQuery.of(context);
    final maxWidth = media.size.width * 0.72;

    return Positioned(
      right: 12,
      bottom: 16 + media.padding.bottom,
      child: DecanReflectionLowerThirdBadge(
        prompt: prompt,
        maxWidth: maxWidth,
        onTap: _showReflectionSheet,
      ),
    );
  }

  void _showReflectionSheet() {
    final prompt = _reflectionPrompt;
    if (prompt == null) return;
    final dateRange =
        '${_formatDateOnlyLocal(prompt.decanStart)} → ${_formatDateOnlyLocal(prompt.decanEnd)}';

    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.black,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(18)),
      ),
      builder: (sheetCtx) {
        final inset = MediaQuery.of(sheetCtx).viewInsets.bottom;
        return SafeArea(
          child: Padding(
            padding: EdgeInsets.fromLTRB(16, 12, 16, 12 + inset),
            child: SizedBox(
              height: MediaQuery.of(sheetCtx).size.height * 0.65,
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Center(
                    child: Container(
                      width: 48,
                      height: 4,
                      decoration: BoxDecoration(
                        color: Colors.white12,
                        borderRadius: BorderRadius.circular(99),
                      ),
                    ),
                  ),
                  const SizedBox(height: 12),
                  Text(
                    prompt.decanName,
                    style: const TextStyle(
                      color: _gold,
                      fontSize: 16,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                  const SizedBox(height: 4),
                  Text(
                    dateRange,
                    style: const TextStyle(
                      color: Colors.white70,
                      fontSize: 12.5,
                    ),
                  ),
                  if (prompt.isCompositionalV1 &&
                      prompt.compositionalInteractionCount > 0) ...[
                    const SizedBox(height: 4),
                    Text(
                      '${prompt.compositionalInteractionCount} Ma’at interaction${prompt.compositionalInteractionCount == 1 ? '' : 's'} reflected',
                      style: const TextStyle(
                        color: Colors.white60,
                        fontSize: 12,
                      ),
                    ),
                  ] else if (prompt.badgeCount > 0) ...[
                    const SizedBox(height: 4),
                    Text(
                      '${prompt.badgeCount} badge${prompt.badgeCount == 1 ? '' : 's'} captured',
                      style: const TextStyle(
                        color: Colors.white60,
                        fontSize: 12,
                      ),
                    ),
                  ],
                  const SizedBox(height: 14),
                  Expanded(
                    child: SingleChildScrollView(
                      child: Text(
                        prompt.detailText,
                        style: const TextStyle(
                          color: Colors.white,
                          fontSize: 14.5,
                          height: 1.5,
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(height: 12),
                  Row(
                    children: [
                      ElevatedButton.icon(
                        onPressed: _archivingReflection
                            ? null
                            : () => _archiveReflectionPrompt(sheetCtx),
                        style: ElevatedButton.styleFrom(
                          backgroundColor: _gold,
                          foregroundColor: Colors.black,
                          padding: const EdgeInsets.symmetric(
                            horizontal: 16,
                            vertical: 12,
                          ),
                        ),
                        icon: _archivingReflection
                            ? const SizedBox(
                                width: 16,
                                height: 16,
                                child: CircularProgressIndicator(
                                  strokeWidth: 2,
                                  color: Colors.black,
                                ),
                              )
                            : const Icon(Icons.archive_outlined, size: 18),
                        label: const Text('Archive to profile'),
                      ),
                      const SizedBox(width: 12),
                      TextButton(
                        onPressed: () => Navigator.of(sheetCtx).pop(),
                        child: const Text(
                          'Close',
                          style: TextStyle(color: _gold),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            ),
          ),
        );
      },
    ).whenComplete(() {
      if (!mounted) return;
      final current = _reflectionPrompt;
      if (current == null) return;
      if (!DateUtils.isSameDay(current.decanStart, prompt.decanStart)) return;
      unawaited(_dismissReflectionPrompt());
    });
  }

  String _formatDateOnlyLocal(DateTime date) {
    final d = date.toLocal();
    final yyyy = d.year.toString().padLeft(4, '0');
    final mm = d.month.toString().padLeft(2, '0');
    final dd = d.day.toString().padLeft(2, '0');
    return '$yyyy-$mm-$dd';
  }

  DateTime _dateOnlyLocal(DateTime date) {
    final d = date.toLocal();
    return DateTime(d.year, d.month, d.day);
  }

  Future<void> _dismissReflectionPrompt() async {
    final prompt = _reflectionPrompt;
    if (prompt == null) return;
    if (mounted) {
      setState(() => _reflectionPrompt = null);
    }
    await _markReflectionPromptInteracted(prompt, interactionKind: 'dismissed');
    if (!mounted) return;
    final current = _reflectionPrompt;
    if (current != null &&
        DateUtils.isSameDay(current.decanStart, prompt.decanStart)) {
      setState(() => _reflectionPrompt = null);
    }
  }

  ({
    DateTime start,
    DateTime end,
    String decanName,
    String? decanTheme,
    String decanContextKey,
    int kMonth,
    int kYear,
    int decanIndex,
  })?
  _latestCompletedDecanWindow() {
    final now = DateTime.now();
    final kem = KemeticMath.fromGregorian(now);

    // Skip epagomenal days (month 13) for reflection generation; fall back to month 12.
    int kMonth = kem.kMonth;
    int kYear = kem.kYear;
    int completedDecan = kem.kDay ~/ 10; // 1-based decan completion count

    if (kMonth == 13) {
      kMonth = 12;
      completedDecan = 3;
    }

    if (completedDecan == 0) {
      if (kMonth <= 1) {
        kYear -= 1;
        kMonth = 12;
      } else {
        kMonth -= 1;
      }
      completedDecan = 3;
    }

    completedDecan = completedDecan.clamp(1, 3);
    if (kMonth == 13) return null; // guard epagomenal month fallback

    final decanStartDay = ((completedDecan - 1) * 10) + 1;
    final decanEndDay = completedDecan * 10;

    final start = KemeticMath.toGregorian(kYear, kMonth, decanStartDay);
    final end = KemeticMath.toGregorian(kYear, kMonth, decanEndDay);
    final todayLocal = _dateOnlyLocal(DateTime.now());
    if (_dateOnlyLocal(end).isAfter(todayLocal)) {
      return null; // only after completion
    }

    final decanLabel = DecanMetadata.decanNameFor(
      kMonth: kMonth,
      kDay: decanEndDay,
      expanded: true,
    );
    final monthLabel = getMonthById(kMonth).displayShort;

    return (
      start: start,
      end: end,
      decanName: '$monthLabel — $decanLabel',
      decanTheme: decanLabel,
      decanContextKey: '$kMonth-$completedDecan',
      kMonth: kMonth,
      kYear: kYear,
      decanIndex: completedDecan,
    );
  }

  Future<bool> _hasInteractedWithReflectionPrompt(DateTime decanStart) async {
    if (await _decanReflectionPromptState.hasInteracted(decanStart)) {
      return true;
    }
    final cloudInteracted = await _decanReflectionRepo.hasPromptInteracted(
      decanStart,
    );
    if (cloudInteracted) {
      await _decanReflectionPromptState.markInteracted(decanStart);
    }
    return cloudInteracted;
  }

  Future<void> _markReflectionPromptInteracted(
    CalendarDecanReflectionPrompt prompt, {
    required String interactionKind,
  }) async {
    await _recordCompositionalReflectionUsage(prompt);
    await _decanReflectionPromptState.markInteracted(prompt.decanStart);
    await _decanReflectionRepo.markPromptInteracted(
      decanStart: prompt.decanStart,
      decanEnd: prompt.decanEnd,
      interactionKind: interactionKind,
    );
  }

  Future<void> _recordCompositionalReflectionUsage(
    CalendarDecanReflectionPrompt prompt,
  ) async {
    final phraseIds = decanCompositionPhraseIdsFromMetadata(
      prompt.renderMetadata,
    );
    if (phraseIds.isEmpty) return;
    final now = DateTime.now();
    await _compositionUsageStore.recordAll(
      phraseIds
          .map(
            (phraseId) => CompositionUsageRecord(
              phraseId: phraseId,
              date: now,
              surface: kDecanReflectionSurface,
            ),
          )
          .toList(growable: false),
    );
  }

  bool get _shouldSuppressDecanReflectionForOnboarding {
    if (_onboardingReviewMode || _showOnboarding) return true;
    final progress = _onboardingProgress;
    if (!progress.completedOnboarding) return true;
    if (!progress.hasSeenMenuPrompt) return true;
    switch (progress.currentStep) {
      case TrueOnboardingStep.welcome:
      case TrueOnboardingStep.currentDecanIntro:
      case TrueOnboardingStep.profileBasics:
      case TrueOnboardingStep.firstMaatFlow:
      case TrueOnboardingStep.firstFlowCalendarDay:
      case TrueOnboardingStep.firstFlowDayEvent:
      case TrueOnboardingStep.eventDetailObservedJournal:
      case TrueOnboardingStep.menuExplore:
        return true;
      case TrueOnboardingStep.complete:
        return false;
    }
  }

  OnboardingDecanIdentity? _currentOnboardingDecanIdentity() {
    final kem = KemeticMath.fromGregorian(DateTime.now());
    return OnboardingDecanIdentity.fromKemeticDay(
      kYear: kem.kYear,
      kMonth: kem.kMonth,
      kDay: kem.kDay,
    );
  }

  OnboardingProgress _withReflectionDecanBaseline(OnboardingProgress progress) {
    if (progress.reflectionSignupDecanIdentity?.trim().isNotEmpty == true) {
      return progress;
    }
    if (progress.completedOnboarding &&
        progress.currentStep == TrueOnboardingStep.complete) {
      return progress;
    }
    final currentDecan = _currentOnboardingDecanIdentity();
    if (currentDecan == null) return progress;
    return progress.copyWith(
      reflectionSignupDecanIdentity: currentDecan.wireName,
    );
  }

  Future<void> _refreshFirstDecanBoundaryCrossingIfNeeded(
    OnboardingDecanIdentity? currentDecan,
  ) async {
    if (_onboardingReviewMode || currentDecan == null) return;
    final progress = _onboardingProgress;
    if (progress.hasCrossedFirstDecanBoundary) return;
    if (!DecanReflectionOnboardingGate.hasCrossedBoundary(
      signupDecanIdentity: progress.reflectionSignupDecanIdentity,
      currentDecanIdentity: currentDecan,
    )) {
      return;
    }
    await _saveOnboardingProgress(
      progress.copyWith(
        hasCrossedFirstDecanBoundary: true,
        firstReflectionEligibleDecanIdentity: currentDecan.wireName,
      ),
    );
  }

  Future<void> _maybeLoadDecanReflectionPrompt({bool force = false}) async {
    if (!mounted || _reflectionInFlight) return;
    if (_shouldSuppressDecanReflectionForOnboarding) {
      if (_reflectionPrompt != null) {
        setState(() => _reflectionPrompt = null);
      }
      return;
    }
    final user = Supabase.instance.client.auth.currentUser;
    if (user == null) return;

    final currentDecan = _currentOnboardingDecanIdentity();
    await _refreshFirstDecanBoundaryCrossingIfNeeded(currentDecan);

    final today = DateUtils.dateOnly(DateTime.now());
    if (_lastReflectionCheckDay != null &&
        DateUtils.isSameDay(today, _lastReflectionCheckDay) &&
        !force &&
        _reflectionPrompt != null) {
      return;
    }
    _lastReflectionCheckDay = today;

    final window = _latestCompletedDecanWindow();
    if (window == null) {
      if (_reflectionPrompt != null) {
        setState(() => _reflectionPrompt = null);
      }
      return;
    }

    final promptDecan = OnboardingDecanIdentity(
      kYear: window.kYear,
      kMonth: window.kMonth,
      decan: window.decanIndex,
    );
    if (DecanReflectionOnboardingGate.shouldBlock(
      progress: _onboardingProgress,
      currentDecanIdentity: currentDecan,
      promptDecanIdentity: promptDecan,
    )) {
      if (_reflectionPrompt != null) {
        setState(() => _reflectionPrompt = null);
      }
      return;
    }

    // Gate visibility until 8pm local on the 10th day of the decan
    final decanStartLocal = window.start.toLocal();
    final gateLocal = DateTime(
      decanStartLocal.year,
      decanStartLocal.month,
      decanStartLocal.day,
    ).add(const Duration(days: 9, hours: 20)); // day 10 at 8pm
    if (DateTime.now().isBefore(gateLocal)) {
      if (_reflectionPrompt != null) setState(() => _reflectionPrompt = null);
      return;
    }

    _reflectionInFlight = true;
    try {
      if (await _hasInteractedWithReflectionPrompt(window.start)) {
        if (!mounted) return;
        if (_reflectionPrompt != null) {
          setState(() => _reflectionPrompt = null);
        }
        return;
      }

      final existing = await _decanReflectionRepo.findByWindow(
        window.start,
        window.end,
      );
      if (existing != null) {
        final renderMetadata = await _decanReflectionRepo
            .getRenderMetadataForReflection(existing);
        if (!mounted) return;
        setState(() {
          _reflectionPrompt = CalendarDecanReflectionPrompt(
            id: existing.id,
            decanName: existing.decanName,
            decanTheme: existing.decanTheme,
            decanStart: existing.decanStart,
            decanEnd: existing.decanEnd,
            badgeCount: existing.badgeCount,
            reflectionText: existing.reflectionText,
            persisted: true,
            renderMetadata: renderMetadata,
          );
        });
        return;
      }

      if (!FeatureFlags.enableCompositionalDecanReflections) {
        if (_reflectionPrompt != null) {
          setState(() => _reflectionPrompt = null);
        }
        return;
      }

      final facts = await _maatFlowDecanFactCollector.collect(
        decanStart: window.start,
        decanEnd: window.end,
        surface: kDecanReflectionSurface,
      );
      final usageHistory = await _compositionUsageStore.load();
      final composition = _decanReflectionComposer.compose(
        facts: facts,
        usageHistory: usageHistory,
        generatedAt: DateTime.now(),
      );

      if (composition == null) {
        if (_reflectionPrompt != null) {
          setState(() => _reflectionPrompt = null);
        }
        return;
      }

      if (!mounted) return;
      setState(() {
        _reflectionPrompt = CalendarDecanReflectionPrompt(
          id: null,
          decanName: window.decanName,
          decanTheme: window.decanTheme,
          decanStart: window.start,
          decanEnd: window.end,
          badgeCount: 0,
          reflectionText: composition.output.text,
          persisted: false,
          renderMetadata: composition.renderMetadata,
        );
      });
      Events.trackIfAuthed('decan_reflection_generated', {
        'renderer': kDecanReflectionCompositionalRenderer,
        'used_llm': false,
        'total_interactions':
            composition.output.factSummary['total_interactions'],
        'intent_id': composition.output.intentId,
        'fact_fingerprint': composition.output.factFingerprint,
      });
    } catch (e) {
      if (kDebugMode) {
        _calendarDebugPrint('[DecanReflection] prompt load failed: $e');
      }
    } finally {
      _reflectionInFlight = false;
    }
  }

  Future<void> _archiveReflectionPrompt([BuildContext? ctx]) async {
    final prompt = _reflectionPrompt;
    if (prompt == null || _archivingReflection) return;

    if (mounted) {
      setState(() => _archivingReflection = true);
    }

    try {
      DecanReflection? saved = prompt.persisted && prompt.id != null
          ? await _decanReflectionRepo.getById(prompt.id!)
          : null;

      saved ??= await _decanReflectionRepo.saveReflection(
        decanName: prompt.decanName,
        decanTheme: prompt.decanTheme,
        decanStart: prompt.decanStart,
        decanEnd: prompt.decanEnd,
        badgeCount: prompt.badgeCount,
        reflectionText: prompt.detailText,
      );
      if (saved == null) {
        throw Exception('Unable to save reflection');
      }
      final renderMetadata = prompt.renderMetadata;
      if (renderMetadata?.renderer == kDecanReflectionCompositionalRenderer) {
        await _decanReflectionRepo.saveCompositionalGeneration(
          reflection: saved,
          renderMetadata: renderMetadata!,
          modelVersion:
              renderMetadata.raw['engine_version']?.toString() ??
              kCompositionEngineVersion,
        );
      }

      await _markReflectionPromptInteracted(
        prompt,
        interactionKind: 'archived',
      );

      if (!mounted) return;
      setState(() => _reflectionPrompt = null);
      if (ctx != null && ctx.mounted && Navigator.of(ctx).canPop()) {
        Navigator.of(ctx).pop();
      }
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Reflection archived to your profile'),
          duration: Duration(seconds: 2),
        ),
      );
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Could not archive reflection: $e')),
      );
    } finally {
      if (mounted) {
        setState(() => _archivingReflection = false);
      } else {
        _archivingReflection = false;
      }
    }
  }

  int _currentYearCenterMonthForScroll() {
    final existing = _currentYearCenterMonth;
    if (existing != null) return existing;
    final preferredMonth = _lastViewKy == _today.kYear ? _lastViewKm : null;
    final resolved = (preferredMonth ?? _today.kMonth).clamp(1, 13).toInt();
    _currentYearCenterMonth = resolved;
    return resolved;
  }

  String? _currentYearSeasonHeaderForMonth(int kMonth) {
    switch (kMonth) {
      case 1:
        return 'Flood season (Akhet)';
      case 5:
        return 'Emergence season (Peret)';
      case 9:
        return 'Harvest season (Shemu)';
      default:
        return null;
    }
  }

  String _seasonShortForMonth(int kMonth) {
    if (kMonth >= 1 && kMonth <= 4) return 'Akhet';
    if (kMonth >= 5 && kMonth <= 8) return 'Peret';
    return 'Shemu';
  }

  Widget _buildCurrentYearMonthSliver({
    required int kYear,
    required int kMonth,
    required int centerMonth,
  }) {
    final sectionHeader = _currentYearSeasonHeaderForMonth(kMonth);
    final child = Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        if (sectionHeader != null) _SeasonHeader(title: sectionHeader),
        if (kMonth <= 12)
          _MonthCard(
            anchorKey: keyForMonth(kYear, kMonth),
            monthHeaderKey: keyForMonthHeader(kYear, kMonth),
            dayAnchorKeyProvider: (m, d) =>
                _calendarDayAnchorKeyFor(kYear, m, d),
            kYear: kYear,
            kMonth: kMonth,
            seasonShort: _seasonShortForMonth(kMonth),
            todayMonth: _today.kMonth,
            todayDay: _today.kDay,
            todayDayKey: _todayDayKey,
            notesGetter: (m, d) => _getNotes(kYear, m, d),
            flowColorsGetter: (ky, km, kd) => getFlowColorsForDay(ky, km, kd),
            temporalAnchorVisible: _currentDecanVisibleInViewport,
            onDayTap: (c, m, d) => _openDayView(c, kYear, m, d),
            showGregorian: _showGregorian,
            expansionLevel: _monthExpansion,
            noteColorResolver: _noteColor,
            flowNameGetter: _flowName,
            onManageFlows: _getMyFlowsCallback(),
            onEditNote: (ky, km, kd, evt) async =>
                _editNoteByEvent(ky, km, kd, evt),
            onDeleteNote: (ky, km, kd, evt) async =>
                _deleteNoteByEvent(ky, km, kd, evt),
            onShareNote: (evt) async => _shareNoteSimple(evt),
            onEditReminder: (id) async => _editReminderById(id),
            onEndReminder: (id) async => _endReminderRule(id),
            onShareReminder: (evt) async => _shareNoteSimple(evt),
            onEndFlow: (id) => _endFlow(id),
            onAppendToJournal: _appendToJournalAndRefresh,
            onMonthHeaderTap: (context) =>
                _handleMonthHeaderTapped(context, kYear, kMonth),
            onDecanTap: (context, decanIndex) =>
                _handleDecanHeaderTapped(context, kYear, kMonth, decanIndex),
          )
        else
          KeyedSubtree(
            key: keyForMonth(kYear, 13),
            child: _EpagomenalCard(
              kYear: kYear,
              todayMonth: _today.kMonth,
              todayDay: _today.kDay,
              todayDayKey: _todayDayKey,
              notesGetter: (m, d) => _getNotes(kYear, 13, d),
              flowColorsGetter: (ky, km, kd) => getFlowColorsForDay(ky, km, kd),
              onDayTap: (c, m, d) => _openDayView(c, kYear, 13, d),
              showGregorian: _showGregorian,
              expansionLevel: _monthExpansion,
              noteColorResolver: _noteColor,
              flowNameGetter: _flowName,
              onManageFlows: _getMyFlowsCallback(),
              onEditNote: (ky, km, kd, evt) async =>
                  _editNoteByEvent(ky, km, kd, evt),
              onDeleteNote: (ky, km, kd, evt) async =>
                  _deleteNoteByEvent(ky, km, kd, evt),
              onShareNote: (evt) async => _shareNoteSimple(evt),
              onEditReminder: (id) async => _editReminderById(id),
              onEndReminder: (id) async => _endReminderRule(id),
              onShareReminder: (evt) async => _shareNoteSimple(evt),
              onEndFlow: (id) => _endFlow(id),
              onAppendToJournal: _appendToJournalAndRefresh,
            ),
          ),
        const _GoldDivider(),
      ],
    );

    return SliverToBoxAdapter(
      key: kMonth == centerMonth ? _centerKey : null,
      child: child,
    );
  }

  bool get _shouldUseStartupSingleMonthCalendar {
    return !_startupFullCalendarScrollEnabled &&
        _hasUsableCalendarSnapshotForPaint() &&
        !_initialCalendarLoadFinished;
  }

  void _scheduleFullCalendarScrollAfterStartupFrame() {
    if (_startupFullCalendarScrollEnableScheduled) return;
    _startupFullCalendarScrollEnableScheduled = true;
    unawaited(() async {
      await _waitForFirstRasterizedFrameForDeferredStartup();
      void enableFullCalendarScroll() {
        if (!mounted || _startupFullCalendarScrollEnabled) return;
        setState(() {
          _startupFullCalendarScrollEnabled = true;
        });
      }

      if (_isWidgetTestBindingForDeferredStartup()) {
        enableFullCalendarScroll();
      } else {
        Timer.run(enableFullCalendarScroll);
      }
    }());
  }

  Widget _buildStartupSingleMonthCalendarScrollView({
    required ({int kYear, int kMonth, int kDay}) kToday,
    required int centerMonth,
  }) {
    _scheduleFullCalendarScrollAfterStartupFrame();
    return CustomScrollView(
      key: const PageStorageKey('calendar_portrait_scroll_startup_month'),
      anchor: 0.0,
      slivers: [
        _buildCurrentYearMonthSliver(
          kYear: kToday.kYear,
          kMonth: centerMonth,
          centerMonth: centerMonth,
        ),
      ],
    );
  }

  Widget _buildCalendarScrollView() {
    final kToday = _today;
    final centerMonth = _currentYearCenterMonthForScroll();

    if (_shouldUseStartupSingleMonthCalendar) {
      return _buildStartupSingleMonthCalendarScrollView(
        kToday: kToday,
        centerMonth: centerMonth,
      );
    }

    // ✅ FIX 4: Wrap with NotificationListener to capture scroll-end events
    return NotificationListener<ScrollNotification>(
      onNotification: (notification) {
        if (!_initialViewportSettled) return false;
        WidgetsBinding.instance.addPostFrameCallback((_) {
          _refreshCurrentDecanViewportAnchor();
        });
        if (notification is ScrollEndNotification) {
          if (_scrollCtrl.hasClients) {
            _lastKnownCalendarScrollOffset = _scrollCtrl.position.pixels;
          }
          // ✅ Only update centered month when scrolling STOPS
          WidgetsBinding.instance.addPostFrameCallback((_) {
            if (!mounted || !_initialViewportSettled) return;

            final centered = _computeCenteredMonthPrecisely();
            if (centered.$1 != _lastViewKy || centered.$2 != _lastViewKm) {
              _handlePortraitMonthChanged(centered.$1, centered.$2);
            }
            _scheduleCalendarRestorationSave(reason: 'calendar_scroll_end');
          });
        }
        return false;
      },
      child: CustomScrollView(
        key: const PageStorageKey('calendar_portrait_scroll'),
        controller: _scrollCtrl,
        anchor: 0.0, // start the center sliver at the top on cold open
        center: _centerKey, // startup month in the current Kemetic year
        slivers: [
          // PAST years
          SliverList(
            delegate: SliverChildBuilderDelegate(
              (ctx, i) {
                final kYear = kToday.kYear - (i + 1);
                return _YearSection(
                  kYear: kYear,
                  todayMonth: null,
                  todayDay: null,
                  todayDayKey: null, // no anchor in past/future lists
                  monthAnchorKeyProvider: (m) => keyForMonth(kYear, m),
                  monthHeaderKeyProvider: (m) => keyForMonthHeader(kYear, m),
                  dayAnchorKeyProvider: (m, d) =>
                      _calendarDayAnchorKeyFor(kYear, m, d),
                  onMonthHeaderTap: (context, kMonth) =>
                      _handleMonthHeaderTapped(context, kYear, kMonth),
                  onDecanTap: (context, kMonth, decanIndex) =>
                      _handleDecanHeaderTapped(
                        context,
                        kYear,
                        kMonth,
                        decanIndex,
                      ),
                  onDayTap: (c, m, d) => _openDayView(c, kYear, m, d),
                  notesGetter: (m, d) => _getNotes(kYear, m, d),
                  flowColorsGetter: (ky, km, kd) =>
                      getFlowColorsForDay(ky, km, kd),
                  showGregorian: _showGregorian,
                  expansionLevel: _monthExpansion,
                  noteColorResolver: _noteColor,
                  flowNameGetter: _flowName,
                  onManageFlows: _getMyFlowsCallback(),
                  onEditNote: (ky, km, kd, evt) async =>
                      _editNoteByEvent(ky, km, kd, evt),
                  onDeleteNote: (ky, km, kd, evt) async =>
                      _deleteNoteByEvent(ky, km, kd, evt),
                  onShareNote: (evt) async => _shareNoteSimple(evt),
                  onEditReminder: (id) async => _editReminderById(id),
                  onEndReminder: (id) async => _endReminderRule(id),
                  onShareReminder: (evt) async => _shareNoteSimple(evt),
                  onEndFlow: (id) => _endFlow(id),
                  onAppendToJournal: _appendToJournalAndRefresh,
                );
              },
              childCount: 200, //
            ),
          ),

          // CURRENT year, split by month so the first drawable frame does not
          // construct every month/day card before cached content is visible.
          for (var month = 1; month <= 13; month++)
            _buildCurrentYearMonthSliver(
              kYear: kToday.kYear,
              kMonth: month,
              centerMonth: centerMonth,
            ),

          // FUTURE years
          SliverList(
            delegate: SliverChildBuilderDelegate(
              (ctx, i) {
                final kYear = kToday.kYear + (i + 1);
                return _YearSection(
                  kYear: kYear,
                  todayMonth: null,
                  todayDay: null,
                  todayDayKey: null,
                  monthAnchorKeyProvider: (m) => keyForMonth(kYear, m),
                  monthHeaderKeyProvider: (m) => keyForMonthHeader(kYear, m),
                  dayAnchorKeyProvider: (m, d) =>
                      _calendarDayAnchorKeyFor(kYear, m, d),
                  onMonthHeaderTap: (context, kMonth) =>
                      _handleMonthHeaderTapped(context, kYear, kMonth),
                  onDecanTap: (context, kMonth, decanIndex) =>
                      _handleDecanHeaderTapped(
                        context,
                        kYear,
                        kMonth,
                        decanIndex,
                      ),
                  onDayTap: (c, m, d) => _openDayView(c, kYear, m, d),
                  notesGetter: (m, d) => _getNotes(kYear, m, d),
                  flowColorsGetter: (ky, km, kd) =>
                      getFlowColorsForDay(ky, km, kd),
                  showGregorian: _showGregorian,
                  expansionLevel: _monthExpansion,
                  noteColorResolver: _noteColor,
                  flowNameGetter: _flowName,
                  onManageFlows: _getMyFlowsCallback(),
                  onEditNote: (ky, km, kd, evt) async =>
                      _editNoteByEvent(ky, km, kd, evt),
                  onDeleteNote: (ky, km, kd, evt) async =>
                      _deleteNoteByEvent(ky, km, kd, evt),
                  onShareNote: (evt) async => _shareNoteSimple(evt),
                  onEditReminder: (id) async => _editReminderById(id),
                  onEndReminder: (id) async => _endReminderRule(id),
                  onShareReminder: (evt) async => _shareNoteSimple(evt),
                  onEndFlow: (id) => _endFlow(id),
                  onAppendToJournal: _appendToJournalAndRefresh,
                );
              },
              childCount: 200, //
            ),
          ),
        ],
      ),
    );
  }

  Map<int, FlowData> _buildCalendarFlowChromeIndex() {
    final allFlowsById = _allFlowsById();
    final activeLedgerFlowIds = _buildActiveLedgerFlowIds();
    final referencedFlowIds = _calendarReferencedFlowIds();
    final chromeIds = {...activeLedgerFlowIds, ...referencedFlowIds}.toList()
      ..sort();
    final index = <int, FlowData>{};

    for (final flowId in chromeIds) {
      final flow = allFlowsById[flowId];
      if (flow == null) {
        if (kDebugMode) {
          _calendarDebugPrint(
            '[calendarFlowChrome] MISSING_FLOW_OWNER_ROW flowId=$flowId',
          );
        }
        continue;
      }

      final snapshot = _flowRecordSnapshotFromFlow(flow);
      if (!shouldExposeFlowChromeForCalendar(
        snapshot,
        isReferencedByCalendar: referencedFlowIds.contains(flowId),
        isActiveLedgerFlow: activeLedgerFlowIds.contains(flowId),
      )) {
        continue;
      }

      index[flowId] = _flowDataFromFlow(flow);
    }

    return index;
  }

  FlowLedger<_Flow> _buildFlowLedger(Iterable<_Flow> flows) {
    return buildFlowLedger<_Flow>(
      flows: flows,
      idOf: (flow) => flow.id,
      activeOf: (flow) => flow.active,
      isSavedOf: (flow) => flow.isSaved,
      isHiddenOf: (flow) => flow.isHidden,
      isReminderOf: (flow) => flow.isReminder,
      endDateOf: (flow) => flow.end,
      notesOf: (flow) => flow.notes,
      useRemainingEventCount: true,
      totalEventCounts: _flowTotalEventCounts,
      remainingEventCounts: _flowRemainingEventCounts,
    );
  }

  FlowData? _calendarChromeFlowDataForId(int? flowId) {
    if (flowId == null || flowId <= 0) return null;
    final flow = _allFlowsById()[flowId];
    if (flow == null) return null;
    final activeLedgerFlowIds = _buildActiveLedgerFlowIds();
    final snapshot = _flowRecordSnapshotFromFlow(flow);
    if (!shouldExposeFlowChromeForCalendar(
      snapshot,
      isReferencedByCalendar: true,
      isActiveLedgerFlow: activeLedgerFlowIds.contains(flowId),
    )) {
      return null;
    }
    return _flowDataFromFlow(flow);
  }

  EventItem _calendarSheetEventItemFromNote(_Note note) {
    final startMin = note.allDay
        ? 9 * 60
        : (note.start?.hour ?? 9) * 60 + (note.start?.minute ?? 0);
    final endMin = note.allDay
        ? 17 * 60
        : (note.end?.hour ?? 17) * 60 + (note.end?.minute ?? 0);

    return EventItem(
      id: note.id,
      clientEventId: note.clientEventId,
      calendarId: note.calendarId,
      calendarName: note.calendarName,
      title: note.title,
      detail: note.detail,
      location: note.location,
      startMin: startMin,
      endMin: endMin,
      flowId: note.flowId,
      color: _noteColor(note),
      manualColor: note.manualColor,
      allDay: note.allDay,
      category: note.category,
      isReminder: note.isReminder,
      reminderId: note.reminderId,
      behaviorPayload: note.behaviorPayload,
    );
  }

  bool _noteHasStableIdentity(_Note note) =>
      (note.id?.trim().isNotEmpty ?? false) ||
      (note.clientEventId?.trim().isNotEmpty ?? false);

  int _visibleDayNotePriority(_Note note, {bool preferTimed = false}) {
    var score = 0;
    if (_noteHasStableIdentity(note)) score += 8;
    if (note.id?.trim().isNotEmpty ?? false) score += 3;
    if (note.clientEventId?.trim().isNotEmpty ?? false) score += 2;
    if (note.start != null) score += 1;
    if (note.end != null) score += 1;
    if (note.detail?.trim().isNotEmpty ?? false) score += 1;
    if (preferTimed && !note.allDay) score += 12;
    return score;
  }

  String _visibleDayNoteBaseKey(_Note note) {
    final flowKey = note.flowId?.toString() ?? 'NO_FLOW';

    String startKey;
    String endKey;

    if (note.allDay) {
      startKey = 'ALLDAY';
      endKey = 'ALLDAY';
    } else if (note.start != null && note.end != null) {
      startKey = '${note.start!.hour * 60 + note.start!.minute}';
      endKey = '${note.end!.hour * 60 + note.end!.minute}';
    } else {
      startKey = 'NO_START';
      endKey = 'NO_END';
    }

    final titleKey = note.title.trim().toLowerCase();
    return '$flowKey|$startKey|$endKey|$titleKey';
  }

  String? _visibleDayFlowLogicalKey(_Note note) {
    final flowId = note.flowId;
    if (flowId == null || flowId <= 0 || note.isReminder) return null;
    final titleKey = note.title.trim().toLowerCase();
    if (titleKey.isEmpty) return null;
    return 'flow-logical|$flowId|$titleKey';
  }

  String? _trackSkyVisibleDayNoteKey(_Note note, {Set<int>? trackSkyFlowIds}) {
    final flowId = note.flowId;
    final isTrackSkyNote =
        flowId != null &&
        flowId > 0 &&
        ((trackSkyFlowIds != null && trackSkyFlowIds.contains(flowId)) ||
            _isTrackSkyFlowName(_flowName(note)));
    if (!isTrackSkyNote) return null;
    final flowKey = note.flowId?.toString() ?? 'NO_FLOW';
    final titleKey = note.title.trim().toLowerCase();
    final categoryKey = (note.category ?? '').trim().toLowerCase();
    return 'track-sky|$flowKey|$categoryKey|$titleKey';
  }

  void _mergeVisibleDayDuplicate({
    required List<_Note> deduped,
    required Map<String, int> indexByKey,
    required String key,
    required _Note note,
    bool preferTimed = false,
  }) {
    final existingIndex = indexByKey[key];
    if (existingIndex == null) {
      indexByKey[key] = deduped.length;
      deduped.add(note);
      return;
    }

    final existing = deduped[existingIndex];
    final existingScore = _visibleDayNotePriority(
      existing,
      preferTimed: preferTimed,
    );
    final incomingScore = _visibleDayNotePriority(
      note,
      preferTimed: preferTimed,
    );
    if (incomingScore > existingScore) {
      deduped[existingIndex] = note;
    }
  }

  void _mergeVisibleDayFlowLogicalDuplicate({
    required List<_Note> deduped,
    required Map<String, int> indexByKey,
    required String key,
    required _Note note,
  }) {
    final existingIndex = indexByKey[key];
    if (existingIndex == null) {
      indexByKey[key] = deduped.length;
      deduped.add(note);
      return;
    }

    final existing = deduped[existingIndex];
    final existingScore = _visibleDayNotePriority(existing, preferTimed: true);
    final incomingScore = _visibleDayNotePriority(note, preferTimed: true);
    if (incomingScore >= existingScore || !_noteHasStableIdentity(note)) {
      deduped[existingIndex] = note;
    }
  }

  List<_Note> _dedupeVisibleDayNotes(
    List<_Note> notes, {
    Set<int>? trackSkyFlowIds,
  }) {
    if (notes.length < 2) return notes;

    final exactDeduped = <_Note>[];
    final exactIndexByKey = <String, int>{};
    for (final note in notes) {
      _mergeVisibleDayDuplicate(
        deduped: exactDeduped,
        indexByKey: exactIndexByKey,
        key: _visibleDayNoteBaseKey(note),
        note: note,
      );
    }

    final trackSkyDeduped = <_Note>[];
    final trackSkyIndexByKey = <String, int>{};
    for (final note in exactDeduped) {
      final trackSkyKey = _trackSkyVisibleDayNoteKey(
        note,
        trackSkyFlowIds: trackSkyFlowIds,
      );
      if (trackSkyKey == null) {
        trackSkyDeduped.add(note);
        continue;
      }

      _mergeVisibleDayDuplicate(
        deduped: trackSkyDeduped,
        indexByKey: trackSkyIndexByKey,
        key: trackSkyKey,
        note: note,
        preferTimed: true,
      );
    }

    final flowLogicalDeduped = <_Note>[];
    final flowLogicalIndexByKey = <String, int>{};
    for (final note in trackSkyDeduped) {
      final flowLogicalKey = _visibleDayFlowLogicalKey(note);
      if (flowLogicalKey == null) {
        flowLogicalDeduped.add(note);
        continue;
      }

      _mergeVisibleDayFlowLogicalDuplicate(
        deduped: flowLogicalDeduped,
        indexByKey: flowLogicalIndexByKey,
        key: flowLogicalKey,
        note: note,
      );
    }

    return flowLogicalDeduped;
  }

  String _calendarSheetEventIdentityKey(EventItem event) {
    final id = event.id?.trim();
    if (id != null && id.isNotEmpty) return 'id:$id';

    final clientEventId = event.clientEventId?.trim();
    if (clientEventId != null && clientEventId.isNotEmpty) {
      return 'cid:$clientEventId';
    }

    final reminderId = event.reminderId?.trim();
    if (reminderId != null && reminderId.isNotEmpty) {
      return 'rid:$reminderId';
    }

    return [
      event.title.trim().toLowerCase(),
      event.startMin,
      event.endMin,
      event.flowId ?? '',
      event.location?.trim().toLowerCase() ?? '',
      event.detail?.trim().toLowerCase() ?? '',
      event.allDay,
      event.isReminder,
    ].join('|');
  }

  bool _calendarSheetEventsShareStableIdentity(EventItem a, EventItem b) {
    final aId = a.id?.trim();
    final bId = b.id?.trim();
    if (aId != null && aId.isNotEmpty && bId != null && bId.isNotEmpty) {
      return aId == bId;
    }

    final aClientId = a.clientEventId?.trim();
    final bClientId = b.clientEventId?.trim();
    if (aClientId != null &&
        aClientId.isNotEmpty &&
        bClientId != null &&
        bClientId.isNotEmpty) {
      return aClientId == bClientId;
    }

    final aReminderId = a.reminderId?.trim();
    final bReminderId = b.reminderId?.trim();
    if (aReminderId != null &&
        aReminderId.isNotEmpty &&
        bReminderId != null &&
        bReminderId.isNotEmpty) {
      return aReminderId == bReminderId;
    }

    return _calendarSheetEventIdentityKey(a) ==
        _calendarSheetEventIdentityKey(b);
  }

  int _compareCalendarSheetEventItems(EventItem a, EventItem b) {
    final startCmp = a.startMin.compareTo(b.startMin);
    if (startCmp != 0) return startCmp;

    final endCmp = a.endMin.compareTo(b.endMin);
    if (endCmp != 0) return endCmp;

    return _calendarSheetEventIdentityKey(
      a,
    ).compareTo(_calendarSheetEventIdentityKey(b));
  }

  List<EventItem> _calendarSheetEventsForDay(int ky, int km, int kd) {
    final window = _calendarSheetDayWindow(ky, km, kd);
    final noteOccurrences = filterAndDedupeDaySheetCandidates(
      _calendarSheetNoteCandidatesForDay(ky, km, kd),
      window: window,
      candidateOf: (entry) => _calendarSheetNoteCandidate(
        entry.note,
        entry.bucketStart,
        sourceType: entry.note.isReminder ? 'reminder' : 'day_view_event',
      ),
    );
    final notes = [for (final entry in noteOccurrences) entry.note];
    final events = [
      for (final note in notes) _calendarSheetEventItemFromNote(note),
    ];
    events.sort(_compareCalendarSheetEventItems);
    return events;
  }

  DayViewSheetEventTarget? _resolveCalendarAdjacentEventTarget({
    required int ky,
    required int km,
    required int kd,
    required EventItem event,
    required bool forward,
  }) {
    final currentEvents = _calendarSheetEventsForDay(ky, km, kd);
    final currentIndex = currentEvents.indexWhere(
      (candidate) => _calendarSheetEventsShareStableIdentity(candidate, event),
    );

    if (currentIndex >= 0) {
      final sameDayIndex = forward ? currentIndex + 1 : currentIndex - 1;
      if (sameDayIndex >= 0 && sameDayIndex < currentEvents.length) {
        return DayViewSheetEventTarget(
          ky: ky,
          km: km,
          kd: kd,
          event: currentEvents[sameDayIndex],
        );
      }
    }

    final currentGregorian = KemeticMath.toGregorian(ky, km, kd);
    final direction = forward ? 1 : -1;
    for (int offset = 1; offset <= 366; offset++) {
      final nextGregorian = currentGregorian.add(
        Duration(days: direction * offset),
      );
      final nextKemetic = KemeticMath.fromGregorian(nextGregorian);
      final nextDayEvents = _calendarSheetEventsForDay(
        nextKemetic.kYear,
        nextKemetic.kMonth,
        nextKemetic.kDay,
      );
      if (nextDayEvents.isEmpty) continue;
      return DayViewSheetEventTarget(
        ky: nextKemetic.kYear,
        km: nextKemetic.kMonth,
        kd: nextKemetic.kDay,
        event: forward ? nextDayEvents.first : nextDayEvents.last,
      );
    }

    return null;
  }

  DayViewSheetEventTarget _resolveCalendarCurrentEventTarget(
    DayViewSheetEventTarget target,
  ) {
    final currentEvents = _calendarSheetEventsForDay(
      target.ky,
      target.km,
      target.kd,
    );
    if (currentEvents.isEmpty) return target;

    for (final candidate in currentEvents) {
      if (!_calendarSheetEventsShareStableIdentity(candidate, target.event)) {
        continue;
      }
      return DayViewSheetEventTarget(
        ky: target.ky,
        km: target.km,
        kd: target.kd,
        event: candidate,
      );
    }

    return target;
  }

  @visibleForTesting
  int filteredNoteCountForDay(int kYear, int kMonth, int kDay) {
    // Unified logic: all views read from _notes (which is the canonical source).
    // Zombie filters are already applied during _loadFromDisk, so we just count.
    final key = _kKey(kYear, kMonth, kDay);
    return (_notes[key] ?? const []).length;
  }
}

